# Centralized Memory Management System
class MemoryManager:
    """Centralized memory management for optimal performance."""
    
    def __init__(self):
        self._last_gc = time.time()
        self._gc_interval = 30.0  # GC every 30 seconds
        self._memory_threshold = 80.0  # Trigger GC at 80% memory usage
    
    def check_and_collect(self, force: bool = False) -> None:
        """Check memory usage and collect garbage if needed."""
        current_time = time.time()
        
        # Force GC or check interval
        if force or (current_time - self._last_gc) > self._gc_interval:
            try:
                # Check memory usage
                if psutil:
                    memory_percent = psutil.virtual_memory().percent
                    if memory_percent > self._memory_threshold or force:
                        gc.collect()
                        self._last_gc = current_time
            except Exception:
                pass  # Silent fail for memory management
    
    def optimize_caches(self) -> None:
        """Optimize internal caches for better performance."""
        try:
            # Clear internal caches
            if hasattr(gc, 'get_count'):
                gc.collect()
        except Exception:
            pass

# Global memory manager instance
_memory_manager = MemoryManager()

# Warning suppression with context manager
@contextlib.contextmanager
def suppress_warnings() -> Generator[None, None, None]:
    """Context manager to suppress common warnings during execution."""
    with warnings.catch_warnings():
        warnings.filterwarnings('ignore', category=DeprecationWarning)
        warnings.filterwarnings('ignore', category=FutureWarning)
        warnings.filterwarnings('ignore', message='.*pynvml.*deprecated.*')
        warnings.filterwarnings('ignore', message='.*sklearn.utils.parallel.delayed.*should be used with sklearn.utils.parallel.Parallel.*')
        warnings.filterwarnings('ignore', message='.*sklearn.utils.parallel.delayed.*')
        warnings.filterwarnings('ignore', module='sklearn.utils.parallel')
        warnings.filterwarnings('ignore', category=UserWarning)
        yield

# Apply warning suppression globally
with suppress_warnings():
    pass

