    def _calculate_file_creation_rate(self, process_info):
        """Calculate suspicious file creation rate (files per second)."""
        try:
            pid = process_info.get('pid', 0)
            if not pid:
                return 0.0
            
            # Monitor file creation activity for this process
            current_time = time.time()
            if not hasattr(self, '_file_creation_tracking'):
                self._file_creation_tracking = {}
            
            if pid not in self._file_creation_tracking:
                self._file_creation_tracking[pid] = {'count': 0, 'last_check': current_time}
            
            tracking = self._file_creation_tracking[pid]
            time_diff = current_time - tracking['last_check']
            
            if time_diff > 5.0:  # Check every 5 seconds
                # Simulate file creation monitoring (would integrate with file system watcher)
                suspicious_rate = len(process_info.get('cmdline', [])) > 5
                tracking['count'] = 10 if suspicious_rate else 1
                tracking['last_check'] = current_time
            
            rate = tracking['count'] / max(time_diff, 1.0)
            return min(rate / 10.0, 1.0)  # Normalize: 10 files/sec = max suspicious
        except Exception:
            return 0.0

    def _calculate_network_entropy(self, process_info):
        """Calculate network traffic entropy for anomaly detection."""
        try:
            connections = process_info.get('network_connections', 0)
            cmd_entropy = self._calculate_string_entropy(' '.join(process_info.get('cmdline', [])))
            
            # High entropy in network activity + high connections = suspicious
            network_score = min(connections / 20.0, 1.0)
            entropy_score = min(cmd_entropy / 4.0, 1.0)
            
            return (network_score * 0.6) + (entropy_score * 0.4)
        except Exception:
            return 0.0

    def _detect_syscall_anomalies(self, process_info):
        """Detect anomalous system call patterns."""
        try:
            cmdline = process_info.get('cmdline', [])
            suspicious_syscalls = [
                'virtualalloc', 'writeprocessmemory', 'createremotethread',
                'setwindowshookex', 'ntunmapviewofsection', 'zwunmapviewofsection'
            ]
            
            syscall_count = sum(1 for cmd in str(cmdline).lower() 
                             if any(sus in cmd for sus in suspicious_syscalls))
            
            # Also check for encoded/packed commands
            encoded_patterns = ['powershell -enc', 'powershell -e', '-encodedcommand']
            encoded_count = sum(1 for cmd in str(cmdline).lower() 
                             if any(pattern in cmd for pattern in encoded_patterns))
            
            total_suspicious = syscall_count + (encoded_count * 2)
            return min(total_suspicious / 5.0, 1.0)
        except Exception:
            return 0.0

    def _analyze_memory_patterns(self, process_info):
        """Analyze memory usage patterns for anomalies."""
        try:
            mem_pct = float(process_info.get('memory_percent', 0))
            cpu_pct = float(process_info.get('cpu_percent', 0))
            
            # Suspicious: high memory with low CPU (possible memory scraping)
            # Or very high memory usage overall
            if mem_pct > 80 and cpu_pct < 20:
                return 0.8
            elif mem_pct > 60:
                return 0.6
            elif mem_pct > 40:
                return 0.3
            
            return 0.0
        except Exception:
            return 0.0

    def _check_timing_consistency(self, process_info):
        """Check for consistent timing patterns (bot-like behavior)."""
        try:
            pid = process_info.get('pid', 0)
            if not pid:
                return 0.0
            
            current_time = time.time()
            if not hasattr(self, '_process_timing'):
                self._process_timing = {}
            
            if pid not in self._process_timing:
                self._process_timing[pid] = {'last_seen': current_time, 'intervals': []}
            
            timing = self._process_timing[pid]
            interval = current_time - timing['last_seen']
            timing['last_seen'] = current_time
            
            if len(timing['intervals']) > 10:
                timing['intervals'].pop(0)
            timing['intervals'].append(interval)
            
            # Check for very regular intervals (possible bot)
            if len(timing['intervals']) >= 5:
                intervals = timing['intervals'][-5:]
                avg_interval = sum(intervals) / len(intervals)
                variance = sum((x - avg_interval) ** 2 for x in intervals) / len(intervals)
                
                # Low variance = regular timing = suspicious
                if variance < 0.1 and avg_interval < 60:  # Regular and frequent
                    return 0.7
            
            return 0.0
        except Exception:
            return 0.0

    def _calculate_process_tree_depth(self, process_info):
        """Calculate process tree depth (deep nesting = suspicious)."""
        try:
            parent_pid = process_info.get('ppid', 0)
            depth = 0
            max_depth = 10
            
            # Simulate process tree traversal (would integrate with real process tree)
            while parent_pid and depth < max_depth:
                depth += 1
                # In real implementation, would look up parent process
                # For now, simulate based on process characteristics
                if process_info.get('parent_mismatch', False):
                    depth += 2  # Penalty for parent mismatch
                break
            
            return min(depth / 5.0, 1.0)  # Normalize: depth 5 = max suspicious
        except Exception:
            return 0.0

    def _detect_resource_spikes(self, process_info):
        """Detect frequent resource usage spikes."""
        try:
            pid = process_info.get('pid', 0)
            if not pid:
                return 0.0
            
            current_time = time.time()
            if not hasattr(self, '_resource_monitoring'):
                self._resource_monitoring = {}
            
            if pid not in self._resource_monitoring:
                self._resource_monitoring[pid] = {
                    'cpu_history': [], 'mem_history': [], 'last_check': current_time
                }
            
            monitoring = self._resource_monitoring[pid]
            cpu_pct = float(process_info.get('cpu_percent', 0))
            mem_pct = float(process_info.get('memory_percent', 0))
            
            monitoring['cpu_history'].append(cpu_pct)
            monitoring['mem_history'].append(mem_pct)
            
            # Keep only last 10 measurements
            if len(monitoring['cpu_history']) > 10:
                monitoring['cpu_history'].pop(0)
                monitoring['mem_history'].pop(0)
            
            # Calculate spike frequency
            if len(monitoring['cpu_history']) >= 5:
                cpu_spikes = sum(1 for i in range(1, len(monitoring['cpu_history']))
                               if abs(monitoring['cpu_history'][i] - monitoring['cpu_history'][i-1]) > 30)
                spike_rate = cpu_spikes / len(monitoring['cpu_history'])
                return min(spike_rate * 2, 1.0)
            
            return 0.0
        except Exception:
            return 0.0

    def _detect_encryption_activity(self, process_info):
        """Detect file encryption activity (ransomware indicator)."""
        try:
            cmdline = ' '.join(process_info.get('cmdline', [])).lower()
            name = process_info.get('name', '').lower()
            path = process_info.get('path', '').lower()
            
            encryption_indicators = [
                'encrypt', 'decrypt', 'cipher', 'aes', 'rsa', 'des',
                'crypt', 'lock', 'unlock', 'key', 'certificate'
            ]
            
            # Check process name and command line
            name_score = sum(1 for indicator in encryption_indicators if indicator in name)
            cmd_score = sum(1 for indicator in encryption_indicators if indicator in cmdline)
            
            # Check for suspicious file extensions being accessed
            suspicious_extensions = ['.doc', '.pdf', '.jpg', '.mp4', '.txt', '.db']
            extension_score = sum(1 for ext in suspicious_extensions if ext in cmdline)
            
            total_score = (name_score * 0.5) + (cmd_score * 0.3) + (extension_score * 0.2)
            return min(total_score / 5.0, 1.0)
        except Exception:
            return 0.0

