    def _calculate_model_confidence(self, model, features, prediction):
        """Calculate confidence score for model prediction."""
        try:
            if hasattr(model, 'predict_proba'):
                proba = model.predict_proba([features])
                return float(max(proba[0]))
            elif hasattr(model, 'decision_function'):
                decision = model.decision_function([features])
                return float(abs(decision[0]) / (abs(decision[0]) + 1))
            else:
                return 0.5  # Default confidence
        except Exception:
            return 0.3  # Low confidence on error

