        """Log model prediction errors for debugging."""
        try:
            error_msg = f"Model {model_name} prediction failed: {str(error)}"
            if hasattr(self, 'db') and self.db:
                self.db.execute("INSERT INTO model_errors VALUES (?, ?)", 
                              (model_name, error_msg[:500]))
        except Exception:
            pass  # Silent fail to avoid breaking main flow

