# psutil compat: .connections() renamed to .net_connections() in psutil 6.0
# Keep the warning filter as a belt-and-suspenders measure
warnings.filterwarnings('ignore', message=r'connections\(\) is deprecated',
                        category=DeprecationWarning)

def _proc_net_connections(proc, kind='inet'):
    """psutil 5.x / 6.x compatible wrapper for proc.connections()."""
    try:
        return proc.net_connections(kind=kind)   # psutil 6.0+
    except AttributeError:
        return proc.connections(kind=kind)        # psutil < 6.0

def _proc_has_connections(proc):
    """Return list of connections for proc, compatible with psutil 5 & 6."""
    try:
        return proc.net_connections()
    except AttributeError:
        try:
            return proc.connections()
        except Exception:
            return []

