def find_latest_python() -> str:
    """Find the latest Python installation (prioritizing 3.15+)."""
    import subprocess
    import sys
    import os
    from pathlib import Path
    
    # First, check if current Python is 3.15+
    current_version = sys.version_info
    if current_version.major >= 3 and current_version.minor >= 15:
        logger.info(f"Using current Python {current_version.major}.{current_version.minor}.{current_version.micro}")
        return sys.executable
    
    # Search for Python 3.15+ installations
    python_candidates = []
    
    # Common installation paths
    search_paths = [
        r"C:\Python3*",
        r"C:\Program Files\Python3*",
        r"C:\Program Files (x86)\Python3*",
        r"C:\Users\{}\AppData\Local\Programs\Python\Python3*".format(os.getenv('USERNAME', '')),
        r"C:\Python*",
    ]
    try:
        result = subprocess.run(['py', '--list'], capture_output=True, text=True, timeout=10, creationflags=_NO_WIN)
        if result.returncode == 0:
            versions = []
            for line in result.stdout.split('\n'):
                if line.strip() and '-' in line:
                    try:
                        version_part = line.split('-')[0].strip()
                        version_parts = version_part.split('.')
                        if len(version_parts) >= 2:
                            major, minor = int(version_parts[0]), int(version_parts[1])
                            versions.append((major, minor, version_part))
                    except (ValueError, IndexError):
                        continue
            
            if versions:
                # Sort by version (newest first) and get the best 3.8+ version
                versions.sort(reverse=True)
                for major, minor, version_str in versions:
                    if major > 3 or (major == 3 and minor >= 8):
                        py_cmd = f'py -{major}.{minor}'
                        # Verify this version actually works
                        verify_result = subprocess.run(
                            [py_cmd, '--version'], 
                            capture_output=True, text=True, timeout=5
                        , creationflags=_NO_WIN)
                        if verify_result.returncode == 0:
                            logger.info(f"Found Python {major}.{minor} via py launcher")
                            return py_cmd
        
    except (subprocess.TimeoutExpired, FileNotFoundError, PermissionError):
        pass
    
    # Fallback to common Python locations
    python_paths = [
        sys.executable,
        r'C:\Python312\python.exe',
        r'C:\Python311\python.exe',
        r'C:\Python310\python.exe',
        r'C:\Python39\python.exe',
        r'C:\Python38\python.exe',
        r'C:\Program Files\Python312\python.exe',
        r'C:\Program Files\Python311\python.exe',
        r'C:\Program Files\Python310\python.exe',
        r'C:\Program Files\Python39\python.exe',
        r'C:\Program Files\Python38\python.exe',
        r'C:\Program Files (x86)\Python312\python.exe',
        r'C:\Program Files (x86)\Python311\python.exe',
        r'C:\Program Files (x86)\Python310\python.exe',
        r'C:\Program Files (x86)\Python39\python.exe',
        r'C:\Program Files (x86)\Python38\python.exe',
    ]
    
    # Test each Python path and find the newest working version
    working_versions = []
    for python_path in python_paths:
        try:
            result = subprocess.run(
                [python_path, '--version'], 
                capture_output=True, text=True, timeout=5
            , creationflags=_NO_WIN)
            if result.returncode == 0:
                # Parse version from output
                version_output = result.stdout.strip() or result.stderr.strip()
                if 'Python' in version_output:
                    version_str = version_output.split()[-1]
                    version_parts = version_str.split('.')
                    if len(version_parts) >= 2:
                        major, minor = int(version_parts[0]), int(version_parts[1])
                        if major >= 3 and minor >= 8:
                            working_versions.append((major, minor, python_path, version_str))
        except (subprocess.TimeoutExpired, FileNotFoundError, PermissionError, ValueError):
            continue
    
    if working_versions:
        # Sort by version (newest first) and return the best
        working_versions.sort(reverse=True)
        major, minor, python_path, version_str = working_versions[0]
        logger.info(f"Using Python {major}.{minor} at: {python_path}")
        return python_path
    
    # Final fallback to current Python
    logger.info(f"No newer Python found, using current: {sys.executable}")
    return sys.executable

