BEST_PYTHON = find_latest_python()

def upgrade_package_manager() -> bool:
    """Upgrade pip and setuptools to latest versions using best Python."""
    try:
        import subprocess
        logger.info("Upgrading package management tools...")
        
        python_cmd = BEST_PYTHON.split() if BEST_PYTHON.startswith('py') else [BEST_PYTHON]
        _NO_WIN = getattr(subprocess, 'CREATE_NO_WINDOW', 0x08000000)
        
        # Upgrade pip first
        try:
            subprocess.check_call(
                python_cmd + ['-m', 'pip', 'install', '--upgrade', 'pip'],
                creationflags=_NO_WIN
            )
            logger.info("[OK] Upgraded pip to latest version")
        except subprocess.CalledProcessError as e:
            logger.warning(f"Failed to upgrade pip: {e}")
        
        # Upgrade setuptools and wheel
        try:
            subprocess.check_call(
                python_cmd + ['-m', 'pip', 'install', '--upgrade', 'setuptools', 'wheel'],
                creationflags=_NO_WIN
            )
            logger.info("[OK] Upgraded setuptools and wheel")
        except subprocess.CalledProcessError as e:
            logger.warning(f"Failed to upgrade setuptools/wheel: {e}")
        
        return True
        
    except Exception as e:
        logger.error(f"Package manager upgrade failed: {e}")
        return False

def verify_python_compatibility() -> dict:
    """Verify Python version compatibility and capabilities."""
    import subprocess
    import sys
    
    compatibility_report = {
        'current_version': f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}",
        'best_version': None,
        'compatible': False,
        'recommendations': [],
        'capabilities': []
    }
    
    try:
        # Get best Python version
        python_cmd = BEST_PYTHON.split() if BEST_PYTHON.startswith('py') else [BEST_PYTHON]
        
        result = subprocess.run(
            python_cmd + ['-c', 
                'import sys; '
                'print(f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}")'],
            capture_output=True, text=True, timeout=10
        , creationflags=_NO_WIN)
        
        if result.returncode == 0:
            compatibility_report['best_version'] = result.stdout.strip()
            
            # Check compatibility
            version_parts = result.stdout.strip().split('.')
            major, minor = int(version_parts[0]), int(version_parts[1])
            
            if major >= 3 and minor >= 8:
                compatibility_report['compatible'] = True
                
                # Add capabilities based on version
                if minor >= 10:
                    compatibility_report['capabilities'].append('Pattern matching')
                if minor >= 11:
                    compatibility_report['capabilities'].append('Exception groups')
                if minor >= 12:
                    compatibility_report['capabilities'].append('f-string debugging')
                if minor >= 13:
                    compatibility_report['capabilities'].append('PEP 696 TypeVar defaults')
                if minor >= 14:
                    compatibility_report['capabilities'].append('Improved error messages (3.14)')
                if minor >= 15:
                    compatibility_report['capabilities'].append('Latest Python 3.15 features')
            else:
                compatibility_report['recommendations'].append(
                    f"Python {major}.{minor} is too old. Please upgrade to 3.8+"
                )
        
        # Compare with current
        if compatibility_report['best_version'] != compatibility_report['current_version']:
            compatibility_report['recommendations'].append(
                f"Consider switching from Python {compatibility_report['current_version']} to {compatibility_report['best_version']}"
            )
        
    except Exception as e:
        logger.error(f"Compatibility verification failed: {e}")
        compatibility_report['recommendations'].append("Failed to verify Python compatibility")
    
    return compatibility_report

