def check_deps() -> dict[str, list[str]]:
    """Check dependencies and return missing packages by category."""
    missing_by_category: dict[str, list[str]] = {}
    
    for req in REQUIRED_PACKAGES:
        try:
            __import__(req.import_name)
        except ImportError:
            if req.category not in missing_by_category:
                missing_by_category[req.category] = []
            missing_by_category[req.category].append(req.package_name)
    
    return missing_by_category

def install_missing_packages(missing_by_category: dict[str, list[str]]) -> None:
    """Install missing packages with progress indication using best Python version."""
    if not missing_by_category:
        logger.info("All dependencies are satisfied")
        return
    
    # First, verify Python compatibility
    compatibility = verify_python_compatibility()
    logger.info(f"Python compatibility check: {compatibility['best_version']} (Current: {compatibility['current_version']})")
    
    if compatibility['recommendations']:
        for rec in compatibility['recommendations']:
            logger.info(f"Recommendation: {rec}")
    
    # Upgrade package manager first
    upgrade_package_manager()
    
    total_missing = sum(len(packages) for packages in missing_by_category.values())
    logger.info(f"Installing {total_missing} missing packages using Python: {BEST_PYTHON}")
    
    try:
        import subprocess
        import sys
        
        for category, packages in missing_by_category.items():
            logger.info(f"Installing {category} packages: {', '.join(packages)}")
            _NO_WIN = getattr(subprocess, 'CREATE_NO_WINDOW', 0x08000000)
            for package in packages:
                try:
                    # Use the best Python version found
                    python_cmd = BEST_PYTHON.split() if BEST_PYTHON.startswith('py') else [BEST_PYTHON]
                    
                    # Try with pre-compiled binaries first (faster)
                    install_cmd = python_cmd + ['-m', 'pip', 'install', '--only-binary', ':all:', package]
                    subprocess.check_call(install_cmd, creationflags=_NO_WIN)
                    logger.info(f"[OK] Installed {package} with binaries")
                except subprocess.CalledProcessError:
                    try:
                        # Fallback to source installation
                        install_cmd = python_cmd + ['-m', 'pip', 'install', package]
                        subprocess.check_call(install_cmd, creationflags=_NO_WIN)
                        logger.info(f"[OK] Installed {package} from source")
                    except subprocess.CalledProcessError as e:
                        # Try with --user flag as last resort
                        try:
                            install_cmd = python_cmd + ['-m', 'pip', 'install', '--user', package]
                            subprocess.check_call(install_cmd, creationflags=_NO_WIN)
                            logger.info(f"[OK] Installed {package} for current user")
                        except subprocess.CalledProcessError as e:
                            logger.error(f"[X] Failed to install {package}: {e}")
                    
    except Exception as e:
        logger.error(f"Package installation failed: {e}")

if '--check-deps' in sys.argv:
    missing = check_deps()
    if missing:
        print(f"Missing packages by category: {missing}")
        sys.exit(2)
    print("All dependencies OK")

if '--check-python' in sys.argv:
    """Check Python version and compatibility."""
    compatibility = verify_python_compatibility()
    print(f"\n=== Python Version Analysis ===")
    print(f"Current Python: {compatibility['current_version']}")
    print(f"Best Available:  {compatibility['best_version']}")
    print(f"Compatible:      {'[OK]' if compatibility['compatible'] else '[X]'}")
    
    if compatibility['capabilities']:
        print(f"\nCapabilities:")
        for cap in compatibility['capabilities']:
            print(f"  - {cap}")
    
    if compatibility['recommendations']:
        print(f"\nRecommendations:")
        for rec in compatibility['recommendations']:
            print(f"  - {rec}")
    
    print(f"\nUsing Python executable: {BEST_PYTHON}")
    sys.exit(0)

if '--upgrade-pip' in sys.argv:
    """Upgrade pip and package management tools."""
    print("Upgrading package management tools...")
    if upgrade_package_manager():
        print("[OK] Package manager upgrade completed successfully")
    else:
        print("[X] Package manager upgrade failed")
    sys.exit(0)



