# [ascii art removed]
#  LIVE CVE / CISA-KEV ENGINE  (auto-refreshes every 6 hours)
# [ascii art removed]
# stdlib aliases (CisaKevEngine uses _threading, _json, _time, _os, _re, _dt)
_threading = threading
_json      = json
_time      = time
_urlreq    = urllib.request
_os        = os
_math      = math
_re        = re
_dt        = datetime

class CisaKevEngine:
    """Downloads and caches the CISA Known Exploited Vulnerabilities catalog.
    Refreshes every 6 hours. Thread-safe. Used by CveDashboard tab."""

    KEV_URL    = "https://raw.githubusercontent.com/cisagov/kev-data/develop/known_exploited_vulnerabilities.json"
    _DATA_DIR  = _os.path.join(_os.path.dirname(__file__), "downpour_data")
    CACHE_PATH = _os.path.join(_DATA_DIR, "cisa_kev.json")
    REFRESH_HRS = 6

    def __init__(self, data_dir=None, callback=None):
        # Memory optimization
        self._last_gc = time.time()
        self._lock   = _threading.Lock()
        self._data   = []
        self._by_cve = {}
        self._last_refresh = 0.0
        self._loaded = False
        self._callback = callback
        self._running = False
        self._processes = {}
        self._network = {}
        self._filesystem = {}
        self._last_cleanup = time.time()
        self._last_network_scan = time.time()
        self._network_activity = {}  # Track network activity for anomaly detection
        self._file_replication = {}  # Track file replication patterns
        self._process_creation = {}  # Track process creation patterns
        self._network_shares = {}  # Track network share access
        self._removable_media = {}  # Track removable media activity
        self._email_activity = {}  # Track email sending patterns
        self._scan_results = {}  # Cache network scan results
        self._vulnerability_scan = {}  # Track vulnerability scanning activity
        self._propagation_attempts = {}  # Track propagation attempts
        self._worm_signatures = self._init_worm_signatures()
        self._blocked_processes = set()  # Track blocked worm processes
        self._quarantined_files = {}  # Track quarantined worm files
        self._network_isolation_active = False  # Track network isolation status
        self._callbacks = []

    def start(self):
        self.load_cache()
        t = _threading.Thread(target=self._loop, daemon=True, name='CisaKEV')
        t.start()

    def _loop(self):
        _stop = getattr(self, '_stop_event', None)
        while True:
            try:
                self._fetch()
            except Exception:
                pass
            if _stop and _stop.wait(self.REFRESH_HRS * 3600):
                break
            elif not _stop:
                _time.sleep(self.REFRESH_HRS * 3600)

    def _fetch(self):
        req = _urlreq.Request(self.KEV_URL,
                              headers={'User-Agent': 'Downpour/1.0'})
        with _urlreq.urlopen(req, timeout=25) as r:
            raw = _json.loads(r.read())
        vulns = raw.get('vulnerabilities', [])
        with self._lock:
            self._data   = vulns
            self._by_cve = {v['cveID']: v for v in vulns}
            self._last_refresh = _time.time()
            self._loaded = True
        _os.makedirs(self._DATA_DIR, exist_ok=True)
        with open(self.CACHE_PATH, 'w', encoding='utf-8') as f:
            _json.dump(raw, f)
        for cb in list(self._callbacks):  # snapshot: safe against mutation
            try: cb(len(vulns))
            except Exception: pass

    def load_cache(self):
        try:
            if _os.path.exists(self.CACHE_PATH):
                with open(self.CACHE_PATH, encoding='utf-8') as f:
                    raw = _json.load(f)
                vulns = raw.get('vulnerabilities', [])
                with self._lock:
                    self._data   = vulns
                    self._by_cve = {v['cveID']: v for v in vulns}
                    self._loaded = True
        except Exception:
            pass

    def get(self, cve_id):
        with self._lock:
            return self._by_cve.get(cve_id, {})

    def search(self, term):
        t = term.lower()
        with self._lock:
            return [v for v in self._data
                    if t in (v.get('product','') + v.get('vendorProject','') +
                              v.get('vulnerabilityName','')).lower()]

    def windows_cves(self, since_days=365):
        cutoff = _time.time() - since_days * 86400
        with self._lock:
            return [v for v in self._data
                    if any(w in (v.get('product','') +
                                  v.get('vendorProject','')).lower()
                           for w in ['windows','microsoft','office','exchange',
                                     'edge','iis','sharepoint','teams','outlook'])
                    and self._date_ts(v.get('dateAdded','')) >= cutoff]

    def recent(self, days=30):
        cutoff = _time.time() - days * 86400
        with self._lock:
            out = [v for v in self._data
                   if self._date_ts(v.get('dateAdded','')) >= cutoff]
        out.sort(key=lambda x: x.get('dateAdded',''), reverse=True)
        return out

    def _date_ts(self, s):
        try: return _dt.strptime(s, '%Y-%m-%d').timestamp()
        except Exception: return 0.0

    @property
    def count(self):
        with self._lock: return len(self._data)

    @property
    def last_updated(self):
        if self._last_refresh == 0: return "cached"
        return _dt.fromtimestamp(self._last_refresh).strftime('%Y-%m-%d %H:%M')

    def on_refresh(self, cb):
        self._callbacks.append(cb)

