# [ascii art removed]
#  ROOTKIT DETECTOR
# [ascii art removed]
class RootkitDetector:
    """Detects rootkit indicators:
     - Hidden processes (WMI vs psutil DKOM check)
     - Hidden ports (netstat vs psutil cross-check)
     - BYOVD / suspicious kernel drivers
     - DLL injection into critical processes
     - Autorun hijack indicators
    """

    _TRUSTED_DIRS = frozenset([
        'c:\\windows\\system32\\drivers',
        'c:\\windows\\syswow64',
        'c:\\program files',
        'c:\\program files (x86)',
        'c:\\windows\\system32',
        'c:\\windows\\sysnative',
    ])

    # Merged BYOVD driver set (original + 2024-2026 additions)
    # FIX-08: the original code had two separate sets; _check_drivers only
    # tested _BYOVD_DRIVERS (smaller). Merged into one canonical set.
    _BYOVD_DRIVERS = frozenset({
        # Original set
        'gdrv.sys','winio.sys','speedfan.sys','ene.sys','rentdrv2.sys',
        'mtipciide.sys','phymemx64.sys','dbutil_2_3.sys','mhyprot2.sys',
        'procexp.sys','elbycdio.sys','cpuz141_x64.sys','gpu-z.sys',
        'atillk64.sys','aswarpot.sys','asrdrv106.sys','nvflash.sys',
        'kprocesshacker.sys','openlibsys.sys','ntiolib.sys',
        # 2024-2027 additions
        'inpoutx64.sys','gmer.sys','amifldrv64.sys','bs_def64.sys',
        'zemana.sys','rtkio64.sys','lha.sys',
        'directio64.sys','hwrwdrv.sys','superbmc.sys',
        'etdsupp.sys','amdppm.sys','msio64.sys',
        'cpuz141.sys','cpuz143.sys',
        'rtcore64.sys','iqvw64e.sys',
        'nvflash64.sys','asio64.sys','mhyprot3.sys',
        'winio64.sys','winring0x64.sys','physmem.sys',
    })
    BYOVD_DRIVERS = _BYOVD_DRIVERS  # alias  -  both names work

    def run_full_check(self, alert_cb, graph_cb):
        findings = []
        for fn in [self._check_hidden_procs, self._check_hidden_ports,
                   self._check_drivers,      self._check_dll_inject,
                   self._check_autorun]:
            try:
                findings += fn(alert_cb, graph_cb)
            except Exception:
                pass
        return findings

    def _check_hidden_procs(self, alert_cb, graph_cb):
        import subprocess, psutil
        findings = []
        r = subprocess.run(
            ['wmic','process','get','ProcessId', '/FORMAT:csv'],
            capture_output=True, text=True, timeout=15, creationflags=_NO_WIN)
        wmi_pids = set()
        for line in r.stdout.splitlines():
            parts = line.strip().split(',')
            if parts:
                try: wmi_pids.add(int(parts[-1]))
                except ValueError: pass
        ps_pids = set(psutil.pids())
        ghost   = ps_pids - wmi_pids - {0, 2, 4, 8}  # 0=idle,2=interrupt,4=system,8=HAL
        for pid in ghost:
            try:
                p    = psutil.Process(pid)
                name = p.name()
                exe  = ''
                try: exe = p.exe()
                except psutil.AccessDenied: exe = '(access denied)'
                msg = (f'[ROOTKIT] Ghost process  -  visible to psutil, NOT in WMI:\n'
                       f'PID {pid}  {name}  {exe}\n'
                       f'DKOM rootkit indicator  -  process hidden from task managers.')
                alert_cb(msg, Colors.GAUGE_RED)
                graph_cb(f'PID:{pid}', 'Rootkit-DKOM', f'ghost {name}')
                findings.append({'type': 'hidden_proc', 'pid': pid, 'name': name})
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
        return findings

    def _check_hidden_ports(self, alert_cb, graph_cb):
        import subprocess, psutil, re
        findings = []
        r = subprocess.run(['netstat','-ano'], capture_output=True, text=True, timeout=10, creationflags=_NO_WIN)
        ns_ports = set()
        for line in r.stdout.splitlines():
            m = re.search(r':(\d+)\s+\S+\s+(LISTENING|ESTABLISHED)', line)
            if m:
                ns_ports.add(int(m.group(1)))
        ps_ports = set()
        for c in psutil.net_connections(kind='inet'):
            if c.laddr: ps_ports.add(c.laddr.port)
        hidden = {p for p in (ps_ports - ns_ports) if p < 49152 and p > 0}
        for port in hidden:
            msg = (f'[ROOTKIT] Port {port} visible to psutil but HIDDEN from netstat.\n'
                   f'Network rootkit may be filtering netstat output.')
            alert_cb(msg, Colors.GAUGE_RED)
            graph_cb(f'PORT:{port}', 'Rootkit-NetHook', f'hidden port {port}')
            findings.append({'type': 'hidden_port', 'port': port})
        return findings

    def _check_drivers(self, alert_cb, graph_cb):
        import subprocess, os, json
        findings = []
        r = subprocess.run(
            ['powershell','-NoProfile','-NonInteractive','-Command',
             'Get-WmiObject Win32_SystemDriver | Select-Object Name,PathName,State | ConvertTo-Json -Depth 2'],
            capture_output=True, text=True, timeout=20, creationflags=0x08000000)
        if r.returncode != 0 or not r.stdout.strip():
            return findings
        try:
            drivers = json.loads(r.stdout)
            if isinstance(drivers, dict): drivers = [drivers]
            for d in drivers:
                path  = (d.get('PathName') or '').lower().replace('/', '\\')
                state = d.get('State', '')
                fname = os.path.basename(path)
                if fname in self._BYOVD_DRIVERS:
                    alert_cb(
                        f'[BYOVD] Known-vulnerable driver loaded: {d.get("PathName","?")}\n'
                        f'State: {state}  -  this driver is a CVE-mapped BYOVD abuse target.',
                        Colors.GAUGE_RED)
                    graph_cb(path, 'BYOVD-Driver', fname)
                    findings.append({'type': 'byovd', 'driver': fname})
                elif path and state == 'Running':
                    if not any(path.startswith(td) for td in self._TRUSTED_DIRS):
                        alert_cb(
                            f'[ROOTKIT] Driver running from unusual location:\n{d.get("PathName","?")}\n'
                            f'Expected: system32\\drivers  -  investigate immediately.',
                            Colors.GAUGE_ORANGE)
                        graph_cb(path, 'Rootkit-Driver', 'unusual path')
                        findings.append({'type': 'unusual_driver', 'path': path})
        except (json.JSONDecodeError, TypeError):
            pass
        return findings

    def _check_dll_inject(self, alert_cb, graph_cb):
        import psutil
        findings = []
        TARGETS = {'lsass.exe','winlogon.exe','services.exe','csrss.exe',
                   'explorer.exe','svchost.exe','spoolsv.exe'}
        SUS     = {'\\temp\\','\\appdata\\local\\temp\\','\\downloads\\',
                   '\\public\\','\\programdata\\','\\users\\public\\'}
        for proc in psutil.process_iter(['pid','name']):
            if not proc.info.get('name'): continue
            if proc.info['name'].lower() not in TARGETS: continue
            try:
                for m in proc.memory_maps():
                    pl = m.path.lower()
                    if not pl.endswith('.dll'): continue
                    if any(s in pl for s in SUS):
                        alert_cb(
                            f'[DLL INJECT] Suspicious DLL in {proc.info["name"]} '
                            f'(PID {proc.pid}):\n{m.path}',
                            Colors.GAUGE_RED)
                        graph_cb(m.path, 'DLL-Inject', proc.info['name'])
                        findings.append({'type': 'dll_inject',
                                         'proc': proc.info['name'], 'dll': m.path})
            except (psutil.AccessDenied, psutil.NoSuchProcess,
                    psutil.ZombieProcess, NotImplementedError):
                pass
        return findings

    def _check_autorun(self, alert_cb, graph_cb):
        import subprocess
        findings = []
        KEYS = [
            r'HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\Run',
            r'HKCU\SOFTWARE\Microsoft\Windows\CurrentVersion\Run',
            r'HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\RunOnce',
            r'HKCU\SOFTWARE\Microsoft\Windows\CurrentVersion\RunOnce',
            r'HKLM\SOFTWARE\Wow6432Node\Microsoft\Windows\CurrentVersion\Run',
        ]
        SUS = {'\\temp\\','\\appdata\\local\\temp\\','\\downloads\\','\\users\\public\\',
               '%temp%','%appdata%','powershell','cmd /c','wscript','cscript',
               'mshta','regsvr32','rundll32 ','certutil','.ps1','base64'}
        for key in KEYS:
            try:
                r = subprocess.run(['reg','query', key],
                                   capture_output=True, text=True, timeout=5, creationflags=_NO_WIN)
                for line in r.stdout.splitlines():
                    if 'REG_' not in line: continue
                    ll = line.lower()
                    if any(s in ll for s in SUS):
                        alert_cb(
                            f'[AUTORUN HIJACK] Suspicious autorun entry:\n'
                            f'Key: {key}\nValue: {line.strip()[:200]}',
                            Colors.GAUGE_RED)
                        graph_cb(key, 'Autorun-Hijack', line.strip()[:80])
                        findings.append({'type': 'autorun', 'key': key,
                                         'value': line.strip()})
            except Exception:
                pass
        return findings

    # -------------------------------------------------------------------
    # Deep Persistence Cleaning  (added v28-titanium p16)
    # -------------------------------------------------------------------

    def deep_clean(self, alert_cb, graph_cb):
        """Run all deep persistence cleaning passes and return findings."""
        findings = []
        for fn in [self._clean_wmi_persistence,
                   self._clean_ifeo_debuggers,
                   self._clean_appinit_dlls,
                   self._clean_com_hijacks,
                   self._clean_malicious_services,
                   self._clean_alternate_data_streams,
                   self._clean_lsa_providers,
                   self._clean_print_monitor_dlls]:
            try:
                findings += fn(alert_cb, graph_cb)
            except Exception:
                pass
        return findings

    # -- WMI event subscription persistence --
    def _clean_wmi_persistence(self, alert_cb, graph_cb):
        import subprocess, json
        findings = []
        for cls in ['__EventFilter', 'CommandLineEventConsumer',
                    'ActiveScriptEventConsumer',
                    '__FilterToConsumerBinding']:
            try:
                r = subprocess.run(
                    ['powershell', '-NoProfile', '-NonInteractive', '-Command',
                     f'Get-WmiObject -Namespace root\\subscription -Class {cls} '
                     f'| Select-Object -Property * | ConvertTo-Json -Depth 3'],
                    capture_output=True, text=True, timeout=20,
                    creationflags=0x08000000)
                if r.returncode != 0 or not r.stdout.strip():
                    continue
                items = json.loads(r.stdout)
                if isinstance(items, dict):
                    items = [items]
                for item in items:
                    name = item.get('Name', item.get('__RELPATH', 'unknown'))
                    cmd  = (item.get('CommandLineTemplate', '')
                            or item.get('ScriptText', '')
                            or str(item.get('Filter', '')))
                    cmd_l = cmd.lower()
                    # Flag anything that runs powershell, cmd, scripts from
                    # temp/appdata, or uses encoded commands
                    sus_markers = ['powershell', 'cmd.exe', '\\temp\\',
                                   '\\appdata\\', '-enc ', '-e ', 'base64',
                                   'iex(', 'invoke-expression',
                                   'downloadstring', 'downloadfile',
                                   '.vbs', '.js', '.hta', 'mshta',
                                   'certutil', 'bitsadmin']
                    if any(m in cmd_l for m in sus_markers):
                        alert_cb(
                            f'[ROOTKIT] Malicious WMI persistence found:\n'
                            f'Class: {cls}  Name: {name}\n'
                            f'Payload: {cmd[:200]}\n'
                            f'Removing...',
                            Colors.GAUGE_RED)
                        graph_cb(f'WMI:{cls}', 'Rootkit-WMI', name)
                        # Remove
                        subprocess.run(
                            ['powershell', '-NoProfile', '-NonInteractive',
                             '-Command',
                             f'Get-WmiObject -Namespace root\\subscription '
                             f'-Class {cls} -Filter "Name=\'{name}\'" '
                             f'| Remove-WmiObject -Confirm:$false'],
                            capture_output=True, timeout=10,
                            creationflags=0x08000000)
                        findings.append({'type': 'wmi_persistence',
                                         'class': cls, 'name': name,
                                         'action': 'removed'})
            except (json.JSONDecodeError, TypeError, subprocess.TimeoutExpired):
                pass
        return findings

    # -- Image File Execution Options debugger hijacks --
    def _clean_ifeo_debuggers(self, alert_cb, graph_cb):
        import subprocess
        findings = []
        r = subprocess.run(
            ['reg', 'query',
             r'HKLM\SOFTWARE\Microsoft\Windows NT\CurrentVersion'
             r'\Image File Execution Options',
             '/s', '/v', 'Debugger'],
            capture_output=True, text=True, timeout=10,
            creationflags=0x08000000)
        for line in r.stdout.splitlines():
            if 'Debugger' not in line or 'REG_SZ' not in line:
                continue
            ll = line.lower()
            sus = ['cmd', 'powershell', 'mshta', 'wscript', 'cscript',
                   'certutil', '\\temp\\', '\\appdata\\', '.bat', '.ps1']
            if any(s in ll for s in sus):
                # Extract the key path from context
                parts = line.strip().split('REG_SZ')
                debugger_val = parts[-1].strip() if len(parts) > 1 else ''
                alert_cb(
                    f'[ROOTKIT] IFEO debugger hijack detected:\n'
                    f'Debugger: {debugger_val[:200]}\n'
                    f'This redirects legitimate executables to malware.',
                    Colors.GAUGE_RED)
                graph_cb('IFEO', 'Rootkit-IFEO', debugger_val[:80])
                findings.append({'type': 'ifeo_hijack',
                                 'debugger': debugger_val})
        return findings

    # -- AppInit_DLLs (loaded into every user-mode process) --
    def _clean_appinit_dlls(self, alert_cb, graph_cb):
        import subprocess
        findings = []
        for key in [r'HKLM\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Windows',
                    r'HKLM\SOFTWARE\Wow6432Node\Microsoft\Windows NT'
                    r'\CurrentVersion\Windows']:
            try:
                r = subprocess.run(
                    ['reg', 'query', key, '/v', 'AppInit_DLLs'],
                    capture_output=True, text=True, timeout=5,
                    creationflags=0x08000000)
                for line in r.stdout.splitlines():
                    if 'AppInit_DLLs' not in line or 'REG_SZ' not in line:
                        continue
                    val = line.split('REG_SZ')[-1].strip()
                    if not val:
                        continue
                    vl = val.lower()
                    # Trusted: empty or known AV DLLs
                    trusted = ['pghook', 'uxtheme', 'comctl32']
                    if any(t in vl for t in trusted):
                        continue
                    alert_cb(
                        f'[ROOTKIT] AppInit_DLLs set — injects into ALL '
                        f'processes:\n{val}\nClearing...',
                        Colors.GAUGE_RED)
                    graph_cb('AppInit', 'Rootkit-AppInit', val[:80])
                    subprocess.run(
                        ['reg', 'add', key, '/v', 'AppInit_DLLs',
                         '/t', 'REG_SZ', '/d', '', '/f'],
                        capture_output=True, timeout=5,
                        creationflags=0x08000000)
                    findings.append({'type': 'appinit_dll', 'value': val,
                                     'action': 'cleared'})
            except subprocess.TimeoutExpired:
                pass
        return findings

    # -- COM object hijacks (CLSID persistence) --
    def _clean_com_hijacks(self, alert_cb, graph_cb):
        import subprocess, os
        findings = []
        # Common hijacked CLSIDs used for persistence
        hijack_clsids = [
            ('{b5f8350b-0548-48b1-a6ee-88bd00b4a5e7}', 'CAccPropServicesClass'),
            ('{BCDE0395-E52F-467C-8E3D-C4579291692E}', 'MMDeviceEnumerator'),
            ('{C6B14B32-76AA-4A86-A7C5-2D88CC610BD5}', 'EventSystem'),
        ]
        for clsid, desc in hijack_clsids:
            key = f'HKCU\\SOFTWARE\\Classes\\CLSID\\{clsid}\\InprocServer32'
            try:
                r = subprocess.run(
                    ['reg', 'query', key],
                    capture_output=True, text=True, timeout=5,
                    creationflags=0x08000000)
                if r.returncode == 0 and r.stdout.strip():
                    # HKCU override exists — this is a hijack
                    for line in r.stdout.splitlines():
                        if 'REG_SZ' in line or 'REG_EXPAND_SZ' in line:
                            dll_path = line.split('REG_')[-1].split(None, 1)
                            dll_val = dll_path[-1].strip() if dll_path else ''
                            if dll_val:
                                alert_cb(
                                    f'[ROOTKIT] COM object hijack ({desc}):\n'
                                    f'CLSID: {clsid}\nDLL: {dll_val}\n'
                                    f'Removing HKCU override...',
                                    Colors.GAUGE_RED)
                                graph_cb(f'COM:{clsid}', 'Rootkit-COM', desc)
                                subprocess.run(
                                    ['reg', 'delete', key, '/f'],
                                    capture_output=True, timeout=5,
                                    creationflags=0x08000000)
                                findings.append({'type': 'com_hijack',
                                                 'clsid': clsid,
                                                 'dll': dll_val,
                                                 'action': 'removed'})
                                break
            except subprocess.TimeoutExpired:
                pass
        return findings

    # -- Malicious services installed by rootkits --
    def _clean_malicious_services(self, alert_cb, graph_cb):
        import subprocess, json
        findings = []
        try:
            r = subprocess.run(
                ['powershell', '-NoProfile', '-NonInteractive', '-Command',
                 'Get-WmiObject Win32_Service | Where-Object {'
                 '$_.PathName -and $_.Started -eq $true -and '
                 '$_.PathName -notlike "*system32*" -and '
                 '$_.PathName -notlike "*Program Files*" -and '
                 '$_.PathName -notlike "*SysWOW64*"'
                 '} | Select-Object Name,PathName,StartMode,Description '
                 '| ConvertTo-Json -Depth 2'],
                capture_output=True, text=True, timeout=25,
                creationflags=0x08000000)
            if r.returncode != 0 or not r.stdout.strip():
                return findings
            svcs = json.loads(r.stdout)
            if isinstance(svcs, dict):
                svcs = [svcs]
            sus_paths = ['\\temp\\', '\\appdata\\', '\\downloads\\',
                         '\\users\\public\\', '\\programdata\\',
                         '\\perflogs\\']
            for svc in svcs:
                path = (svc.get('PathName') or '').lower()
                name = svc.get('Name', '?')
                if any(s in path for s in sus_paths):
                    alert_cb(
                        f'[ROOTKIT] Suspicious service running from '
                        f'non-standard path:\n'
                        f'Service: {name}\nPath: {svc.get("PathName","?")}\n'
                        f'StartMode: {svc.get("StartMode","?")}\n'
                        f'Stopping and disabling...',
                        Colors.GAUGE_RED)
                    graph_cb(f'SVC:{name}', 'Rootkit-Service', path[:80])
                    subprocess.run(
                        ['sc', 'stop', name],
                        capture_output=True, timeout=10,
                        creationflags=0x08000000)
                    subprocess.run(
                        ['sc', 'config', name, 'start=', 'disabled'],
                        capture_output=True, timeout=10,
                        creationflags=0x08000000)
                    findings.append({'type': 'malicious_service',
                                     'name': name, 'path': path,
                                     'action': 'stopped_disabled'})
        except (json.JSONDecodeError, TypeError, subprocess.TimeoutExpired):
            pass
        return findings

    # -- Alternate Data Streams hiding malware in NTFS --
    def _clean_alternate_data_streams(self, alert_cb, graph_cb):
        import subprocess, os
        findings = []
        # Check common persistence locations for ADS
        check_dirs = [
            os.path.expandvars(r'%APPDATA%'),
            os.path.expandvars(r'%LOCALAPPDATA%'),
            os.path.expandvars(r'%TEMP%'),
            os.path.expandvars(r'%USERPROFILE%\Desktop'),
        ]
        for d in check_dirs:
            if not os.path.isdir(d):
                continue
            try:
                r = subprocess.run(
                    ['powershell', '-NoProfile', '-NonInteractive',
                     '-Command',
                     f'Get-ChildItem -Path "{d}" -Recurse -ErrorAction '
                     f'SilentlyContinue | ForEach-Object {{ '
                     f'Get-Item $_.FullName -Stream * -ErrorAction '
                     f'SilentlyContinue | Where-Object {{ '
                     f'$_.Stream -ne ":$DATA" -and $_.Stream -ne "Zone.Identifier" '
                     f'}} }} | Select-Object FileName,Stream,Length '
                     f'| ConvertTo-Json -Depth 2'],
                    capture_output=True, text=True, timeout=30,
                    creationflags=0x08000000)
                if r.returncode != 0 or not r.stdout.strip():
                    continue
                import json
                streams = json.loads(r.stdout)
                if isinstance(streams, dict):
                    streams = [streams]
                for s in streams:
                    fname  = s.get('FileName', '?')
                    stream = s.get('Stream', '?')
                    length = s.get('Length', 0)
                    if length and length > 100:  # small ADS are usually benign
                        alert_cb(
                            f'[ROOTKIT] Hidden NTFS Alternate Data Stream:\n'
                            f'File: {fname}\nStream: {stream} '
                            f'({length} bytes)\n'
                            f'Malware can hide payloads in ADS.',
                            Colors.GAUGE_ORANGE)
                        graph_cb(f'ADS:{fname}', 'Rootkit-ADS', stream)
                        findings.append({'type': 'ads', 'file': fname,
                                         'stream': stream, 'size': length})
            except (subprocess.TimeoutExpired, json.JSONDecodeError,
                    TypeError):
                pass
        return findings

    # -- LSA authentication/security provider DLL injection --
    def _clean_lsa_providers(self, alert_cb, graph_cb):
        import subprocess
        findings = []
        keys = [
            (r'HKLM\SYSTEM\CurrentControlSet\Control\Lsa',
             'Security Packages'),
            (r'HKLM\SYSTEM\CurrentControlSet\Control\Lsa',
             'Authentication Packages'),
            (r'HKLM\SYSTEM\CurrentControlSet\Control\Lsa\OSConfig',
             'Security Packages'),
        ]
        known_safe = {'kerberos', 'msv1_0', 'schannel', 'wdigest',
                      'tspkg', 'pku2u', 'cloudap', 'negoextender',
                      'negossp', 'livessp', '', 'msoidssp'}
        for key_path, val_name in keys:
            try:
                r = subprocess.run(
                    ['reg', 'query', key_path, '/v', val_name],
                    capture_output=True, text=True, timeout=5,
                    creationflags=0x08000000)
                for line in r.stdout.splitlines():
                    if val_name not in line:
                        continue
                    if 'REG_MULTI_SZ' in line:
                        packages = line.split('REG_MULTI_SZ')[-1].strip()
                        for pkg in packages.split('\\0'):
                            pkg = pkg.strip()
                            if pkg.lower() not in known_safe and pkg:
                                alert_cb(
                                    f'[ROOTKIT] Unknown LSA provider:\n'
                                    f'{val_name}: {pkg}\n'
                                    f'Rootkits inject credential-stealing '
                                    f'DLLs here (mimikatz SSP).',
                                    Colors.GAUGE_RED)
                                graph_cb('LSA', 'Rootkit-LSA', pkg)
                                findings.append({'type': 'lsa_provider',
                                                 'package': pkg})
            except subprocess.TimeoutExpired:
                pass
        return findings

    # -- Print Monitor DLLs (System-level persistence) --
    def _clean_print_monitor_dlls(self, alert_cb, graph_cb):
        import subprocess, os
        findings = []
        key = (r'HKLM\SYSTEM\CurrentControlSet\Control\Print\Monitors')
        try:
            r = subprocess.run(
                ['reg', 'query', key, '/s'],
                capture_output=True, text=True, timeout=10,
                creationflags=0x08000000)
            known_monitors = {'localspl.dll', 'tcpmon.dll', 'wsdmon.dll',
                              'usbmon.dll', 'apmon.dll', 'localui.dll',
                              'tcpmonui.dll', 'wsdmonui.dll',
                              'pjlmon.dll', 'clprint.dll',
                              'msonppmon.dll', 'fxsmon.dll',
                              'hpmon.dll', 'redmonnt.dll'}
            for line in r.stdout.splitlines():
                if 'Driver' not in line or 'REG_SZ' not in line:
                    continue
                dll = line.split('REG_SZ')[-1].strip().lower()
                dll_base = os.path.basename(dll)
                if dll_base and dll_base not in known_monitors:
                    # Verify it's not in system32
                    sys32 = os.path.join(
                        os.environ.get('SystemRoot', r'C:\Windows'),
                        'system32', dll_base)
                    if not os.path.isfile(sys32):
                        alert_cb(
                            f'[ROOTKIT] Suspicious Print Monitor DLL:\n'
                            f'{dll}\nPrint monitors run as SYSTEM — '
                            f'malware uses this for persistence.',
                            Colors.GAUGE_RED)
                        graph_cb('PrintMon', 'Rootkit-PrintMon', dll)
                        findings.append({'type': 'print_monitor',
                                         'dll': dll})
        except subprocess.TimeoutExpired:
            pass
        return findings


# [ascii art removed]
#  BOOTKIT DETECTOR
# [ascii art removed]
class BootkitDetector:
    """Detects bootkit/UEFI implant indicators:
     - Secure Boot state
     - BCD anomalies (nointegritychecks, testsigning, WinPE)
     - MBR hash baseline comparison
    """

    _DATA_DIR    = _os.path.join(_os.path.dirname(__file__), 'downpour_data')
    MBR_BASELINE = _os.path.join(_DATA_DIR, 'mbr_baseline.bin')

    def run_check(self, alert_cb, graph_cb):
        findings = []
        for fn in [self._check_secure_boot, self._check_bcd,
                   self._check_test_signing, self._check_mbr,
                   self._check_efi_partition, self._check_driver_signatures]:
            try:
                findings += fn(alert_cb, graph_cb)
            except Exception:
                pass
        return findings

    def _check_efi_partition(self, alert_cb, graph_cb):
        """Check EFI system partition for unauthorized bootloaders."""
        findings = []
        try:
            import subprocess
            # List EFI boot entries
            r = subprocess.run(['bcdedit', '/enum', 'firmware'],
                               capture_output=True, text=True, timeout=10,
                               creationflags=0x08000000)
            if r.returncode == 0:
                lines = r.stdout.lower()
                # Check for suspicious boot entries
                suspicious = ['linux', 'grub', 'shell', 'debug', 'test', 'custom']
                for s in suspicious:
                    if s in lines and s not in ('linuxsubsystem',):
                        findings.append({
                            'check': 'EFI Boot Entries',
                            'status': 'WARNING',
                            'detail': f'Non-standard boot entry found: {s}',
                            'severity': 'MEDIUM',
                        })
                        if alert_cb:
                            alert_cb(f"[!] EFI: Non-standard boot entry '{s}' found", '#FFD700')
        except Exception:
            pass
        return findings

    def _check_driver_signatures(self, alert_cb, graph_cb):
        """Check for unsigned kernel drivers that could indicate rootkits."""
        findings = []
        try:
            import subprocess
            r = subprocess.run(
                ['powershell', '-Command',
                 'Get-WmiObject Win32_SystemDriver | Where-Object {$_.Started -eq $true} | Select-Object Name,PathName,State | ConvertTo-Json'],
                capture_output=True, text=True, timeout=30,
                creationflags=0x08000000)
            if r.returncode == 0 and r.stdout.strip():
                import json
                drivers = json.loads(r.stdout)
                if isinstance(drivers, dict):
                    drivers = [drivers]
                suspicious_drivers = []
                for d in drivers:
                    name = (d.get('Name') or '').lower()
                    path = (d.get('PathName') or '').lower()
                    # Flag drivers not in system32/drivers
                    if path and 'system32\\drivers' not in path and 'systemroot' not in path:
                        suspicious_drivers.append(name)
                if suspicious_drivers:
                    findings.append({
                        'check': 'Driver Signatures',
                        'status': 'WARNING',
                        'detail': f'{len(suspicious_drivers)} drivers loaded from non-standard paths',
                        'severity': 'HIGH',
                    })
                    if alert_cb:
                        alert_cb(f"[!] {len(suspicious_drivers)} drivers from non-standard paths", '#FF6600')
        except Exception:
            pass
        return findings

    def _check_secure_boot(self, alert_cb, graph_cb):
        import subprocess
        findings = []
        r = subprocess.run(
            ['powershell','-NoProfile','-NonInteractive','-Command',
             'Confirm-SecureBootUEFI 2>&1'],
            capture_output=True, text=True, timeout=10, creationflags=0x08000000)
        out = r.stdout.strip().lower()
        if 'false' in out:
            # Only alert if user has NOT bypassed TPM/BitLocker checks
            import __main__
            app = getattr(__main__, '_downpour_app', None)
            bypassed = getattr(app, '_bypass_tpm_bitlocker', False) if app else False
            if not bypassed:
                alert_cb(
                    '[BOOTKIT RISK] Secure Boot is DISABLED!\n'
                    'Unsigned bootloaders and bootkits can load before Windows.\n'
                    'Fix: BIOS/UEFI -> Security -> Secure Boot -> Enabled\n'
                    'Or enable bypass in Settings to suppress this warning.',
                    Colors.GAUGE_RED)
                graph_cb('SecureBoot', 'Bootkit-UEFI', 'disabled')
                findings.append({'type': 'secure_boot_off'})
        return findings

    def _check_bcd(self, alert_cb, graph_cb):
        import subprocess
        findings = []
        r = subprocess.run(['bcdedit','/enum','all'],
                           capture_output=True, text=True, timeout=10, creationflags=_NO_WIN)
        bc = r.stdout.lower()
        checks = [
            ('nointegritychecks  yes',
             '[BOOTKIT] Kernel integrity checks DISABLED (nointegritychecks yes)\n'
             'Fix: bcdedit /set nointegritychecks off'),
            ('recoveryenabled  no',
             '[RANSOMWARE] Boot recovery disabled  -  ransomware prep indicator\n'
             'Fix: bcdedit /set recoveryenabled yes'),
            ('hypervisorlaunchtype  off',
             '[SECURITY] Hypervisor/VBS is OFF  -  kernel isolation disabled\n'
             'Fix: bcdedit /set hypervisorlaunchtype auto'),
        ]
        for indicator, msg in checks:
            if indicator in bc:
                alert_cb(msg, Colors.GAUGE_ORANGE)
                graph_cb('BCD', 'Bootkit-BCD', indicator)
                findings.append({'type': 'bcd_anomaly', 'indicator': indicator})
        return findings

    def _check_test_signing(self, alert_cb, graph_cb):
        import subprocess
        findings = []
        r = subprocess.run(['bcdedit','/enum'], capture_output=True, text=True, timeout=8, creationflags=_NO_WIN)
        if 'testsigning  yes' in r.stdout.lower():
            alert_cb(
                '[ROOTKIT] Test signing mode ENABLED!\n'
                'Unsigned kernel drivers (rootkits) can load freely.\n'
                'Auto-fixing: bcdedit /set testsigning off',
                Colors.GAUGE_RED)
            graph_cb('TestSigning', 'Rootkit-Signing', 'enabled')
            subprocess.run(['bcdedit','/set','testsigning','off'], capture_output=True, timeout=15, creationflags=_NO_WIN)
            findings.append({'type': 'test_signing'})
        return findings

    def _check_mbr(self, alert_cb, graph_cb):
        import subprocess, hashlib, os, base64
        findings = []
        r = subprocess.run(
            ['powershell','-NoProfile','-NonInteractive','-Command',
             r'try{$d=[System.IO.File]::OpenRead("\\.\PhysicalDrive0");'
             r'$b=New-Object byte[] 512;$d.Read($b,0,512)|Out-Null;$d.Close();'
             r'[Convert]::ToBase64String($b)}catch{"ERROR"}'],
            capture_output=True, text=True, timeout=15, creationflags=_NO_WIN)
        out = r.stdout.strip()
        if not out or out == 'ERROR': return findings
        try:
            mbr   = base64.b64decode(out)
            mhash = hashlib.sha256(mbr).hexdigest()
            os.makedirs(self._DATA_DIR, exist_ok=True)
            if os.path.exists(self.MBR_BASELINE):
                try:
                    with open(self.MBR_BASELINE, 'rb') as _mbrf:
                        baseline_hash = hashlib.sha256(_mbrf.read()).hexdigest()
                except OSError:
                    baseline_hash = None
                if baseline_hash is not None and mhash != baseline_hash:
                    alert_cb(
                        f'[BOOTKIT] MBR HASH MISMATCH  -  possible bootkit installed!\n'
                        f'Baseline: {baseline_hash[:24]}...\n'
                        f'Current:  {mhash[:24]}...\n'
                        f'Investigate with a live boot CD before next reboot.',
                        Colors.GAUGE_RED)
                    graph_cb('MBR', 'Bootkit-MBR', 'hash changed')
                    findings.append({'type': 'mbr_changed', 'hash': mhash})
            else:
                try:
                    os.makedirs(self._DATA_DIR, exist_ok=True)
                    with open(self.MBR_BASELINE, 'wb') as f:
                        f.write(mbr)
                except OSError:
                    pass  # Non-fatal: baseline will be created on next run
        except Exception:
            pass
        return findings


