class ConfigManager:
    """Manages all Downpour configuration with type validation and defaults."""
    VALID_KEYS = {
        'scan_threads', 'scan_timeout', 'max_file_size', 'entropy_threshold',
        'fp_threshold', 'auto_quarantine', 'auto_update_feeds', 'feed_update_interval',
        'enable_behavioral', 'enable_memory_forensics', 'enable_ransomware_protection',
        'enable_network_monitor', 'enable_hardening_checks', 'parental_controls',
        'dark_mode', 'notification_level', 'quarantine_path',
    }

    DEFAULTS = {
        'general':   {'minimize_to_tray': 'true', 'start_minimized': 'false', 'show_widget': 'false',
                      'rain_intensity': '200', 'lightning_freq': '0.012'},
        'scanning':  {'max_file_size_mb': '100', 'max_depth': '20', 'scan_archives': 'true'},
        'network':   {'port_scan_detection': 'true', 'block_suspicious': 'false', 'connection_monitor': 'true'},
        'modules':   {m: 'true' for m in ['real_time', 'process_monitor', 'network_shield',
                                           'file_guardian', 'threat_engine', 'anti_keylogger',
                                           'anti_rat', 'anti_surveillance', 'port_scan_detector',
                                           'ai_analyzer', 'c2_detector', 'parental_controls']},
        'parental':  {'enabled': 'false', 'child_user': '', 'weekday_mins': '120',
                      'weekend_mins': '240', 'bedtime_start': '21:00', 'bedtime_end': '07:00',
                      'block_adult': 'true', 'block_gambling': 'true', 'block_violence': 'true'},
        'intel':     {'auto_update': 'false', 'update_interval_hours': '6'},
        'security':  {'bypass_tpm_bitlocker': 'false'},
    }

    def __init__(self):
        # Memory optimization
        self._last_gc = time.time()
        self.path = SETTINGS_PATH
        self.config = configparser.ConfigParser()
        if self.path.exists():
            self.config.read(str(self.path))
        for section, vals in self.DEFAULTS.items():
            if not self.config.has_section(section):
                self.config.add_section(section)
            for k, v in vals.items():
                if not self.config.has_option(section, k):
                    self.config.set(section, k, v)
        self._save()

    def _save(self):
        try:
            with open(str(self.path), 'w', encoding='utf-8') as f:
                self.config.write(f)
        except Exception:
            pass

    def get(self, section: str, key: str, fallback=None):
        try:
            val = self.config.get(section, key)
            if val.lower() in ('true', 'yes'): return True
            if val.lower() in ('false', 'no'): return False
            try: return int(val)
            except Exception:
                try: return float(val)
                except Exception: return val
        except Exception:
            return fallback

    def set(self, section: str, key: str, value):
        if not self.config.has_section(section):
            self.config.add_section(section)
        self.config.set(section, key, str(value))
        self._save()


