# [ascii art removed]
#                                    THREAT LEARNING ENGINE
# [ascii art removed]
@dataclass
class ThreatPattern:
    name: str
    signatures: List[str] = field(default_factory=list)
    behaviors: List[str] = field(default_factory=list)
    persistence_methods: List[str] = field(default_factory=list)
    file_patterns: List[str] = field(default_factory=list)
    count: int = 0

class ThreatLearningEngine:
    def __init__(self, db: Database):
        # Memory optimization
        self._last_gc = time.time()
        self.db = db
        self.patterns: Dict[str, ThreatPattern] = {}
        self._load()

    def _load(self):
        try:
            for row in self.db.execute("SELECT name, signatures, behaviors, persistence_methods, count FROM threat_families"):
                self.patterns[row[0]] = ThreatPattern(
                    name=row[0],
                    signatures=json.loads(row[1] or '[]'),
                    behaviors=json.loads(row[2] or '[]'),
                    persistence_methods=json.loads(row[3] or '[]'),
                    count=row[4] or 0,
                )
        except Exception:
            pass

    def learn(self, threat_type: str, path: str, indicators: list):
        p = self.patterns.setdefault(threat_type, ThreatPattern(name=threat_type))
        p.count += 1
        if path:
            d = os.path.dirname(path).lower()
            if d and d not in p.file_patterns:
                p.file_patterns.append(d)
        for ind in indicators:
            if ind not in p.signatures:
                p.signatures.append(ind)
        self._save(p)

    def _save(self, p: ThreatPattern):
        try:
            self.db.execute(
                '''INSERT OR REPLACE INTO threat_families
                   (name, signatures, behaviors, persistence_methods, first_seen, count)
                   VALUES (?,?,?,?,?,?)''',
                (p.name, json.dumps(p.signatures[:100]), json.dumps(p.behaviors[:50]),
                 json.dumps(p.persistence_methods[:20]), datetime.now().isoformat(), p.count))
        except Exception:
            pass

    def find_root_cause(self, path: str) -> dict:
        result = {'persistence': [], 'related_files': [], 'dropper': None}
        if not path or not os.path.exists(path):
            return result
        name = os.path.basename(path).lower()
        # Check registry persistence
        for hkey, hname, subkey in [
            (winreg.HKEY_CURRENT_USER, 'HKCU', r'SOFTWARE\Microsoft\Windows\CurrentVersion\Run'),
            (winreg.HKEY_LOCAL_MACHINE, 'HKLM', r'SOFTWARE\Microsoft\Windows\CurrentVersion\Run'),
        ]:
            try:
                key = winreg.OpenKey(hkey, subkey, 0, winreg.KEY_READ)
                i = 0
                while True:
                    try:
                        n, v, _ = winreg.EnumValue(key, i)
                        if name in v.lower():
                            result['persistence'].append({'type':'registry','location':f'{hname}\\{subkey}','name':n,'value':v})
                        i += 1
                    except WindowsError:
                        break
                winreg.CloseKey(key)
            except Exception:
                pass
        # Check startup folders
        for sf in [
            os.path.join(os.environ.get('APPDATA',''), r'Microsoft\Windows\Start Menu\Programs\Startup'),
            r'C:\ProgramData\Microsoft\Windows\Start Menu\Programs\Startup',
        ]:
            if os.path.exists(sf):
                for item in os.listdir(sf):
                    if name in item.lower():
                        result['persistence'].append({'type':'startup','location':sf,'name':item})
        # Related files in same dir
        try:
            base = os.path.splitext(os.path.basename(path))[0]
            for item in os.listdir(os.path.dirname(path)):
                if base.lower() in item.lower() and item != os.path.basename(path):
                    result['related_files'].append(os.path.join(os.path.dirname(path), item))
        except Exception:
            pass
        return result

    def record_history(self, path: str, hash_: str, threat_type: str, indicators: list, action: str):
        try:
            self.db.execute(
                '''INSERT INTO threat_history (path, hash, threat_type, indicators, detected_at, action)
                   VALUES (?,?,?,?,?,?)''',
                (path, hash_, threat_type, json.dumps(indicators), datetime.now().isoformat(), action))
        except Exception:
            pass


# [ascii art removed]
#                                    YARA-LIKE DETECTION ENGINE
# [ascii art removed]
class YaraEngine:
    def __init__(self):
        # Memory optimization
        self._last_gc = time.time()
        self.rules = KnownThreats.DETECTION_RULES

    @quantum_optimized
    @neural_protected
    @infinitely_scalable
    def scan_bytes(self, data: bytes) -> List[dict]:
        hits = []
        data_lower = data.lower()
        for rule in self.rules:
            matched = sum(1 for s in rule['strings'] if s.lower() in data_lower)
            total = len(rule['strings'])
            cond = rule['condition']
            triggered = False
            if cond == 'all':
                triggered = matched == total
            elif cond == 'any':
                triggered = matched > 0
            elif '_of' in cond:
                triggered = matched >= int(cond.split('_')[0])
            if triggered:
                hits.append({'rule': rule['name'], 'score': rule['score'],
                             'matched': matched, 'total': total})
        return hits

    @quantum_optimized
    @neural_protected
    @infinitely_scalable
    def scan_file(self, path: str) -> List[dict]:
        try:
            path = os.path.realpath(os.path.abspath(str(path)))
            if not os.path.isfile(path):
                return []
            if _is_own_path(path):
                return []
            size = os.path.getsize(path)
            if size > 100 * 1024 * 1024:  # 100MB cap
                return []
            if size == 0:
                return []
            # Read only first 4MB for speed  -  most signatures are in headers/early code
            with open(path, 'rb') as f:
                data = f.read(min(size, 4 * 1024 * 1024))
            return self.scan_bytes(data)
        except (PermissionError, OSError):
            return []
        except Exception:
            return []

    def check_behaviors(self, data: bytes) -> List[str]:
        """Detect malicious behaviors in file data.

        IMPORTANT: Each behavior check must be SPECIFIC enough to avoid false
        positives. Generic capabilities (file I/O, networking, crypto) are
        normal software features — only flag them when combined with other
        malicious indicators that together indicate actual malicious intent.

        Removed overly broad checks that caused mass false positives:
        - file_creation: CreateFile+WriteFile is used by every program
        - network_capable: socket/winsock is in every networked app
        - surveillance_api: single API imports are too common
        - crypto_mining: crypto strings appear in legitimate crypto libraries
        - ransomware_strings: too many legitimate tools contain these strings
        - temp_usage: most installers and updaters use temp dirs
        - shellcode_pattern \\xfc\\xe8: common CLD+CALL x86 instruction pair
        """
        behaviors = []
        d = data.lower()
        checks = [
            # -- Persistence (high-specificity) --
            (b'currentversion\\run' in d and b'\\temp\\' in d, 'persistence_attempt'),
            (b'currentversion\\runonce' in d and b'\\temp\\' in d, 'persistence_registry'),
            # -- Process injection (requires BOTH open + write, already specific) --
            (_dbs('b3BlbnByb2Nlc3M=') in d and _dbs('d3JpdGVwcm9jZXNzbWVtb3J5') in d, 'process_injection'),
            # -- Keylogger (requires BOTH hook + async key state for higher specificity) --
            (_dbs('Z2V0YXN5bmNrZXlzdGF0ZQ==') in d and _dbs('c2V0d2luZG93c2hvb2tleA==') in d, 'keylogger_api'),
            # -- Credential theft (these are specific enough) --
            (_dbs('Y3JlZGVudGlhbGVudW1lcmF0ZQ==') in d or _dbs('Y3JlZHJlYWQ=') in d, 'credential_theft'),
            (_dbs('bHNhdW5wcm90ZWN0ZGF0YQ==') in d or _dbs('Y3JlZHVp') in d, 'credential_theft'),
            (_dbs('c2VrdXJsc2E=') in d or _dbs('bG9nb25wYXNzd29yZHM=') in d, 'credential_theft'),
            (_dbs('c2FtXFxkb21haW5zXFxhY2NvdW50') in d, 'credential_theft'),
            # -- Privilege escalation (require AND conditions) --
            (_dbs('YWRqdXN0dG9rZW5wcml2aWxlZ2Vz') in d and _dbs('c2VfZGVidWdfbmFtZQ==') in d, 'privilege_escalation'),
            (_dbs('aW1wZXJzb25hdGVsb2dnZWRvbnVzZXI=') in d, 'privilege_escalation'),
            (_dbs('bnRzZXRpbmZvcm1hdGlvbnRva2Vu') in d, 'privilege_escalation'),
            # -- Defense evasion (specific) --
            (_dbs('bnR1bm1hcHZpZXdvZnNlY3Rpb24=') in d, 'process_hollowing'),
            (_dbs('end1bm1hcHZpZXdvZnNlY3Rpb24=') in d, 'process_hollowing'),
            (_dbs('dmlydHVhbGFsbG9jZXg=') in d and _dbs('Y3JlYXRlcmVtb3RldGhyZWFk') in d, 'process_injection'),
            (_dbs('YW1zaXV0aWxz') in d and _dbs('YW1zaXNjYW5idWZmZXI=') in d, 'defense_evasion'),
            (_dbs('ZXR3ZXZlbnR3cml0ZQ==') in d and _dbs('cGF0Y2g=') in d, 'defense_evasion'),
            (_dbs('bnR0cmFjZWNvbnRyb2w=') in d, 'defense_evasion'),
            # -- Lateral movement (specific, already uses AND) --
            (b'wnetaddconnection' in d or b'netusedel' in d, 'lateral_movement'),
            (b'ipc$' in d and b'admin$' in d, 'lateral_movement'),
            (b'psexec' in d or b'paexec' in d, 'lateral_movement'),
            (b'wmic' in d and b'/node:' in d, 'lateral_movement'),
            (b'invoke-command' in d and b'computername' in d, 'lateral_movement'),
            # -- Advanced persistence (specific, uses AND) --
            (b'schtasks' in d and b'/create' in d, 'persistence_registry'),
            (b'sc create' in d or b'new-service' in d, 'persistence_registry'),
            (b'\\currentversion\\winlogon' in d and b'userinit' in d, 'persistence_registry'),
            # -- Ransomware behavior (specific multi-keyword, these are good) --
            (b'vssadmin' in d and b'delete' in d and b'shadows' in d, 'ransomware_behavior'),
            (b'wbadmin' in d and b'delete' in d, 'ransomware_behavior'),
            (b'bcdedit' in d and b'recoveryenabled' in d and b'no' in d, 'ransomware_behavior'),
            (b'wmic shadowcopy delete' in d, 'ransomware_behavior'),
            # -- Exfiltration indicators --
            (b'invoke-webrequest' in d and b'-outfile' in d, 'exfiltration'),
            (b'bitsadmin' in d and b'/transfer' in d, 'exfiltration'),
            (_dbs('Y2VydHV0aWw=') in d and _dbs('LXVybGNhY2hl') in d, 'exfiltration'),
            # -- Shellcode: require MULTIPLE specific patterns, not just \\xfc\\xe8 --
            # \\xfc\\xe8 alone is a CLD+CALL pair found in millions of legitimate PE files.
            # Require the full shellcode preamble: CLD + CALL + NOP sled or stack setup
            (b'\xfc\xe8' in data and b'\x60\x89\xe5\x31' in data, 'shellcode_pattern'),
            (b'\xfc\x48\x83\xe4\xf0' in data, 'shellcode_pattern'),  # x64 shellcode preamble
        ]
        for condition, label in checks:
            if condition:
                if label not in behaviors:
                    behaviors.append(label)
        return behaviors

    def compute_entropy(self, data: bytes) -> float:
        """Numpy-accelerated Shannon entropy  -  10-50x faster than pure Python loop."""
        if not data:
            return 0.0
        try:
            import numpy as _np
            arr = _np.frombuffer(data, dtype=_np.uint8)
            counts = _np.bincount(arr, minlength=256)
            counts = counts[counts > 0]
            probs = counts / len(arr)
            return float(-_np.sum(probs * _np.log2(probs)))
        except Exception:
            # Fallback: pure Python
            freq = defaultdict(int)
            for b in data: freq[b] += 1
            n = len(data)
            return -sum((c/n)*math.log2(c/n) for c in freq.values() if c)


# [ascii art removed]
#                                    PROCESS SCANNER & MITIGATOR
# [ascii art removed]
@dataclass
class ProcessInfo:
    pid: int
    name: str
    path: str = ""
    cmdline: str = ""
    username: str = ""
    parent_pid: int = 0
    parent_name: str = ""
    connections: List[Dict] = field(default_factory=list)
    children: List[int] = field(default_factory=list)
    memory_mb: float = 0.0
    cpu_percent: float = 0.0
    risk_score: int = 0
    risk_reasons: List[str] = field(default_factory=list)
    is_suspicious: bool = False
    yara_hits: List[str] = field(default_factory=list)
    c2_framework: str = ""

class AdvancedProcessScanner:
    def __init__(self, yara: YaraEngine, learning: ThreatLearningEngine):
        # Memory optimization
        self._last_gc = time.time()
        self.yara = yara
        self.learning = learning
        self._fp = FalsePositiveDB()
        self._threats = KnownThreats()

    def scan_all(self) -> List[ProcessInfo]:
        """Parallel process scan  -  submits each analysis to a thread pool.
        psutil calls (connections, open_files, memory_maps) are syscall-bound
        and release the GIL, so all CPU cores work concurrently."""
        if not PSUTIL_AVAILABLE:
            return []
        import os as _os
        from concurrent.futures import ThreadPoolExecutor, as_completed
        _opid = _os.getpid()
        _ncpu = _os.cpu_count() or 4
        # Snapshot process list first (cheap single-threaded call)
        procs = list(psutil.process_iter(['pid','name','exe','cmdline','username','ppid',
                                          'memory_info']))
        results = []
        # Fan out to all cores  -  each worker analyzes one process independently
        # Cap workers: too many threads cause context-switch pressure that
        # stalls the UI. _ncpu*4 on a 16-core box = 64 threads  -  far too many.
        # Optimal is ~2x cores, capped at 32 to avoid scheduler thrash.
        # Use hardware profile for worker count to avoid overwhelming old systems
        _hwp = getattr(self, '_hw_profile', None)
        # FIX-v28: Use 75% of CPU for parallel downloads
        if _hwp:
            _workers = getattr(_hwp, 'workers_io', max(2, _ncpu * 3 // 4))
        else:
            _workers = max(2, _ncpu * 3 // 4)
        
        with ThreadPoolExecutor(max_workers=_workers,
                                thread_name_prefix="scan-worker") as pool:
            futures = {pool.submit(self._analyze, p): p for p in procs
                       if p.pid != _opid}
            for fut in as_completed(futures):
                try:
                    info = fut.result(timeout=5)
                    if info:
                        results.append(info)
                except (psutil.NoSuchProcess, psutil.AccessDenied):
                    pass
                except Exception:
                    pass
        results.sort(key=lambda x: x.risk_score, reverse=True)
        return results

    def _analyze(self, proc) -> Optional[ProcessInfo]:
        try:
            pi = proc.info
            info = ProcessInfo(
                pid=pi['pid'],
                name=pi['name'] or 'Unknown',
                path=pi['exe'] or '',
                cmdline=' '.join(pi['cmdline']) if pi.get('cmdline') else '',
                username=pi.get('username') or '',
                parent_pid=pi.get('ppid') or 0,
                memory_mb=(pi['memory_info'].rss / 1048576) if pi.get('memory_info') else 0,
                cpu_percent=pi.get('cpu_percent') or 0,
            )
            try:
                if info.parent_pid:
                    info.parent_name = psutil.Process(info.parent_pid).name()
            except Exception:
                pass
            try:
                # Skip expensive connection scan for known-safe system processes
                _safe_procs = {'svchost.exe','system','registry','smss.exe','csrss.exe',
                               'wininit.exe','services.exe','lsass.exe','fontdrvhost.exe',
                               'dwm.exe','explorer.exe','taskhostw.exe','dllhost.exe'}
                if info.name.lower() not in _safe_procs:
                    for conn in (proc.net_connections(kind='inet')
                         if hasattr(proc, 'net_connections')
                         else _proc_net_connections(proc, kind='inet')):
                        if conn.status == 'ESTABLISHED' and conn.raddr:
                            info.connections.append({
                                'remote_ip': conn.raddr.ip,
                                'remote_port': conn.raddr.port,
                                'local_port': conn.laddr.port if conn.laddr else 0,
                            })
            except Exception:
                pass
            try:
                info.children = [c.pid for c in proc.children()]
            except Exception:
                pass
            self._score(info)
            return info
        except Exception:
            return None

    # Own-process whitelist  -  never flag downpour itself as a threat
    _OWN_NAMES = frozenset({
        'downpour_v20_titanium.py', 'downpour_v20_titanium.exe',
        'downpour', 'downpour.exe',
        # python.exe NOT here  -  would make all Python processes immune.
        # Python running Downpour is caught by _OWN_PATHS_FRAGMENTS below.
    })
    _OWN_PATHS_FRAGMENTS = (
        r'familysecuritysuite', r'downpour_portable', r'downpour_v20',
        r'downpour\downpour', r'portable\downpour',
    )

    # == Enhanced Behavioral Analysis Engine =====================================
    _BEHAVIORAL_PARENTS = {
        'svchost.exe': {'services.exe'},
        'lsass.exe':   {'wininit.exe'},
        'csrss.exe':   {'smss.exe'},
        'winlogon.exe':{'smss.exe'},
        'services.exe':{'wininit.exe'},
        'taskhost.exe':{'svchost.exe','services.exe'},
        'taskhostw.exe':{'svchost.exe','services.exe'},
    }

    def _behavioral_analysis(self, info):
        """Deep behavioral analysis - returns list of (score_delta, reason) tuples."""
        findings = []
        nl = info.name.lower()
        cl = info.cmdline.lower() if info.cmdline else ""

        # 1. Parent-child relationship analysis (MITRE T1036)
        if nl in self._BEHAVIORAL_PARENTS:
            expected = self._BEHAVIORAL_PARENTS[nl]
            try:
                if PSUTIL_AVAILABLE:
                    proc = psutil.Process(info.pid)
                    parent = proc.parent()
                    if parent:
                        pname = parent.name().lower()
                        if pname not in expected:
                            findings.append((60,
                                f"Abnormal parent for {nl}: {pname} (expected: {expected})"))
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass

        # 2. Resource anomalies (crypto miner, data exfil)
        try:
            if PSUTIL_AVAILABLE:
                proc = psutil.Process(info.pid)
                # v28p37: Raised thresholds dramatically. Chrome, VS Code, Discord,
                # game launchers etc. regularly have 200+ threads and 5000+ handles.
                # These are not anomalous in modern software.
                try:
                    tcount = proc.num_threads()
                    if tcount > 500:  # v28p37: raised from 200
                        findings.append((5, f"High thread count: {tcount}"))
                except Exception:
                    pass
                try:
                    hcount = proc.num_handles()
                    if hcount > 15000:  # v28p37: raised from 5000
                        findings.append((5, f"High handle count: {hcount}"))
                except Exception:
                    pass
                try:
                    cpu = proc.cpu_percent(interval=0.1)
                    if cpu > 90.0:  # v28p37: raised from 80
                        findings.append((10, f"Sustained high CPU: {cpu:.0f}%"))
                except Exception:
                    pass
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            pass

        # 2b. Executable entropy analysis (packed/encrypted malware detection)
        if info.path and info.name.lower() not in self._OWN_NAMES:
            try:
                import os as _os2
                _size = _os2.path.getsize(info.path)
                if 10240 < _size < 50_000_000:  # 10KB-50MB
                    with open(info.path, 'rb') as _f:
                        _head = _f.read(8192)  # first 8KB
                    if len(_head) >= 256:
                        _counts = [0] * 256
                        for _b in _head:
                            _counts[_b] += 1
                        _ent = 0.0
                        _ln = len(_head)
                        for _c in _counts:
                            if _c > 0:
                                _p = _c / _ln
                                _ent -= _p * math.log2(_p)
                        # v28p37: Raised thresholds and lowered scores.
                        # Many legitimate signed programs (games, .NET, UPX-packed
                        # portable apps) have entropy 7.0-7.5. Only truly anomalous
                        # entropy (7.8+) is worth flagging, and even then with LOW score
                        # because it needs other indicators to be meaningful.
                        if _ent > 7.8:
                            findings.append((15,
                                f"Very high entropy ({_ent:.2f}/8.0) — likely encrypted"))
                        # v28p37: REMOVED 7.0-7.4 range — too many false positives
            except (PermissionError, FileNotFoundError, OSError):
                pass

        # 3. Network behavior
        # v28p37: Raised threshold — browsers, cloud sync, game launchers commonly
        # have 50-200+ connections. Only flag truly extreme cases.
        if info.connections:
            conn_count = len(info.connections)
            if conn_count > 200:  # v28p37: raised from 50
                findings.append((10, f"Excessive connections: {conn_count}"))
            remote_ports = {c.get('remote_port', 0) for c in info.connections}
            tor_ports = {9001, 9030, 9050, 9051, 9150}
            tor_hits = remote_ports & tor_ports
            if tor_hits:
                findings.append((35, f"Tor network ports: {tor_hits}"))

        # 4. Command-line behavioral heuristics
        if cl:
            if cl.count('^') > 5:
                findings.append((30, "Heavy caret obfuscation in cmdline"))
            if cl.count('%') > 8:
                findings.append((25, "Excessive env variable expansion"))
            if len(cl) > 2000:
                findings.append((20, f"Abnormally long cmdline ({len(cl)} chars)"))
            import re as _re
            if _re.search(r'[A-Za-z0-9+/]{60,}={0,2}', cl):
                findings.append((40, "Base64 payload in command line"))
            if _re.search(r'(iex|invoke-expression).*downloadstring', cl):
                findings.append((70, "PowerShell download cradle (IEX)"))
            if _re.search(r'(iwr|invoke-webrequest).*\|.*iex', cl):
                findings.append((70, "PowerShell web request piped to IEX"))
            if _re.search(r'reflection\.assembly.*load', cl):
                findings.append((65, "Reflective assembly loading"))
            if _re.search(r'amsiutils|amsiinitfailed|amsi\.dll', cl):
                findings.append((80, "AMSI bypass attempt"))
            if _re.search(r'ntdll.*etwevtwrite|etw.*patch', cl):
                findings.append((75, "ETW evasion technique"))
            if _re.search(r'-nop\s+-w\s+hidden\s+-enc', cl):
                findings.append((60, "Hidden encoded PowerShell"))
            if _re.search(r'certutil.*-urlcache.*-split', cl):
                findings.append((55, "Certutil download abuse"))
            if _re.search(r'bitsadmin.*(/transfer|/create)', cl):
                findings.append((50, "BITSAdmin download abuse"))
            if _re.search(r'mshta\s+(http|vbscript|javascript)', cl):
                findings.append((65, "MSHTA execution"))
            if _re.search(r'rundll32.*javascript:', cl):
                findings.append((70, "Rundll32 script execution"))
            if _re.search(r'regsvr32.*/s.*/n.*/u.*scrobj', cl):
                findings.append((65, "Regsvr32 squiblydoo attack"))

        # 5. Binary packer detection
        if info.path and os.path.exists(info.path):
            try:
                with open(info.path, 'rb') as f:
                    header = f.read(1024)
                if header[:2] == b'MZ':
                    # v28p37: Only flag MALWARE-ASSOCIATED packers.
                    # UPX and ASPack are used by thousands of legitimate programs
                    # (portable apps, game mods, embedded tools). NOT suspicious.
                    malware_packers = {
                        b'.themida': 'Themida',    # Almost exclusively malware
                        b'.vmp0': 'VMProtect', b'.vmp1': 'VMProtect',  # Heavily abused
                    }
                    for sig, name in malware_packers.items():
                        if sig in header:
                            findings.append((10, f"Protected with {name}"))
                            break
            except (PermissionError, OSError):
                pass

        return findings


    def _score(self, info: ProcessInfo):
        nl = info.name.lower()
        pl = info.path.lower() if info.path else ""
        # -- Own-process immunity ------------------------------------------
        if nl in self._OWN_NAMES:
            info.risk_score = 0
            info.risk_reasons = ['[SELF] Downpour security suite  -  trusted']
            return
        if pl and any(frag in pl for frag in self._OWN_PATHS_FRAGMENTS):
            info.risk_score = 0
            info.risk_reasons = ['[SELF] Downpour suite path  -  trusted']
            return
        # MUST assign cl before using it  -  cmdline own-process check
        cl = info.cmdline.lower()
        if cl and any(frag in cl for frag in self._OWN_PATHS_FRAGMENTS):
            info.risk_score = 0
            info.risk_reasons = ['[SELF] Downpour suite process (cmdline)  -  trusted']
            return

        # Skip safe processes  -  cached set avoids rebuilding per call
        if not hasattr(self, '_safe_proc_cache'):
            self._safe_proc_cache = {p.lower() for p in self._fp.SAFE_PROCESSES}
        _safe_proc_names = self._safe_proc_cache
        if nl in _safe_proc_names:
            if not info.path:
                # No path accessible  -  benefit of the doubt, skip scoring
                return
            # Has a path  -  only continue if it looks wrong (impersonation check below)
            if any(pl.startswith(sp.lower()) for sp in self._fp.SAFE_PATHS):
                return
            # Path present but not in safe paths  -  could be impersonation,
            # BUT also could be AppData install. Only penalise if it's a
            # core Windows binary in the wrong location (handled below).
            _CORE_WINDOWS = {'svchost.exe','csrss.exe','lsass.exe','services.exe',
                              'winlogon.exe','smss.exe','wininit.exe','spoolsv.exe'}
            if nl not in _CORE_WINDOWS:
                return  # non-system binary in non-standard path is fine

        # Known malware name
        for m in self._threats.MALWARE_PROCESSES:
            if m in nl or m in pl:
                info.risk_score += 80
                info.risk_reasons.append(f"Known malware: {m}")

        # Suspicious name pattern
        for pat in self._threats.SUSPICIOUS_PATTERNS:
            if re.match(pat, nl):
                info.risk_score += 40
                info.risk_reasons.append("Suspicious name pattern")
                break

        # Running from temp/downloads  -  only add points if this isn't a
        # recognisable legitimate installer scenario (single indicator = too weak)
        _temp_dirs = ['\\temp\\', '\\tmp\\', '\\downloads\\',
                      'appdata\\local\\temp']
        _from_temp = any(t in pl for t in _temp_dirs)
        if _from_temp and nl not in _safe_proc_names:
            # Only penalise executables, not scripts/installers people just downloaded
            if pl.endswith('.exe') and not any(
                legit in pl for legit in ['setup', 'install', 'update', 'patch',
                                          'upgrade', '_temp', 'unpack']):
                info.risk_score += 20   # reduced from 30, needs combination
                info.risk_reasons.append("Executing from temp/downloads")

        # Recycle bin / hidden dir
        if any(x in pl for x in ['\\recycler\\', '\\$recycle.bin\\']):
            info.risk_score += 50
            info.risk_reasons.append("Running from recycle bin")

        # Suspicious command line
        susp_cmds = [
            (r'powershell.*(enc|encodedcommand)', 'Encoded PowerShell'),
            (r'mshta.*vbscript', 'MSHTA VBScript'),
            (r'regsvr32.*/s.*/u', 'Regsvr32 bypass'),
            (r'certutil.*(decode|urlcache)', 'Certutil download'),
            (r'bitsadmin.*/transfer', 'Bitsadmin download'),
            (r'rundll32.*javascript', 'Rundll32 JS'),
        ]
        for pattern, label in susp_cmds:
            if re.search(pattern, cl):
                info.risk_score += 60
                info.risk_reasons.append(label)

        # RAT ports in connections
        for conn in info.connections:
            port = conn['remote_port']
            if port in self._threats.RAT_PORTS:
                info.risk_score += 50
                info.risk_reasons.append(f"RAT port {port}: {self._threats.RAT_PORTS[port]}")

        # C2 framework detection
        # Port-alone match = 10 pts max. Skip known safe apps entirely.
        _c2_skip = {'chrome.exe','firefox.exe','msedge.exe','code.exe','cursor.exe',
                     'windsurf.exe','discord.exe','slack.exe','steam.exe','node.exe',
                     'python.exe','java.exe','spotify.exe','teams.exe','zoom.exe',
                     'brave.exe','opera.exe','vivaldi.exe','arc.exe','obs64.exe',
                     'steamwebhelper.exe','msedgewebview2.exe','chromium.exe',
                     'WhatsApp.exe','Telegram.exe','Signal.exe','thunderbird.exe'}
        if nl not in _c2_skip:
            for fw_key, fw in self._threats.C2_FRAMEWORKS.items():
                for port in fw.get('ports', []):
                    for conn in info.connections:
                        if conn['remote_port'] == port:
                            _port_score = min(5, fw['score'])  # port-only = very weak signal
                            info.risk_score += _port_score
                            info.c2_framework = fw['name']
                            info.risk_reasons.append(
                                f"C2 port {port}: {fw['name']} (+{_port_score})"
                            )
                            break

        # Process impersonation check
        system_map = {
            'svchost.exe': 'c:\\windows\\system32\\',
            'csrss.exe': 'c:\\windows\\system32\\',
            'lsass.exe': 'c:\\windows\\system32\\',
            'services.exe': 'c:\\windows\\system32\\',
            'explorer.exe': 'c:\\windows\\',
        }
        if nl in system_map and info.path and not pl.startswith(system_map[nl]):
            info.risk_score += 70
            info.risk_reasons.append("Impersonating system process")

        # YARA scan  -  skip own files (they contain detection strings by design)
        if info.path and os.path.exists(info.path) and not _is_own_path(info.path):
            try:
                hits = self.yara.scan_file(info.path)
                if hits:
                    info.yara_hits = [h['rule'] for h in hits]
                    info.risk_score += max(h['score'] for h in hits) // 2
                    info.risk_reasons.extend(f"YARA: {h['rule']}" for h in hits)
            except Exception:
                pass

        # Deep behavioral analysis
        try:
            behavioral_hits = self._behavioral_analysis(info)
            for score_delta, reason in behavioral_hits:
                info.risk_score += score_delta
                info.risk_reasons.append(f"[BEHAVIOR] {reason}")
        except Exception:
            pass

        # -- sklearn AI scoring (opportunistic  -  only when models are trained) -
        try:
            _ai = getattr(self, '_ai_detector', None)
            if _ai is None:
                # Lazy-create a shared detector instance tied to this scanner
                _ai = AIEnhancedThreatDetector(None)
                self._ai_detector = _ai
            # Try the real sklearn path first; fall back to heuristic
            sk = _ai.analyze_process_sklearn({
                'name': info.name, 'path': info.path,
                'cmdline': info.cmdline.split() if info.cmdline else [],
                'cpu_percent': info.cpu_percent,
                'memory_percent': (info.memory_mb / 1024) if info.memory_mb else 0,
                'network_connections': len(info.connections),
                'description': getattr(info, 'description', ''),
                'parent_mismatch': any('[BEHAVIOR] Abnormal parent' in r for r in info.risk_reasons),
                'unsigned': getattr(info, 'unsigned', False),
            })
            if sk is None:
                # sklearn not ready yet  -  use heuristic models
                adv = _ai.analyze_process_advanced({
                    'name': info.name, 'path': info.path or '',
                    'cmdline': info.cmdline.split() if info.cmdline else [],
                    'cpu_percent': info.cpu_percent,
                    'memory_percent': (info.memory_mb / 1024) if info.memory_mb else 0,
                    'network_connections': len(info.connections),
                })
                sk_score = adv.get('confidence', 0)
                sk_level = adv.get('threat_level', 'LOW')
                sk_model = 'heuristic'
            else:
                sk_score = sk['sklearn_score']
                sk_level = sk['threat_level']
                sk_model = sk['model']

            # Only boost risk when AI is confident (>= 0.55 to avoid FP noise)
            if sk_score >= 0.55 and sk_level in ('HIGH', 'CRITICAL'):
                boost = int(sk_score * 20)  # max +20 points from ML
                info.risk_score += boost
                info.risk_reasons.append(
                    f"[{sk_model.upper()}] AI threat score {sk_score:.2f} -> +{boost}pts")
        except Exception:
            pass

        # -- Advanced process anomaly checks --------------------------
        # Parent PID spoofing detection (use info.parent_pid  -  already fetched)
        try:
            ppid = info.parent_pid
            if ppid and ppid != 0:
                try:
                    parent = psutil.Process(ppid)
                    parent_name = parent.name().lower()
                    if nl in ('svchost.exe','csrss.exe','lsass.exe','services.exe'):
                        if parent_name not in ('services.exe','wininit.exe','smss.exe','lsass.exe'):
                            info.risk_score += 35
                            info.risk_reasons.append(f"\u26a0 Suspicious parent: {parent_name} \u2192 {nl} (PPID spoof?)")
                except psutil.NoSuchProcess:
                    # v28p37: REMOVED score penalty for orphan processes.
                    # Parent processes exit ALL THE TIME in normal operation
                    # (installers, updaters, launchers that exit after spawning).
                    # An orphan process is completely normal, not suspicious.
                    pass
        except Exception:
            pass

        # v28p37: REMOVED standalone thread count and memory anomaly checks.
        # These are already handled in _behavioral_analysis() with better thresholds.
        # Having them in BOTH places caused double-counting, inflating scores.
        # Modern applications regularly use 200+ threads and 2GB+ memory
        # (Electron apps, IDEs, game launchers, browsers, Docker, etc.).

        info.risk_score = min(100, info.risk_score)

        # v28p37: CORROBORATION REQUIREMENT — a single weak indicator should NEVER
        # trigger a threat. Require either a high score with strong evidence,
        # or multiple independent indicators corroborating each other.
        _num_reasons = len(info.risk_reasons)
        _has_strong = any(kw in r.lower() for r in info.risk_reasons
                          for kw in ['malware', 'impersonat', 'rat port',
                                     'yara', 'amsi bypass', 'etw evasion',
                                     'download cradle', 'reflective assembly',
                                     'credential dump', 'lsass dump',
                                     'kill defender', 'shadow cop'])
        if _has_strong and info.risk_score >= 50:
            info.is_suspicious = True
        elif _num_reasons >= 3 and info.risk_score >= 60:
            # Multiple independent weak indicators corroborating = suspicious
            info.is_suspicious = True
        elif info.risk_score >= 85:
            # Very high score is suspicious regardless
            info.is_suspicious = True
        else:
            info.is_suspicious = False

    def mitigate(self, pid: int, action: str, quarantine_dir: Path) -> Tuple[bool, str]:
        """
        Threat mitigation engine.
        Actions: suspend, resume, kill_tree, quarantine,
                 network_isolate, firewall_block, dump_memory,
                 clean_persistence, root_cause
        Returns (success, message).
        """
        if not PSUTIL_AVAILABLE:
            return False, "psutil not available"
        try:
            proc = psutil.Process(pid)
            name = proc.name()

            # -- Suspend / Resume ----------------------------------------------
            if action == "suspend":
                proc.suspend()
                return True, f"Suspended {name} (PID {pid})"

            elif action == "resume":
                proc.resume()
                return True, f"Resumed {name} (PID {pid})"

            # -- Kill entire process tree ---------------------------------------
            elif action == "kill_tree":
                children = proc.children(recursive=True)
                for child in children:
                    try: child.kill()
                    except Exception: pass
                proc.kill()
                return True, f"Killed {name} + {len(children)} children (PID {pid})"

            # -- Quarantine: kill + move EXE to locked folder -------------------
            elif action == "quarantine":
                try:
                    exe = proc.exe()
                except Exception:
                    exe = ''
                children = proc.children(recursive=True)
                for child in children:
                    try: child.kill()
                    except Exception: pass
                proc.kill()
                if exe and os.path.exists(exe):
                    dest = quarantine_dir / "locked" / (
                        os.path.basename(exe) + ".locked"
                    )
                    try:
                        shutil.move(exe, str(dest))
                        return True, f"Quarantined {name} -> {dest.name}"
                    except Exception as e:
                        return True, f"Killed {name} (quarantine move failed: {e})"
                return True, f"Killed {name} (no EXE path)"

            # -- Network isolation: block all outbound connections for this exe -
            elif action == "network_isolate":
                try:
                    exe = proc.exe()
                except Exception:
                    exe = ''
                msgs = []
                # Block outbound via Windows Firewall using exe path
                if exe:
                    _safe = re.sub(r'[^\w\-_.\\: ]', '_', exe)[:200]
                    rule_name = f"DOWNPOUR_ISOLATE_{name.replace('.','_')}_{pid}"
                    r = subprocess.run(
                        ['netsh', 'advfirewall', 'firewall', 'add', 'rule',
                         f'name={rule_name}', 'dir=out', 'action=block',
                         'protocol=any', f'program={exe}'],
                        capture_output=True, timeout=10,
                        creationflags=subprocess.CREATE_NO_WINDOW
                    )
                    if r.returncode == 0:
                        msgs.append(f"Outbound blocked for {name}")
                    else:
                        msgs.append("Firewall rule failed (run as Admin)")
                # Also kill active connections by suspending then resuming
                # with firewall rule already in place
                try:
                    proc.suspend()
                    msgs.append("Process suspended")
                except Exception:
                    pass
                return bool(msgs), ' | '.join(msgs) or "Network isolation attempted"

            # -- Firewall block: block all traffic to/from process IPs ----------
            elif action == "firewall_block":
                try:
                    conns = (proc.net_connections(kind='inet')
                             if hasattr(proc, 'net_connections')
                             else _proc_net_connections(proc, kind='inet'))
                    blocked = []
                    for conn in conns:
                        if conn.raddr and conn.raddr.ip:
                            ip = conn.raddr.ip
                            _safe_ip = re.sub(r'[^\d.]', '', ip)[:39]
                            rule = f"DOWNPOUR_BLOCK_{_safe_ip.replace('.','_')}"
                            r = subprocess.run(
                                ['netsh', 'advfirewall', 'firewall', 'add', 'rule',
                                 f'name={rule}', 'dir=out', 'action=block',
                                 'protocol=any', f'remoteip={_safe_ip}'],
                                capture_output=True, timeout=10,
                                creationflags=subprocess.CREATE_NO_WINDOW
                            )
                            if r.returncode == 0:
                                blocked.append(_safe_ip)
                    if blocked:
                        return True, f"Blocked {len(blocked)} IPs: {', '.join(blocked[:5])}"
                    return False, "No active connections to block"
                except Exception as e:
                    return False, f"Firewall block failed: {e}"

            # -- Memory dump: write full process memory to quarantine dir -------
            elif action == "dump_memory":
                try:
                    dump_path = quarantine_dir / "dumps" / f"{name}_{pid}.dmp"
                    dump_path.parent.mkdir(parents=True, exist_ok=True)
                    # Use procdump if available, else fall back to MiniDump via PS
                    procdump = shutil.which('procdump') or shutil.which('procdump64')
                    if procdump:
                        r = subprocess.run(
                            [procdump, '-ma', str(pid), str(dump_path)],
                            capture_output=True, timeout=60,
                            creationflags=subprocess.CREATE_NO_WINDOW
                        )
                        if r.returncode == 0:
                            return True, f"Memory dumped -> {dump_path.name}"
                    # PowerShell fallback via Out-Minidump
                    ps = (
                        f"$proc = Get-Process -Id {pid} -EA 0; "
                        f"if ($proc) {{ "
                        f"Add-Type @'\n"
                        f"  using System; using System.Runtime.InteropServices;\n"
                        f"  public class MiniDump {{"
                        f"    [DllImport(\"dbghelp.dll\")] public static extern bool "
                        f"    MiniDumpWriteDump(IntPtr hProcess, int ProcessId, "
                        f"    SafeHandle hFile, int DumpType, IntPtr ExcInfo, "
                        f"    IntPtr UserStream, IntPtr Callback);\n"
                        f"  }}\n'@; "
                        f"$fs = [System.IO.File]::Create('{dump_path}'); "
                        f"[MiniDump]::MiniDumpWriteDump($proc.Handle, {pid}, "
                        f"$fs.SafeFileHandle, 2, [IntPtr]::Zero, "
                        f"[IntPtr]::Zero, [IntPtr]::Zero); "
                        f"$fs.Close() }}"
                    )
                    r2 = subprocess.run(
                        ['powershell', '-NoProfile', '-NonInteractive', '-Command', ps],
                        capture_output=True, timeout=60,
                        creationflags=subprocess.CREATE_NO_WINDOW
                    )
                    if dump_path.exists() and dump_path.stat().st_size > 0:
                        return True, f"Memory dumped -> {dump_path.name}"
                    return False, "Memory dump failed (need Admin or Procdump)"
                except Exception as e:
                    return False, f"Dump error: {e}"

            # -- Clean persistence: remove known autorun entries for this exe ---
            elif action == "clean_persistence":
                try:
                    exe = proc.exe()
                except Exception:
                    exe = ''
                cleaned = []
                run_keys = [
                    r'HKCU\Software\Microsoft\Windows\CurrentVersion\Run',
                    r'HKCU\Software\Microsoft\Windows\CurrentVersion\RunOnce',
                    r'HKLM\Software\Microsoft\Windows\CurrentVersion\Run',
                    r'HKLM\Software\Microsoft\Windows\CurrentVersion\RunOnce',
                    r'HKLM\Software\WOW6432Node\Microsoft\Windows\CurrentVersion\Run',
                ]
                if exe:
                    exe_norm = os.path.normcase(exe)
                    for key in run_keys:
                        try:
                            r = subprocess.run(
                                ['reg', 'query', key],
                                capture_output=True, text=True, timeout=5,
                                creationflags=subprocess.CREATE_NO_WINDOW
                            )
                            for line in r.stdout.splitlines():
                                parts = line.split('    ')
                                if (len(parts) >= 4
                                        and exe_norm in os.path.normcase(parts[-1])):
                                    val_name = parts[1].strip()
                                    subprocess.run(
                                        ['reg', 'delete', key, '/v', val_name, '/f'],
                                        capture_output=True, timeout=5,
                                        creationflags=subprocess.CREATE_NO_WINDOW
                                    )
                                    cleaned.append(f"{val_name} from {key.split(chr(92))[-1]}")
                        except Exception:
                            pass
                    # Also check scheduled tasks by searching for exe path
                    try:
                        rt = subprocess.run(
                            ['schtasks', '/query', '/fo', 'csv', '/v'],
                            capture_output=True, text=True, timeout=15,
                            creationflags=subprocess.CREATE_NO_WINDOW
                        )
                        for line in rt.stdout.splitlines():
                            if exe_norm in os.path.normcase(line):
                                parts = line.split(',')  # CSV
                                if parts:
                                    task = parts[0].strip('"')
                                    subprocess.run(
                                        ['schtasks', '/delete', '/tn', task, '/f'],
                                        capture_output=True, timeout=10,
                                        creationflags=subprocess.CREATE_NO_WINDOW
                                    )
                                    cleaned.append(f"Task: {task}")
                    except Exception:
                        pass
                if cleaned:
                    return True, f"Removed {len(cleaned)} persistence entries: "\
                                 f"{', '.join(cleaned[:4])}"
                return True, "No persistence entries found for this process"

            # -- Root cause analysis: gather process + parent + connections -----
            elif action == "root_cause":
                try:
                    lines_out = [f"PROCESS: {name} (PID {pid})"]
                    try:
                        lines_out.append(f"  EXE:     {proc.exe()}")
                        lines_out.append(f"  CMD:     {' '.join(proc.cmdline())}")
                        lines_out.append(f"  USER:    {proc.username()}")
                        lines_out.append(f"  CWD:     {proc.cwd()}")
                        lines_out.append(f"  Created: {proc.create_time()}")
                        lines_out.append(f"  CPU:     {proc.cpu_percent(interval=0.3):.1f}%")
                        lines_out.append(f"  MEM:     {proc.memory_info().rss / 1048576:.1f} MB")
                    except Exception:
                        pass
                    try:
                        parent = psutil.Process(proc.ppid())
                        lines_out.append(
                            f"  PARENT:  {parent.name()} (PID {parent.pid})"
                        )
                    except Exception:
                        pass
                    try:
                        children = proc.children(recursive=True)
                        if children:
                            lines_out.append(
                                "  CHILDREN: "
                                + ', '.join(f"{c.name()}({c.pid})"
                                            for c in children[:8])
                            )
                    except Exception:
                        pass
                    try:
                        conns = (proc.net_connections(kind='inet')
                                 if hasattr(proc, 'net_connections')
                                 else _proc_net_connections(proc, kind='inet'))
                        for c in conns:
                            if c.raddr:
                                lines_out.append(
                                    f"  CONN: {c.laddr.ip}:{c.laddr.port} -> "
                                    f"{c.raddr.ip}:{c.raddr.port} [{c.status}]"
                                )
                    except Exception:
                        pass
                    return True, '\n'.join(lines_out)
                except Exception as e:
                    return False, f"Root cause analysis failed: {e}"

            # -- Full 5-layer remediation via advanced engine -----------------
            elif action == "full_remediation":
                if not _rem:
                    return False, "Remediation engine not available"
                try:
                    exe = proc.exe()
                except Exception:
                    exe = ''
                try:
                    from advanced_threat_remediation import ThreatProfile
                    c2_ips = []
                    try:
                        conns = (proc.net_connections(kind='inet')
                                 if hasattr(proc, 'net_connections')
                                 else _proc_net_connections(proc, kind='inet'))
                        c2_ips = [c.raddr.ip for c in conns
                                  if c.raddr and c.raddr.ip
                                  and not c.raddr.ip.startswith(('127.', '0.'))]
                    except Exception:
                        pass
                    profile = ThreatProfile(
                        threat_id=f"proc_{pid}_{int(time.time())}",
                        threat_type='process',
                        threat_family=name,
                        severity='HIGH',
                        summary=f"Full remediation of suspicious process {name} (PID {pid})",
                        processes=[{'pid': pid, 'name': name, 'path': exe}],
                        files=[exe] if exe else [],
                        network_connections=[{'ip': ip, 'port': 0} for ip in c2_ips],
                    )
                    result = _rem.full_remediation(profile)
                    success_count = sum(1 for a in result.actions_taken if a.success)
                    fail_count = sum(1 for a in result.actions_taken if not a.success)
                    return True, (
                        f"Full remediation of {name}: "
                        f"{success_count} actions succeeded, "
                        f"{fail_count} failed"
                    )
                except Exception as e:
                    return False, f"Full remediation failed: {e}"

            return False, f"Unknown action: {action}"

        except psutil.NoSuchProcess:
            return False, f"PID {pid} no longer exists"
        except psutil.AccessDenied:
            return False, "Access denied  -  run as Administrator"
        except Exception as e:
            return False, str(e)


