#                                    NETWORK SHIELD & PORT SCAN DETECTOR
# [ascii art removed]
class PortScanDetector:
    """Detects port scans, SYN floods, and suspicious network behaviour"""
    def __init__(self, db: Database):
        # Memory optimization
        self._last_gc = time.time()
        self.db = db
        self._connection_history: Dict[str, List[float]] = defaultdict(list)
        self._port_history: Dict[str, Set[int]] = defaultdict(set)
        self._blocked_ips: Set[str] = set()
        self._lock = threading.Lock()
        self._callbacks: List[Callable] = []

    def register_callback(self, fn: Callable):
        self._callbacks.append(fn)

    def analyze_connections(self, connections: list) -> List[dict]:
        if not PSUTIL_AVAILABLE or not connections:
            return []
        _own_pid = os.getpid()
        alerts = []
        now = time.time()
        with self._lock:
            for conn in connections:
                if conn.pid == _own_pid:
                    continue  # never alert on our own network activity
                try:
                    if not conn.raddr:
                        continue
                    ip = conn.raddr.ip
                    port = conn.raddr.port
                    # Track connection rate per IP
                    self._connection_history[ip] = [
                        t for t in self._connection_history[ip] if now - t < 60
                    ]
                    self._connection_history[ip].append(now)
                    self._port_history[ip].add(port)
                    # Detect port scan: >10 different ports from same IP in 60s
                    if len(self._port_history[ip]) > 10:
                        alert = {
                            'type': 'port_scan',
                            'ip': ip,
                            'ports_scanned': len(self._port_history[ip]),
                            'severity': 'HIGH',
                            'msg': f"Port scan from {ip}: {len(self._port_history[ip])} ports",
                        }
                        alerts.append(alert)
                        self._port_history[ip].clear()
                        for cb in self._callbacks:
                            try: cb(alert)
                            except Exception: pass
                    # Detect connection flood: >20 connections per minute
                    if len(self._connection_history[ip]) > 20:
                        alert = {
                            'type': 'connection_flood',
                            'ip': ip,
                            'count': len(self._connection_history[ip]),
                            'severity': 'HIGH',
                            'msg': f"Connection flood from {ip}",
                        }
                        alerts.append(alert)
                        self._connection_history[ip].clear()

                    # -- Suspicious port detection --
                    _suspicious_ports = {4444, 5555, 1234, 6666, 6667, 6697,
                                         9001, 9030, 9050, 9051, 9150,  # Tor
                                         31337, 12345, 27015, 1337,  # classic backdoor
                                         4443, 8888, 8000, 2222}  # C2 common
                    if port in _suspicious_ports:
                        alert = {
                            'type': 'suspicious_port',
                            'ip': ip, 'port': port,
                            'severity': 'MEDIUM',
                            'msg': f"Connection to suspicious port {port} on {ip}",
                        }
                        alerts.append(alert)
                        for cb in self._callbacks:
                            try: cb(alert)
                            except Exception: pass

                    # -- Beaconing detection: regular intervals suggest C2 --
                    hist = self._connection_history.get(ip, [])
                    if len(hist) >= 4:
                        intervals = [hist[i+1] - hist[i] for i in range(len(hist)-1)]
                        if intervals:
                            avg = sum(intervals) / len(intervals)
                            if avg > 0:
                                variance = sum((x - avg)**2 for x in intervals) / len(intervals)
                                # Low variance = regular beaconing
                                if variance < (avg * 0.15) ** 2 and avg < 120:
                                    alert = {
                                        'type': 'c2_beacon',
                                        'ip': ip, 'interval': round(avg, 1),
                                        'severity': 'CRITICAL',
                                        'msg': f"C2 beaconing detected: {ip} every ~{avg:.0f}s (variance: {variance:.1f})",
                                    }
                                    alerts.append(alert)
                                    for cb in self._callbacks:
                                        try: cb(alert)
                                        except Exception: pass
                except Exception:
                    pass
        return alerts

    def get_all_connections(self) -> list:
        if not PSUTIL_AVAILABLE:
            return []
        try:
            return psutil.net_connections(kind='all')
        except Exception:
            return []

    def detect_beaconing(self, connections: list, window_sec: int = 300) -> List[dict]:
        """Detect C2 beaconing: regular-interval connections to the same IP."""
        alerts = []
        now = time.time()
        ip_times: Dict[str, List[float]] = defaultdict(list)
        _own_pid = os.getpid()
        for conn in connections:
            if not conn.raddr or conn.pid == _own_pid:
                continue
            ip = conn.raddr.ip
            if ipaddress.ip_address(ip).is_private:
                continue
            ip_times[ip].append(now)
        with self._lock:
            for ip, times in ip_times.items():
                hist = self._connection_history.get(ip, [])
                all_times = sorted([t for t in hist if now - t < window_sec] + times)
                if len(all_times) < 4:
                    continue
                # Calculate intervals between connections
                intervals = [all_times[i+1] - all_times[i] for i in range(len(all_times)-1)]
                if not intervals:
                    continue
                avg = sum(intervals) / len(intervals)
                if avg < 1:
                    continue
                variance = sum((i - avg)**2 for i in intervals) / len(intervals)
                std_dev = variance ** 0.5
                # Beaconing: low jitter (std_dev < 20% of mean) with regular intervals
                if avg > 5 and std_dev < (avg * 0.20) and len(all_times) >= 5:
                    alerts.append({
                        'type': 'beaconing', 'ip': ip,
                        'interval_avg': round(avg, 1),
                        'jitter_pct': round((std_dev/avg)*100, 1),
                        'count': len(all_times),
                        'severity': 'CRITICAL',
                        'msg': f"C2 Beaconing: {ip} every ~{avg:.0f}s (jitter {std_dev/avg*100:.0f}%, {len(all_times)} hits)",
                    })
                    for cb in self._callbacks:
                        try: cb(alerts[-1])
                        except Exception: pass
        return alerts

    def detect_data_exfil(self, threshold_mb: float = 500) -> Optional[dict]:
        """Detect potential data exfiltration via unusually high outbound traffic."""
        if not PSUTIL_AVAILABLE:
            return None
        try:
            stats = psutil.net_io_counters()
            sent_mb = stats.bytes_sent / (1024*1024)
            if sent_mb > threshold_mb:
                ratio = stats.bytes_sent / max(stats.bytes_recv, 1)
                if ratio > 2.0:  # sending 2x more than receiving
                    return {
                        'type': 'data_exfil', 'severity': 'HIGH',
                        'sent_mb': round(sent_mb, 1),
                        'ratio': round(ratio, 2),
                        'msg': f"Potential exfiltration: {sent_mb:.0f}MB sent (send/recv ratio: {ratio:.1f}x)",
                    }
        except Exception:
            pass
        return None

    def get_connection_stats(self) -> dict:
        if not PSUTIL_AVAILABLE:
            return {}
        try:
            stats = psutil.net_io_counters()
            return {
                'bytes_sent': stats.bytes_sent,
                'bytes_recv': stats.bytes_recv,
                'packets_sent': stats.packets_sent,
                'packets_recv': stats.packets_recv,
                'errin': stats.errin,
                'errout': stats.errout,
            }
        except Exception:
            return {}


