#                                    PARENTAL CONTROLS
# [ascii art removed]
# -- Standalone elevated hosts-write helper (used by classes that don't
#    inherit from the main app window) ---------------------------------
def _write_hosts_file_elevated(new_content: str, hosts_path: str = r'C:\Windows\System32\drivers\etc\hosts') -> bool:
    """Write new_content to the system hosts file bypassing Windows Defender CFA.
    Works from any class/thread. Returns True on success."""
    import tempfile, shutil as _sh
    try: _sh.copy2(hosts_path, hosts_path + '.downpour.bak')
    except Exception: pass
    # Attempt 1: direct write
    try:
        with open(hosts_path, 'w', encoding='utf-8', newline='\n') as _f:
            _f.write(new_content)
        return True
    except (PermissionError, OSError):
        pass
    # Attempt 2: write to temp then PowerShell Copy-Item (CFA-allowlisted)
    try:
        _NO_WIN = getattr(subprocess, 'CREATE_NO_WINDOW', 0x08000000)
        tmp_fd, tmp_path = tempfile.mkstemp(prefix='dp_hosts_', suffix='.tmp')
        try:
            with os.fdopen(tmp_fd, 'w', encoding='utf-8', newline='\n') as _tf:
                _tf.write(new_content)
            ps = f"Copy-Item -LiteralPath '{tmp_path}' -Destination '{hosts_path}' -Force"
            r = subprocess.run(['powershell', '-NoProfile', '-NonInteractive',
                                '-ExecutionPolicy', 'Bypass', '-Command', ps],
                               capture_output=True, text=True, timeout=15,
                               creationflags=_NO_WIN)
            if r.returncode == 0:
                return True
            # Attempt 3: cmd copy
            r2 = subprocess.run(['cmd', '/c', f'copy /y "{tmp_path}" "{hosts_path}"'],
                                capture_output=True, timeout=10, creationflags=_NO_WIN)
            return r2.returncode == 0
        finally:
            try: os.unlink(tmp_path)
            except Exception: pass
    except Exception:
        return False


class ParentalControls:
    """Screen time, web filtering, app restrictions from parental_controls.py"""

    HOSTS_FILE = os.path.join(os.environ.get('SYSTEMROOT', r'C:\Windows'), r'System32\drivers\etc\hosts')
    HOSTS_MARKER = "# DOWNPOUR_PARENTAL_BLOCK"

    def __init__(self, cfg: ConfigManager, db: Database):
        # Memory optimization
        self._last_gc = time.time()
        self.cfg = cfg
        self.db = db
        self._active = cfg.get('parental', 'enabled')
        self._lock = threading.Lock()

    def is_within_screen_time(self) -> Tuple[bool, str]:
        now = datetime.now()
        weekday = now.weekday() < 5
        limit_key = 'weekday_mins' if weekday else 'weekend_mins'
        limit = self.cfg.get('parental', limit_key) or 120
        # Check bedtime
        try:
            bt_start = self.cfg.get('parental', 'bedtime_start') or '21:00'
            bt_end   = self.cfg.get('parental', 'bedtime_end')   or '07:00'
            h, m = map(int, bt_start.split(':'))
            bedtime = now.replace(hour=h, minute=m, second=0)
            h2, m2 = map(int, bt_end.split(':'))
            waketime = now.replace(hour=h2, minute=m2, second=0)
            if now >= bedtime or now < waketime:
                return False, f"Bedtime! Hours: {bt_start} - {bt_end}"
        except Exception:
            pass
        return True, "Screen time OK"

    def apply_web_filter(self, domains: List[str]):
        """Add domains to hosts file via elevated write (bypasses CFA)."""
        try:
            with open(self.HOSTS_FILE, 'r', encoding='utf-8', errors='replace') as f:
                content = f.read()
        except Exception:
            content = ''
        lines = [l for l in content.splitlines() if self.HOSTS_MARKER not in l]
        for domain in domains:
            lines.append(f"0.0.0.0 {domain} {self.HOSTS_MARKER}")
            lines.append(f"0.0.0.0 www.{domain} {self.HOSTS_MARKER}")
        return _write_hosts_file_elevated('\n'.join(lines), self.HOSTS_FILE)

    def remove_web_filter(self):
        try:
            with open(self.HOSTS_FILE, 'r', encoding='utf-8', errors='replace') as f:
                content = f.read()
        except Exception:
            return
        lines = [l for l in content.splitlines() if self.HOSTS_MARKER not in l]
        _write_hosts_file_elevated('\n'.join(lines), self.HOSTS_FILE)

    def apply_all_blocks(self):
        domains = []
        if self.cfg.get('parental', 'block_adult'):
            domains.extend(KnownThreats.BLOCKED_DOMAINS_ADULT)
        if self.cfg.get('parental', 'block_gambling'):
            domains.extend(KnownThreats.BLOCKED_DOMAINS_GAMBLING)
        if self.cfg.get('parental', 'block_violence'):
            domains.extend(KnownThreats.BLOCKED_DOMAINS_VIOLENCE)
        return self.apply_web_filter(domains)

    def log_event(self, event_type: str, detail: str):
        try:
            self.db.execute(
                "INSERT INTO parental_log (event_type, detail, logged_at) VALUES (?,?,?)",
                (event_type, detail, datetime.now().isoformat()))
        except Exception:
            pass

    def get_recent_log(self, limit=50) -> List[dict]:
        try:
            rows = self.db.execute(
                "SELECT event_type, detail, logged_at FROM parental_log ORDER BY id DESC LIMIT ?",
                (limit,))
            return [{'type': r[0], 'detail': r[1], 'time': r[2]} for r in rows]
        except Exception:
            return []


