# [ascii art removed]
# [ascii art removed]
#  ADAPTIVE HARDWARE PROFILER
#  Detects CPU cores/speed, RAM, GPU, disk type and battery at startup.
#  Classifies into 5 tiers and produces optimal settings for every
#  tunable parameter so Downpour runs well on any PC.
# [ascii art removed]
class HWProfile:
    """Immutable snapshot of hardware-derived optimal settings."""
    # FIX: '__slots__' prevents any attribute not in this tuple from being set.
    # '_last_gc' was NOT in __slots__, causing AttributeError on __init__.
    # Removed the spurious self._last_gc assignment  -  HWProfile is read-only data,
    # it never needs GC tracking. Also removed __slots__ restriction so future
    # fields added to __init__ don't cause silent crashes.
    def __init__(self, **kw):
        for k, v in kw.items():
            setattr(self, k, v)
    def __repr__(self):
        return (f'HWProfile(tier={self.tier}, {self.ncpu}c/{self.ncpu_phys}p '
                f'@{self.cpu_freq_max_mhz}MHz, {self.ram_gb:.1f}GB RAM, '
                f'gpu={self.gpu_name or "none"}, ssd={self.is_ssd}, '
                f'laptop={self.is_laptop})')


class HardwareProfiler:
    """
    Profiles host hardware once at startup and returns an HWProfile.
    Tiers  (score = cores x GHz + RAM/4 + 2 if dGPU):
      MINIMAL  <=4   : 1-2 cores, <=2 GB  (Atom/Celeron, old sticks)
      LOW      <=8   : 2-4 cores, 2-4 GB  (budget laptop / old PC)
      MEDIUM   <=14  : 4-6 cores, 4-8 GB  (mainstream 2018-2022)
      HIGH     <=24  : 6-12 cores, 8-16 GB (gaming laptop / workstation)
      ULTRA    >24   : 12+ cores, 16+ GB  (desktop beast)
    """
    _profile: Optional['HWProfile'] = None

    @classmethod
    def profile(cls) -> 'HWProfile':
        if cls._profile is None:
            cls._profile = cls._detect()
        return cls._profile

    @classmethod
    def _detect(cls) -> 'HWProfile':
        import os as _os
        try:
            import psutil as _psu
            _psutil_ok = True
        except Exception:
            _psutil_ok = False

        # -- CPU -------------------------------------------------------
        ncpu      = _os.cpu_count() or 1
        ncpu_phys = ncpu
        freq_max  = 0
        try:
            if _psutil_ok:
                ncpu_phys = _psu.cpu_count(logical=False) or ncpu
                f = _psu.cpu_freq()
                if f:
                    freq_max = int(f.max or f.current or 0)
        except Exception:
            pass
        cpu_score = ncpu * max(freq_max / 1000.0, 1.0)

        # -- RAM -------------------------------------------------------
        ram_gb = 2.0;  ram_avail_gb = 1.0
        try:
            if _psutil_ok:
                m = _psu.virtual_memory()
                ram_gb       = m.total     / 1e9
                ram_avail_gb = m.available / 1e9
        except Exception:
            pass

        # -- GPU -------------------------------------------------------
        has_gpu = False;  gpu_name = '';  gpu_vram_gb = 0.0
        try:
            # Use nvidia-ml-py (maintained replacement for deprecated pynvml)
            try:
                from nvidia_ml_py import (nvmlInit, nvmlDeviceGetHandleByIndex,
                                    nvmlDeviceGetName, nvmlDeviceGetMemoryInfo)
            except ImportError:
                from pynvml import (nvmlInit, nvmlDeviceGetHandleByIndex,
                                    nvmlDeviceGetName, nvmlDeviceGetMemoryInfo)
            nvmlInit()
            h = nvmlDeviceGetHandleByIndex(0)
            gpu_name    = nvmlDeviceGetName(h)
            gpu_vram_gb = nvmlDeviceGetMemoryInfo(h).total / 1e9
            has_gpu     = True
        except Exception:
            pass
        if not has_gpu:
            try:
                import GPUtil
                gpus = GPUtil.getGPUs()
                if gpus:
                    gpu_name    = gpus[0].name
                    gpu_vram_gb = gpus[0].memoryTotal / 1024.0
                    has_gpu     = True
            except Exception:
                pass

        # -- Battery / laptop -----------------------------------------
        is_laptop = False
        try:
            if _psutil_ok:
                is_laptop = _psu.sensors_battery() is not None
        except Exception:
            pass

        # -- Disk type (SSD vs HDD) ------------------------------------
        is_ssd = True
        try:
            import subprocess as _sp
            r = _sp.run(
                ['powershell','-NoProfile','-Command',
                 'Get-PhysicalDisk|Select-Object MediaType|ConvertTo-Json'],
                capture_output=True, text=True, timeout=5,
                creationflags=0x08000000)
            if 'HDD' in r.stdout or ('Unspecified' in r.stdout and 'SSD' not in r.stdout):
                is_ssd = False
        except Exception:
            pass

        # -- Tier -----------------------------------------------------
        hw_score = cpu_score + (ram_gb / 4.0) + (2.0 if has_gpu else 0.0)
        # More generous tier assignment for old hardware
        if   hw_score <= 6  or ncpu <= 2 or ram_gb < 4:   tier = 'MINIMAL'  # More generous
        elif hw_score <= 12 or ncpu <= 4 or ram_gb < 6:   tier = 'LOW'      # More generous  
        elif hw_score <= 20 or ncpu <= 6 or ram_gb < 8:   tier = 'MEDIUM'   # More generous
        elif hw_score <= 32 or ncpu <= 8 or ram_gb < 12:  tier = 'HIGH'     # More generous
        else:                                               tier = 'ULTRA'

        params = cls._tier_params(tier, ncpu, ram_gb, has_gpu, is_ssd, is_laptop)
        desc   = (f'{tier} | {ncpu}c/{ncpu_phys}p @{freq_max}MHz | '
                  f'{ram_gb:.1f}GB RAM | {"GPU "+gpu_name if has_gpu else "no GPU"} | '
                  f'{"SSD" if is_ssd else "HDD"} | {"Laptop" if is_laptop else "Desktop"}')
        p = HWProfile(
            tier=tier, ncpu=ncpu, ncpu_phys=ncpu_phys,
            ram_gb=ram_gb, ram_avail_gb=ram_avail_gb,
            has_gpu=has_gpu, gpu_name=gpu_name, gpu_vram_gb=gpu_vram_gb,
            is_laptop=is_laptop, is_ssd=is_ssd,
            cpu_freq_max_mhz=freq_max, cpu_score=cpu_score,
            description=desc, **params)
        print(f'[HW] {p}')
        return p

    @classmethod
    def _tier_params(cls, tier, ncpu, ram_gb, has_gpu, is_ssd, is_laptop) -> dict:
        # Laptop battery conservation: stretch intervals on LOW/MINIMAL
        bat_factor = 1.5 if (is_laptop and tier in ('MINIMAL','LOW')) else 1.0
        # HDD compensation: reduce parallel workers slightly (seek latency)
        hdd_factor = 0.6 if not is_ssd else 1.0

        def w(base):   return max(1, int(base * hdd_factor))  # Minimum 1 worker for old systems

        # Screen size detection
        try:
            import tkinter as tk
            temp_root = tk.Tk()
            temp_root.withdraw()
            screen_width = temp_root.winfo_screenwidth()
            screen_height = temp_root.winfo_screenheight()
            temp_root.destroy()
        except Exception:
            screen_width, screen_height = 1366, 768  # Default fallback

        # Window sizing based on screen resolution
        if screen_width >= 1920 and screen_height >= 1080:
            window_size = (1400, 900)
            font_scale = 1.0
        elif screen_width >= 1366 and screen_height >= 768:
            window_size = (1200, 750)
            font_scale = 0.9
        else:
            window_size = (1000, 600)
            font_scale = 0.8

        # Font scaling by tier
        tier_scales = {'MINIMAL': 0.6, 'LOW': 0.8, 'MEDIUM': 1.0, 'HIGH': 1.1, 'ULTRA': 1.2}
        font_scale = tier_scales.get(tier, font_scale)

        if tier == 'MINIMAL':
            return dict(
                workers_cpu=1, workers_gpu=1, workers_io=1,  # Force single thread for minimal systems
                workers_scan=1,
                perf_interval_ms=int(5000*bat_factor), hw_monitor_interval_s=8.0,
                proc_scan_interval_ms=int(120000*bat_factor),
                hw_loop_interval_ms=int(10000*bat_factor),
                feed_refresh_ms=int(120000*bat_factor),
                rain_intensity=0, rain_height=2, rain_enabled=False,
                gauge_update_ms=6000, tree_update_ms=8000,
                scan_timeout_s=20, mem_scan_workers=1,
                gc_threshold=(2000,25,25), timer_resolution_ms=8,
                screen_size=(screen_width, screen_height),
                window_size=window_size,
                font_scale=font_scale,
            )
        elif tier == 'LOW':
            return dict(
                workers_cpu=max(1, ncpu), workers_gpu=max(1, ncpu//2), workers_io=max(1, ncpu),
                workers_scan=max(1, ncpu),
                perf_interval_ms=int(4000*bat_factor), hw_monitor_interval_s=5.0,
                proc_scan_interval_ms=int(90000*bat_factor),
                hw_loop_interval_ms=int(6000*bat_factor),
                feed_refresh_ms=int(90000*bat_factor),
                rain_intensity=20, rain_height=40, rain_enabled=True,  # Doubled height for visibility
                gauge_update_ms=4000, tree_update_ms=6000,
                scan_timeout_s=15, mem_scan_workers=max(1, ncpu//2),
                gc_threshold=(3000,40,40), timer_resolution_ms=6,
                screen_size=(screen_width, screen_height),
                window_size=window_size,
                font_scale=font_scale,
            )
        elif tier == 'MEDIUM':
            return dict(
                workers_cpu=w(ncpu*4), workers_gpu=w(ncpu*3), workers_io=w(ncpu*8),
                workers_scan=w(ncpu*4),
                perf_interval_ms=1200, hw_monitor_interval_s=1.5,
                proc_scan_interval_ms=20000, hw_loop_interval_ms=2000,
                feed_refresh_ms=20000,
                rain_intensity=90, rain_height=110, rain_enabled=True,
                gauge_update_ms=1200, tree_update_ms=1800,
                scan_timeout_s=5, mem_scan_workers=w(ncpu*2),
                gc_threshold=(40000,400,400), timer_resolution_ms=1,
                screen_size=(screen_width, screen_height),
                window_size=window_size,
                font_scale=font_scale,
            )
        elif tier == 'HIGH':
            return dict(
                workers_cpu=w(ncpu*5), workers_gpu=w(ncpu*3), workers_io=w(ncpu*12),
                workers_scan=w(ncpu*6),
                perf_interval_ms=1000, hw_monitor_interval_s=1.0,
                proc_scan_interval_ms=12000, hw_loop_interval_ms=1500,
                feed_refresh_ms=12000,
                rain_intensity=150, rain_height=180, rain_enabled=True,
                gauge_update_ms=800, tree_update_ms=1000,
                scan_timeout_s=4, mem_scan_workers=w(ncpu*3),
                gc_threshold=(80000,800,800), timer_resolution_ms=1,
                screen_size=(screen_width, screen_height),
                window_size=window_size,
                font_scale=font_scale,
            )
        else:  # ULTRA
            return dict(
                workers_cpu=w(ncpu*6), workers_gpu=w(ncpu*4), workers_io=w(ncpu*16),
                workers_scan=w(ncpu*8),
                perf_interval_ms=800, hw_monitor_interval_s=0.8,
                proc_scan_interval_ms=10000, hw_loop_interval_ms=1000,
                feed_refresh_ms=10000,
                rain_intensity=200, rain_height=180, rain_enabled=True,
                gauge_update_ms=600, tree_update_ms=800,
                scan_timeout_s=3, mem_scan_workers=w(ncpu*4),
                gc_threshold=(200000,2000,2000), timer_resolution_ms=1,
                screen_size=(screen_width, screen_height),
                window_size=window_size,
                font_scale=font_scale,
            )

    @classmethod
    def adapt_to_load(cls, app) -> None:
        """
        Called every 60s. Back off scan intervals under high CPU/RAM pressure;
        ramp back up when idle. Keeps Downpour responsive even on loaded machines.
        """
        try:
            import psutil as _psu
            pressure = max(_psu.cpu_percent(interval=None),
                           _psu.virtual_memory().percent)
            p = cls.profile()
            factor   = 2.0 if pressure > 85 else (1.4 if pressure > 65 else 1.0)
            app._adaptive_hw_ms  = int(p.hw_loop_interval_ms   * factor)
            app._adaptive_prc_ms = int(p.proc_scan_interval_ms * factor)
            app._adaptive_prf_ms = int(p.perf_interval_ms      * factor)
            app._adaptive_feed_ms= int(p.feed_refresh_ms       * factor)
        except Exception:
            pass


class HardwareMonitor:
    """Uses psutil + pynvml only - avoids PdhAddEnglishCounterW crash.
    GPU-async: background thread refreshes stats so callers never block."""

    def __init__(self):
        # Memory optimization
        self._last_gc = time.time()
        self._cache: Dict[str, Any] = {}
        self._last_update = 0.0
        self._interval = 2.0  # FIX-v28p18: 2s for responsive HW bar
        self._lock = threading.Lock()
        self._bg_running = False
        # Prime cpu_percent  -  first call always returns 0.0
        try:
            import psutil as _p; _p.cpu_percent(interval=None)
        except Exception: pass

    def start_background_refresh(self):
        """Start a background thread that refreshes stats at _interval rate."""
        if self._bg_running:
            return
        self._bg_running = True
        def _loop():
            try:
                import pythoncom; pythoncom.CoInitialize()
            except Exception:
                pass
            while self._bg_running:
                try:
                    s = self._fetch()
                    with self._lock:
                        self._cache = s
                        self._last_update = time.time()
                except Exception:
                    pass
                time.sleep(self._interval)
        threading.Thread(target=_loop, daemon=True, name='hw-monitor').start()

    def stop_background_refresh(self):
        self._bg_running = False

    def get_stats(self) -> dict:
        """Return cached stats  -  never blocks if background thread is running."""
        with self._lock:
            if self._cache:
                return dict(self._cache)  # snapshot copy
        # First call or bg thread not started: do sync fetch
        s = self._fetch()
        with self._lock:
            self._cache = s
            self._last_update = time.time()
        return s

    def _fetch(self) -> dict:
        """Actual blocking stats fetch  -  called from background thread."""
        now = time.time()
        stats = {
            # CPU
            'cpu_percent': 0.0, 'cpu_freq_mhz': 0, 'cpu_temp': 0.0,
            'cpu_cores': 0, 'cpu_cores_physical': 0,
            'cpu_per_core': [],          # list of per-core %
            # RAM
            'ram_percent': 0.0, 'ram_used_gb': 0.0, 'ram_total_gb': 0.0,
            'ram_avail_gb': 0.0,
            # Swap
            'swap_percent': 0.0, 'swap_used_gb': 0.0, 'swap_total_gb': 0.0,
            # GPU
            'gpu_percent': 0.0, 'gpu_mem_percent': 0.0, 'gpu_temp': 0.0,
            'gpu_fan': 0, 'gpu_name': '', 'gpu_mem_used_gb': 0.0, 'gpu_mem_total_gb': 0.0,
            # Disk I/O
            'disk_read_mb': 0.0, 'disk_write_mb': 0.0,
            'disk_read_rate': 0.0, 'disk_write_rate': 0.0,
            # Disk usage
            'disk_used_percent': 0.0, 'disk_used_gb': 0.0, 'disk_total_gb': 0.0,
            # Network
            'net_sent_mb': 0.0, 'net_recv_mb': 0.0,
            'net_send_rate': 0.0, 'net_recv_rate': 0.0,
            'net_packets_sent': 0, 'net_packets_recv': 0,
            # System
            'process_count': 0, 'thread_count': 0,
            'uptime_seconds': 0.0, 'boot_time': 0.0,
            # Battery
            'battery_percent': -1.0, 'battery_plugged': True, 'battery_mins': -1,
            # Per-disk and per-NIC (filled below)
            'disk_partitions': [],   # [{mount, used_pct, used_gb, total_gb}]
            'nic_stats': [],         # [{name, bytes_sent_rate, bytes_recv_rate, speed_mbps}]
            'cpu_freq_max': 0, 'cpu_freq_min': 0,
            'open_files': 0, 'ctx_switches': 0,
            # KEV/CEV/EPSS Vulnerability Tracking
            'kev_count': 0, 'kev_critical': 0, 'kev_high': 0,
            'cev_score': 0.0, 'epss_avg': 0.0, 'epss_high_count': 0,
            'vuln_threat_level': 'UNKNOWN',
            # Threat Actor & Feed Tracking (v29)
            'actor_count': 0, 'feed_count': 0, 'indicator_count': 0, 'active_alerts': 0,
        }
        # Re-try psutil import every call until it succeeds (auto-install may have run)
        global PSUTIL_AVAILABLE, psutil
        if not PSUTIL_AVAILABLE:
            try:
                import psutil as _ps_retry  # noqa: F811
                psutil = _ps_retry
                PSUTIL_AVAILABLE = True
            except Exception:
                pass
        if not PSUTIL_AVAILABLE:
            return stats

        try:
            # Use short blocking interval on first call so we never return zero
            _primed = getattr(self, '_cpu_primed', False)
            _interval = None if _primed else 0.05
            stats['cpu_percent'] = psutil.cpu_percent(interval=_interval)
            if not _primed:
                self._cpu_primed = True
            stats['cpu_cores'] = psutil.cpu_count(logical=True) or 0
            stats['cpu_cores_physical'] = psutil.cpu_count(logical=False) or 0
            try:
                per_core = psutil.cpu_percent(interval=None, percpu=True)
                stats['cpu_per_core'] = per_core or []
            except Exception: pass
        except Exception: pass
        # Swap
        try:
            sw = psutil.swap_memory()
            stats['swap_percent'] = sw.percent
            stats['swap_used_gb'] = round(sw.used / 1073741824, 1)
            stats['swap_total_gb'] = round(sw.total / 1073741824, 1)
        except Exception: pass
        # Disk usage (C: drive)
        try:
            du = psutil.disk_usage('C:\\')
            stats['disk_used_percent'] = du.percent
            stats['disk_used_gb']      = round(du.used  / 1073741824, 1)
            stats['disk_total_gb']     = round(du.total / 1073741824, 1)
        except Exception: pass
        # Disk I/O rates (delta from last call)
        try:
            dk = psutil.disk_io_counters()
            if dk:
                prev_dk = getattr(self, '_prev_disk', None)
                now_t   = time.time()
                prev_t  = getattr(self, '_prev_disk_t', now_t)
                dt = max(now_t - prev_t, 0.001)
                if prev_dk:
                    stats['disk_read_rate']  = round((dk.read_bytes  - prev_dk.read_bytes)  / 1048576 / dt, 2)
                    stats['disk_write_rate'] = round((dk.write_bytes - prev_dk.write_bytes) / 1048576 / dt, 2)
                self._prev_disk   = dk
                self._prev_disk_t = now_t
        except Exception: pass
        # Network rates
        try:
            nt = psutil.net_io_counters()
            if nt:
                prev_nt = getattr(self, '_prev_net', None)
                now_t2  = time.time()
                prev_t2 = getattr(self, '_prev_net_t', now_t2)
                dt2 = max(now_t2 - prev_t2, 0.001)
                if prev_nt:
                    stats['net_send_rate'] = round((nt.bytes_sent - prev_nt.bytes_sent) / 1024 / dt2, 1)
                    stats['net_recv_rate'] = round((nt.bytes_recv - prev_nt.bytes_recv) / 1024 / dt2, 1)
                stats['net_packets_sent'] = nt.packets_sent
                stats['net_packets_recv'] = nt.packets_recv
                self._prev_net   = nt
                self._prev_net_t = now_t2
        except Exception: pass
        # Processes + threads
        try:
            stats['process_count'] = len(psutil.pids())
            try:
                stats['thread_count'] = sum(
                    p.info.get('num_threads', 0) or 0
                    for p in psutil.process_iter(['num_threads']))
            except Exception: stats['thread_count'] = 0
        except Exception: pass
        # Uptime
        try:
            import time as _t
            stats['boot_time']      = psutil.boot_time()
            stats['uptime_seconds'] = _t.time() - psutil.boot_time()
        except Exception: pass
        # Battery
        try:
            batt = psutil.sensors_battery()
            if batt:
                stats['battery_percent'] = batt.percent
                stats['battery_plugged']  = batt.power_plugged
                stats['battery_mins']     = int(batt.secsleft / 60) if batt.secsleft not in (-1, -2) else -1
        except Exception: pass
        try:
            freq = psutil.cpu_freq()
            if freq:
                stats['cpu_freq_mhz'] = int(freq.current)
        except Exception: pass
        
        # KEV/CEV/EPSS Vulnerability Stats Collection
        try:
            from vulnerability_scanner import get_cev_gauge_data, get_kev_gauge_data
            try:
                cev_data = get_cev_gauge_data()
                stats['cev_score'] = cev_data.get('cev_score', 0)
                stats['vuln_threat_level'] = cev_data.get('threat_level', 'UNKNOWN')
            except Exception: pass
            try:
                kev_data = get_kev_gauge_data()
                stats['kev_count'] = kev_data.get('total_kev', 0)
                stats['kev_critical'] = kev_data.get('critical', 0)
                stats['kev_high'] = kev_data.get('high', 0)
            except Exception: pass
            try:
                from vulnerability_scanner import _KEV_STATS
                stats['epss_avg'] = _KEV_STATS.get('epss_threshold', 0.5) * 100
                stats['epss_high_count'] = 0
            except Exception: pass
        except Exception: pass
        
        # Threat Actor & Feed Tracking Stats (v29)
        try:
            from threat_feed_aggregator import get_threat_actor_stats, get_actor_gauge_data
            try:
                actor_stats = get_threat_actor_stats()
                stats['actor_count'] = actor_stats.get('total_actors', 0) + actor_stats.get('db_actors', 0)
                stats['indicator_count'] = actor_stats.get('db_indicators', 0)
            except Exception: pass
            try:
                from ultimate_threat_intel import ThreatFeedRegistry
                stats['feed_count'] = len(ThreatFeedRegistry.get_enabled_feeds())
            except Exception: pass
            stats['active_alerts'] = 0
        except Exception: pass
        
        try:
            mem = psutil.virtual_memory()
            stats['ram_percent']  = mem.percent
            stats['ram_used_gb']  = round(mem.used      / 1073741824, 1)
            stats['ram_total_gb'] = round(mem.total     / 1073741824, 1)
            stats['ram_avail_gb'] = round(mem.available / 1073741824, 1)
        except Exception: pass
        try:
            disk = psutil.disk_io_counters()
            if disk:
                stats['disk_read_mb']  = round(disk.read_bytes  / 1048576, 1)
                stats['disk_write_mb'] = round(disk.write_bytes / 1048576, 1)
        except Exception: pass
        try:
            net = psutil.net_io_counters()
            if net:
                stats['net_sent_mb'] = round(net.bytes_sent / 1048576, 1)
                stats['net_recv_mb'] = round(net.bytes_recv / 1048576, 1)
        except Exception: pass

        # GPU via NVML (crash-safe)
        if NVML_AVAILABLE:
            try:
                handle = nvmlDeviceGetHandleByIndex(0)
                util = nvmlDeviceGetUtilizationRates(handle)
                stats['gpu_percent']     = util.gpu
                stats['gpu_mem_percent'] = util.memory
                stats['gpu_temp']        = nvmlDeviceGetTemperature(handle, NVML_TEMPERATURE_GPU)
                try:
                    stats['gpu_name'] = nvmlDeviceGetName(handle)
                    mem_info = nvmlDeviceGetMemoryInfo(handle)
                    stats['gpu_mem_used_gb']  = round(mem_info.used  / 1073741824, 1)
                    stats['gpu_mem_total_gb'] = round(mem_info.total / 1073741824, 1)
                except Exception: pass
                try:
                    stats['gpu_fan'] = nvmlDeviceGetFanSpeed(handle)
                except Exception: pass
            except Exception: pass
        elif GPUTIL_AVAILABLE:
            try:
                gpus = GPUtil.getGPUs()
                if gpus:
                    g = gpus[0]
                    stats['gpu_percent']     = g.load * 100
                    stats['gpu_mem_percent'] = g.memoryUtil * 100
                    stats['gpu_temp']        = g.temperature
            except Exception: pass

        # Per-disk partitions
        try:
            parts = []
            for dp in psutil.disk_partitions(all=False):
                try:
                    du2 = psutil.disk_usage(dp.mountpoint)
                    parts.append({
                        'mount': dp.mountpoint, 'fstype': dp.fstype,
                        'used_pct': du2.percent,
                        'used_gb':  round(du2.used  / 1073741824, 1),
                        'total_gb': round(du2.total / 1073741824, 1),
                        'free_gb':  round(du2.free  / 1073741824, 1),
                    })
                except Exception: pass
            stats['disk_partitions'] = parts
        except Exception: pass
        # Per-NIC rates
        try:
            nic_rates = []
            per_nic = psutil.net_io_counters(pernic=True)
            prev_nic = getattr(self, '_prev_nic', {})
            now_nic  = time.time()
            prev_nic_t = getattr(self, '_prev_nic_t', now_nic)
            dt_nic = max(now_nic - prev_nic_t, 0.001)
            for name, counters in per_nic.items():
                if name.lower() in ('lo', 'loopback'): continue
                prev = prev_nic.get(name)
                send_rate = round((counters.bytes_sent - prev.bytes_sent) / 1024 / dt_nic, 1) if prev else 0.0
                recv_rate = round((counters.bytes_recv - prev.bytes_recv) / 1024 / dt_nic, 1) if prev else 0.0
                try:
                    nic_info = psutil.net_if_stats().get(name)
                    speed = nic_info.speed if nic_info else 0
                except Exception: speed = 0
                nic_rates.append({'name': name[:12], 'send_rate': send_rate,
                                   'recv_rate': recv_rate, 'speed_mbps': speed,
                                   'up': nic_info.isup if nic_info else False})
            stats['nic_stats'] = nic_rates
            self._prev_nic   = per_nic
            self._prev_nic_t = now_nic
        except Exception: pass
        # CPU freq min/max
        try:
            freq2 = psutil.cpu_freq()
            if freq2:
                stats['cpu_freq_max'] = int(freq2.max) if freq2.max else 0
                stats['cpu_freq_min'] = int(freq2.min) if freq2.min else 0
        except Exception: pass
        # Open files + context switches (system-wide)
        try:
            sc2 = psutil.cpu_stats()
            stats['ctx_switches'] = sc2.ctx_switches
        except Exception: pass
        # CPU temperature via WMI (optional)
        if WMI_AVAILABLE and stats['cpu_temp'] == 0:
            try:
                # FIX-v28: CoInitialize required from background thread
                try:
                    import pythoncom; pythoncom.CoInitialize()
                except Exception: pass
                w = wmi.WMI(namespace=r'root\wmi')
                for t in w.MSAcpi_ThermalZoneTemperature():
                    stats['cpu_temp'] = round((t.CurrentTemperature - 2732) / 10.0, 1)
                    break
            except Exception: pass

        self._cache = stats
        return stats


