#                                    XBOX CONTROLLER (from Umbrella v12)
# [ascii art removed]
class XInputController:
    BTN_A=0x1000; BTN_B=0x2000; BTN_X=0x4000; BTN_Y=0x8000
    BTN_START=0x0010; BTN_BACK=0x0020
    DPAD_UP=0x0001; DPAD_DOWN=0x0002; DPAD_LEFT=0x0004; DPAD_RIGHT=0x0008

    def __init__(self):
        # Memory optimization
        self._last_gc = time.time()
        self.xinput = None
        self.connected = False
        if platform.system() != 'Windows':
            return
        for dll in ('xinput1_4.dll', 'xinput1_3.dll', 'xinput9_1_0.dll'):
            try:
                lib = ctypes.windll.LoadLibrary(dll)
                st = self._mk_state()
                if lib.XInputGetState(0, ctypes.byref(st)) == 0:
                    self.xinput = lib
                    self.connected = True
                    break
            except Exception:
                continue

    def _mk_state(self):
        class GP(ctypes.Structure):
            _fields_ = [('btns',ctypes.c_ushort),('lt',ctypes.c_ubyte),('rt',ctypes.c_ubyte),
                        ('lx',ctypes.c_short),('ly',ctypes.c_short),('rx',ctypes.c_short),('ry',ctypes.c_short)]
        class ST(ctypes.Structure):
            _fields_ = [('pkt',ctypes.c_uint),('gp',GP)]
        return ST()

    def get(self) -> Optional[dict]:
        if not self.xinput:
            return None
        try:
            st = self._mk_state()
            if self.xinput.XInputGetState(0, ctypes.byref(st)) != 0:
                self.connected = False
                return None
            self.connected = True
            g = st.gp
            return {
                'a':bool(g.btns&self.BTN_A),'b':bool(g.btns&self.BTN_B),
                'x':bool(g.btns&self.BTN_X),'y':bool(g.btns&self.BTN_Y),
                'start':bool(g.btns&self.BTN_START),'back':bool(g.btns&self.BTN_BACK),
                'up':bool(g.btns&self.DPAD_UP),'down':bool(g.btns&self.DPAD_DOWN),
                'left':bool(g.btns&self.DPAD_LEFT),'right':bool(g.btns&self.DPAD_RIGHT),
                'lx':g.lx/32768.0,'ly':g.ly/32768.0,
            }
        except Exception:
            return None

    def vibrate(self, l=0.5, r=0.5, dur=0.2):
        if not self.xinput:
            return
        try:
            class VIB(ctypes.Structure):
                _fields_ = [('lm',ctypes.c_ushort),('rm',ctypes.c_ushort)]
            v = VIB(int(l*65535), int(r*65535))
            self.xinput.XInputSetState(0, ctypes.byref(v))
            if dur > 0:
                threading.Timer(dur, lambda: self.vibrate(0,0,0)).start()
        except Exception:
            pass

#                               IMMERSIVE RAIN CANVAS (Apex v18 engine)
# [ascii art removed]
class ImmersiveRainCanvas(tk.Canvas):
    """
    Downpour v29 — Ultra-performance rain canvas with storm dynamics.

    ALL canvas items are pre-allocated at init. The animation loop ONLY calls
    coords() and itemconfig() — never create_*/delete(). This eliminates the
    Tk object churn that was causing 14,000+ alloc/dealloc ops per second.

    v29 Enhancements (FIXES):
      - FIX: USB monitor window-exists check to prevent crash on app close
      - FIX: Firewall duplicate item prevention with _fw_filtering flag
      - 24fps smooth animation (42ms) — no more _busy_frames pausing
      - Delta-time compensation — consistent speed regardless of frame drops
      - Wind gust system — dynamic gusts with acceleration/deceleration
      - Storm phases — calm/drizzle/storm/tempest cycle automatically
      - Fog/mist layer — pre-allocated gradient rectangles at ground level
      - Enhanced lightning — multi-flash with afterglow and screen shake
      - Threat-adaptive intensity — rain responds to active threat level
      - Cloud silhouettes — atmospheric depth at top of canvas
      - Star twinkle — subtle brightness oscillation on star items
    """

    # Expanded color palette with depth layers
    _COLORS_NEAR = ['#ccefff', '#bbddff', '#aaddff', '#ddf4ff']  # bright foreground
    _COLORS_MID  = ['#88ccee', '#77bbdd', '#99ccee', '#88bbdd']   # mid layer
    _COLORS_FAR  = ['#445577', '#3a4a66', '#4d6080', '#3d5070']   # distant/dim
    _COLORS      = _COLORS_NEAR + _COLORS_MID  # compat

    # Storm phase definitions: (name, intensity_mult, wind_range, lightning_chance, fog_alpha)
    _STORM_PHASES = [
        ('calm',    0.4, (-0.1, 0.3), 0.0000, 0.15),
        ('drizzle', 0.7, (-0.2, 0.5), 0.0008, 0.25),
        ('storm',   1.0, (-0.4, 0.8), 0.0060, 0.40),
        ('tempest', 1.3, (-0.6, 1.2), 0.0150, 0.55),
    ]

    # ── Construction ──────────────────────────────────────────────────────
    def __init__(self, parent, width=800, height=110, intensity=200, **kw):
        super().__init__(parent, width=width, height=height,
                         bg='#080c18', highlightthickness=0, **kw)
        self.w = width
        self.h = height
        self.intensity = min(intensity, 150)
        self._running = False
        self._frame = 0
        self._moon_enabled = True
        self._stop_flag = threading.Event()
        self._lightning_phase = 0
        self._lightning_cb = None
        self._last_frame_time = 0.0

        # ── Storm dynamics ────────────────────────────────────────────────
        self._storm_phase_idx = 2          # start at 'storm'
        self._storm_phase_timer = 0        # frames until next phase shift
        self._phase_transition = 0.0       # 0-1 blend between phases
        self._target_phase_idx = 2
        self._threat_level = 0             # 0-100, set externally

        # ── Wind gust system ──────────────────────────────────────────────
        self._wind_base = 0.3              # base wind direction
        self._wind_gust = 0.0              # current gust strength
        self._wind_gust_target = 0.0       # target gust
        self._wind_gust_timer = 0          # frames until next gust change

        # ── Pre-allocate ALL canvas items ─────────────────────────────────
        self._bg_items = []
        self._init_bg()

        # Cloud silhouettes (drawn once, layered behind rain)
        self._cloud_items = []
        self._init_clouds()

        self._drops = []
        self._drop_items = []
        self._drop_colors = []
        self._drop_widths = []
        self._init_drops()

        self._SPLASH_POOL = 50
        self._splashes = []
        self._splash_items = []
        for _ in range(self._SPLASH_POOL):
            oid = self.create_oval(-20, -20, -10, -10, outline='#88ccee',
                                    fill='', width=1)
            self._splash_items.append(oid)

        self._STREAK_POOL = 70
        self._streaks = []
        self._streak_items = []
        for _ in range(self._STREAK_POOL):
            lid = self.create_line(-20, -20, -20, -20, fill='#88ccee', width=1)
            self._streak_items.append(lid)

        # Fog / mist layer (pre-allocated semi-transparent bands at bottom)
        self._FOG_BANDS = 5
        self._fog_items = []
        for i in range(self._FOG_BANDS):
            fid = self.create_rectangle(-10, -10, -5, -5,
                                         fill='#0a1020', outline='', stipple='gray25')
            self._fog_items.append(fid)

        self._lightning_overlay = self.create_rectangle(
            -10, -10, -5, -5, fill='', outline='', state='hidden')
        self._BOLT_POOL = 24
        self._bolt_items = []
        self._bolt_glow_items = []
        for _ in range(self._BOLT_POOL):
            glow = self.create_line(-10, -10, -10, -10, fill='#bbddff',
                                     width=5, state='hidden')
            core = self.create_line(-10, -10, -10, -10, fill='#ffffff',
                                     width=2, state='hidden')
            self._bolt_glow_items.append(glow)
            self._bolt_items.append(core)
        self._bolt_segments = []

        # Afterglow overlay (lingers after lightning)
        self._afterglow_phase = 0

        # ── Puddle reflection system (shimmering ground reflections) ──────
        self._PUDDLE_POOL = 12
        self._puddle_items = []
        self._puddle_state = []  # {x, w, shimmer_phase, brightness}
        for i in range(self._PUDDLE_POOL):
            pid = self.create_oval(-20, -20, -10, -10,
                                    fill='#0a1a30', outline='#112840',
                                    width=1, stipple='gray25')
            self._puddle_items.append(pid)
            self._puddle_state.append({
                'x': random.uniform(0, self.w),
                'w': random.uniform(20, 60),
                'phase': random.uniform(0, 6.28),
                'bright': random.uniform(0.3, 0.8),
            })

        # ── Ambient mist particles (float slowly upward from ground) ─────
        self._MIST_POOL = 15
        self._mist_items = []
        self._mist_state = []
        for i in range(self._MIST_POOL):
            mid = self.create_oval(-20, -20, -10, -10,
                                    fill='#0e1828', outline='',
                                    stipple='gray12')
            self._mist_items.append(mid)
            self._mist_state.append({
                'x': random.uniform(0, self.w),
                'y': random.uniform(self.h * 0.7, self.h),
                'r': random.uniform(8, 25),
                'vx': random.uniform(-0.3, 0.3),
                'vy': random.uniform(-0.4, -0.1),
                'life': random.randint(60, 180),
                'max_life': 180,
            })

        self._moon_items = []
        self._star_items = []  # separate tracking for twinkle
        self._init_moon()
        self.bind('<Configure>', self._on_resize)

    # ── Background gradient (deeper, more bands) ─────────────────────────
    def _init_bg(self):
        bands = 8
        self._bg_items = []
        for i in range(bands):
            t = i / (bands - 1)
            r = int(4 + 6 * t)
            g = int(6 + 8 * t)
            b = int(14 + 22 * t)
            y0 = int(i * self.h / bands)
            y1 = int((i + 1) * self.h / bands) + 1
            item = self.create_rectangle(0, y0, self.w, y1,
                                          fill=f'#{r:02x}{g:02x}{b:02x}',
                                          outline='')
            self._bg_items.append(item)
            self.tag_lower(item)

    def _refresh_bg(self):
        bands = len(self._bg_items)
        if bands == 0:
            return
        for i, item in enumerate(self._bg_items):
            t = i / max(bands - 1, 1)
            r = int(4 + 6 * t)
            g = int(6 + 8 * t)
            b = int(14 + 22 * t)
            y0 = int(i * self.h / bands)
            y1 = int((i + 1) * self.h / bands) + 1
            self.coords(item, 0, y0, self.w, y1)
            self.itemconfig(item, fill=f'#{r:02x}{g:02x}{b:02x}')

    # ── Cloud silhouettes (atmospheric depth) ────────────────────────────
    def _init_clouds(self):
        rng = random.Random(77)
        cloud_shapes = []
        # Generate 4-6 overlapping cloud blobs across the top
        for _ in range(rng.randint(4, 6)):
            cx = rng.uniform(-40, self.w + 40)
            cy = rng.uniform(-15, self.h * 0.25)
            rw = rng.uniform(60, 180)
            rh = rng.uniform(15, 40)
            shade = rng.choice(['#0a0e1e', '#0c1022', '#0e1228', '#081018'])
            oid = self.create_oval(cx - rw, cy - rh, cx + rw, cy + rh,
                                    fill=shade, outline='')
            self._cloud_items.append(oid)
        # Ensure clouds are above background but below everything else
        for cid in self._cloud_items:
            self.tag_raise(cid)

    # ── Drop management ───────────────────────────────────────────────────
    def _init_drops(self):
        n = self.intensity
        self._drops = [self._new_drop(warm=True) for _ in range(n)]
        old = getattr(self, '_drop_items', [])
        if len(old) != n:
            for item in old:
                try: self.delete(item)
                except Exception: pass
            self._drop_items = [
                self.create_line(0, 0, 0, 0, fill='#88ccee', width=1)
                for _ in range(n)
            ]
            self._drop_colors = ['#88ccee'] * n
            self._drop_widths = [1] * n

    def _new_drop(self, warm=False):
        h = self.h
        # Depth layer: 0=far(slow,dim), 1=mid, 2=near(fast,bright)
        layer = random.choices([0, 1, 2], [2, 5, 3])[0]
        if layer == 0:
            col = random.choice(self._COLORS_FAR)
            spd = random.uniform(4, 8)
            ln = random.uniform(4, 10)
            wid = 1
        elif layer == 1:
            col = random.choice(self._COLORS_MID)
            spd = random.uniform(8, 15)
            ln = random.uniform(8, 18)
            wid = random.choices([1, 2], [6, 4])[0]
        else:
            col = random.choice(self._COLORS_NEAR)
            spd = random.uniform(14, 24)
            ln = random.uniform(14, 28)
            wid = random.choices([1, 2, 3], [3, 5, 2])[0]
        return {
            'x':   random.uniform(0, self.w),
            'y':   random.uniform(-h, h * 0.5) if warm else random.uniform(-h * 0.4, -4),
            'len': ln,
            'spd': spd,
            'wnd': random.uniform(-0.3, 0.7),
            'col': col,
            'wid': wid,
            'fat': random.random() < 0.04,
            'layer': layer,
        }

    # ── Moon + stars (drawn ONCE, twinkle via coords shift) ──────────────
    def _init_moon(self):
        if not self._moon_enabled:
            return
        mx = self.w - 62
        my = max(self.h // 2, 30)
        R = 22
        # Atmospheric halo rings (more layers for glow effect)
        for ring_r, col, w in [
            (R + 22, '#0a1833', 6),
            (R + 18, '#112244', 5),
            (R + 12, '#1a3a6a', 3),
            (R + 6,  '#2255aa', 2),
        ]:
            oid = self.create_oval(mx - ring_r, my - ring_r * 0.85,
                                    mx + ring_r, my + ring_r * 0.85,
                                    outline=col, fill='', width=w)
            self._moon_items.append(oid)
        # Moon disc
        oid = self.create_oval(mx - R, my - R, mx + R, my + R,
                                fill='#e8f0ff', outline='#c8dcff', width=1)
        self._moon_items.append(oid)
        # Crescent shadow
        ox, oy = mx - R * 0.42, my + R * 0.08
        sr = R * 0.88
        oid = self.create_oval(ox - sr, oy - sr, ox + sr, oy + sr,
                                fill='#080c18', outline='#080c18', width=2)
        self._moon_items.append(oid)
        # Rim highlight
        oid = self.create_arc(mx - R + 1, my - R + 1, mx + R - 1, my + R - 1,
                               start=310, extent=100, style='arc',
                               outline='#ffffff', width=1)
        self._moon_items.append(oid)
        # Stars — seeded random for consistency across sessions
        rng = random.Random(42)
        for layer in range(3):
            count = 8 + layer * 4
            for _ in range(count):
                angle = rng.uniform(0, 2 * math.pi)
                dist = rng.uniform(28 + layer * 45, 70 + layer * 45)
                sx = mx + math.cos(angle) * dist
                sy = my + math.sin(angle) * dist * 0.6
                sc = rng.choice(['#ffffff', '#aaccff', '#ddeeff', '#88bbee', '#cce0ff'])
                ss = rng.randint(1, 3 if layer > 0 else 4)
                oid = self.create_oval(sx - ss, sy - ss, sx + ss, sy + ss,
                                        fill=sc, outline='')
                self._moon_items.append(oid)
                self._star_items.append((oid, sx, sy, ss, sc))

    # ── Resize ────────────────────────────────────────────────────────────
    def _on_resize(self, event):
        nw = max(event.width, 100)
        nh = max(event.height, 40)
        if abs(nw - self.w) > 10 or abs(nh - self.h) > 5:
            self.w, self.h = nw, nh
            self._refresh_bg()
            for d in self._drops:
                d['x'] = random.uniform(0, nw)

    # ── Public interface ──────────────────────────────────────────────────
    def start(self):
        self._running = True
        self._stop_flag.clear()
        self._last_frame_time = time.monotonic()
        self._animate()

    def stop(self):
        self._running = False
        self._stop_flag.set()

    def set_lightning_callback(self, cb):
        self._lightning_cb = cb

    def set_threat_level(self, level):
        """Set 0-100 threat level. Higher = heavier rain + more lightning."""
        self._threat_level = max(0, min(100, level))
        # Auto-select storm phase based on threat level
        if level >= 80:
            self._target_phase_idx = 3  # tempest
        elif level >= 50:
            self._target_phase_idx = 2  # storm
        elif level >= 20:
            self._target_phase_idx = 1  # drizzle
        else:
            self._target_phase_idx = 0  # calm

    def set_storm_phase(self, phase_name):
        """Manually set storm phase: 'calm', 'drizzle', 'storm', 'tempest'."""
        for i, (name, *_) in enumerate(self._STORM_PHASES):
            if name == phase_name:
                self._target_phase_idx = i
                break

    # ── Main animation loop (24fps with delta-time) ──────────────────────
    def _animate(self):
        if not self._running:
            return
        # Skip when not visible — check is cheap
        try:
            if self.winfo_viewable() == 0 or self.winfo_height() < 20:
                self.after(250, self._animate)
                return
        except Exception:
            self.after(250, self._animate)
            return

        # Delta-time compensation for consistent speed
        now = time.monotonic()
        dt = min(now - self._last_frame_time, 0.1) if self._last_frame_time else 0.042
        self._last_frame_time = now
        dt_scale = dt / 0.042  # normalize to 24fps baseline

        self._frame += 1
        try:
            self._update_wind(dt_scale)
            self._update_storm_phase()
            self._update_drops(dt_scale)
            self._update_splashes(dt_scale)
            self._update_fog()

            # Puddle shimmer (every 3rd frame — lightweight)
            if self._frame % 3 == 0:
                self._update_puddles(dt_scale)
            # Mist particles (every 2nd frame)
            if self._frame % 2 == 0:
                self._update_mist(dt_scale)

            # Lightning based on current storm phase
            phase = self._STORM_PHASES[self._storm_phase_idx]
            lightning_chance = phase[3]
            if random.random() < lightning_chance:
                self._trigger_lightning()
            if self._lightning_phase > 0:
                self._update_lightning()
            if self._afterglow_phase > 0:
                self._afterglow_phase -= 1

            # Star twinkle (every 6th frame to save CPU)
            if self._frame % 6 == 0:
                self._twinkle_stars()
        except Exception:
            pass
        # 10fps — smooth enough for rain, much less CPU
        self.after(100, self._animate)

    # ── Wind gust dynamics ───────────────────────────────────────────────
    def _update_wind(self, dt_scale):
        self._wind_gust_timer -= 1
        if self._wind_gust_timer <= 0:
            phase = self._STORM_PHASES[self._storm_phase_idx]
            wmin, wmax = phase[2]
            self._wind_gust_target = random.uniform(wmin, wmax)
            self._wind_gust_timer = random.randint(30, 120)  # 1-5 seconds at 24fps
        # Smooth interpolation toward target
        self._wind_gust += (self._wind_gust_target - self._wind_gust) * 0.05 * dt_scale
        self._wind_base = self._wind_gust

    # ── Storm phase transitions ──────────────────────────────────────────
    def _update_storm_phase(self):
        if self._storm_phase_idx != self._target_phase_idx:
            self._storm_phase_timer += 1
            if self._storm_phase_timer > 48:  # 2 seconds at 24fps
                # Step toward target
                if self._target_phase_idx > self._storm_phase_idx:
                    self._storm_phase_idx += 1
                else:
                    self._storm_phase_idx -= 1
                self._storm_phase_timer = 0

    # ── Drop physics + rendering ─────────────────────────────────────────
    def _update_drops(self, dt_scale):
        items = self._drop_items
        colors = self._drop_colors
        widths = self._drop_widths
        h = self.h
        w = self.w
        wind = self._wind_base
        phase = self._STORM_PHASES[self._storm_phase_idx]
        spd_mult = phase[1]

        for i, d in enumerate(self._drops):
            # Apply wind + speed with delta-time
            d['y'] += d['spd'] * spd_mult * dt_scale
            d['x'] += (d['wnd'] + wind) * dt_scale
            if d['x'] < -10:
                d['x'] = w + 10
            elif d['x'] > w + 10:
                d['x'] = -10
            # Hit bottom — recycle + spawn splash
            if d['y'] > h + d['len']:
                self._alloc_splash(d['x'], h, d['col'])
                nd = self._new_drop()
                d.update(nd)
                if i < len(items):
                    self.coords(items[i], -20, -20, -20, -20)
                continue
            # Render — only coords() and conditional itemconfig()
            wind_tilt = (d['wnd'] + wind) * 2.5
            x2 = d['x'] - wind_tilt
            y2 = d['y'] - d['len']
            if i < len(items):
                self.coords(items[i], d['x'], d['y'], x2, y2)
                col = '#eef8ff' if d['fat'] else d['col']
                wid = 3 if d['fat'] else d['wid']
                if i < len(colors) and colors[i] != col:
                    self.itemconfig(items[i], fill=col)
                    colors[i] = col
                if i < len(widths) and widths[i] != wid:
                    self.itemconfig(items[i], width=wid)
                    widths[i] = wid

    # ── Splash system (pre-allocated pool — zero canvas allocs) ──────────
    def _alloc_splash(self, x, y, color):
        """Allocate from splash pool — no canvas create_* calls."""
        if random.random() > 0.5:
            return  # 50% splash rate
        rings = random.randint(1, 3)
        self._splashes.append({
            'x': x, 'y': y, 'col': color,
            'life': random.randint(5, 10),
            'max_life': 10,
            'r': random.uniform(3, 10),
            'rings': rings,
        })
        for _ in range(random.randint(1, 3)):
            ang = random.uniform(0.2, 2.9)
            speed = random.uniform(1.5, 4.0)
            self._streaks.append({
                'x': x, 'y': y,
                'vx': math.cos(ang) * speed,
                'vy': -abs(math.sin(ang)) * speed,
                'life': random.randint(3, 7),
                'col': color,
            })

    def _update_splashes(self, dt_scale):
        """Update splash/streak positions using pre-allocated canvas items."""
        alive_s = []
        oval_idx = 0
        for s in self._splashes:
            s['life'] -= 1
            if s['life'] <= 0:
                continue
            alive_s.append(s)
            age = (s['max_life'] - s['life']) / s['max_life']
            for ring in range(s['rings']):
                if oval_idx >= self._SPLASH_POOL:
                    break
                r = s['r'] * (0.3 + age * 1.6) * (1 + ring * 0.4)
                oid = self._splash_items[oval_idx]
                self.coords(oid, s['x'] - r, s['y'] - r * 0.3,
                             s['x'] + r, s['y'] + r * 0.3)
                self.itemconfig(oid, outline=s['col'])
                oval_idx += 1
        for j in range(oval_idx, self._SPLASH_POOL):
            self.coords(self._splash_items[j], -20, -20, -10, -10)
        self._splashes = alive_s
        # Update streaks
        alive_t = []
        line_idx = 0
        for t in self._streaks:
            t['life'] -= 1
            if t['life'] <= 0:
                continue
            alive_t.append(t)
            if line_idx >= self._STREAK_POOL:
                continue
            nx = t['x'] + t['vx'] * dt_scale
            ny = t['y'] + t['vy'] * dt_scale + 0.4
            lid = self._streak_items[line_idx]
            self.coords(lid, t['x'], t['y'], nx, ny)
            self.itemconfig(lid, fill=t['col'])
            t['x'], t['y'] = nx, ny
            t['vy'] += 0.35 * dt_scale
            line_idx += 1
        for j in range(line_idx, self._STREAK_POOL):
            self.coords(self._streak_items[j], -20, -20, -20, -20)
        self._streaks = alive_t

    # ── Fog / mist layer ─────────────────────────────────────────────────
    def _update_fog(self):
        """Animate ground-level fog bands that drift with wind."""
        phase = self._STORM_PHASES[self._storm_phase_idx]
        fog_intensity = phase[4]
        h = self.h
        w = self.w
        fog_base = h * (1.0 - fog_intensity * 0.3)
        band_h = (h - fog_base) / max(self._FOG_BANDS, 1)
        for i, fid in enumerate(self._fog_items):
            y0 = fog_base + i * band_h
            y1 = y0 + band_h + 2
            # Slight horizontal drift with wind
            drift = math.sin(self._frame * 0.01 + i * 1.5) * 10 * fog_intensity
            self.coords(fid, -20 + drift, y0, w + 20 + drift, y1)
            # Vary stipple density based on position (denser at bottom)
            stipple = 'gray25' if i < self._FOG_BANDS // 2 else 'gray12'
            fog_col = '#0a1428' if i % 2 == 0 else '#0e1830'
            self.itemconfig(fid, fill=fog_col, stipple=stipple)

    # ── Puddle reflections ─────────────────────────────────────────────
    def _update_puddles(self, dt_scale):
        """Shimmering ground-level puddles that reflect lightning."""
        h = self.h
        w = self.w
        phase = self._STORM_PHASES[self._storm_phase_idx]
        intensity = phase[1]  # storm intensity multiplier
        for i, ps in enumerate(self._puddle_state):
            if i >= self._PUDDLE_POOL:
                break
            ps['phase'] += 0.06 * dt_scale
            # Shimmer brightness oscillation
            shimmer = 0.5 + 0.5 * math.sin(ps['phase'])
            br = ps['bright'] * shimmer * intensity
            # Lightning reflection boost
            if self._lightning_phase > 5:
                br = min(1.0, br + 0.6)
            elif self._afterglow_phase > 10:
                br = min(1.0, br + 0.2)
            r = int(10 + 20 * br)
            g = int(24 + 30 * br)
            b = int(48 + 50 * br)
            col = f'#{r:02x}{g:02x}{b:02x}'
            pw = ps['w']
            ph = pw * 0.18  # flat ellipse
            y = h - 4 - (i % 3) * 3
            pid = self._puddle_items[i]
            self.coords(pid, ps['x'] - pw / 2, y - ph,
                        ps['x'] + pw / 2, y + ph)
            self.itemconfig(pid, fill=col, outline=col)

    # ── Ambient mist particles ─────────────────────────────────────────
    def _update_mist(self, dt_scale):
        """Slow-rising mist particles near the ground."""
        h = self.h
        w = self.w
        for i, ms in enumerate(self._mist_state):
            if i >= self._MIST_POOL:
                break
            ms['x'] += (ms['vx'] + self._wind_base * 0.3) * dt_scale
            ms['y'] += ms['vy'] * dt_scale
            ms['life'] -= 1
            if ms['life'] <= 0 or ms['y'] < h * 0.4:
                # Respawn at ground level
                ms['x'] = random.uniform(0, w)
                ms['y'] = random.uniform(h * 0.75, h)
                ms['r'] = random.uniform(8, 25)
                ms['vx'] = random.uniform(-0.3, 0.3)
                ms['vy'] = random.uniform(-0.4, -0.1)
                ms['life'] = random.randint(60, 180)
                ms['max_life'] = ms['life']
            # Fade based on remaining life
            age = 1.0 - ms['life'] / ms['max_life']
            alpha = max(0.1, 1.0 - age * 1.5)
            r = ms['r'] * (1.0 + age * 0.5)
            mid = self._mist_items[i]
            # Stipple changes for fade effect
            stipple = 'gray25' if alpha > 0.5 else 'gray12'
            br = int(14 + 10 * alpha)
            col = f'#0e{br:02x}28'
            self.coords(mid, ms['x'] - r, ms['y'] - r * 0.4,
                        ms['x'] + r, ms['y'] + r * 0.4)
            self.itemconfig(mid, fill=col, stipple=stipple)

    # ── Star twinkle ─────────────────────────────────────────────────────
    def _twinkle_stars(self):
        """Subtle brightness oscillation on stars."""
        f = self._frame
        for idx, (oid, sx, sy, ss, base_col) in enumerate(self._star_items):
            # Only twinkle ~20% of stars per cycle
            if (f + idx * 7) % 5 != 0:
                continue
            # Oscillate size by +/- 1px
            phase = math.sin(f * 0.08 + idx * 2.1)
            ns = max(1, ss + int(phase * 1.2))
            try:
                self.coords(oid, sx - ns, sy - ns, sx + ns, sy + ns)
            except Exception:
                pass

    # ── Lightning (pre-allocated bolt lines, enhanced multi-flash) ───────
    def _trigger_lightning(self):
        self._lightning_phase = 10  # longer flash
        self._afterglow_phase = 18  # lingering glow
        segs = []
        xs = random.uniform(self.w * 0.1, self.w * 0.9)
        self._gen_bolt(segs, xs, 0,
                        xs + random.uniform(-50, 50), self.h)
        self._bolt_segments = segs[:self._BOLT_POOL]
        if self._lightning_cb:
            try: self._lightning_cb()
            except Exception: pass

    def _gen_bolt(self, segs, x1, y1, x2, y2, depth=0):
        if depth > 5 or abs(y2 - y1) < 4:
            return
        jitter = 20 - depth * 3
        mx = (x1 + x2) / 2 + random.uniform(-jitter, jitter)
        my = (y1 + y2) / 2
        segs.append((x1, y1, mx, my))
        segs.append((mx, my, x2, y2))
        # Branch probability decreases with depth
        if random.random() < 0.45 - depth * 0.08 and depth < 3:
            bx = mx + random.uniform(-50, 50)
            by = my + random.uniform(8, 35)
            self._gen_bolt(segs, mx, my, bx, by, depth + 1)
        self._gen_bolt(segs, mx, my, x2, y2, depth + 1)

    def _update_lightning(self):
        self._lightning_phase -= 1
        # Multi-flash pattern: bright → dim → bright → fade
        if self._lightning_phase >= 8:
            self.coords(self._lightning_overlay, 0, 0, self.w, self.h)
            self.itemconfig(self._lightning_overlay, fill='#c8ddef',
                             stipple='gray25', state='normal')
        elif self._lightning_phase == 5:
            # Second flash (re-illuminate)
            self.itemconfig(self._lightning_overlay, fill='#8aabcc',
                             stipple='gray12', state='normal')
        elif self._lightning_phase <= 0:
            self.itemconfig(self._lightning_overlay, state='hidden')
            for j in range(self._BOLT_POOL):
                self.itemconfig(self._bolt_items[j], state='hidden')
                self.itemconfig(self._bolt_glow_items[j], state='hidden')
            return
        elif self._lightning_phase not in (8, 5):
            self.itemconfig(self._lightning_overlay, state='hidden')
        for j in range(self._BOLT_POOL):
            if j < len(self._bolt_segments):
                x1, y1, x2, y2 = self._bolt_segments[j]
                self.coords(self._bolt_glow_items[j], x1, y1, x2, y2)
                self.coords(self._bolt_items[j], x1, y1, x2, y2)
                # Bolts flicker — visible only during bright phases
                vis = 'normal' if self._lightning_phase > 2 else 'hidden'
                self.itemconfig(self._bolt_glow_items[j], state=vis)
                self.itemconfig(self._bolt_items[j], state=vis)
            else:
                self.itemconfig(self._bolt_items[j], state='hidden')
                self.itemconfig(self._bolt_glow_items[j], state='hidden')

    # ── API compat helpers ────────────────────────────────────────────────
    def _rain_start_y(self):
        return self.h

#  PROJECT AEGIS V2  -  LAYER 1: PHYSICAL ANTI-SURVEILLANCE & SENSOR GATING
# [ascii art removed]
class AegisPhysicalShield:
    """
    Layer 1  -  Physical Anti-Surveillance & Sensor Gating
    * IMSI catcher / Stingray detection via WiFi + cellular signal anomalies
    * Camera / microphone / GPS access gating  -  injects white noise on violation
    * Hardware data diode: all IOC ingestion is one-way only
    * Defangs all stored indicators so they are never executable
    """

    CAMERA_NOISE_FRAMES   = 30   # frames of static to inject
    MIC_NOISE_DURATION_MS = 5000
    GPS_SPOOF_RADIUS_M    = 5000

    # Known legitimate sensor consumers
    SENSOR_WHITELIST = {
        'camera':     {'obs64.exe','zoom.exe','teams.exe','slack.exe','webex.exe',
                       'skype.exe','chrome.exe','firefox.exe','msedge.exe'},
        'microphone': {'obs64.exe','zoom.exe','teams.exe','slack.exe','webex.exe',
                       'skype.exe','chrome.exe','firefox.exe','msedge.exe','discord.exe',
                       'audacity.exe','audiodg.exe',
                       # Windows system audio services hosted by svchost
                       'svchost.exe',      # hosts AudioEndpointBuilder, Audiosrv, SpeechRuntime
                       'speechruntime.exe','speechprivacyd.exe',
                       'cortana.exe','searchapp.exe','runtimebroker.exe',
                       'windows.media.speech.exe'},
    }

    def __init__(self, db: Database, alert_cb: Optional[Callable] = None):
        # Memory optimization
        self._last_gc = time.time()
        self.db        = db
        self.alert_cb  = alert_cb
        self._running   = False
        self._stop_flag = threading.Event()
        self._lock      = threading.Lock()
        self._thread: Optional[threading.Thread] = None
        self._violations: deque = deque(maxlen=1000)
        self._wifi_history: deque = deque(maxlen=500)
        self._imsi_alerts: int = 0
        self._sensor_blocks: int = 0
        self._last_wifi_scan: float = 0.0

    def start(self):
        if self._running:
            return
        self._running = True
        self._thread = threading.Thread(target=self._loop, daemon=True, name="AegisPhysical")
        self._thread.start()

    def stop(self):
        self._running = False

    # Per-message cooldown: suppress repeated identical alerts within this window.
    _ALERT_COOLDOWN = 120   # seconds before same message fires again

    def _alert(self, msg: str, level: str = 'HIGH'):
        # Deduplication: skip if this exact message was fired within cooldown window
        now = time.time()
        if not hasattr(self, '_alert_timestamps'):
            self._alert_timestamps: dict = {}
        # For WiFi alerts: normalize BSSID to OUI (XX:XX:XX:??:??:??) so devices
        # that rotate their last 3 MAC octets (Comcast/Xfinity, randomized BSSIDs)
        # hit the same cooldown bucket. Also collapse signal% fluctuations.
        key_msg = re.sub(
            r'BSSID:([0-9a-fA-F]{2}:[0-9a-fA-F]{2}:[0-9a-fA-F]{2}):[0-9a-fA-F:]+',
            r'BSSID:\1:??:??:??', msg)
        key_msg = re.sub(r'Signal:\d+%', 'Signal:??%', key_msg)
        key = key_msg[:120]
        if now - self._alert_timestamps.get(key, 0) < self._ALERT_COOLDOWN:
            return
        self._alert_timestamps[key] = now
        # Prune old entries to prevent unbounded growth
        if len(self._alert_timestamps) > 500:
            cutoff = now - self._ALERT_COOLDOWN * 2
            self._alert_timestamps = {k: v for k, v in self._alert_timestamps.items() if v > cutoff}

        ts = datetime.now().isoformat()
        self._violations.append({'ts': ts, 'msg': msg, 'level': level})
        try:
            self.db.execute(
                "INSERT OR IGNORE INTO aegis_events (ts, layer, event, severity) VALUES (?,?,?,?)",
                (ts, 'physical', msg[:500], level))
        except Exception:
            pass
        if self.alert_cb:
            try:
                self.alert_cb(f"[SHIELD] [AEGIS-L1] {msg}", level)
            except Exception:
                pass

    def _loop(self):
        """Main monitoring loop  -  runs every 15 seconds"""
        while self._running:
            try:
                self._check_sensor_access()
                if time.time() - self._last_wifi_scan > 60:
                    self._detect_imsi_catcher()
                    self._last_wifi_scan = time.time()
            except Exception as e:
                error_logger.log('AegisPhysical', 'Loop error', e)
            time.sleep(15)

    def _check_media_sessions_winapi(self, cam_suspects, mic_suspects):
        """
        Use CapabilityAccessManager registry to find active camera/mic consumers.
        Unified handler: alerts + noise injection for any app active in last 5 minutes
        that is not on the whitelist.  cam_suspects / mic_suspects are psutil-level hints
        (may be empty); the registry scan is authoritative.
        """
        try:
            cam_key = r"SOFTWARE\Microsoft\Windows\CurrentVersion\CapabilityAccessManager\ConsentStore\webcam"
            mic_key = r"SOFTWARE\Microsoft\Windows\CurrentVersion\CapabilityAccessManager\ConsentStore\microphone"
            for key_path, sensor_name in [(cam_key, 'camera'), (mic_key, 'microphone')]:
                try:
                    key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE, key_path)
                    i = 0
                    while True:
                        try:
                            subkey_name = winreg.EnumKey(key, i)
                            if subkey_name.lower() not in ('nonpackaged', 'allow', 'deny', 'value'):
                                proc_lower = subkey_name.lower().replace('#', '\\').split('\\')[-1]
                                if proc_lower and proc_lower not in self.SENSOR_WHITELIST.get(sensor_name, set()):
                                    try:
                                        subkey = winreg.OpenKey(key, subkey_name)
                                        last_used, _ = winreg.QueryValueEx(subkey, 'LastUsedTimeStop')
                                        winreg.CloseKey(subkey)
                                        ft  = last_used / 10000000 - 11644473600
                                        age = time.time() - ft
                                        if 0 < age < 300:   # active in last 5 minutes
                                            self._sensor_blocks += 1
                                            self._alert(
                                                f"UNAUTHORIZED {sensor_name.upper()} ACCESS: "
                                                f"'{subkey_name}' used {int(age)}s ago  -  "
                                                f"INJECTING SENSOR NOISE", 'CRITICAL')
                                            # Attempt to find and terminate the process
                                            if PSUTIL_AVAILABLE:
                                                for p in psutil.process_iter(['pid', 'name']):
                                                    try:
                                                        if p.name().lower() == proc_lower:
                                                            self._inject_sensor_noise(
                                                                sensor_name, p.pid, p.name())
                                                            break
                                                    except Exception:
                                                        pass
                                    except Exception:
                                        pass
                            i += 1
                        except OSError:
                            break
                    winreg.CloseKey(key)
                except Exception:
                    pass
        except Exception as e:
            error_logger.log('AegisSensor', 'WinAPI sensor check failed', e)

    def _detect_imsi_catcher(self):
        """
        Detect IMSI catchers (Stingrays) via WiFi network anomalies.
        Real detection uses: sudden SSIDs with max signal, no encryption, MAC changes.
        """
        try:
            result = subprocess.run(
                ['netsh', 'wlan', 'show', 'networks', 'mode=bssid'],
                capture_output=True, text=True, timeout=10,
                creationflags=subprocess.CREATE_NO_WINDOW)
            output = result.stdout
            networks = self._parse_wifi_networks(output)
            for net in networks:
                risk_reasons = []
                # Red flags for IMSI catchers:
                if net.get('signal', 0) >= 95:
                    risk_reasons.append("Signal strength suspiciously high (>=95%)")
                if net.get('encryption', '').lower() in ('none', 'open', ''):
                    risk_reasons.append("No encryption (open network)")
                if net.get('authentication', '').lower() == 'open':
                    risk_reasons.append("Open authentication")
                # Compare against previous scan  -  look for new nets at max signal
                known_ssids = {n['ssid'] for n in self._wifi_history if 'ssid' in n}
                if net.get('ssid') and net['ssid'] not in known_ssids and net.get('signal', 0) >= 90:
                    risk_reasons.append(f"NEW high-signal network appeared: '{net['ssid']}'")
                # Known-legitimate open SSIDs  -  ISP hotspots, TV audio cast,
                # airport / hotel networks. These are open by design and are NOT
                # IMSI catchers. Still alert if signal is suspiciously high (>=95%)
                # because real catchers often spoof these exact SSIDs.
                _LEGIT_OPEN_SSIDS = {
                    'xfinitywifi', 'xfinity', 'cablewifi', 'cableone',
                    'attwifi', 'att wifi', 'spectrum', 'optimumwifi',
                    'boingo', 'boingo hotspot', 'google starbucks',
                    'starbucks', 'airportnetwork', '_the cloud',
                    'btopenwifi', 'btfon', 'btwifi',
                    # Smart TV / cast networks (open by design)
                    'viziocastaudio', 'androidap', 'direct-',
                }
                ssid_lower = net.get('ssid', '').lower().strip()
                # A legit open SSID only triggers if signal is ALSO suspiciously high
                is_legit_open = any(ssid_lower.startswith(s) or ssid_lower == s
                                    for s in _LEGIT_OPEN_SSIDS)
                # Require 3+ risk factors for open networks, or 2+ if signal >=95%
                # (real IMSI catchers will always trigger the high-signal flag)
                threshold = 2 if net.get('signal', 0) >= 95 else 3
                if is_legit_open and net.get('signal', 0) < 95:
                    threshold = 4   # effectively suppressed for known-legit SSIDs at normal signal
                if len(risk_reasons) >= threshold:
                    self._imsi_alerts += 1
                    bssid = net.get('bssid', '?')
                    self._alert(
                        f"[NET] POSSIBLE IMSI CATCHER DETECTED: '{net.get('ssid','?')}' "
                        f"BSSID:{bssid} Signal:{net.get('signal',0)}% "
                        f"| {'; '.join(risk_reasons)}",
                        'CRITICAL')
                    # Auto-block: add to known IMSI BSSID list and block WiFi profile
                    if bssid and bssid != '?':
                        if not hasattr(self, '_blocked_bssids'):
                            self._blocked_bssids = set()
                        if bssid not in self._blocked_bssids:
                            self._blocked_bssids.add(bssid)
                            self._block_imsi_bssid(bssid, net.get('ssid', ''))
            # Store current scan for comparison
            for net in networks:
                self._wifi_history.append(net)
        except Exception as e:
            error_logger.log('AegisIMSI', 'WiFi scan failed', e)

    def _block_imsi_bssid(self, bssid: str, ssid: str):
        """Block a confirmed IMSI catcher BSSID by creating a deny WiFi profile."""
        try:
            # Log to database for persistence
            if hasattr(self, 'db') and self.db:
                try:
                    self.db.execute(
                        "INSERT OR IGNORE INTO threat_events "
                        "(type, detail, severity, timestamp) VALUES (?,?,?,datetime('now'))",
                        ('IMSI_CATCHER_BLOCKED',
                         f"BSSID:{bssid} SSID:'{ssid}'", 'CRITICAL'))
                    self.db.commit()
                except Exception:
                    pass
            # Add a Windows Firewall rule to block the IP range associated with this BSSID
            # (Can't directly block by BSSID in Windows — log and alert is primary action)
            self._alert(
                f"[NET] IMSI CATCHER BSSID BLOCKED: {bssid} ('{ssid}') "
                f"— avoid this network, added to block list. "
                f"If you connected to it, run Full Cleanup immediately.",
                'CRITICAL')
            error_logger.log('AegisIMSI', f'IMSI BSSID blocked: {bssid} ({ssid})')
        except Exception as e:
            error_logger.log('AegisIMSI', 'BSSID block failed', e)

    def _parse_wifi_networks(self, text: str) -> List[dict]:
        """Parse netsh wlan show networks output"""
        networks = []
        current: dict = {}
        for line in text.splitlines():
            line = line.strip()
            if line.startswith('SSID') and ':' in line and 'BSSID' not in line:
                if current:
                    networks.append(current)
                current = {'ssid': line.split(':', 1)[1].strip()}
            elif 'BSSID' in line and ':' in line and len(line.split(':')) > 2:
                current['bssid'] = line.split(':', 1)[1].strip()
            elif line.startswith('Signal') and ':' in line:
                try:
                    current['signal'] = int(line.split(':')[1].strip().replace('%', ''))
                except Exception:
                    pass
            elif line.startswith('Authentication') and ':' in line:
                current['authentication'] = line.split(':', 1)[1].strip()
            elif line.startswith('Encryption') and ':' in line:
                current['encryption'] = line.split(':', 1)[1].strip()
        if current:
            networks.append(current)
        return networks

    def defang(self, ioc: str) -> str:
        """Convert IOC to non-executable defanged format for safe storage"""
        ioc = ioc.replace('http://', 'hxxp://')
        ioc = ioc.replace('https://', 'hxxps://')
        ioc = ioc.replace('ftp://', 'fxp://')
        ioc = re.sub(r'(\d+)\.(\d+)\.(\d+)\.(\d+)', r'\1[.]\2[.]\3[.]\4', ioc)
        ioc = ioc.replace('@', '[at]')
        return ioc

    # -- SYN flood detection thresholds -------------------------------------
    SYN_FLOOD_THRESHOLD = 100  # SYN packets per second
    SYN_FLOOD_WINDOW = 5       # seconds

    def _detect_syn_flood(self) -> bool:
        """Check for SYN flood indicators via netstat."""
        try:
            if not PSUTIL_AVAILABLE:
                return False
            conns = psutil.net_connections(kind='tcp')
            syn_recv = sum(1 for c in conns if c.status == 'SYN_RECV')
            syn_sent = sum(1 for c in conns if c.status == 'SYN_SENT')
            if syn_recv > self.SYN_FLOOD_THRESHOLD:
                self._alert(f"[FLOOD] SYN flood detected: {syn_recv} SYN_RECV connections", 'CRITICAL')
                return True
            if syn_sent > 50:
                self._alert(f"[FLOOD] Outbound SYN storm: {syn_sent} SYN_SENT (possible DDoS participation)", 'HIGH')
                return True
            return False
        except Exception:
            return False

    def _inject_sensor_noise(self, sensor: str, offending_pid: int, offending_name: str):
        """
        Hardware-Level Sensor Masking: actively neutralise unauthorised capture.
        Priority: (1) TerminateProcess, (2) NtSuspendProcess, (3) registry consent revoke.
        Breaking the pipeline = equivalent to injecting white noise at hardware level.
        """
        killed = False
        try:
            h = ctypes.windll.kernel32.OpenProcess(0x0001, False, offending_pid)
            if h:
                ret = ctypes.windll.kernel32.TerminateProcess(h, 1)
                ctypes.windll.kernel32.CloseHandle(h)
                if ret:
                    killed = True
                    self._alert(
                        f"[BOOM] SENSOR NOISE INJECTED: '{offending_name}' (PID {offending_pid}) "
                        f"TERMINATED  -  {sensor.upper()} capture stream destroyed", 'CRITICAL')
        except Exception:
            pass
        if not killed:
            try:
                h = ctypes.windll.kernel32.OpenProcess(0x0800, False, offending_pid)
                if h:
                    ctypes.windll.ntdll.NtSuspendProcess(h)
                    ctypes.windll.kernel32.CloseHandle(h)
                    self._alert(
                        f"[PAUSE] SENSOR GATED: '{offending_name}' (PID {offending_pid}) "
                        f"SUSPENDED  -  {sensor.upper()} stream frozen (white-noise equivalent)", 'HIGH')
            except Exception:
                pass
        self._revoke_sensor_consent(sensor, offending_name)

    def _revoke_sensor_consent(self, sensor: str, app_name: str):
        """Revoke CapabilityAccessManager consent -> Deny so app cannot re-open sensor"""
        cap_map = {'camera': 'webcam', 'microphone': 'microphone', 'gps': 'location'}
        cap = cap_map.get(sensor, sensor)
        try:
            key_path = (f"SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\"
                        f"CapabilityAccessManager\\ConsentStore\\{cap}\\{app_name}")
            k = winreg.CreateKey(winreg.HKEY_LOCAL_MACHINE, key_path)
            winreg.SetValueEx(k, 'Value', 0, winreg.REG_SZ, 'Deny')
            winreg.CloseKey(k)
        except Exception:
            pass

    def _detect_gps_access(self):
        """
        GPS / Location sensor gating via Windows Location Framework.
        Detects any app that accessed location in the last 3 minutes,
        not on whitelist. Responds with coordinate spoofing (Null Island 0 degN 0 degE).
        """
        GPS_KEY = (r"SOFTWARE\Microsoft\Windows\CurrentVersion"
                   r"\CapabilityAccessManager\ConsentStore\location")
        GPS_WHITELIST = {
            'maps.exe', 'locationnotificationwindows.exe', 'runtimebroker.exe',
            'svchost.exe', 'explorer.exe', 'cortana.exe', 'find my device.exe',
            'microsoft.maps.winapp.exe', 'systemsettings.exe',
        }
        try:
            key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE, GPS_KEY)
            i = 0
            while True:
                try:
                    sub = winreg.EnumKey(key, i)
                    if sub.lower() not in ('nonpackaged', 'allow', 'deny', 'value'):
                        try:
                            sk = winreg.OpenKey(key, sub)
                            last_ts, _ = winreg.QueryValueEx(sk, 'LastUsedTimeStop')
                            ft  = last_ts / 10000000 - 11644473600
                            age = time.time() - ft
                            app = sub.lower().replace('#', '\\').split('\\')[-1]
                            if 0 < age < 180 and app not in GPS_WHITELIST:
                                self._sensor_blocks += 1
                                self._alert(
                                    f"[GPS] UNAUTHORIZED GPS ACCESS: '{sub}' accessed location "
                                    f"{int(age)}s ago  -  SPOOFING coordinates to Null Island (0 degN,0 degE)",
                                    'CRITICAL')
                                self._revoke_sensor_consent('gps', sub)
                                self._spoof_gps_registry()
                        except Exception:
                            pass
                    i += 1
                except OSError:
                    break
            winreg.CloseKey(key)
        except Exception:
            pass

    def _spoof_gps_registry(self):
        """Set Windows Location Override so all consumers receive spoofed 0,0 coordinates"""
        try:
            k = winreg.CreateKey(
                winreg.HKEY_LOCAL_MACHINE,
                r"SOFTWARE\Microsoft\Windows NT\CurrentVersion\Sensor\Overrides"
                r"\{BFA794E4-F964-4FDB-90F6-51056BFE4B44}")
            winreg.SetValueEx(k, 'SensorPermissionState', 0, winreg.REG_DWORD, 0)
            winreg.CloseKey(k)
        except Exception:
            pass

    def _check_sensor_access(self):
        """Detect unauthorized process access to camera/microphone/GPS and inject noise"""
        if not PSUTIL_AVAILABLE:
            return
        # GPS check every cycle
        self._detect_gps_access()
        try:
            for proc in psutil.process_iter(['pid', 'name']):
                try:
                    name = proc.name().lower()
                    for f in proc.open_files():
                        fl = f.path.lower()
                        if 'video' in fl and name not in self.SENSOR_WHITELIST['camera']:
                            self._sensor_blocks += 1
                            self._alert(
                                f"[CAM] UNAUTHORIZED CAMERA ACCESS: '{name}' (PID {proc.pid})",
                                'CRITICAL')
                            self._inject_sensor_noise('camera', proc.pid, name)
                        elif 'audio' in fl and 'capture' in fl and name not in self.SENSOR_WHITELIST['microphone']:
                            self._sensor_blocks += 1
                            self._alert(
                                f"[MIC] UNAUTHORIZED MIC ACCESS: '{name}' (PID {proc.pid})",
                                'CRITICAL')
                            self._inject_sensor_noise('microphone', proc.pid, name)
                except (psutil.AccessDenied, psutil.NoSuchProcess):
                    pass
            self._check_media_sessions_winapi([], [])
        except Exception as e:
            error_logger.log('AegisSensor', 'Sensor check failed', e)

    def get_stats(self) -> dict:
        return {
            'sensor_blocks': self._sensor_blocks,
            'imsi_alerts': self._imsi_alerts,
            'total_violations': len(self._violations),
            'recent': list(self._violations)[-20:],
        }


# [ascii art removed]
#  PROJECT AEGIS V2  -  LAYER 2: DEEP NETWORK & PORT DEFENSE (Anti-Port Stealing / RAT Lockdown)
# [ascii art removed]
class AegisTCPStackGuard:
    """
    Layer 2  -  TCP Stack & Port Hijacking Prevention + RAT Lockdown + DNS Shield
    * Monitors kernel TCP/IP for unauthorized port binding, forwarding, stealth knocking
    * Whitelists legitimate remote-access tools; flags behavioral hijacking (UEBA)
    * Encrypted local DNS resolver  -  drops C2 requests before handshake
    """

    # Legitimate remote-access tools  -  watch for behavioral anomalies
    LEGITIMATE_REMOTE_TOOLS = {
        'anydesk.exe', 'connectwise.exe', 'teamviewer.exe', 'logmein.exe',
        'rdpclip.exe', 'mstsc.exe', 'parsec.exe', 'rustdesk.exe',
        'splashtop.exe', 'gotoassist.exe', 'screenconnect.exe',
        'ultraviewer.exe', 'supremoservice.exe',
    }

    # Ports that should NEVER be bound by unknown processes
    PROTECTED_PORTS = {80, 443, 445, 139, 135, 3389, 21, 22, 23, 25, 110, 143, 993, 995}

    # Port-knock fingerprints (sequences seen in real RATs)
    PORT_KNOCK_SEQUENCES = [
        [7000, 8000, 9000],  # Knock-knock
        [1, 2, 3],           # Minimal knock
        [31337, 31338, 31339],
    ]

    def __init__(self, db: Database, intel, alert_cb: Optional[Callable] = None):
        # Memory optimization
        self._last_gc = time.time()
        self.db        = db
        self.intel     = intel
        self.alert_cb  = alert_cb
        self._running  = False
        self._lock     = threading.Lock()
        self._known_bindings: Dict[int, str] = {}  # port -> process
        # -- FIX C3: Bounded deques replace unbounded lists -------------------
        # PREVIOUS BUG 1 (O(n) pop): _knock_tracker and _knock_times used plain
        # lists, with list.pop(0) inside the hot inner loop  -  O(n) per call.
        # Under a port scan from a single IP touching 500 ports, each 10-second
        # cycle ran 500 O(n) pops = O(n^2) total.
        #
        # PREVIOUS BUG 2 (unbounded growth): The outer dicts had no eviction
        # policy. A scan from 10 000 unique IPs left 10 000 forever-growing
        # dict entries  -  a memory exhaustion vector exploitable by any scanner.
        #
        # FIX: deque(maxlen=100) per IP -> O(1) append + auto-evict from left.
        # Outer dict capped at _KNOCK_MAX_IPS via LRU-evict; entries older than
        # _KNOCK_WINDOW are never retained beyond their deque slot anyway.
        self._knock_tracker: Dict[str, deque] = {}   # ip -> deque of recent ports
        self._knock_times:   Dict[str, deque] = {}   # ip -> deque of timestamps
        self._KNOCK_MAX_IPS   = 2000   # max unique source IPs tracked
        self._KNOCK_WINDOW    = 5.0    # seconds for sliding window
        self._KNOCK_MAXLEN    = 100    # max entries per IP (100 ports in 5s is a hard scan)
        self._dns_blocked: int = 0
        self._port_violations: int = 0
        self._ueba_anomalies: int = 0
        self._rat_tool_anomalies: List[dict] = []
        self._thread: Optional[threading.Thread] = None
        self._stop_flag = threading.Event()   # FIX: was missing, caused AttributeError on _loop

    def start(self):
        if self._running:
            return
        self._stop_flag.clear()   # reset so wait() blocks properly
        self._running = True
        self._thread = threading.Thread(target=self._loop, daemon=True, name="AegisTCP")
        self._thread.start()

    def stop(self):
        self._running = False

    _ALERT_COOLDOWN = 120   # seconds before same message fires again

    def _alert(self, msg: str, level: str = 'HIGH'):
        # Deduplication: suppress repeated identical alerts within cooldown window.
        now = time.time()
        if not hasattr(self, '_alert_timestamps'):
            self._alert_timestamps: dict = {}
        key = msg[:120]
        if now - self._alert_timestamps.get(key, 0) < self._ALERT_COOLDOWN:
            return
        self._alert_timestamps[key] = now
        if len(self._alert_timestamps) > 500:
            cutoff = now - self._ALERT_COOLDOWN * 2
            self._alert_timestamps = {k: v for k, v in self._alert_timestamps.items() if v > cutoff}
        ts = datetime.now().isoformat()
        try:
            self.db.execute(
                "INSERT OR IGNORE INTO aegis_events (ts, layer, event, severity) VALUES (?,?,?,?)",
                (ts, 'network', msg[:500], level))
        except Exception:
            pass
        if self.alert_cb:
            try:
                self.alert_cb(f"[LOCK] [AEGIS-L2] {msg}", level)
            except Exception:
                pass

    def _loop(self):
        """TCP stack guard loop  -  only calls methods owned by this class."""
        # Safety: ensure _stop_flag exists even if __init__ order ever changes
        if not hasattr(self, '_stop_flag'):
            self._stop_flag = threading.Event()
        while self._running:
            try:
                self._check_port_bindings()
                self._check_port_forwarding()
            except Exception as e:
                error_logger.log('AegisTCP', 'Loop error', e)
            if self._stop_flag.wait(10):
                break

    def _check_port_bindings(self):
        """Detect unauthorized port binding, port stealing, and stealth port-knocking"""
        if not PSUTIL_AVAILABLE:
            return
        try:
            current_bindings: Dict[int, str] = {}
            proc_map: Dict[int, str] = {}
            pid_map:  Dict[int, int] = {}   # port -> pid for kill/block
            for proc in psutil.process_iter(['pid', 'name']):
                try:
                    proc_map[proc.pid] = proc.name().lower()
                except Exception:
                    pass
            for conn in psutil.net_connections(kind='inet'):
                if conn.status in ('LISTEN', 'BOUND') and conn.laddr:
                    port = conn.laddr.port
                    proc_name = proc_map.get(conn.pid, 'unknown')
                    current_bindings[port] = proc_name
                    pid_map[port] = conn.pid or 0
                    # Protected port bound by unauthorised process
                    if port in self.PROTECTED_PORTS and proc_name.lower() not in {
                            p.lower() for p in FalsePositiveDB.SAFE_PROCESSES}:
                        if proc_name not in ('system', 'nt kernel & system', 'unknown'):
                            self._port_violations += 1
                            self._alert(
                                f"[!] PROTECTED PORT {port} BOUND by '{proc_name}' "
                                f"(PID {conn.pid})  -  BLOCKING IP + flagging process", 'CRITICAL')
                            # Actively block via firewall
                            self._block_port_binder(port, conn.pid, proc_name)
                # Port-knock detection: track rapid sequential port accesses from same remote IP
                if conn.raddr and conn.status in ('SYN_SENT', 'SYN_RECV', 'ESTABLISHED'):
                    rip = conn.raddr.ip
                    # Skip loopback — that's Downpour's own internal scanning
                    if rip in ('127.0.0.1', '::1', '0.0.0.0'):
                        continue
                    rport = conn.raddr.port
                    now = time.time()
                    with self._lock:
                        # -- Initialise bounded deques for new IPs -----------------
                        # If tracker is at capacity, evict the oldest IP entry to
                        # prevent unbounded dict growth (memory exhaustion defence).
                        if rip not in self._knock_tracker:
                            if len(self._knock_tracker) >= self._KNOCK_MAX_IPS:
                                # Evict one entry (oldest insertion order in CPython 3.7+)
                                oldest_ip = next(iter(self._knock_tracker))
                                del self._knock_tracker[oldest_ip]
                                self._knock_times.pop(oldest_ip, None)
                            # deque(maxlen) auto-evicts oldest port from left  -  O(1)
                            self._knock_tracker[rip] = deque(maxlen=self._KNOCK_MAXLEN)
                            self._knock_times[rip]   = deque(maxlen=self._KNOCK_MAXLEN)

                        self._knock_tracker[rip].append(rport)
                        self._knock_times[rip].append(now)

                        # Prune timestamps outside the sliding window.
                        # deque.popleft() is O(1)  -  critical correctness here.
                        cutoff = now - self._KNOCK_WINDOW
                        while self._knock_times[rip] and self._knock_times[rip][0] < cutoff:
                            self._knock_times[rip].popleft()    # O(1)
                            if self._knock_tracker[rip]:
                                self._knock_tracker[rip].popleft()  # O(1)

                        recent_ports = list(self._knock_tracker[rip])
                    # Check against known knock sequences
                    for seq in self.PORT_KNOCK_SEQUENCES:
                        if len(recent_ports) >= len(seq):
                            window = recent_ports[-len(seq):]
                            if window == seq:
                                self._port_violations += 1
                                self._alert(
                                    f"[KNOCK] PORT-KNOCK SEQUENCE DETECTED from {rip}: "
                                    f"{seq}  -  stealth RAT knock  -  BLOCKING IP", 'CRITICAL')
                                self.block_ip_immediate(rip)
                    # General rapid scan: >8 unique ports in 5 seconds = scanner/RAT
                    with self._lock:
                        unique_ports = len(set(self._knock_tracker[rip]))
                    if unique_ports >= 8:
                        self._port_violations += 1
                        self._alert(
                            f"[SEARCH] RAPID PORT PROBE from {rip}: "
                            f"{unique_ports} ports in 5s  -  possible RAT/scanner  -  BLOCKING",
                            'CRITICAL')
                        self.block_ip_immediate(rip)
                        with self._lock:
                            self._knock_tracker[rip].clear()
                            self._knock_times[rip].clear()
            # Port stealing: same port bound by different process than before
            with self._lock:
                for port, old_proc in self._known_bindings.items():
                    new_proc = current_bindings.get(port)
                    if new_proc and new_proc != old_proc and old_proc != 'unknown':
                        self._port_violations += 1
                        self._alert(
                            f"[ALERT] PORT STEAL DETECTED: Port {port} switched "
                            f"'{old_proc}' -> '{new_proc}' (PID {pid_map.get(port,0)}) "
                            f" -  BLOCKING new binder", 'CRITICAL')
                        self._block_port_binder(port, pid_map.get(port, 0), new_proc)
                self._known_bindings = current_bindings
        except Exception as e:
            error_logger.log('AegisTCP', 'Port binding check failed', e)

    def block_ip_immediate(self, ip: str):
        """Immediately block all traffic from a remote IP via Windows Firewall.

        FIX: This method was called by _check_port_bindings (port-knock and rapid
        scan detection) but was never defined, causing repeated AttributeError logged
        as 'AegisTCP Port binding check failed' on every 10-second loop cycle.
        The detection logic ran correctly but the block action silently failed.
        """
        if not ip or ip.startswith(('127.', '::1')):
            return
        # Sanitise IP to prevent any injection via netsh name/remoteip fields
        import re as _re
        if not _re.match(r'^[\d.:a-fA-F]+$', ip):
            return
        rule_name = f'AEGIS_BLOCK_{ip.replace(".", "_").replace(":", "_")}'
        try:
            # Remove stale rule first (idempotent)
            subprocess.run(
                ['netsh', 'advfirewall', 'firewall', 'delete', 'rule', f'name={rule_name}'],
                capture_output=True, creationflags=subprocess.CREATE_NO_WINDOW, timeout=8,
                check=False)
            # Add inbound + outbound block
            for direction in ('in', 'out'):
                subprocess.run(
                    ['netsh', 'advfirewall', 'firewall', 'add', 'rule',
                     f'name={rule_name}', f'dir={direction}', 'action=block',
                     'enable=yes', f'remoteip={ip}'],
                    capture_output=True, creationflags=subprocess.CREATE_NO_WINDOW,
                    timeout=8, check=False)
            error_logger.log('AegisTCP', f'Blocked IP via firewall: {ip}', None)
        except Exception as e:
            error_logger.log('AegisTCP', f'block_ip_immediate failed for {ip}', e)

    def _block_port_binder(self, port: int, pid: int, proc_name: str):
        """Actively block a process that is illegitimately binding a protected port.

        FIX H2: proc_name is sanitised before embedding in the netsh rule name.
        PREVIOUS BUG: A process with a name like 'evil & cmd.exe' or one containing
        spaces, slashes, or quotes could produce a malformed netsh rule name  -  either
        causing the rule to be silently rejected or (in edge cases) being interpreted
        as a secondary netsh command segment when the shell later lists rules.
        Although subprocess list mode prevents shell injection, netsh itself parses
        the name= argument and may behave unexpectedly with special chars.
        FIX: Strip to [A-Za-z0-9_.-] before use in any string that touches netsh.
        """
        # Sanitise: keep only safe characters  -  max 64 chars to stay within netsh limits
        safe_name = re.sub(r'[^A-Za-z0-9_.\-]', '_', proc_name)[:64]

        # FIX-X3: Resolve the absolute executable path for the PID.
        # PREVIOUS BUG: `program={proc_name}` passed a bare name like "svchost.exe".
        # Windows netsh advfirewall requires an ABSOLUTE path for the program= filter;
        # a bare name is silently accepted by netsh but the rule never matches any
        # traffic, making the block completely ineffective.
        # FIX: Use psutil.Process(pid).exe() to get the full disk path.
        # If resolution fails (e.g. access denied, pid already gone) fall back to
        # an IP-only block so we still get some mitigation.
        proc_path = None
        if pid and PSUTIL_AVAILABLE:
            try:
                proc_path = psutil.Process(pid).exe()
            except Exception:
                proc_path = None

        # 1. Block outbound/inbound via firewall  -  use absolute path when available
        for direction in ('in', 'out'):
            try:
                rule_args = [
                    'netsh', 'advfirewall', 'firewall', 'add', 'rule',
                    f'name=AEGIS_PORTBLOCK_{safe_name}_{port}_{direction}',
                    f'dir={direction}', 'action=block', 'enable=yes',
                    f'localport={port}', 'protocol=tcp',
                ]
                if proc_path:
                    rule_args.append(f'program={proc_path}')   # FIX-X3: absolute path
                subprocess.run(
                    rule_args,
                    capture_output=True, creationflags=subprocess.CREATE_NO_WINDOW, check=False,
                             timeout=15)
            except Exception:
                pass
        # 2. Attempt to kill the process if it's truly unauthorised
        if pid and proc_name.lower() not in {p.lower() for p in FalsePositiveDB.SAFE_PROCESSES}:
            try:
                h = ctypes.windll.kernel32.OpenProcess(0x0001, False, pid)
                if h:
                    ctypes.windll.kernel32.TerminateProcess(h, 1)
                    ctypes.windll.kernel32.CloseHandle(h)
            except Exception:
                pass

    def _check_port_forwarding(self):
        """Detect netsh portproxy / SSH tunnel / unauthorized forwarding.
        
        FIX: Track rule counts  -  only alert when count CHANGES (new rules added),
        not on every loop iteration when existing rules are present.
        Also: portproxy rules can be legitimate (WSL2, Docker, VPN, dev tools).
        We alert once on discovery then only on count increases.
        """
        try:
            result = subprocess.run(
                ['netsh', 'interface', 'portproxy', 'show', 'all'],
                capture_output=True, text=True, timeout=8,
                creationflags=subprocess.CREATE_NO_WINDOW)
            if result.stdout.strip() and 'No port proxy' not in result.stdout:
                lines = [l for l in result.stdout.splitlines()
                         if l.strip() and 'Listen' not in l and '---' not in l and '---------' not in l]
                rule_count = len([l for l in lines if l.strip()])
                if rule_count > 0:
                    prev_count = getattr(self, '_portproxy_last_count', -1)
                    if rule_count != prev_count:
                        # Only alert when count changes (new rules were added/removed)
                        self._port_violations += 1
                        self._portproxy_last_count = rule_count
                        if prev_count == -1:
                            # First discovery
                            self._alert(
                                f"[FWD] PORT FORWARDING: {rule_count} netsh portproxy rule(s) found "
                                f" -  review with: netsh interface portproxy show all", 'HIGH')
                        elif rule_count > prev_count:
                            # Rules were ADDED  -  more concerning
                            self._alert(
                                f"[FWD] PORT FORWARDING INCREASED: {prev_count}->{rule_count} rule(s) "
                                f" -  possible MITM tunnel added!", 'CRITICAL')
                        else:
                            # Rules decreased  -  informational
                            self._alert(
                                f"[i] Port proxy rules decreased: {prev_count}->{rule_count}", 'LOW')
                    # else: same count as last check, no alert
                else:
                    self._portproxy_last_count = 0
        except Exception:
            pass
        # Check registry for persistent portproxy  -  only alert once per session
        try:
            key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                 r"SYSTEM\CurrentControlSet\Services\PortProxy")
            winreg.CloseKey(key)
            if not getattr(self, '_portproxy_registry_alerted', False):
                self._portproxy_registry_alerted = True
                self._alert("[!] Persistent port proxy found in registry  -  potential MITM backdoor", 'HIGH')
        except Exception:
            self._portproxy_registry_alerted = False   # reset if key disappears


