    def _cve_update_table(self, _):
        """Populate CVE table from cached KEV data."""
        try:
            with _kev._lock:
                vulns = list(_kev._data)
            # Thread-safe UI updates
            self._thread_safe_ui_update(
                self._kev_count_var.set,
                f'CISA KEV: {len(vulns)} entries  |  Updated: {_kev.last_updated}')
            self._thread_safe_ui_update(self._cve_populate, vulns)
        except Exception as e:
            error_logger.log('CveTab', 'update_table', e)

    def _cve_populate(self, vulns):
        try:
            tree = self._cve_tree
            tree.delete(*tree.get_children())
            for v in vulns:
                name = v.get('vulnerabilityName','')[:60]
                vendor = v.get('vendorProject','')[:18]
                product = v.get('product','')[:20]
                date = v.get('dateAdded','')
                cid  = v.get('cveID','')
                # Simple severity heuristic from name
                nl = name.lower()
                if any(w in nl for w in ['remote code exec','rce','command inject',
                                          'unauthenticated','critical','deserialization']):
                    sev, tag = 'CRITICAL', 'critical'
                elif any(w in nl for w in ['privilege','elevation','bypass','injection']):
                    sev, tag = 'HIGH', 'high'
                else:
                    sev, tag = 'MEDIUM', 'normal'
                tree.insert('', 'end',
                            values=(cid, date, vendor, product, sev, name),
                            tags=(tag,))
            # Thread-safe UI update
            self._thread_safe_ui_update(
                self._cve_status_var.set,
                f'Showing {len(vulns)} entries.')
        except Exception as e:
            error_logger.log('CveTab', 'populate', e)

    def _cve_search(self):
        term = self._cve_search_var.get().strip()
        if not term: return
        results = _kev.search(term)
        self._cve_populate(results)
        self._thread_safe_ui_update(
            self._cve_status_var.set,
            f'{len(results)} results for "{term}"')

    def _cve_show_windows(self):
        results = _kev.windows_cves(since_days=3650)
        self._cve_populate(results)
        self._thread_safe_ui_update(
            self._cve_status_var.set,
            f'{len(results)} Windows/Microsoft CVEs')

    def _cve_show_recent(self):
        results = _kev.windows_cves(since_days=30)
        self._cve_populate(results)
        self._thread_safe_ui_update(
            self._cve_status_var.set,
            f'{len(results)} Windows CVEs added in last 30 days')

    def _cve_sort(self, col):
        data = [(self._cve_tree.set(c, col), c)
                for c in self._cve_tree.get_children('')]
        data.sort(reverse=getattr(self, '_cve_sort_rev', False))
        for i, (_, c) in enumerate(data):
            self._cve_tree.move(c, '', i)
        self._cve_sort_rev = not getattr(self, '_cve_sort_rev', False)

    def _cve_on_select(self, _):
        sel = self._cve_tree.selection()
        if not sel: return
        vals = self._cve_tree.item(sel[0])['values']
        if not vals: return
        cid   = vals[0]
        entry = _kev.get(cid)
        if not entry: entry = {'cveID': cid}
        txt = (
            f"CVE ID:      {entry.get('cveID','')}\n"
            f"Date Added:  {entry.get('dateAdded','')}\n"
            f"Vendor:      {entry.get('vendorProject','')}\n"
            f"Product:     {entry.get('product','')}\n"
            f"Due Date:    {entry.get('dueDate','')}\n"
            f"Required Action: {entry.get('requiredAction','')}\n\n"
            f"VULNERABILITY:\n{entry.get('vulnerabilityName','')}\n\n"
            f"DESCRIPTION:\n{entry.get('shortDescription','')}\n\n"
            f"NOTES:\n{entry.get('notes','N/A')}\n\n"
        )
        # Show matching mitigations
        mits = []
        name = (entry.get('vulnerabilityName','') + ' ' +
                entry.get('shortDescription','')).lower()
        for kw, m in _cveh.MITIGATIONS.items():
            if kw in name:
                mits.append(f'  [{kw.upper()}] {m["desc"]}')
        if mits:
            txt += 'MITIGATIONS AVAILABLE:\n' + '\n'.join(mits)
        else:
            txt += 'No specific mitigation mapped yet for this CVE family.'
        self._cve_detail_text.config(state='normal')
        self._cve_detail_text.delete('1.0', 'end')
        self._cve_detail_text.insert('1.0', txt)
        self._cve_detail_text.config(state='disabled')

    def _cve_apply_selected(self):
        sel = self._cve_tree.selection()
        if not sel:
            self._cve_status_var.set('Select a CVE first.')
            return
        vals = self._cve_tree.item(sel[0])['values']
        cid  = vals[0]
        entry = _kev.get(cid)
        if not entry:
            self._cve_status_var.set(f'No KEV data for {cid}')
            return
        def _apply():
            applied = _cveh.apply_for_cve(entry, self._add_alert)
            self._ts_var_set(self._cve_status_var, 
                f'Applied {len(applied)} mitigations for {cid}: '
                + ', '.join(applied[:3]))
        self._executor.submit(_apply)

    def get_stats(self) -> dict:
        return {
            'dns_blocked': self._dns_blocked,
            'port_violations': self._port_violations,
            'ueba_anomalies': self._ueba_anomalies,
            'rat_tool_anomalies': self._rat_tool_anomalies[-20:],
        }


