#                          VULNERABILITY SCANNER
# [ascii art removed]
class VulnerabilityScanner:
    # CVSS severity thresholds
    CVSS_CRITICAL = 9.0
    CVSS_HIGH = 7.0
    CVSS_MEDIUM = 4.0
    # Auto-check intervals
    CHECK_INTERVAL = 3600  # 1 hour
    """
    Zero-day vulnerability scanner and exploit detection system.

    Checks installed software versions against a locally-cached CVE list,
    monitors for CISA Known Exploited Vulnerabilities (KEV), scans running
    processes for exploit-pattern indicators, and reports missing Windows
    security patches.

    Design philosophy: every operation is offline-capable; network fetches
    refresh the CVE/KEV cache in the background and are never mandatory for
    a scan to complete.
    """

    # NVD / CISA feed URLs (refreshed in background  -  gracefully handled offline)
    CVE_FEED_URL  = "https://raw.githubusercontent.com/cisagov/kev-data/develop/known_exploited_vulnerabilities.json"
    NVD_RECENT    = "https://services.nvd.nist.gov/rest/json/cves/2.0/?resultsPerPage=100&pubStartDate={start}&pubEndDate={end}"

    # Heuristic exploit behavioural patterns observed in running processes / their CLI
    EXPLOIT_PATTERNS = [
        (re.compile(r'powershell.*-[Ee]nc', re.I),         "Encoded PowerShell",    80),
        (re.compile(r'mshta.*vbs',          re.I),          "MSHTA VBScript",        85),
        (re.compile(r'certutil.*(decode|urlcache)', re.I),  "Certutil lolbin",       75),
        (re.compile(r'bitsadmin.*\/transfer', re.I),        "Bitsadmin download",    70),
        (re.compile(r'regsvr32.*\/s.*\/u',  re.I),          "Regsvr32 bypass",       80),
        (re.compile(r'wmic.*process.*call.*create', re.I),  "WMIC spawn",            75),
        (re.compile(r'rundll32.*javascript:', re.I),        "Rundll32 JS",           85),
        (re.compile(r'curl.*-o.*\.(exe|ps1|bat|vbs)', re.I),"Drop via curl",         70),
        (re.compile(r'\\\\temp\\\\[a-f0-9]{6,}\.exe', re.I),"Temp hex EXE",         80),
        (re.compile(r'wscript.*\.vbs', re.I),                     "WScript VBS exec",      70),
        (re.compile(r'cscript.*\.js', re.I),                      "CScript JS exec",       70),
        (re.compile(r'msiexec.*/q.*/i.*http', re.I),              "MSI remote install",    80),
        (re.compile(r'schtasks.*/create.*/sc.*/tr', re.I),        "Schtask persistence",   75),
        (re.compile(r'reg.*add.*\\run\b', re.I),               "Registry run key",      75),
        (re.compile(r'net\s+user.*\/add', re.I),                "User account creation", 80),
        (re.compile(r'netsh.*firewall.*delete', re.I),            "Firewall rule delete",  85),
        (re.compile(r'icacls.*\/grant.*everyone', re.I),         "ACL grant everyone",    70),
        (re.compile(r'vssadmin.*delete.*shadows', re.I),          "Shadow copy delete",    90),
    ]

    def __init__(self, db: Database):
        # Memory optimization
        self._last_gc = time.time()
        self.db  = db
        self._lock   = threading.Lock()
        self._kev    : List[dict] = []       # CISA Known Exploited Vulnerabilities
        self._results: List[dict] = []       # latest scan results
        self._status  = "Idle"
        self._progress_cb: Optional[Callable] = None
        self._ensure_schema()

    # -- DB schema --------------------------------------------------------------
    def _ensure_schema(self):
        try:
            self.db.execute('''
                CREATE TABLE IF NOT EXISTS vuln_results
                (id INTEGER PRIMARY KEY, cve_id TEXT, severity TEXT,
                 description TEXT, affected TEXT, detected_at TEXT,
                 exploited_in_wild INTEGER DEFAULT 0, remediation TEXT)
            ''')
        except Exception:
            pass

    # -- Background KEV refresh -------------------------------------------------
    def refresh_kev(self, callback: Optional[Callable] = None):
        """Download CISA KEV list in background; call callback(count) when done."""
        self._progress_cb = callback

        def _fetch():
            try:
                if not REQUESTS_AVAILABLE:
                    return
                resp = requests.get(self.CVE_FEED_URL, timeout=20,
                                    headers={'User-Agent': 'Downpour/1.0'})
                data = resp.json()
                vulns = data.get('vulnerabilities', [])
                with self._lock:
                    self._kev = vulns
                if callback:
                    try: callback(len(vulns))
                    except Exception: pass
            except Exception as e:
                error_logger.log('VulnScanner', 'KEV refresh failed', e)

        threading.Thread(target=_fetch, daemon=True).start()

    # -- Main scan --------------------------------------------------------------
    def scan(self, progress_cb: Optional[Callable] = None) -> List[dict]:
        """
        Run a full vulnerability scan. Returns list of finding dicts.
        Stages:
          1. Process exploit-pattern sweep
          2. Missing Windows Update check (WMI when available)
          3. KEV cross-reference against known software names
        """
        self._status = "Scanning..."
        findings = []

        # -- Stage 1: process exploit patterns --------------------------------
        if progress_cb: progress_cb("Stage 1/3: Process exploit-pattern sweep...")
        if PSUTIL_AVAILABLE:
            for proc in psutil.process_iter(['pid', 'name', 'cmdline', 'exe']):
                try:
                    cmdline = ' '.join(proc.info.get('cmdline') or [])
                    for pattern, label, score in self.EXPLOIT_PATTERNS:
                        if cmdline and pattern.search(cmdline):
                            findings.append({
                                'type':        'exploit_pattern',
                                'severity':    'HIGH' if score >= 80 else 'MEDIUM',
                                'score':       score,
                                'process':     proc.info['name'],
                                'pid':         proc.info['pid'],
                                'description': f"Exploit indicator: {label}",
                                'cmdline':     cmdline[:200],
                                'remediation': "Investigate and terminate process if unauthorised.",
                                'cve_id':      '',
                            })
                            break
                except (psutil.NoSuchProcess, psutil.AccessDenied):
                    pass

        # -- Stage 2: Windows Update / missing patches (WMI) ------------------
        if progress_cb: progress_cb("Stage 2/3: Checking Windows Update status...")
        if WMI_AVAILABLE:
            try:
                # FIX-v28: CoInitialize required from background thread
                try:
                    import pythoncom; pythoncom.CoInitialize()
                except Exception: pass
                c = wmi.WMI()
                # QFEs = quick-fix engineering (hotfixes)
                installed = {h.HotFixID for h in c.Win32_QuickFixEngineering()}
                # Check a handful of well-known critical patches
                CRITICAL_KBS = {
                    'KB5034441': 'CVE-2024-21338  -  Windows Kernel EoP (Jan 2024)',
                    'KB5035845': 'CVE-2024-26234  -  Proxy Driver Spoofing (Mar 2024)',
                    'KB5039211': 'CVE-2024-30080  -  MSMQ RCE (Jun 2024)',
                    'KB5041587': 'CVE-2024-38063  -  IPv6 Stack RCE (Aug 2024)',
                    'KB5044273': 'CVE-2024-43573  -  MSHTML Platform (Oct 2024)',
                    'KB5046617': 'CVE-2024-49138  -  CLFS Driver EoP (Dec 2024)',
                    'KB5049981': 'CVE-2025-21298  -  OLE RCE (Jan 2025)',
                    'KB5052000': 'CVE-2025-21391  -  Storage EoP (Feb 2025)',
                    'KB5053598': 'CVE-2025-24985  -  FAT FS RCE (Mar 2025)',
                    'KB5055518': 'CVE-2025-29824  -  CLFS UAF EoP (Apr 2025)',
                    'KB5058379': 'CVE-2025-30397  -  Scripting Engine RCE (May 2025)',
                }
                for kb, desc in CRITICAL_KBS.items():
                    if kb not in installed:
                        findings.append({
                            'type':        'missing_patch',
                            'severity':    'CRITICAL',
                            'score':       95,
                            'process':     'Windows Update',
                            'pid':         0,
                            'description': f"Missing security patch {kb}: {desc}",
                            'cmdline':     '',
                            'remediation': f"Run Windows Update to install {kb}.",
                            'cve_id':      desc.split(' - ')[0].strip() if ' - ' in desc else '',
                        })
            except Exception as e:
                error_logger.log('VulnScanner', 'WMI patch check failed', e)

        # -- Stage 3: KEV software cross-reference ----------------------------
        if progress_cb: progress_cb("Stage 3/3: KEV cross-reference...")
        with self._lock:
            kev_snapshot = list(self._kev)

        if kev_snapshot and PSUTIL_AVAILABLE:
            # Build a set of running executable names (lowercase, no ext)
            try:
                running = {os.path.splitext(p.info['name'])[0].lower()
                           for p in psutil.process_iter(['name'])
                           if p.info.get('name')}
            except Exception:
                running = set()

            # Also collect installed software names from registry (best-effort)
            installed_sw: set = set()
            for hive, flag in [(winreg.HKEY_LOCAL_MACHINE, 0),
                               (winreg.HKEY_LOCAL_MACHINE, winreg.KEY_WOW64_32KEY)]:
                for path in [
                    r'SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall',
                    r'SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall',
                ]:
                    try:
                        key = winreg.OpenKey(hive, path, 0, winreg.KEY_READ | flag)
                        for i in range(winreg.QueryInfoKey(key)[0]):
                            try:
                                sub = winreg.OpenKey(key, winreg.EnumKey(key, i))
                                try:
                                    name, _ = winreg.QueryValueEx(sub, 'DisplayName')
                                    if name:
                                        installed_sw.add(name.lower())
                                except FileNotFoundError:
                                    pass
                                winreg.CloseKey(sub)
                            except Exception:
                                pass
                        winreg.CloseKey(key)
                    except Exception:
                        pass

            for entry in kev_snapshot[:500]:            # cap to 500 to stay fast
                vendor  = (entry.get('vendorProject') or '').lower()
                product = (entry.get('product')       or '').lower()
                cve_id  = entry.get('cveID', '')
                desc    = entry.get('vulnerabilityName', '')
                due_date= entry.get('dueDate', '')

                # Check if any running process or installed SW matches
                matched_via = None
                for sw_name in running | installed_sw:
                    if (vendor and vendor in sw_name) or (product and product in sw_name):
                        matched_via = sw_name
                        break

                if matched_via:
                    findings.append({
                        'type':        'kev_match',
                        'severity':    'CRITICAL',
                        'score':       90,
                        'process':     matched_via,
                        'pid':         0,
                        'description': f"{cve_id}: {desc}",
                        'cmdline':     '',
                        'remediation': f"CISA KEV due {due_date}. Patch or isolate immediately.",
                        'cve_id':      cve_id,
                    })

        # Sort by score desc, deduplicate by cve_id
        seen_cves: set = set()
        deduped = []
        for f in sorted(findings, key=lambda x: x['score'], reverse=True):
            key = f['cve_id'] or id(f)
            if key not in seen_cves:
                seen_cves.add(key)
                deduped.append(f)

        with self._lock:
            self._results = deduped

        # Persist critical findings
        try:
            self.db.executemany(
                '''INSERT OR IGNORE INTO vuln_results
                   (cve_id, severity, description, affected, detected_at, exploited_in_wild, remediation)
                   VALUES (?,?,?,?,?,?,?)''',
                [(f['cve_id'], f['severity'], f['description'],
                  f['process'], datetime.now().isoformat(),
                  1 if f['type'] == 'kev_match' else 0,
                  f['remediation'])
                 for f in deduped if f['cve_id']])
        except Exception:
            pass

        self._status = f"Scan complete  -  {len(deduped)} findings"
        if progress_cb: progress_cb(self._status)
        return deduped

    def get_results(self) -> List[dict]:
        with self._lock:
            return list(self._results)

    def get_status(self) -> str:
        return self._status


