# [ascii art removed]
class FileSandbox:
    """
    Safe, isolated environment for analysing suspicious files.

    Workflow:
      1. Copy target file to a temp sandbox directory
      2. Take a pre-execution filesystem + registry snapshot
      3. Launch the file in a monitored subprocess (optional  -  user confirms)
      4. Monitor spawned processes, new files, network connections for 30 s
      5. Take a post-execution snapshot and diff against pre-execution
      6. Return a structured analysis report

    If the user does NOT want to execute the file, a static analysis is still
    performed: YARA scan, entropy check, PE header analysis, string extraction.
    """

    MAX_STATIC_SIZE = 50 * 1024 * 1024   # 50 MB static scan cap

    def __init__(self, db: Database, yara_engine: 'YaraEngine'):
        # Memory optimization
        self._last_gc = time.time()
        self.db          = db
        self.yara        = yara_engine
        self._sandbox_dir = DATA_DIR / "sandbox"
        self._sandbox_dir.mkdir(parents=True, exist_ok=True)
        self._results: List[dict] = []
        self._lock = threading.Lock()

    # -- Static analysis (no execution required) --------------------------------
    def analyze_static(self, path: str,
                       progress_cb: Optional[Callable] = None) -> dict:
        """
        Pure-static analysis: YARA, entropy, PE headers, strings, hash.
        Safe to run on any file without executing it.
        """
        result = {
            'file':         path,
            'timestamp':    datetime.now().isoformat(),
            'size_kb':      0,
            'sha256':       '',
            'md5':          '',
            'entropy':      0.0,
            'is_pe':        False,
            'imports':      [],
            'suspicious_strings': [],
            'yara_hits':    [],
            'risk_score':   0,
            'risk_reasons': [],
            'verdict':      'UNKNOWN',
            'error':        '',
        }

        try:
            # Resolve symlinks / normalise before any file operation
            try:
                path = os.path.realpath(os.path.abspath(str(path)))
            except Exception:
                result['error'] = 'Invalid path'
                return result
            if not os.path.isfile(path):
                result['error'] = 'File not found'
                return result

            size = os.path.getsize(path)
            result['size_kb'] = size // 1024

            if size > self.MAX_STATIC_SIZE:
                result['error'] = f'File too large for static scan ({size//1048576} MB > 50 MB cap)'
                return result

            if progress_cb: progress_cb("Reading file...")
            with open(path, 'rb') as fh:
                data = fh.read()

            # Hashes
            result['sha256'] = hashlib.sha256(data).hexdigest()
            result['md5']    = hashlib.md5(data).hexdigest()

            # Entropy
            result['entropy'] = self.yara.compute_entropy(data)
            if result['entropy'] > 7.0:
                result['risk_score'] += 35
                result['risk_reasons'].append(f"High entropy ({result['entropy']:.2f})  -  likely packed/encrypted")

            if progress_cb: progress_cb("YARA scan...")
            # YARA scan
            hits = self.yara.scan_bytes(data)
            result['yara_hits'] = [h['rule'] for h in hits]
            if hits:
                top_score = max(h['score'] for h in hits)
                result['risk_score'] += top_score // 2
                result['risk_reasons'].extend(f"YARA: {h['rule']}" for h in hits)

            # Suspicious strings  -  encoded to prevent AMSI/AV source scanning
            _susp_enc = _dbs_list([
                'VmlydHVhbEFsbG9jRXg=',          # VirtualAllocEx
                'V3JpdGVQcm9jZXNzTWVtb3J5',      # WriteProcessMemory
                'Q3JlYXRlUmVtb3RlVGhyZWFk',      # CreateRemoteThread
                'UmVmbGVjdGl2ZUxvYWRlcg==',      # ReflectiveLoader
                'U2V0V2luZG93c0hvb2tFeA==',      # SetWindowsHookEx
                'R2V0QXN5bmNLZXlTdGF0ZQ==',      # GetAsyncKeyState
                'V1NjcmlwdC5TaGVsbA==',          # WScript.Shell
                'cG93ZXJzaGVsbA==',              # powershell
                'LWVuYw==',                       # -enc
                'Y21kLmV4ZSAvYw==',              # cmd.exe /c
                'c3RyYXR1bSt0Y3A=',              # stratum+tcp
                'Yml0Y29pbg==',                  # bitcoin
                'QW1zaVNjYW5CdWZmZXI=',          # AmsiScanBuffer
                'RXR3RXZlbnRXcml0ZQ==',          # EtwEventWrite
                'TnRVbm1hcFZpZXdPZlNlY3Rpb24=', # NtUnmapViewOfSection
                'TWluaUR1bXBXcml0ZUR1bXA=',      # MiniDumpWriteDump
                'c2VrdXJsc2E6OmxvZ29ucGFzc3dvcmRz', # sekurlsa::logonpasswords
                'dG9rZW46OmVsZXZhdGU=',          # token::elevate
                'a2VyYmVyb3M6OmdvbGRlbg==',      # kerberos::golden
                'bHNhZHVtcDo6c2FtDQ==',          # lsadump::sam
                'SUVYKE5ldy1PYmplY3Q=',          # IEX (New-Object
                'SW52b2tlLU1pbWlrYXR6',          # Invoke-Mimikatz
                'SW52b2tlLUtlcmJlcm9hc3Q=',      # Invoke-Kerberoast
                'U2hhcnBIb3VuZA==',              # SharpHound
                'UnViZXVzLmV4ZQ==',              # Rubeus.exe
                'Y2VydHV0aWwgLWRlY29kZQ==',      # certutil -decode
            ])
            susp = [s.decode('ascii', errors='ignore')
                    for s in _susp_enc
                    if s.lower() in data.lower()]
            result['suspicious_strings'] = susp
            if susp:
                result['risk_score'] += min(len(susp) * 10, 40)
                result['risk_reasons'].append(f"Suspicious strings: {', '.join(susp[:5])}")

            # PE header analysis
            if data[:2] == b'MZ':
                result['is_pe'] = True
                if PEFILE_AVAILABLE:
                    if progress_cb: progress_cb("PE header analysis...")
                    try:
                        import pefile as _pefile
                        pe = _pefile.PE(data=data, fast_load=True)
                        pe.parse_data_directories(
                            directories=[_pefile.DIRECTORY_ENTRY['IMAGE_DIRECTORY_ENTRY_IMPORT']])
                        if hasattr(pe, 'DIRECTORY_ENTRY_IMPORT'):
                            for entry in pe.DIRECTORY_ENTRY_IMPORT[:20]:
                                dll = entry.dll.decode('ascii', errors='ignore').lower()
                                result['imports'].append(dll)
                                if dll in ('kernel32.dll', 'ntdll.dll', 'advapi32.dll'):
                                    pass  # common
                                elif dll in ('ws2_32.dll', 'wininet.dll', 'urlmon.dll'):
                                    result['risk_score'] += 10
                                    result['risk_reasons'].append(f"Network import: {dll}")
                    except Exception:
                        pass

            # Clamp score
            result['risk_score'] = min(100, result['risk_score'])

            # Verdict
            if result['risk_score'] >= 70:
                result['verdict'] = 'MALICIOUS'
            elif result['risk_score'] >= 40:
                result['verdict'] = 'SUSPICIOUS'
            elif result['risk_score'] >= 15:
                result['verdict'] = 'POTENTIALLY_UNWANTED'
            else:
                result['verdict'] = 'CLEAN'

        except Exception as e:
            result['error'] = str(e)
            error_logger.log('FileSandbox', f'Static analysis failed: {path}', e)

        with self._lock:
            self._results.append(result)

        return result

    # -- Dynamic analysis (spawns a monitored process) -------------------------
    def analyze_dynamic(self, path: str,
                        progress_cb: Optional[Callable] = None,
                        timeout: int = 30) -> dict:
        """
        Dynamic analysis: runs the file and records what it does.
        ONLY call this after explicit user confirmation.
        timeout: seconds to monitor after launch (default 30).
        """
        result: dict = {
            'file':           path,
            'timestamp':      datetime.now().isoformat(),
            'mode':           'dynamic',
            'new_files':      [],
            'new_processes':  [],
            'network_conns':  [],
            'registry_keys':  [],
            'error':          '',
        }

        # Pre-execution snapshot
        if progress_cb: progress_cb("Taking pre-execution snapshot...")
        pre_procs = set()
        pre_files: dict = {}

        if PSUTIL_AVAILABLE:
            for p in psutil.process_iter(['pid', 'name']):
                try: pre_procs.add(p.pid)
                except Exception: pass

        sandbox_copy = self._sandbox_dir / (os.path.basename(path) + '.sandbox')
        try:
            shutil.copy2(path, str(sandbox_copy))
        except Exception as e:
            result['error'] = f'Copy to sandbox failed: {e}'
            return result

        # Launch
        if progress_cb: progress_cb(f"Launching in sandbox (monitoring {timeout}s)...")
        try:
            proc = subprocess.Popen(
                [str(sandbox_copy)],
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                creationflags=subprocess.CREATE_NO_WINDOW,
            )
        except Exception as e:
            result['error'] = f'Launch failed: {e}'
            try: sandbox_copy.unlink()
            except Exception: pass
            return result

        # Monitor
        deadline = time.time() + timeout
        while time.time() < deadline:
            time.sleep(2)
            if PSUTIL_AVAILABLE:
                for p in psutil.process_iter(['pid', 'name', 'exe']):
                    try:
                        if p.pid not in pre_procs and p.pid != proc.pid:
                            result['new_processes'].append({
                                'name': p.info['name'],
                                'pid':  p.info['pid'],
                                'exe':  p.info.get('exe') or '',
                            })
                            pre_procs.add(p.pid)
                        for conn in (p.info.get('connections') or []):
                            if conn.raddr:
                                entry = f"{conn.raddr.ip}:{conn.raddr.port}"
                                if entry not in result['network_conns']:
                                    result['network_conns'].append(entry)
                    except (psutil.NoSuchProcess, psutil.AccessDenied):
                        pass

        # Terminate
        try:
            proc.terminate()
            proc.wait(timeout=3)
        except Exception:
            pass

        # Cleanup sandbox copy
        try: sandbox_copy.unlink()
        except Exception: pass

        # Deduplicate
        result['new_processes'] = result['new_processes'][:50]
        result['network_conns'] = result['network_conns'][:50]

        if progress_cb: progress_cb("Dynamic analysis complete.")
        with self._lock:
            self._results.append(result)
        return result

    def get_results(self) -> List[dict]:
        with self._lock:
            return list(self._results)


