    def submit_async_task(self, task_func, *args, priority='normal', **kwargs):
        """Submit an async task for background execution."""
        try:
            import uuid
            
            task = {
                'id': str(uuid.uuid4()),
                'func': task_func,
                'args': args,
                'kwargs': kwargs,
                'priority': priority,
                'submitted_at': time.time(),
                'status': 'pending'
            }
            
            # Add to queue
            self._task_queue.put(task)
            
            return task['id']
            
        except Exception as e:
            logger.error(f"Failed to submit async task: {e}")
            return None

    def schedule_ui_update(self, widget, update_func, priority='normal'):
        """Schedule a UI update for optimized rendering."""
        try:
            update_id = f"{widget.winfo_id()}_{id(update_func)}"
            
            # Defer the update if batching is enabled
            if self._render_config.get('batch_updates', True):
                self._deferred_updates[update_id] = {
                    'widget': widget,
                    'func': update_func,
                    'priority': priority,
                    'scheduled_at': time.time()
                }
            else:
                # Execute immediately
                self._execute_ui_update(widget, update_func)
            
            return update_id
            
        except Exception as e:
            logger.error(f"Failed to schedule UI update: {e}")

    def _async_worker_loop(self):
        """Background worker thread for async tasks."""
        import time
        
        while not self._stop_event.is_set():
            try:
                # Get task from queue with timeout
                task = self._task_queue.get(timeout=1.0)  # FIX-v28p11: was 0.1
                
                # Execute task
                start_time = time.time()
                result = self._execute_async_task(task)
                execution_time = time.time() - start_time
                
                # Put result in result queue
                self._result_queue.put({
                    'task_id': task.get('id'),
                    'result': result,
                    'execution_time': execution_time,
                    'timestamp': time.time()
                })
                
                # Mark task as done
                self._task_queue.task_done()
                
            except Exception:
                continue  # Queue timeout or other exception

    def _execute_async_task(self, task):
        """Execute an async task."""
        try:
            func = task['func']
            args = task.get('args', [])
            kwargs = task.get('kwargs', {})
            
            # Execute the function
            if callable(func):
                return func(*args, **kwargs)
            else:
                return None
                
        except Exception as e:
            logger.error(f"Async task execution failed: {e}")
            return {'error': str(e)}

    def _execute_ui_update(self, widget, update_func):
        """Execute a UI update safely."""
        try:
            # Check if widget still exists
            if widget and hasattr(widget, 'winfo_exists') and widget.winfo_exists():
                # Execute update function
                if callable(update_func):
                    update_func()
        except Exception as e:
            logger.error(f"UI update execution failed: {e}")

    def _schedule_ui_updates(self):
        """Schedule processing of UI update queue."""
        try:
            if not self.winfo_exists():
                return  # Window destroyed — stop rescheduling
            with self._ui_update_lock:
                while self._ui_update_queue:
                    widget, update_func = self._ui_update_queue.pop(0)
                    self._execute_ui_update(widget, update_func)
            self._orig_after(150, self._schedule_ui_updates)  # FIX-v28p35: 150ms (was 500ms)
        except Exception:
            try:
                self._orig_after(100, self._schedule_ui_updates)
            except Exception:
                pass

    def _safe_ui_update(self, widget, update_func):
        """Queue a UI update to be executed safely on the main thread."""
        try:
            with self._ui_update_lock:
                self._ui_update_queue.append((widget, update_func))
        except Exception as e:
            logger.error(f"Failed to queue UI update: {e}")
            # Fallback: try to execute immediately if we're on main thread
            try:
                if threading.current_thread() == threading.main_thread():
                    self._execute_ui_update(widget, update_func)
            except Exception:
                pass

    def _task_scheduler_loop(self):
        """Task scheduler for managing async operations.
        FIX: Must NOT call _process_deferred_updates() directly — that executes
        Tkinter widget ops from this background thread, causing a C-level segfault.
        Instead, schedule deferred updates on the main thread via self.after()."""
        import time
        
        while not self._stop_event.is_set():
            try:
                if self._deferred_updates:
                    self.after(500, self._process_deferred_updates)  # FIX-v28p11
                
                # FIX-v28p11: was 0.1s, constant GIL polling
                time.sleep(2.0)
                
            except Exception as e:
                logger.error(f"Task scheduler error: {e}")

    def _performance_monitor_loop(self):
        """UI performance monitoring loop."""
        import time
        import psutil
        
        while not self._stop_event.is_set():
            try:
                current_time = time.time()
                
                # Collect system metrics
                cpu_percent = psutil.cpu_percent(interval=0)
                memory_percent = psutil.virtual_memory().percent
                
                # Store metrics
                self._performance_metrics['cpu_usage'].append({
                    'timestamp': current_time,
                    'value': cpu_percent
                })
                
                self._performance_metrics['memory_usage'].append({
                    'timestamp': current_time,
                    'value': memory_percent
                })
                
                # Keep only last 5 minutes of data
                cutoff_time = current_time - 300
                for metric_type in self._performance_metrics:
                    self._performance_metrics[metric_type] = [
                        m for m in self._performance_metrics[metric_type]
                        if m['timestamp'] > cutoff_time
                    ]
                
                # Sleep for monitoring interval — 3s is plenty for perf graphs
                time.sleep(3.0)
                
            except Exception as e:
                logger.error(f"Performance monitoring error: {e}")

    def _process_deferred_updates(self):
        """Process deferred UI updates in batches."""
        try:
            if not self._deferred_updates:
                return
            
            # Get current time
            current_time = time.time()
            
            # Process high priority updates immediately
            high_priority = {
                uid: update for uid, update in self._deferred_updates.items()
                if update['priority'] == 'high'
            }
            
            # Process normal priority updates after delay
            normal_priority = {
                uid: update for uid, update in self._deferred_updates.items()
                if update['priority'] == 'normal' and 
                current_time - update['scheduled_at'] > 0.016  # 16ms delay
            }
            
            # Execute updates
            updates_to_process = {**high_priority, **normal_priority}
            
            for update_id, update in updates_to_process.items():
                self._execute_ui_update(update['widget'], update['func'])
                del self._deferred_updates[update_id]
                
        except Exception as e:
            logger.error(f"Failed to process deferred updates: {e}")

    def _init_state(self) -> None:
        """Initialize application state and UI."""
        try:
            # -- State ----------------------------------------------------
            self._processes: List[ProcessInfo] = []
            self._connections: List[dict] = []
            self._scan_active = False
            self._realtime_active = False
            self._widget: Optional[FloatingWidget] = None
            self._alert_queue: deque = deque(maxlen=500)
            # Fast alert path: background threads enqueue here; drainer flushes at 100ms
            self._pending_alerts: deque = deque(maxlen=50)  # FIX-v28p15: was 300
            # Structured threat log — feeds the Threats tab
            self._threat_log: list = []
            self._threat_log_idx: int = 0
            self._threat_log_dirty: bool = False  # flag: refresh tab on next drain
            self._alerted_dedup: dict = {}   # msg_prefix -> last_time, for deduplication
            
            # Adaptive interval state (updated by adapt_to_load every 60s)
            if hasattr(self, '_hw_profile'):
                # FIX-v28p9: hw stats every 2s min (was 500ms)
                self._adaptive_hw_ms   = max(2000, self._hw_profile.hw_loop_interval_ms)
                self._adaptive_prc_ms  = 60_000  # FIX-v28p16: 60s (was 10s)
                # FIX-v28p9: perf gauges every 2s min (was 250ms = 4x/sec gauge redraws!)
                self._adaptive_prf_ms  = max(1000, self._hw_profile.perf_interval_ms)  # FIX-v28p18: 1s for responsive gauges
                self._adaptive_feed_ms = self._hw_profile.feed_refresh_ms
            else:
                # Fallback defaults
                self._adaptive_hw_ms = 1000
                self._adaptive_prc_ms = 60_000  # FIX-v28p16: fallback also 60s
                self._adaptive_prf_ms = 500
                self._adaptive_feed_ms = 15000

            def _set_thread_above_normal():
                """Set thread to THREAD_PRIORITY_HIGHEST (2) for maximum scan throughput."""
                try:
                    import ctypes
                    _th = ctypes.windll.kernel32.GetCurrentThread()
                    ctypes.windll.kernel32.SetThreadPriority(_th, 2)  # THREAD_PRIORITY_HIGHEST
                except Exception:
                    pass

            # Initialize thread pools with adaptive sizing
            # FIX-v28p7: GUI apps need max 3 CPU threads or Tkinter dies
            max_workers_cpu = 3
            max_workers_gpu = getattr(self._hw_profile, 'workers_gpu', 2) if hasattr(self, '_hw_profile') else 2
            # FIX-v28: IO workers boosted for download parallelism
            max_workers_io = getattr(self._hw_profile, 'workers_io', 6) if hasattr(self, '_hw_profile') else 6

            # v29 FIX: COM must be initialized on EVERY thread that touches WMI/shell objects.
            # 0x800401f0 = CO_E_NOTINITIALIZED floods crash_fault.log when thread pool
            # workers call WMI without CoInitializeEx.  Use this as the thread initializer
            # for all three pools so every worker auto-inits COM at startup.
            def _com_thread_init():
                try:
                    import pythoncom as _pc
                    _pc.CoInitializeEx(0)   # COINIT_MULTITHREADED
                except Exception:
                    pass   # pythoncom not installed — silently skip

            self._executor = ThreadPoolExecutor(
                max_workers=max(6, (os.cpu_count() or 4) * 3 // 4),
                thread_name_prefix="dp-cpu",
                initializer=_com_thread_init)
            self._gpu_executor = ThreadPoolExecutor(
                max_workers=max(4, (os.cpu_count() or 4) // 2),
                thread_name_prefix="dp-gpu",
                initializer=_com_thread_init)
            self._io_executor = ThreadPoolExecutor(
                max_workers=max(8, (os.cpu_count() or 4) * 2),
                thread_name_prefix="dp-io",
                initializer=_com_thread_init)

            # Build UI
            # NOTE: _build_ui, protocol, _start_loops, _auto_start
            # are now called from _build_ui_safe() after background init
            
            # Log enhanced metrics if available
            if ENHANCED_LOGGING_AVAILABLE:
                try:
                    enhanced_logger.log_performance_metric('app_initialization', (time.time() - init_start) * 1000, 'ms')
                    enhanced_logger.log_ui_response('auto_start_setup', 50)
                except Exception:
                    pass
            
            logger.info("Application state initialized successfully")
            
        except Exception as e:
            logger.error(f"Application state initialization failed: {e}")
            raise

