    def _update_load_progress(self, tab_name: str, idx: int, total: int):
        """Update the loading progress bar during tab construction."""
        try:
            pct = int((idx + 1) / total * 100)
            if hasattr(self, '_load_progress'):
                self._load_progress['value'] = idx + 1
            if hasattr(self, '_load_pct'):
                self._load_pct.configure(text=f"{pct}%")
            if hasattr(self, '_load_status'):
                self._load_status.configure(text=f"Building {tab_name}...")
            # Pump the event loop so the progress bar visually updates
            self.update_idletasks()
        except Exception:
            pass

    def _build_ui(self):
        # NOTE: loading overlay is NOT destroyed here — it stays visible
        # with the progress bar while tabs build underneath. _finish_init()
        # destroys it once everything is ready, revealing the full UI at once.
        try:
            if hasattr(self, "_loading_label"):
                self._loading_label.destroy()
                del self._loading_label
            # Force global dark palette so ALL tk widgets default dark
            try:
                self.tk.call("tk_setPalette",
                    "background",   "#0a0a1a",
                    "foreground",   "#e0e0e0",
                    "activeBackground", "#1a1a2e",
                    "activeForeground", "#ffffff",
                    "highlightBackground", "#0a0a1a",
                    "selectBackground", "#1a3050",
                    "selectForeground", "#00ffcc",
                    "insertBackground", "#00ffcc",
                    "troughColor", "#050810"
                )
            except Exception:
                pass
            self.title("\u26c8 Downpour v29 Titanium \u2502 Advanced Threat Defense \u2502 34 Phases \u2502 400+ Fixes")
            self.configure(bg="#0a0a1a")
            self.deiconify()
            self.lift()
            self.focus_force()
            self.after(1000, lambda: self.attributes("-topmost", False))
        except Exception:
            pass
        # -- Responsive root grid ---------------------------------------------
        self.grid_rowconfigure(2, weight=1)    # notebook row expands
        self.grid_columnconfigure(0, weight=1)

        # -- Enforce minimum window size (prevents overlap on small displays) --
        self.minsize(1024, 650)
        self.resizable(True, True)

        # -- Smart responsive resize: keep rain canvas edge-to-edge ------------
        self._last_win_w: int = 0
        def _on_win_configure(e):
            if e.widget is self and e.width > 50:
                w = e.width
                if abs(w - self._last_win_w) > 20:
                    self._last_win_w = w
                    try:
                        if hasattr(self, 'rain'):
                            self.rain.configure(width=w)
                    except Exception:
                        pass
        self.bind('<Configure>', _on_win_configure)

        # -- Rain header ------------------------------------------------------
        _rh = max(self._hw_profile.rain_height, 1)
        _ri = self._hw_profile.rain_intensity
