    def _init_keyboard_shortcuts(self):
        """Register global keyboard shortcuts for power users."""
        # Navigation
        self.bind('<F1>',       lambda e: self._select_tab('_tab_dashboard'))
        self.bind('<F2>',       lambda e: self._select_tab('_tab_processes'))
        self.bind('<F3>',       lambda e: self._select_tab('_tab_network'))
        self.bind('<F4>',       lambda e: self._select_tab('_tab_scanner'))
        self.bind('<F5>',       lambda e: self._refresh_current_tab())
        self.bind('<F6>',       lambda e: self._select_tab('_tab_intel'))
        self.bind('<F7>',       lambda e: self._select_tab('_tab_aegis'))
        self.bind('<F8>',       lambda e: self._select_tab('_tab_firewall'))
        self.bind('<F9>',       lambda e: self._select_tab('_tab_hunt'))
        self.bind('<F12>',      lambda e: self._select_tab('_tab_settings'))
        # Actions
        self.bind('<Control-f>', lambda e: self._focus_hunt_bar())
        self.bind('<Control-r>', lambda e: self._toggle_rain_btn())
        self.bind('<Control-p>', lambda e: self._panic_button())
        self.bind('<Control-q>', lambda e: self._safe_exit())
        self.bind('<Escape>',    lambda e: self._dismiss_alerts())
        # Tab cycling
        self.bind('<Control-Tab>',       lambda e: self._scroll_tabs(1))
        self.bind('<Control-Shift-Tab>', lambda e: self._scroll_tabs(-1))
        logger.info("Keyboard shortcuts initialized (F1-F9, Ctrl+F/R/P/Q, Ctrl+Tab)")

    def _refresh_current_tab(self):
        """F5 — refresh the currently active tab's data."""
        try:
            idx = self.nb.index(self.nb.select())
            tab_attrs = list(self._nb_outer.keys())
            if idx < len(tab_attrs):
                attr = tab_attrs[idx]
                # Map tab attr to refresh method
                refreshers = {
                    '_tab_processes': '_refresh_proc_list',
                    '_tab_network': '_refresh_net_list',
                    '_tab_services': '_refresh_svc_list',
                    '_tab_firewall': '_fw_scan_rules',
                    '_tab_aegis': '_refresh_aegis_stats',
                }
                method_name = refreshers.get(attr)
                if method_name and hasattr(self, method_name):
                    getattr(self, method_name)()
        except Exception:
            pass

    def _focus_hunt_bar(self):
        """Ctrl+F — focus the threat hunt search bar."""
        try:
            for child in self.winfo_children():
                for sub in child.winfo_children():
                    if isinstance(sub, tk.Entry):
                        sub.focus_set()
                        return
        except Exception:
            pass

    def _dismiss_alerts(self):
        """Escape — dismiss current alert ticker."""
        try:
            self._last_alert_var.set("")
        except Exception:
            pass

    def _safe_exit(self):
        """Ctrl+Q — graceful shutdown."""
        try:
            self.destroy()
        except Exception:
            pass

    def _bind_mousewheel(self, widget, canvas):  # manual use only  -  tabs use Enter/Leave
        """Recursively bind MouseWheel on widget and all children to scroll canvas."""
        def _mw(e, c=canvas):
            c.yview_scroll(int(-1 * (e.delta / 120)), 'units')
        widget.bind('<MouseWheel>', _mw)
        for child in widget.winfo_children():
            self._bind_mousewheel(child, canvas)

    def _select_tab(self, inner_frame_or_attr):
        """Select a notebook tab by inner frame reference or attr name string."""
        target = inner_frame_or_attr
        # Look up outer frame from our mapping
        for attr, outer in self._nb_outer.items():
            if getattr(self, attr, None) is target or attr == target:
                try:
                    self.nb.select(outer)
                except Exception:
                    pass
                return
        # Fallback: try direct select (handles cases where outer was passed)
        try:
            self.nb.select(target)
        except Exception:
            pass

    def _on_nb_tab_changed(self, event):
        """Handle notebook tab change - force canvas width update to fix blank tabs."""
        try:
            # Get the currently selected tab
            selected_tab = self.nb.select()
            if not selected_tab:
                return
            
            # Find the canvas in the selected tab and force width update
            tab_frame = self.nametowidget(selected_tab)
            for widget in tab_frame.winfo_children():
                if isinstance(widget, tk.Canvas):
                    # Force canvas width update by triggering a configure event
                    current_width = widget.winfo_width()
                    if current_width > 1:  # Only if we have a valid width
                        widget.event_generate('<Configure>', width=current_width)
                        # Also update scrollregion to ensure proper scrolling
                        widget.configure(scrollregion=widget.bbox('all'))
                    break
        except Exception as e:
            # Silently fail to avoid breaking tab switching
            pass
        # FIX-v28p18: Update tab scroll indicator
        try: self._update_tab_indicator()
        except Exception: pass

    def _scroll_tabs(self, direction):
        """FIX-v28p18: Navigate tabs left(-1) or right(+1)."""
        try:
            tabs = self.nb.tabs()
            if not tabs:
                return
            current = self.nb.index(self.nb.select())
            new_idx = max(0, min(len(tabs) - 1, current + direction))
            self.nb.select(tabs[new_idx])
            self._update_tab_indicator()
        except Exception:
            pass

    def _update_tab_indicator(self):
        """FIX-v28p18: Update tab position indicator."""
        try:
            tabs = self.nb.tabs()
            current = self.nb.index(self.nb.select()) + 1
            total = len(tabs)
            name = self.nb.tab(self.nb.select(), 'text')
            self._tab_indicator.config(text=f'{name}  ({current}/{total})')
        except Exception:
            pass

    def _activate_gaming_mode(self):
        """Activate comprehensive gaming optimization mode"""
        def apply_gaming_mode():
            try:
                # Apply gaming optimizations
                optimizations = []

                # 1. Optimize CPU for gaming
                try:
                    import subprocess
                    # Set CPU priority to high
                    subprocess.run(['wmic', 'process', 'where', 'name="python.exe"', 'call', 'setpriority', '128'],
                                  capture_output=True, check=False)
                    optimizations.append("CPU priority optimized")
                except Exception:
                    optimizations.append("CPU optimization skipped")

                # 2. Optimize memory for gaming
                try:
                    import gc
                    gc.collect()
                    if hasattr(self, '_enhanced_memory') and self._enhanced_memory:
                        self._enhanced_memory.optimize_for_gaming()
                    optimizations.append("Memory optimized for gaming")
                except Exception:
                    optimizations.append("Memory optimization skipped")

                # 3. Disable background processes
                try:
                    services_to_stop = ['SysMain', 'Themes', 'Windows Search']
                    for service in services_to_stop:
                        subprocess.run(['sc', 'stop', service], capture_output=True, check=False)
                    optimizations.append("Background processes optimized")
                except Exception:
                    optimizations.append("Background optimization skipped")

                # 4. Optimize power settings
                try:
                    subprocess.run(['powercfg', '/setactive', 'SCHEME_MIN'],
                                  capture_output=True, check=False)
                    optimizations.append("Power set to high performance")
                except Exception:
                    optimizations.append("Power optimization skipped")

                # 5. Optimize visual effects
                try:
                    subprocess.run(['reg', 'add', r'HKCU\Software\Microsoft\Windows\CurrentVersion\Explorer\VisualEffects',
                                  '/v', 'VisualFXSetting', '/t', 'REG_DWORD', '/d', '2', '/f'],
                                  capture_output=True, check=False)
                    optimizations.append("Visual effects optimized")
                except Exception:
                    optimizations.append("Visual optimization skipped")

                # Update performance optimizer
                try:
                    if hasattr(self, 'performance_optimizer'):
                        self.performance_optimizer.optimization_level = 5
                        self.performance_optimizer.optimize_for_gaming()
                except Exception:
                    pass

                self.after(0, lambda: self.show_notification("Gaming Mode Activated", "System optimized for gaming"))
                logger.info("Gaming mode activated: %s", "; ".join(optimizations))

            except Exception as e:
                self.after(0, lambda _e=str(e): self.show_notification("Gaming Mode Error", _e))
                logger.error("Gaming mode activation error: %s", e)

        threading.Thread(target=apply_gaming_mode, daemon=True).start()

