    def _toggle_rain(self):
        """Toggle the header rain canvas  -  called programmatically."""
        if self._rain_on.get():
            self.rain.start()
        else:
            self.rain.stop()

    def _toggle_rain_btn(self):
        """Toggle rain/animations with button  -  updates label to show state."""
        currently_on = self._rain_on.get()
        self._rain_on.set(not currently_on)
        if self._rain_on.get():
            self.rain.start()
            try:
                self._rain_btn.configure(
                    text='\u2602 Rain ON',
                    fg=Colors.GAUGE_BLUE,
                    bg=Colors.GLASS_CARD)
            except Exception:
                pass
        else:
            self.rain.stop()
            try:
                self._rain_btn.configure(
                    text='\u23f8 Rain OFF',
                    fg=Colors.TEXT_DIM,
                    bg=Colors.GLASS_DARK)
            except Exception:
                pass

    def _cycle_storm_phase(self):
        """Cycle through storm phases: calm -> drizzle -> storm -> tempest."""
        if not hasattr(self, 'rain') or not hasattr(self.rain, '_storm_phase_idx'):
            return
        phases = ['calm', 'drizzle', 'storm', 'tempest']
        icons = ['\u2601', '\u2602', '\u26c8', '\u26a1']  # cloud, umbrella, storm, lightning
        cur = self.rain._storm_phase_idx
        nxt = (cur + 1) % len(phases)
        self.rain.set_storm_phase(phases[nxt])
        try:
            self._storm_btn.configure(text=f'{icons[nxt]} {phases[nxt].title()}')
        except Exception:
            pass

