    # -- Alert context-menu actions --------------------------------------------
    def _show_alert_menu(self, event):
        try:
            idx = self._alert_list.nearest(event.y)
            self._alert_list.selection_clear(0, 'end')
            self._alert_list.selection_set(idx)
            self._alert_list.activate(idx)
            self._alert_menu.tk_popup(event.x_root, event.y_root)
        except Exception:
            pass
        finally:
            self._alert_menu.grab_release()

    def _alert_double_click(self, event=None):
        """Double-click: open full threat response panel"""
        txt = self._get_selected_alert_text()
        if txt:
            self._show_threat_action_panel(txt)

    def _get_selected_alert_text(self) -> str:
        try:
            sel = self._alert_list.curselection()
            if sel:
                return self._alert_list.get(sel[0])
        except Exception: pass
        return ""

    def _alert_check_ip(self):
        txt = self._get_selected_alert_text()
        # Extract any IP-like string from the alert
        match = re.search(r'\b(\d{1,3}(?:\.\d{1,3}){3})\b', txt)
        if match:
            ip = match.group(1)
            is_bad = self.intel.check_ip(ip)
            if messagebox.askyesno("Block IP",
                f"IP: {ip}\nIn threat database: {'YES [!]' if is_bad else 'No'}\n\nBlock this IP in Windows Firewall?"):
                self._executor.submit(lambda: self._do_block_ip(ip))
        else:
            messagebox.showinfo("No IP", "No IP address found in this alert.\nCheck the Network tab for connections.")

    # _do_block_ip is defined later with Aegis WFP integration

    def _alert_kill_suspicious(self):
        if not messagebox.askyesno("Kill Suspicious",
            "Kill all currently flagged suspicious processes?\n\nThis cannot be undone."):
            return
        self._kill_all_suspicious()

    def _kill_all_suspicious(self):
        def do():
            killed = []
            with self._lock:
                procs = list(self._processes)
            for p in procs:
                if p.risk_score >= 70:
                    ok, msg = self.scanner.mitigate(p.pid, 'kill_tree', QUARANTINE_DIR)
                    if ok:
                        killed.append(p.name)
            self._queue_alert(
                f"[SKULL] Killed {len(killed)} suspicious processes: {', '.join(killed[:5])}", Colors.GAUGE_RED)
            self.after(0, self._scan_processes_now)
        self._executor.submit(do)

    def _block_all_c2(self):
        def do():
            blocked = 0
            with self._lock:
                procs = list(self._processes)
            for p in procs:
                for conn in p.connections:
                    ip = conn.get('remote_ip', '')
                    # Never flag RFC1918 private IPs from IOC feeds
                    # FIX: 172.16.0.0/12 is 172.16-31.x.x, not all 172.x.x.x
                    _priv_172 = False
                    if ip.startswith('172.'):
                        try: _priv_172 = 16 <= int(ip.split('.')[1]) <= 31
                        except (ValueError, IndexError): pass
                    _priv = (ip.startswith('192.168.') or ip.startswith('10.')
                             or _priv_172 or ip in ('127.0.0.1','::1'))
                    if ip and p.risk_score >= 60 and not _priv:
                        self._do_block_ip(ip)
                        blocked += 1
            self._queue_alert(
                f"[BLOCK] Blocked {blocked} C2/suspicious IPs in firewall", Colors.GAUGE_ORANGE)
        self._executor.submit(do)

    def _alert_quarantine_files(self):
        txt = self._get_selected_alert_text()
        messagebox.showinfo("Quarantine",
            "Select a process in the Processes tab, then use\n'[LOCK] Quarantine EXE' to quarantine its executable.\n\n"
            "Alert context:\n" + txt[:200])

    def _alert_block_network(self):
        if not messagebox.askyesno("Block Network",
            "Add a Windows Firewall rule to block ALL outbound traffic?\n\n"
            "WARNING: This will break internet connectivity.\nUse only if under active attack."):
            return
        self._io_submit(lambda: subprocess.run(
            ['netsh', 'advfirewall', 'set', 'allprofiles', 'firewallpolicy',
             'blockinbound,blockoutbound'], capture_output=True, timeout=15), creationflags=_NO_WIN)
        self._queue_alert("[FIRE] ALL OUTBOUND NETWORK BLOCKED", Colors.GAUGE_RED)

    def _alert_copy_text(self):
        txt = self._get_selected_alert_text()
        self.clipboard_clear()
        self.clipboard_append(txt)
        self._set_status("Copied alert text to clipboard")

    def _alert_dismiss(self):
        try:
            sel = self._alert_list.curselection()
            if sel:
                self._alert_list.delete(sel[0])
        except Exception: pass

    def _clear_all_alerts(self):
        self._alert_list.delete(0, 'end')

    # ------------------------------------------------------------------------
    #  PRIVACY SCORE ENGINE
    # ------------------------------------------------------------------------

    def _calculate_privacy_score(self) -> dict:
        """Calculate a 0-100 Privacy Score based on active protections.
        Returns dict with 'score', 'grade', 'components', 'missing'."""
        components = []
        missing = []

        def check(name: str, label: str, value: bool, weight: int, tip: str = ''):
            components.append({'name': name, 'label': label, 'ok': value, 'weight': weight, 'tip': tip})
            if not value:
                missing.append(f"[X] {label}" + (f"  -  {tip}" if tip else ''))

        # -- VPN / Tunnel (max 25 pts) ----------------------------------
        vpn_active = False
        if _VPN_MODULE_AVAILABLE:
            try:
                vpn_active = getattr(self, '_vpn_active', False)
            except Exception:
                pass
        check('vpn', 'VPN Active', vpn_active, 15, 'Enable VPN in VPN tab')

        tor_active = False
        try:
            tor_active = getattr(self, '_tor_active', False)
        except Exception:
            pass
        check('tor', 'Tor / Anonymization', tor_active, 10, 'Enable Tor in VPN tab')

        # -- DNS Security (max 15 pts) -------------------------------
        dns_secure = False
        try:
            dns_secure = getattr(self, '_dns_secure_active', False)
        except Exception:
            pass
        check('dns', 'Secure DNS (DoH/DoT)', dns_secure, 8, 'Enable DNS Security tab')

        dns_leak_protected = False
        try:
            dns_leak_protected = getattr(self, '_dns_leak_protected', False)
        except Exception:
            pass
        check('dns_leak', 'DNS Leak Protection', dns_leak_protected, 7, 'Enable in VPN/DNS tab')

        # -- Firewall & Remote Access (max 20 pts) --------------------
        import subprocess as _sp
        fw_on = False
        try:
            r = _sp.run(['netsh','advfirewall','show','allprofiles','state'],
                        capture_output=True, text=True, timeout=5,
                        creationflags=_sp.CREATE_NO_WINDOW)
            fw_on = r.stdout.lower().count('on') >= 3
        except Exception:
            pass
        check('firewall', 'Windows Firewall (All Profiles)', fw_on, 10, 'Enable in Hardening tab')

        rdp_disabled = False
        try:
            import winreg as _wr
            k = _wr.OpenKey(_wr.HKEY_LOCAL_MACHINE,
                r'SYSTEM\CurrentControlSet\Control\Terminal Server', 0, _wr.KEY_READ)
            val, _ = _wr.QueryValueEx(k, 'fDenyTSConnections')
            _wr.CloseKey(k)
            rdp_disabled = (val == 1)
        except Exception:
            pass
        check('rdp', 'RDP Disabled', rdp_disabled, 10, 'Disable in Hardening or Remote Access tab')

        # -- Hardening Score (max 20 pts) ------------------------------
        harden_pct = 0
        try:
            s, m = self.hardening.get_score()
            harden_pct = (s / m * 100) if m else 0
        except Exception:
            pass
        # Map hardening % to 20 points
        harden_pts = min(20, int(harden_pct / 100 * 20))
        check('hardening', f'System Hardening ({harden_pct:.0f}%)', harden_pct >= 50, harden_pts,
              'Run Hardening Scan and apply fixes')

        # -- Active Monitors (max 10 pts) -------------------------------
        ransomware_active = getattr(self.ransomware, '_monitoring', False)
        check('ransomware', 'Ransomware Monitor Active', ransomware_active, 5,
              'Start monitor in Ransomware tab')
        mem_active = getattr(self.mem_forensics, '_monitoring', False)
        check('memory', 'Memory Forensics Active', mem_active, 5,
              'Start monitor in Memory tab')

        # -- WDigest (credential hardening) (10 pts) ---------------------
        wdigest_ok = True  # default: disabled on Win10+
        try:
            k = _wr.OpenKey(_wr.HKEY_LOCAL_MACHINE,
                r'SYSTEM\CurrentControlSet\Control\SecurityProviders\WDigest',
                0, _wr.KEY_READ)
            val, _ = _wr.QueryValueEx(k, 'UseLogonCredential')
            _wr.CloseKey(k)
            wdigest_ok = (val == 0)
        except Exception:
            wdigest_ok = True  # key absent = disabled by default
        check('wdigest', 'WDigest Credential Cache Disabled', wdigest_ok, 10,
              'Fix in Hardening tab  -  prevents cleartext password theft')

        # -- Score calculation ---------------------------------------------
        max_pts = sum(c['weight'] for c in components)
        earned  = sum(c['weight'] for c in components if c['ok'])
        # Adjust for hardening partial credit
        earned = earned - (components[6]['weight'] if components[6]['ok'] else 0) + harden_pts
        score = min(100, int(earned / max_pts * 100)) if max_pts else 0

        if score >= 85:   grade = '[G] EXCELLENT'
        elif score >= 65: grade = '[Y] GOOD'
        elif score >= 45: grade = '[O] FAIR'
        else:             grade = '[R] POOR  -  Act Now'

        return {'score': score, 'grade': grade, 'components': components,
                'missing': missing, 'harden_pct': harden_pct}

    def _refresh_privacy_score(self):
        """Recalculate and update the privacy score display."""
        if not self.winfo_exists():
            return
        def _calc():
            try:
                result = self._calculate_privacy_score()
                self.after(0, lambda r=result: _update(r))
            except Exception:
                pass
        def _update(r):
            if not self.winfo_exists():
                return
            score = r['score']
            color = Colors.GAUGE_GREEN if score >= 75 else Colors.GAUGE_YELLOW if score >= 45 else Colors.GAUGE_RED
            self._privacy_score_lbl.config(text=f"{score}/100", fg=color)
            self._privacy_grade_lbl.config(text=r['grade'],
                fg=Colors.GAUGE_GREEN if score >= 75 else Colors.GAUGE_YELLOW if score >= 45 else Colors.GAUGE_RED)
            # Show top 4 missing items  -  update both labels (new tips + legacy details)
            missing_txt = '\n'.join(r['missing'][:4]) if r['missing'] else '[OK] All critical protections active'
            try:
                self._privacy_details_lbl.config(text=missing_txt)
            except Exception:
                pass
            try:
                self._privacy_tips_lbl.config(text=missing_txt)
            except Exception:
                pass
        import threading
        threading.Thread(target=_calc, daemon=True).start()

    def _activate_privacy_mode(self):
        """One-click Privacy Mode: enables VPN kill switch, Tor, secure DNS, and blocks remote access."""
        actions_taken = []
        actions_failed = []

        # 1. Enable DNS Security if available
        try:
            if hasattr(self, '_dns_apply_dns_hardening'):
                self._io_submit(self._dns_apply_dns_hardening)
                actions_taken.append('Secure DNS')
        except Exception:
            actions_failed.append('DNS Security')

        # 2. Enable VPN kill switch if VPN module available
        try:
            if _VPN_MODULE_AVAILABLE and hasattr(self, '_vpn_toggle_kill_switch'):
                self._io_submit(self._vpn_toggle_kill_switch)
                actions_taken.append('VPN Kill Switch')
        except Exception:
            actions_failed.append('Kill Switch')

        # 3. Ensure Windows Firewall is on
        try:
            import subprocess
            subprocess.run(['netsh', 'advfirewall', 'set', 'allprofiles', 'state', 'on'],
                           capture_output=True, timeout=8,
                           creationflags=subprocess.CREATE_NO_WINDOW)
            actions_taken.append('Windows Firewall')
        except Exception:
            actions_failed.append('Firewall')

        # 4. Disable RDP (most critical remote access vector)
        try:
            import winreg
            k = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                r'SYSTEM\CurrentControlSet\Control\Terminal Server', 0, winreg.KEY_WRITE)
            winreg.SetValueEx(k, 'fDenyTSConnections', 0, winreg.REG_DWORD, 1)
            winreg.CloseKey(k)
            actions_taken.append('RDP Disabled')
        except Exception:
            pass

        # 5. Navigate to VPN tab for next action
        try:
            if hasattr(self, '_tab_vpn'):
                self._select_tab(self._tab_vpn)
        except Exception:
            pass

        # FIX: _refresh_privacy_score moved to _auto_start

        ok_txt = ', '.join(actions_taken) if actions_taken else 'None'
        fail_txt = ', '.join(actions_failed) if actions_failed else 'None'
        messagebox.showinfo('Privacy Mode Activated',
            f'Privacy Mode activated\n\n'
            f'[OK] Enabled: {ok_txt}\n'
            f'[!] Manual steps needed:\n'
            f'  - Enable a VPN in the VPN tab\n'
            f'  - Start Tor routing in VPN tab\n'
            f'  - Run Hardening Scan in Hardening tab\n'
            f'  - Review Remote Access tab')

