    def _show_proc_context_menu(self, event):
        item = self._proc_tree.identify_row(event.y)
        if item:
            self._proc_tree.selection_set(item)
            try:
                self._proc_menu.tk_popup(event.x_root, event.y_root)
            finally:
                self._proc_menu.grab_release()

    def _apply_proc_filter(self):
        """Live filter the process tree without re-scanning."""
        try:
            flt = self._proc_filter.get().lower()
            with self._lock:
                procs = list(self._processes)
            threats = [p for p in procs if p.is_suspicious]
            self._update_proc_ui(procs, threats, flt)
        except Exception: pass

    def _sort_proc_tree(self, col: str):
        """Sort process tree by column."""
        try:
            items = [(self._proc_tree.set(k, col), k)
                     for k in self._proc_tree.get_children('')]
            try:
                items.sort(key=lambda x: float(x[0]))
            except ValueError:
                items.sort()
            for idx, (_, k) in enumerate(items):
                self._proc_tree.move(k, '', idx)
        except Exception: pass

    def _proc_check_ips(self):
        sel = self._proc_tree.selection()
        if not sel: return
        pid = int(sel[0])
        proc = next((p for p in self._processes if p.pid == pid), None)
        if not proc: return
        results = []
        for conn in _proc_has_connections(proc):
            ip = conn.get('remote_ip','')
            if ip:
                bad = self.intel.check_ip(ip)
                results.append(f"{'[!]' if bad else '[OK]'} {ip}:{conn.get('remote_port','')} {'[BLACKLISTED]' if bad else ''}")
        messagebox.showinfo(f"IP Check - {proc.name}",
            '\n'.join(results) if results else "No remote connections found.")

    def _proc_copy_info(self):
        sel = self._proc_tree.selection()
        if not sel: return
        pid = int(sel[0])
        proc = next((p for p in self._processes if p.pid == pid), None)
        if not proc: return
        info = f"PID: {proc.pid} | {proc.name} | Risk: {proc.risk_score} | Path: {proc.path}"
        self.clipboard_clear(); self.clipboard_append(info)
        self._set_status("Process info copied")

    def _proc_open_location(self):
        sel = self._proc_tree.selection()
        if not sel: return
        pid = int(sel[0])
        proc = next((p for p in self._processes if p.pid == pid), None)
        if proc and proc.path:
            subprocess.Popen(['explorer', '/select,', str(proc.path)])  # fire-and-forget, no timeout needed

    def _proc_add_watchlist(self):
        sel = self._proc_tree.selection()
        if not sel: return
        pid = int(sel[0])
        proc = next((p for p in self._processes if p.pid == pid), None)
        if proc:
            self._queue_alert(f"Watching: {proc.name} (PID {proc.pid})  -  added to watchlist", Colors.GAUGE_YELLOW)

