        self._scan_stop = threading.Event()
        self._scan_active = False
        self._scan_roots = None
        self._scan_raw_threats = []
        self._scan_lock = threading.Lock()  # protects _scan_raw_threats across threads
        if not hasattr(self, '_executor'):
            from concurrent.futures import ThreadPoolExecutor
            # Use hardware profile for worker count
            _hwp = getattr(self, '_hw_profile', None)
            if _hwp:
                _workers = getattr(_hwp, 'workers_scan', max(1, (os.cpu_count() or 2) // 2))
            else:
                _workers = max(1, (os.cpu_count() or 2) // 2)  # Conservative fallback
            self._executor = ThreadPoolExecutor(max_workers=_workers)

