    def _build_ransomware_tab(self):
        p = self._tab_ransomware
        tk.Label(p, text="🔒 RANSOMWARE PROTECTION & FILE ROLLBACK",
                 font=('Consolas', 12, 'bold'), fg=Colors.GAUGE_ORANGE,
                 bg=Colors.BG_VOID).pack(anchor='w', padx=10, pady=10)

        # Stats row
        stats = tk.Frame(p, bg=Colors.BG_VOID)
        stats.pack(fill='x', padx=10, pady=4)
        self._rw_stats = {}
        for key, label, color in [('snapshots','Snapshots',Colors.GAUGE_BLUE),
                                    ('protected','Protected Dirs',Colors.GAUGE_TEAL),
                                    ('events','Events',Colors.GAUGE_RED)]:
            f = tk.Frame(stats, bg=Colors.GLASS_CARD, padx=16, pady=8)
            f.pack(side='left', padx=6)
            tk.Label(f, text=label, font=('Consolas', 8), fg=Colors.TEXT_DIM, bg=Colors.GLASS_CARD).pack()
            lbl = tk.Label(f, text="0", font=('Consolas', 16, 'bold'), fg=color, bg=Colors.GLASS_CARD)
            lbl.pack()
            self._rw_stats[key] = lbl

        # Control buttons
        btn_row = tk.Frame(p, bg=Colors.BG_VOID)
        btn_row.pack(fill='x', padx=10, pady=6)
        
        def _revert_ransomware_changes():
            """Revert ransomware protection changes."""
            if messagebox.askyesno('Revert Ransomware Protection', 
                'This will revert all ransomware protection changes:\n\n'
                '- Stop active monitoring\n'
                '- Remove file snapshots\n'
                '- Clear protected directories\n'
                '- Disable real-time protection\n\n'
                'Are you sure you want to continue?'):
                try:
                    reverted_items = []
                    
                    # Stop monitoring
                    if hasattr(self, 'ransomware') and self.ransomware:
                        try:
                            self.ransomware.stop_monitoring()
                            reverted_items.append('- Ransomware monitoring stopped')
                        except Exception as e:
                            reverted_items.append(f'- Stop monitoring: {str(e)}')
                    
                    # Clear snapshots
                    try:
                        if hasattr(self, 'ransomware') and self.ransomware:
                            self.ransomware.clear_snapshots()
                            reverted_items.append('- File snapshots cleared')
                    except Exception as e:
                        reverted_items.append(f'- Clear snapshots: {str(e)}')
                    
                    # Clear protected paths
                    try:
                        if hasattr(self, 'ransomware') and self.ransomware:
                            self.ransomware.clear_protected_paths()
                            reverted_items.append('- Protected directories cleared')
                    except Exception as e:
                        reverted_items.append(f'- Clear paths: {str(e)}')
                    
                    # Update UI
                    self._rw_status_lbl.config(text="* Monitoring: OFF", fg=Colors.GAUGE_RED)
                    for key in self._rw_stats:
                        self._rw_stats[key].config(text="0")
                    
                    # Show results
                    result_msg = "Ransomware Protection Reverted\n\n"
                    result_msg += "Details:\n" + "\n".join(reverted_items)
                    messagebox.showinfo('Revert Complete', result_msg)
                    
                except Exception as e:
                    messagebox.showerror('Revert Failed', f'Failed to revert ransomware protection:\n{str(e)}')

        for text, cmd, color in [
            ("📸 Take File Snapshots", self._take_file_snapshots, Colors.GAUGE_BLUE),
            ("> Start Monitoring",    self._start_ransomware_monitor, Colors.GAUGE_GREEN),
            ("⏹️ Stop Monitoring",     self._stop_ransomware_monitor, Colors.GAUGE_ORANGE),
            ("🔄 Rollback Files",     self._rollback_files, Colors.GAUGE_RED),
            ("Revert Changes",     _revert_ransomware_changes, Colors.GAUGE_PURPLE),
        ]:
            tk.Button(btn_row, text=text, font=('Consolas', 9, 'bold'), fg=color,
                      bg=Colors.GLASS_CARD, relief='flat', padx=8,
                      command=cmd).pack(side='left', padx=4)

        # Monitoring status
        self._rw_status_lbl = tk.Label(p, text="* Monitoring: OFF",
                                       font=('Consolas', 10), fg=Colors.GAUGE_RED,
                                       bg=Colors.BG_VOID)
        self._rw_status_lbl.pack(anchor='w', padx=14, pady=4)

        # Protected paths management
        protected_frame = tk.Frame(p, bg=Colors.BG_VOID)
        protected_frame.pack(fill='x', padx=10, pady=6)
        
        tk.Label(protected_frame, text="Protected Directories Management:", 
                 font=('Consolas', 9, 'bold'), fg=Colors.TEXT_DIM, bg=Colors.BG_VOID).pack(anchor='w')
        
        # Directory input and buttons row
        dir_input_frame = tk.Frame(protected_frame, bg=Colors.BG_VOID)
        dir_input_frame.pack(fill='x', pady=4)
        
        # Directory input field
        self._dir_entry = tk.Entry(dir_input_frame, font=('Consolas', 9), 
                                  bg=Colors.GLASS_DARK, fg=Colors.TEXT_LIGHT,
                                  insertbackground=Colors.GAUGE_TEAL, relief='flat')
        self._dir_entry.pack(side='left', fill='x', expand=True, padx=(0, 4))
        self._dir_entry.insert(0, "Enter directory path to protect...")
        
        # Directory management buttons
        def _add_directory():
            dir_path = self._dir_entry.get().strip()
            if dir_path and dir_path != "Enter directory path to protect...":
                if self.ransomware.add_protected_directory(dir_path):
                    self._update_protected_paths_display()
                    self._rw_log.config(state='normal')
                    self._rw_log.insert('end', f"[{datetime.now().strftime('%H:%M:%S')}] Added protected directory: {dir_path}\n")
                    self._rw_log.config(state='disabled')
                    self._refresh_ransomware_stats()
                else:
                    messagebox.showwarning('Add Directory', f'Failed to add directory: {dir_path}\nDirectory may not exist or already protected.')
        
        def _browse_directory():
            from tkinter import filedialog
            directory = filedialog.askdirectory(title="Select Directory to Protect")
            if directory:
                self._dir_entry.delete(0, tk.END)
                self._dir_entry.insert(0, directory)
        
        def _add_all_directories():
            if messagebox.askyesno('Add All Directories', 
                'This will add ALL user directories to the protected list.\n\nThis may take a moment and significantly increase protection coverage.\n\nContinue?'):
                count = self.ransomware.add_all_user_directories()
                self._update_protected_paths_display()
                self._rw_log.config(state='normal')
                self._rw_log.insert('end', f"[{datetime.now().strftime('%H:%M:%S')}] Added {count} new directories to protection\n")
                self._rw_log.config(state='disabled')
                self._refresh_ransomware_stats()
                messagebox.showinfo('Add All Directories', f'Successfully added {count} directories to protection!')
        
        tk.Button(dir_input_frame, text="📁 Browse", font=('Consolas', 8, 'bold'),
                 fg=Colors.GAUGE_BLUE, bg=Colors.GLASS_CARD, relief='flat',
                 command=_browse_directory).pack(side='left', padx=2)
        tk.Button(dir_input_frame, text="➕ Add", font=('Consolas', 8, 'bold'),
                 fg=Colors.GAUGE_GREEN, bg=Colors.GLASS_CARD, relief='flat',
                 command=_add_directory).pack(side='left', padx=2)
        tk.Button(dir_input_frame, text="🌐 Add All", font=('Consolas', 8, 'bold'),
                 fg=Colors.GAUGE_ORANGE, bg=Colors.GLASS_CARD, relief='flat',
                 command=_add_all_directories).pack(side='left', padx=2)
        
        # Clear entry on click
        def _clear_placeholder(event):
            if self._dir_entry.get() == "Enter directory path to protect...":
                self._dir_entry.delete(0, tk.END)
                self._dir_entry.config(fg=Colors.TEXT_LIGHT)
        
        def _restore_placeholder(event):
            if not self._dir_entry.get().strip():
                self._dir_entry.insert(0, "Enter directory path to protect...")
                self._dir_entry.config(fg=Colors.TEXT_DIM)
        
        self._dir_entry.config(fg=Colors.TEXT_DIM)
        self._dir_entry.bind('<FocusIn>', _clear_placeholder)
        self._dir_entry.bind('<FocusOut>', _restore_placeholder)
        
        # Protected paths display with scrollbar
        paths_container = tk.Frame(protected_frame, bg=Colors.BG_VOID)
        paths_container.pack(fill='x', pady=4)
        
        paths_scroll = tk.Scrollbar(paths_container, bg=Colors.GLASS_DARK, 
                                   troughcolor=Colors.BG_VOID, 
                                   activebackground=Colors.GAUGE_TEAL)
        paths_scroll.pack(side='right', fill='y')
        
        self._paths_display = tk.Text(paths_container, height=4, 
                                      bg=Colors.GLASS_DARK, fg=Colors.GAUGE_TEAL,
                                      font=('Consolas', 8), relief='flat',
                                      wrap=tk.WORD, yscrollcommand=paths_scroll.set,
                                      state='disabled')
        self._paths_display.pack(side='left', fill='both', expand=True)
        paths_scroll.config(command=self._paths_display.yview)
        
        # Initialize display
        self._update_protected_paths_display()

        # Event log
        tk.Label(p, text="RANSOMWARE EVENT LOG", font=('Consolas', 9, 'bold'),
                 fg=Colors.GAUGE_RED, bg=Colors.BG_VOID).pack(anchor='w', padx=14, pady=(8,2))
        self._rw_log = tk.Text(p, bg=Colors.GLASS_DARK, fg=Colors.TEXT_LIGHT,
                               font=('Consolas', 8), height=10, state='disabled',
                               relief='flat', wrap=tk.WORD)
        self._rw_log.pack(fill='both', expand=True, padx=10, pady=4)
        # FIX: moved to _auto_start — after() in tab builder fires during repaint
        # self.after(500, self._refresh_ransomware_stats)

    def _refresh_ransomware_stats(self):
        try:
            stats = self.ransomware.get_stats()
            self._rw_stats['snapshots'].config(text=str(stats.get('snapshots', 0)))
            self._rw_stats['protected'].config(text=str(stats.get('protected_dirs', 0)))
            self._rw_stats['events'].config(text=str(stats.get('events', 0)))
        except Exception:
            pass

    def _update_protected_paths_display(self):
        """Update the protected paths display with current paths"""
        try:
            paths = self.ransomware._protected_paths
            self._paths_display.config(state='normal')
            self._paths_display.delete('1.0', tk.END)
            
            if paths:
                for i, path in enumerate(paths, 1):
                    # Format with number and path
                    self._paths_display.insert(tk.END, f"{i:2d}. {path}\n")
            else:
                self._paths_display.insert(tk.END, "No protected directories configured")
            
            self._paths_display.config(state='disabled')
        except Exception:
            pass

    def _take_file_snapshots(self):
        self._rw_log.config(state='normal')
        try:
            self._rw_log.insert('end', f"[{datetime.now().strftime('%H:%M:%S')}] Taking file snapshots...\n")
        finally:
            self._rw_log.config(state='disabled')
        def do():
            count = self.ransomware.take_file_snapshots()
            def _rw_done(c=count):
                if not self.winfo_exists(): return
                self._rw_log.config(state='normal')
                self._rw_log.insert('end', f"[{'{'}datetime.now().strftime('%H:%M:%S'){'}'}] Snapshotted {'{'}c{'}'} files\n")
                self._rw_log.config(state='disabled')
            self.after(1, _rw_done)
            # FIX: _refresh_ransomware_stats in _auto_start
        self._executor.submit(do)

    def _start_ransomware_monitor(self):
        self.ransomware.start_monitoring()
        self._rw_status_lbl.config(text="* Monitoring: ON", fg=Colors.GAUGE_GREEN)
        self._queue_alert("[LOCK] Ransomware monitor started", Colors.GAUGE_GREEN)

    def _stop_ransomware_monitor(self):
        self.ransomware.stop_monitoring()
        self._rw_status_lbl.config(text="* Monitoring: OFF", fg=Colors.GAUGE_RED)

    def _rollback_files(self):
        if not messagebox.askyesno("🔄 Rollback Files",
                                    "Restore all protected files from snapshots?\n\n"
                                    "This overwrites current files with the last snapshotted versions.\n"
                                    "Only use if ransomware has encrypted your files.\n\nContinue?",
                                    icon='warning'):
            return
        def do():
            count = self.ransomware.rollback_files()
            self.after(0, lambda: messagebox.showinfo("Rollback Complete",
                                                       f"Restored {count} files from snapshots."))
            self._queue_alert(f"Rolled back {count} files", Colors.GAUGE_GREEN)
        self._executor.submit(do)

    # --------------------------------------------------------------------------
    #  MEMORY FORENSICS TAB
