    def _build_memory_tab(self):
        p = self._tab_memory
        tk.Label(p, text="🧬 MEMORY FORENSICS & INJECTION DETECTION",
                 font=('Consolas', 12, 'bold'), fg=Colors.GAUGE_PURPLE,
                 bg=Colors.BG_VOID).pack(anchor='w', padx=10, pady=10)

        btn_row = tk.Frame(p, bg=Colors.BG_VOID)
        btn_row.pack(fill='x', padx=10, pady=4)
        
        def _revert_memory_changes():
            """Revert memory forensics changes."""
            if messagebox.askyesno('Revert Memory Forensics', 
                'This will revert all memory forensics changes:\n\n'
                '- Stop active monitoring\n'
                '- Clear event logs\n'
                '- Reset detection rules\n'
                '- Clear process analysis cache\n\n'
                'Are you sure you want to continue?'):
                try:
                    reverted_items = []
                    
                    # Stop monitoring
                    if hasattr(self, 'mem_forensics') and self.mem_forensics:
                        try:
                            self.mem_forensics.stop_monitoring()
                            reverted_items.append('- Memory monitoring stopped')
                        except Exception as e:
                            reverted_items.append(f'- Stop monitoring: {str(e)}')
                    
                    # Clear logs and cache
                    try:
                        self._mem_clear_log()
                        reverted_items.append('- Event logs cleared')
                    except Exception as e:
                        reverted_items.append(f'- Clear logs: {str(e)}')
                    
                    # Reset detection rules
                    try:
                        if hasattr(self, 'mem_forensics') and self.mem_forensics:
                            self.mem_forensics.reset_detection_rules()
                            reverted_items.append('- Detection rules reset')
                    except Exception as e:
                        reverted_items.append(f'- Reset rules: {str(e)}')
                    
                    # Update UI
                    self._mem_status_lbl.config(text="* Auto-Monitor: OFF", fg=Colors.GAUGE_RED)
                    
                    # Show results
                    result_msg = "Memory Forensics Reverted\n\n"
                    result_msg += "Details:\n" + "\n".join(reverted_items)
                    messagebox.showinfo('Revert Complete', result_msg)
                    
                except Exception as e:
                    messagebox.showerror('Revert Failed', f'Failed to revert memory forensics:\n{str(e)}')

        for text, cmd, color in [
            ("🔍 Scan All Processes", self._mem_scan_all, Colors.GAUGE_BLUE),
            ("> Start Auto-Monitor", self._mem_start_monitor, Colors.GAUGE_GREEN),
            ("⏹️ Stop Monitor",       self._mem_stop_monitor, Colors.GAUGE_ORANGE),
            ("Clear Log",          self._mem_clear_log, Colors.TEXT_DIM),
            ("Revert Changes",     _revert_memory_changes, Colors.GAUGE_PURPLE),
        ]:
            tk.Button(btn_row, text=text, font=('Consolas', 9, 'bold'), fg=color,
                      bg=Colors.GLASS_CARD, relief='flat', padx=8,
                      command=cmd).pack(side='left', padx=4)

        self._mem_status_lbl = tk.Label(p, text="* Auto-Monitor: OFF",
                                        font=('Consolas', 10), fg=Colors.GAUGE_RED,
                                        bg=Colors.BG_VOID)
        self._mem_status_lbl.pack(anchor='w', padx=14, pady=2)

        # Results tree
        cols = ('PID','Process','Score','Classification','Severity','Findings')
        self._mem_tree = ttk.Treeview(p, style='Titan.Treeview', columns=cols, show='headings',
                                       selectmode='browse', height=8)
        widths = {'PID':55,'Process':150,'Score':60,'Classification':110,'Severity':80,'Findings':300}
        for col in cols:
            self._mem_tree.heading(col, text=col)
            self._mem_tree.column(col, width=widths.get(col, 90), stretch=(col=='Findings'))
        sb = tk.Scrollbar(p, orient='vertical', command=self._mem_tree.yview)
        self._mem_tree.configure(yscrollcommand=sb.set)
        self._style_sb(sb)
        self._mem_tree.pack(side='left', fill='both', expand=True, padx=(8,0), pady=4)
        sb.pack(side='left', fill='y', pady=4)

        # Event log on right
        log_frame = tk.Frame(p, bg=Colors.GLASS_CARD, width=280)
        log_frame.pack(side='right', fill='y', padx=8, pady=4)
        log_frame.pack_propagate(False)
        tk.Label(log_frame, text="INJECTION EVENTS", font=('Consolas', 9, 'bold'),
                 fg=Colors.GAUGE_PURPLE, bg=Colors.GLASS_CARD).pack(pady=4)
        self._mem_event_log = tk.Text(log_frame, bg=Colors.GLASS_DARK, fg=Colors.TEXT_LIGHT,
                                       font=('Consolas', 8), wrap='word', state='disabled', relief='flat')
        self._mem_event_log.pack(fill='both', expand=True, padx=4, pady=4)

    def _mem_scan_all(self):
        self._set_status("Memory forensics scan running...")
        def do():
            results = self.mem_forensics.scan_all_processes()
            self.after(1, lambda: self._update_mem_tree(results))
            self.after(0, lambda: self._set_status(f"Memory scan: {len(results)} anomalies found"))
        self._executor.submit(do)

    def _update_mem_tree(self, results: list):
        """Diff-based mem tree update  -  avoids full rebuild jank."""
        self._mem_tree.tag_configure('crit', foreground=Colors.GAUGE_RED)
        self._mem_tree.tag_configure('high', foreground=Colors.GAUGE_ORANGE)
        self._mem_tree.tag_configure('med',  foreground=Colors.GAUGE_YELLOW)
        target = {}
        for r in results:
            findings = '; '.join(r.get('findings', [])[:2])
            score = r['risk_score']
            tag = 'crit' if score >= 80 else ('high' if score >= 60 else 'med')
            key = str(r['pid'])
            target[key] = ((r['pid'], '', score, r['classification'], r['severity'], findings), tag)
        existing = set(self._mem_tree.get_children())
        to_remove = existing - set(target.keys())
        if to_remove:
            self._mem_tree.delete(*to_remove)
        for key, (vals, tag) in target.items():
            if key in existing:
                self._mem_tree.item(key, values=vals, tags=(tag,))
            else:
                self._mem_tree.insert('', 'end', iid=key, values=vals, tags=(tag,))
        # Load recent events
        events = self.mem_forensics.get_recent_events(20)
        self._mem_event_log.config(state='normal')
        try:
            self._mem_event_log.delete('1.0', 'end')
            for ev in events:
                self._mem_event_log.insert('end',
                    f"[{ev['ts'][:16]}] PID {ev['pid']} - {ev['class']} (score:{ev['score']})\n")
        finally:
            self._mem_event_log.config(state='disabled')

    def _mem_start_monitor(self):
        self.mem_forensics.start_monitoring(interval=60)
        self._mem_status_lbl.config(text="* Auto-Monitor: ON (60s)", fg=Colors.GAUGE_GREEN)
        self._queue_alert("[DNA] Memory forensics monitor started", Colors.GAUGE_PURPLE)

    def _mem_stop_monitor(self):
        self.mem_forensics.stop_monitoring()
        self._mem_status_lbl.config(text="* Auto-Monitor: OFF", fg=Colors.GAUGE_RED)

    def _mem_clear_log(self):
        self._mem_event_log.config(state='normal')
        try:
            self._mem_event_log.delete('1.0', 'end')
        finally:
            self._mem_event_log.config(state='disabled')
        self._mem_tree.delete(*self._mem_tree.get_children())

