    def _run_full_compliance_audit(self):
        """Run all compliance checks and populate results tree."""
        tree = getattr(self, '_compliance_tree', None)
        if not tree:
            return
        for item in tree.get_children():
            tree.delete(item)

        checks = []
        import winreg as _wr, subprocess as _sp

        # -- Authentication checks ------------------------------------------
        try:
            k = _wr.OpenKey(_wr.HKEY_LOCAL_MACHINE,
                r'SYSTEM\CurrentControlSet\Control\Lsa')
            val, _ = _wr.QueryValueEx(k, 'LmCompatibilityLevel')
            status = 'PASS' if val >= 5 else 'FAIL'
            checks.append(('NTLM Level >=5 (NTLMv2)', 'Authentication', status,
                           'HIGH' if status == 'FAIL' else 'INFO',
                           'Set LmCompatibilityLevel=5 in HKLM\\SYSTEM\\CCS\\Control\\Lsa'))
        except Exception:
            checks.append(('NTLM Compatibility', 'Authentication', 'UNKNOWN', 'MEDIUM',
                           'Could not read registry key'))

        # -- Encryption checks ----------------------------------------------
        try:
            r = _sp.run(['cipher', '/c', 'C:\\'], capture_output=True, text=True, timeout=5)
            checks.append(('BitLocker / Cipher', 'Encryption', 'INFO', 'LOW',
                           'Verify drive encryption is enabled'))
        except Exception:
            pass

        # -- Firewall checks -----------------------------------------------
        try:
            r = _sp.run(['netsh', 'advfirewall', 'show', 'allprofiles', 'state'],
                        capture_output=True, text=True, timeout=5)
            status = 'PASS' if 'ON' in r.stdout.upper() else 'FAIL'
            checks.append(('Windows Firewall State', 'Firewall', status,
                           'CRITICAL' if status == 'FAIL' else 'INFO',
                           'Enable Windows Firewall on all profiles'))
        except Exception:
            pass

        # -- AutoRun/AutoPlay disabled --------------------------------------
        try:
            k = _wr.OpenKey(_wr.HKEY_LOCAL_MACHINE,
                r'SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\Explorer')
            val, _ = _wr.QueryValueEx(k, 'NoDriveTypeAutoRun')
            status = 'PASS' if val == 255 else 'WARN'
            checks.append(('AutoRun Disabled', 'File Integrity', status,
                           'MEDIUM', 'Set NoDriveTypeAutoRun=255 to disable AutoRun'))
        except Exception:
            checks.append(('AutoRun Disabled', 'File Integrity', 'UNKNOWN', 'MEDIUM',
                           'Policy key not found  -  check manually'))

        # -- UAC ----------------------------------------------------------
        try:
            k = _wr.OpenKey(_wr.HKEY_LOCAL_MACHINE,
                r'SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System')
            val, _ = _wr.QueryValueEx(k, 'EnableLUA')
            status = 'PASS' if val == 1 else 'FAIL'
            checks.append(('UAC Enabled', 'Authentication', status,
                           'HIGH' if status == 'FAIL' else 'INFO',
                           'Enable User Account Control (EnableLUA=1)'))
        except Exception:
            pass

        tag_map = {'PASS': 'pass', 'FAIL': 'fail', 'WARN': 'warning', 'UNKNOWN': 'warning', 'INFO': 'pass'}
        for c in checks:
            tree.insert('', 'end', values=c, tags=(tag_map.get(c[2], 'warning'),))

        # Update score
        total = len(checks)
        passed = sum(1 for c in checks if c[2] == 'PASS')
        score = int(passed / total * 100) if total else 0
        score_lbl = getattr(self, '_compliance_score_lbl', None)
        if score_lbl:
            color = Colors.GAUGE_GREEN if score >= 70 else (Colors.GAUGE_ORANGE if score >= 50 else Colors.GAUGE_RED)
            score_lbl.config(text=f"Security Score: {score} / 100  ({passed}/{total} checks passed)",
                             fg=color)

