    _threat_graph: dict = {}    # {key: {'hits': int, 'layers': set, 'first': ts, 'last': ts}}
    _THREAT_ESCALATE_THRESHOLD = 2   # hits from 2+ layers = CRITICAL escalation

    def _threat_graph_hit(self, key: str, layer: str, detail: str = ''):
        """Register a threat hit in the linked IOC graph. Escalates on multi-layer correlation."""
        import time
        now = time.time()
        if key not in self._threat_graph:
            self._threat_graph[key] = {'hits': 0, 'layers': set(), 'first': now, 'last': now, 'details': []}
        g = self._threat_graph[key]
        g['hits'] += 1
        g['layers'].add(layer)
        g['last'] = now
        if detail:
            g['details'].append(f'[{layer}] {detail}')
        # Escalate if multiple independent layers hit the same IOC
        if len(g['layers']) >= self._THREAT_ESCALATE_THRESHOLD:
            layers_str = ' + '.join(sorted(g['layers']))
            detail_str = chr(10).join(g['details'][-5:])
            msg = (f'[LINKED THREAT] Multi-layer hit on: {key}\n'
                   f'Layers: {layers_str}  Hits: {g["hits"]}\n'
                   f'{detail_str}')
            self._add_alert(msg, Colors.GAUGE_RED)
            # Auto-block if it's an IP
            import re
            if re.match(r'^\d+\.\d+\.\d+\.\d+$', key):
                self._executor.submit(lambda ip=key: self._do_block_ip(ip))
        return g['hits']

