        vsb = ttk.Scrollbar(left, orient='vertical',
                             command=self._kev_tree.yview, style='Vertical.TScrollbar')
        self._kev_tree.configure(yscrollcommand=vsb.set)
        self._kev_tree.pack(side='left', fill='both', expand=True)
        vsb.pack(side='right', fill='y')
        self._kev_tree.bind('<<TreeviewSelect>>', self._on_kev_select)
        self._kev_tree.tag_configure('critical', foreground=Colors.GAUGE_RED)
        self._kev_tree.tag_configure('recent',   foreground=Colors.GAUGE_ORANGE)
        self._kev_tree.tag_configure('ms',       foreground=Colors.GAUGE_TEAL)
        self._kev_tree.tag_configure('normal',   foreground=Colors.TEXT_LIGHT)

        right = tk.Frame(pane, bg=Colors.GLASS_DARK)
        pane.add(right, minsize=340)

        tk.Label(right, text='CVE Detail', font=('Consolas',9,'bold'),
                 bg=Colors.GLASS_DARK, fg=Colors.TEXT_DIM).pack(anchor='w', padx=8, pady=4)

        # CVE detail with scrollbar
        cve_detail_frame = tk.Frame(right, bg=Colors.GLASS_CARD)
        cve_detail_frame.pack(fill='both', expand=True, padx=8, pady=4)
        cve_detail_frame.pack_propagate(False)
        cve_detail_frame.grid_rowconfigure(0, weight=1)
        cve_detail_frame.grid_columnconfigure(0, weight=1)
        
        cve_detail_scrollbar = tk.Scrollbar(cve_detail_frame, orient='vertical')
        cve_detail_scrollbar.grid(row=0, column=1, sticky='ns')
        
        self._kev_detail = tk.Text(cve_detail_frame, font=('Consolas',8),
                                   bg=Colors.GLASS_CARD, fg=Colors.TEXT_LIGHT,
                                   relief='flat', wrap='word',
                                   state='disabled', height=14,
                                   yscrollcommand=cve_detail_scrollbar.set)
        self._kev_detail.grid(row=0, column=0, sticky='nsew')
        cve_detail_scrollbar.config(command=self._kev_detail.yview)

        self._kev_harden_btn = tk.Button(
            right, text='Apply Mitigation for This CVE',
            font=('Consolas',8,'bold'), bg=Colors.GAUGE_GREEN,
            fg='white', relief='flat', padx=8, cursor='hand2',
            state='disabled',
            command=self._apply_selected_cve_hardening)
        self._kev_harden_btn.pack(fill='x', padx=8, pady=2)

        # -- Kernel integrity status ---------------------------------------
        rk = tk.LabelFrame(right, text=' Kernel Integrity ',
                           font=('Consolas',8,'bold'),
                           bg=Colors.GLASS_DARK, fg=Colors.GAUGE_ORANGE,
                           relief='flat', bd=1,
                           highlightbackground=Colors.GAUGE_ORANGE,
                           highlightthickness=1)
        rk.pack(fill='x', padx=8, pady=6)

        self._rootkit_status_var = tk.StringVar(value='Not scanned')
        self._bootkit_status_var = tk.StringVar(value='Not scanned')
        self._mbr_status_var     = tk.StringVar(value='Baseline pending')

        for label, var in [('Rootkit:', self._rootkit_status_var),
                           ('Bootkit:', self._bootkit_status_var),
                           ('MBR:',     self._mbr_status_var)]:
            row = tk.Frame(rk, bg=Colors.GLASS_DARK)
            row.pack(fill='x', padx=6, pady=1)
