    def _refresh_threat_graph_panel(self):
        try:
            graph = getattr(self, '_threat_graph', {})
            if not graph:
                content = '(no correlated multi-layer threats yet)\n'
            else:
                lines = [f'{"IOC":<32} {"Layers":<30} Hits', '-' * 70]
                for key, v in sorted(graph.items(),
                                     key=lambda x: x[1]['hits'],
                                     reverse=True)[:20]:
                    layers = '+'.join(sorted(v['layers']))[:28]
                    lines.append(f'{key[:30]:<32} {layers:<30} {v["hits"]}')
                content = '\n'.join(lines)
            box = getattr(self, '_threat_graph_box', None)
            if box:
                self.after(0, lambda c=content: (
                    box.configure(state='normal'),
                    box.delete('1.0', 'end'),
                    box.insert('1.0', c),
                    box.configure(state='disabled')
                ))
        except Exception:
            pass


