    def _check_iot_exploit_traffic(self):
        """Detect CVE-2021-35394 Realtek exploit traffic on the local network."""
        try:
            import psutil
            conns = psutil.net_connections(kind='inet')
            for c in conns:
                rport = c.raddr.port if c.raddr else None
                lport = c.laddr.port if c.laddr else 0
                if rport in self._REALTEK_EXPLOIT_PORTS or lport in self._REALTEK_EXPLOIT_PORTS:
                    port   = rport or lport
                    rip    = c.raddr.ip if c.raddr else 'local'
                    cvename = self._REALTEK_EXPLOIT_NAMES.get(port, f'IoT exploit port {port}')
                    msg = (f'[CVE-2021-35394] EXPLOIT TRAFFIC DETECTED\n'
                           f'Port {port} ({cvename})\n'
                           f'Remote: {rip}  Status: {c.status}')
                    self._add_alert(msg, Colors.GAUGE_RED)
                    # Auto-block the remote IP
                    if c.raddr and not c.raddr.ip.startswith(('192.168.','10.','172.','127.')):
                        self._executor.submit(lambda ip=c.raddr.ip:
                            self._do_block_ip(ip))
        except Exception as e:
            error_logger.log('IoTExploitCheck', 'check failed', e)




    def _check_iot_devices_on_startup(self):
        """On startup, check ARP table for known vulnerable IoT devices."""
        import subprocess, time
        if getattr(self, '_stop_event', None): self._stop_event.wait(8)
        else: time.sleep(8)
        try:
            r = subprocess.run(['arp','-a'], capture_output=True, text=True, timeout=10, creationflags=_NO_WIN)
            arp_text = r.stdout.lower()
            found = []
            watchlist = getattr(self, '_IOT_WATCHLIST_MACS',
                                {'2c:21:72:6f:5f:c5': 'Realtek CVE-2021-35394 target',
                                 '94:b3:f7:e8:7d:c6': 'Gaoshengda IoT HIGH RISK'})
            for mac, desc in watchlist.items():
                norm = mac.replace(':','-')
                if norm in arp_text or mac in arp_text:
                    # Extract IP
                    for line in r.stdout.splitlines():
                        if norm.lower() in line.lower() or mac.lower() in line.lower():
                            ip = line.strip().split()[0] if line.strip().split() else '?'
                            found.append((ip, mac, desc))
            if found:
                msg_lines = ['[CVE-2021-35394] VULNERABLE IoT DEVICES ONLINE:']
                for ip, mac, desc in found:
                    msg_lines.append(f'  {ip}  {mac.upper()}  {desc}')
                msg_lines.append('ACTION: Update firmware or isolate to IoT VLAN')
                self._queue_alert('\n'.join(msg_lines), Colors.GAUGE_ORANGE)
        except Exception as e:
            error_logger.log('IoTStartupCheck', 'failed', e)


