    def _check_remote_tool_hijacking(self):
        """UEBA: Detect legitimate remote-access tools being hijacked"""
        if not PSUTIL_AVAILABLE:
            return
        try:
            for proc in psutil.process_iter(['pid', 'name', 'cmdline']):
                try:
                    name = proc.name().lower()
                    legitimate = getattr(self, "LEGITIMATE_REMOTE_TOOLS", None) or getattr(getattr(self, "aegis_tcp", None), "LEGITIMATE_REMOTE_TOOLS", set())
                    if name not in legitimate:
                        continue
                    # Check for anomalous connection patterns
                    conns = (proc.net_connections(kind='inet')
                             if hasattr(proc, 'net_connections')
                             else _proc_net_connections(proc, kind='inet'))
                    remote_ips = {c.raddr.ip for c in conns if c.raddr and c.status == 'ESTABLISHED'}
                    for rip in remote_ips:
                        if self.intel.check_ip(rip):
                            self._ueba_anomalies += 1
                            anomaly = {
                                'ts': datetime.now().isoformat(),
                                'tool': name,
                                'pid': proc.pid,
                                'remote_ip': rip,
                                'reason': 'Connecting to known-malicious IP',
                            }
                            self._rat_tool_anomalies.append(anomaly)
                            self._add_alert(
                                f"[ALERT] LEGITIMATE TOOL HIJACKED: '{name}' (PID {proc.pid}) "
                                f"connecting to BLACKLISTED IP {rip}  -  possible RAT takeover!",
                                Colors.GAUGE_RED)
                    # Check for suspicious command line (headless/silent mode = hijack indicator)
                    cmdline = ' '.join(proc.cmdline()).lower()
                    hijack_indicators = ['--no-window', '--silent', '--service-mode', '/quiet',
                                         '--background', '--unattended', '/background']
                    found_indicators = [i for i in hijack_indicators if i in cmdline]
                    if found_indicators and len(remote_ips) > 0:
                        self._ueba_anomalies += 1
                        self._add_alert(
                            f"[!] UEBA ALERT: '{name}' running in silent/headless mode "
                            f"with active connections  -  possible unauthorized lateral movement "
                            f"(flags: {found_indicators})", 'HIGH')
                except (psutil.AccessDenied, psutil.NoSuchProcess):
                    pass
        except Exception as e:
            error_logger.log('AegisTCP', 'Remote tool check failed', e)


    
    def _validate_domain_safe(self, domain: str) -> bool:
        """Additional domain validation to prevent false positives"""
        if not domain or len(domain) < 4 or len(domain) > 255:
            return False
        
        # Skip obviously safe domains
        safe_patterns = [
            r'.*\.windows\.com$',
            r'.*\.microsoft\.com$',
            r'.*\.google\.com$',
            r'.*\.apple\.com$',
            r'.*\.adobe\.com$',
            r'.*\.oracle\.com$',
            r'.*\.github\.com$',
            r'.*\.gitlab\.com$',
        ]
        
        for pattern in safe_patterns:
            if re.match(pattern, domain, re.IGNORECASE):
                return False
        
        return True

    def _check_dns_shield(self):
        """Simulate encrypted DNS shield  -  block known C2 domains at resolver level"""
        try:
            # Check Windows DNS cache for C2 domains
            result = subprocess.run(
                ['ipconfig', '/displaydns'],
                capture_output=True, text=True, timeout=10,
                creationflags=subprocess.CREATE_NO_WINDOW)
            lines = result.stdout.splitlines()
            checked_domains = set()
            for line in lines:
                if 'Record Name' in line and ':' in line:
                    domain = line.split(':', 1)[1].strip().rstrip('.').lower()
                    if domain and domain not in checked_domains and len(domain) > 4:
                        checked_domains.add(domain)
                        try:
                            if self.intel.check_domain(domain):
                                self._dns_blocked = getattr(self, "_dns_blocked", 0) + 1
                                self._add_alert(
                                    f"[SHIELD] DNS SHIELD: C2 domain '{domain}' in DNS cache  -  "
                                    f"poisoning entry to block handshake", Colors.GAUGE_RED)
                                self._poison_hosts(domain)
                        except Exception:
                            pass
        except Exception:
            pass

    def _poison_hosts(self, domain: str):
        """Add C2 domain to hosts file pointing to localhost (DNS sinkhole).

        FIX H3: Domain re-validated through AegisDataNeutralizer before file write.
        PREVIOUS BUG: The domain came from parsing ipconfig /displaydns output with
        a simple string split. A crafted DNS response (or corrupted cache entry)
        could produce a domain string containing a newline character or a space,
        injecting extra lines into the hosts file (e.g. '127.0.0.1 evil.com\\n0.0.0.0 legit.com').
        FIX: Pass through neutralize_domain()  -  any domain failing strict regex is
        silently rejected and the hosts file is never touched.
        """
        # Re-validate: reject anything that doesn't pass the strict domain allowlist
        clean_domain = AegisDataNeutralizer.neutralize_domain(domain)
        if not clean_domain:
            return  # Poisoned / malformed domain from DNS cache  -  discard

        hosts = os.path.join(os.environ.get('SYSTEMROOT', r'C:\Windows'), r'System32\drivers\etc\hosts')
        marker = "# AEGIS-DNS-SHIELD"
        try:
            with open(hosts, 'r', encoding='utf-8', errors='ignore') as f:
                content = f.read()
            if clean_domain not in content:
                # Use elevated write helper to bypass Windows Defender CFA
                new_content = content.rstrip('\n') + f'\n127.0.0.1 {clean_domain} {marker}\n'
                self._write_hosts_elevated(new_content)
        except Exception:
            pass  # requires admin; silent fail is correct here



    # -- Performance helpers ------------------------------------------------

    def _io_submit(self, fn, *args, **kwargs):
        """Submit subprocess/disk I/O work to the dedicated I/O thread pool.
        Keeps the main CPU executor free for logic/scanning tasks."""
        return self._io_executor.submit(fn, *args, **kwargs)

    def _safe_after(self, attr: str, delay_ms: int, fn):
        """Schedule fn after delay_ms, cancelling any pending call stored in attr.
        Prevents duplicate after() timers piling up on rapid events."""
        existing = getattr(self, attr, None)
        if existing:
            try: self.after_cancel(existing)
            except Exception: pass
        handle = self.after(delay_ms, fn)
        setattr(self, attr, handle)
        return handle

    def _debounce_update(self, key: str, delay_ms: int, fn):
        """Debounce UI updates  -  only fire fn after delay_ms of inactivity."""
        self._safe_after(f'_debounce_{key}', delay_ms, fn)


