    # FIX-v28p18: Cache font check result (was calling tkfont.families() per gauge per frame)
    _cascadia_font_available = None  # class-level cache

    def _draw_gauge(self, canvas, size, label, value, max_val, unit, scheme):
        """Draw HD modern arc gauge with optimized rendering."""
        import math
        canvas.delete('all')
        # FIX-v28p20: Fill bg immediately to prevent black flash
        canvas.create_rectangle(0, 0, size+10, size+40,
                                fill=Colors.BG_VOID, outline='')
        cx = size // 2
        cy = size // 2 + 10
        r  = size // 2 - 14

        # FIX-v28p18: Font check cached at class level (was 50ms per call)
        if self.__class__._cascadia_font_available is None:
            try:
                import tkinter.font as tkfont
                self.__class__._cascadia_font_available = 'Cascadia Code' in tkfont.families()
            except Exception:
                self.__class__._cascadia_font_available = False
        _cascadia_available = self.__class__._cascadia_font_available

        # -- Enhanced color scheme with HD colors --------------------------------
        def _heat_color(pct):
            if pct < 0.5:
                g = int(255 * pct * 2)
                return f'#{0:02x}{g:02x}{0:02x}'
            else:
                r2 = int(255 * (pct - 0.5) * 2)
                g2 = int(255 * (1 - (pct - 0.5) * 2))
                return f'#{r2:02x}{g2:02x}{0:02x}'

        def _single_color(scheme):
            return {
                'blue':  Colors.GAUGE_BLUE, 'cyan':  Colors.GAUGE_CYAN,
                'green': Colors.GAUGE_GREEN, 'temp':  None,
                'teal':  Colors.GAUGE_TEAL, 'purple': Colors.GAUGE_PURPLE,
                'orange': Colors.GAUGE_ORANGE, 'red': Colors.GAUGE_RED,
                'yellow': Colors.GAUGE_YELLOW, 'pink': Colors.GAUGE_PINK,
            }.get(scheme, Colors.ACCENT_PRIMARY)

        pct   = min(max(value / max_val, 0.0), 1.0) if max_val else 0.0
        sc    = _single_color(scheme)
        color = _heat_color(pct) if (scheme in ('heat','temp')) else (sc or Colors.ACCENT_PRIMARY)

        # -- Enhanced outer bezel with HD styling ---------------------------------
        canvas.create_oval(cx-r-8, cy-r-8, cx+r+8, cy+r+8,
                           fill=Colors.GLASS_DARK, outline=Colors.CHROME_MID, width=2)

        # -- Track arc with enhanced styling ---------------------------------------
        START_ANG = 220   # degrees (bottom-left)
        END_ANG   = -40   # degrees (bottom-right)
        SWEEP     = 260   # total sweep
        canvas.create_arc(cx-r, cy-r, cx+r, cy+r,
                          start=START_ANG, extent=-SWEEP,
                          style='arc', outline=Colors.CHROME_DARK, width=12)

        # -- Enhanced value arc with glow effect -----------------------------------
        val_sweep = SWEEP * pct
        if val_sweep > 0.5:
            # Outer glow
            canvas.create_arc(cx-r-2, cy-r-2, cx+r+2, cy+r+2,
                               start=START_ANG, extent=-val_sweep,
                               style='arc', outline=color, width=3,
                               dash=(2,4))
            # Main value arc
            canvas.create_arc(cx-r, cy-r, cx+r, cy+r,
                               start=START_ANG, extent=-val_sweep,
                               style='arc', outline=color, width=10)

        # -- Enhanced tick marks with better visibility ---------------------------
        for tick in range(11):
            ang = math.radians(START_ANG - SWEEP * tick / 10)
            ix = cx + (r-14) * math.cos(ang)
            iy = cy - (r-14) * math.sin(ang)
            ox = cx + (r-4)  * math.cos(ang)
            oy = cy - (r-4)  * math.sin(ang)
            w = 3 if tick % 5 == 0 else 2
            tc = Colors.CHROME_LIGHT if tick % 5 else Colors.CHROME_MID
            canvas.create_line(ix, iy, ox, oy, fill=tc, width=w, capstyle='round')

        # -- Enhanced needle with modern styling -----------------------------------
        needle_ang = math.radians(START_ANG - SWEEP * pct)
        nx = cx + (r-20) * math.cos(needle_ang)
        ny = cy - (r-20) * math.sin(needle_ang)
        # Needle shadow with better depth
        canvas.create_line(cx+2, cy+2, nx+2, ny+2, fill=Colors.SHADOW_DARK, width=4, capstyle='round')
        # Main needle
        canvas.create_line(cx, cy, nx, ny, fill=Colors.TEXT_BRIGHT, width=3, capstyle='round')
        # Enhanced pivot dot
        canvas.create_oval(cx-6, cy-6, cx+6, cy+6, fill=Colors.ACCENT_PRIMARY, outline=Colors.CHROME_BRIGHT, width=2)

        # -- Enhanced center value display with HD fonts ---------------------------
        if value == 0 and max_val > 0 and not getattr(self, '_perf_data_received', False):
            disp = '...'
        elif max_val >= 1000:
            disp = f'{int(value):,}'
        elif unit == '%' or unit == ' degC':
            disp = f'{value:.1f}'
        elif unit in ('GB', 'MB/s', 'KB/s', 'MHz'):
            disp = f'{value:.1f}'
        else:
            disp = f'{int(value)}'

        canvas.create_text(cx, cy+14, text=disp,
                           font=('Cascadia Code', 18, 'bold') if _cascadia_available else ('Consolas', 18, 'bold'), fill=color, anchor='center')
        canvas.create_text(cx, cy+30, text=unit,
                           font=('Cascadia Code', 9) if _cascadia_available else ('Consolas', 9), fill=Colors.TEXT_LIGHT, anchor='center')

        # -- Enhanced label with better typography --------------------------------
        canvas.create_text(cx, size+18, text=label,
                           font=('Cascadia Code', 9, 'bold') if _cascadia_available else ('Consolas', 9, 'bold'), fill=Colors.TEXT_LIGHT, anchor='center')

        # -- Enhanced min/max labels ---------------------------------------------
        start_x = cx + (r-2) * math.cos(math.radians(START_ANG))
        start_y = cy - (r-2) * math.sin(math.radians(START_ANG))
        end_x   = cx + (r-2) * math.cos(math.radians(END_ANG))
        end_y   = cy - (r-2) * math.sin(math.radians(END_ANG))
        _small_font = ('Cascadia Code', 7) if _cascadia_available else ('Consolas', 7)
        canvas.create_text(start_x-2, start_y+2, text='0',
                           font=_small_font, fill=Colors.TEXT_DIM, anchor='e')
        canvas.create_text(end_x+2, end_y+2, text=str(max_val),
                           font=_small_font, fill=Colors.TEXT_DIM, anchor='w')

    def _perf_loop(self):
        """Schedule background stats fetch; UI update happens in callback."""
        if not self.winfo_exists():
            return
        def _fetch_and_update():
            try:
                s = self.hw.get_stats()
                if self.winfo_exists():
                    self.after(1, lambda: self._update_perf_ui(s))
            except Exception as e:
                error_logger.log('PerfFetch', 'Stats error', e)
        self._executor.submit(_fetch_and_update)
        self._orig_after(self._adaptive_prf_ms, self._perf_loop)

    def _update_perf_ui(self, s: dict):
        """Apply fetched stats to gauge canvases  -  runs on main thread."""
        if not self.winfo_exists():
            return
        # FIX-v28p9: Skip heavy gauge redraws unless Performance tab is visible
        try:
            current_tab = self.nb.tab(self.nb.select(), 'text') if hasattr(self, 'nb') else ''
            if 'Perf' not in current_tab:  # FIX-v28p20: tab renamed to 'Perf'
                return  # tab not visible, skip all canvas work
        except Exception:
            pass
        try:
            # Mark that real data has been received (so gauges stop showing "...")
            # Use a broader check  -  even uptime > 0 means psutil is working
            if any(s.get(k, 0) for k in ('cpu_percent', 'ram_percent', 'process_count',
                                           'uptime_seconds', 'ram_total_gb', 'cpu_cores')):
                self._perf_data_received = True
            # Update each gauge canvas
            for key, canvas in self._perf_canvases.items():
                if not canvas.winfo_exists():
                    continue
                maxv, unit, scheme, label = self._perf_gauge_meta[key]
                val = s.get(key, 0) or 0
                # Battery -1 means no battery  -  show 0
                if key == 'battery_percent' and val < 0:
                    val = 0
                self._draw_gauge(canvas, 170, label, val, maxv, unit, scheme)

            # Update per-core bars
            per_core = s.get('cpu_per_core', [])
            if per_core:
                # Rebuild bars if core count changed
                if len(self._core_bars) != len(per_core):
                    for w in self._core_bar_frame.winfo_children():
                        w.destroy()
                    self._core_bars.clear()
                    self._core_bar_labels.clear()
                    for i, _ in enumerate(per_core):
                        import tkinter as tk
                        col_frame = tk.Frame(self._core_bar_frame, bg=Colors.BG_VOID)
                        col_frame.grid(row=0, column=i, padx=3, pady=2)
                        self._core_bar_frame.grid_columnconfigure(i, weight=1)
                        lbl = tk.Label(col_frame, text=f'C{i}', font=('Consolas', 7),
                                       fg='#666688', bg=Colors.BG_VOID)
                        lbl.pack()
                        bar_canvas = tk.Canvas(col_frame, width=28, height=80,
                                               bg=Colors.BG_VOID, highlightthickness=0)
                        bar_canvas.pack()
                        val_lbl = tk.Label(col_frame, text='0%', font=('Consolas', 7),
                                           fg='#aaaacc', bg=Colors.BG_VOID)
                        val_lbl.pack()
                        self._core_bars.append(bar_canvas)
                        self._core_bar_labels.append(val_lbl)

                for i, (bar, lbl) in enumerate(zip(self._core_bars, self._core_bar_labels)):
                    if i >= len(per_core): break
                    if not bar.winfo_exists(): continue
                    pct = min(per_core[i], 100) / 100
                    bar.delete('all')
                    bar_h = int(78 * pct)
                    bar.create_rectangle(0, 78, 28, 0, fill='#0d0d1a', outline='')
                    if bar_h > 0:
                        r2 = int(255 * pct) if pct > 0.5 else 0
                        g2 = int(255 * (1-pct)) if pct > 0.5 else int(255 * pct * 2)
                        col = f'#{r2:02x}{g2:02x}00'
                        bar.create_rectangle(1, 78-bar_h, 27, 78, fill=col, outline='')
                    lbl.config(text=f'{per_core[i]:.0f}%',
                               fg='#ff4444' if per_core[i] > 80 else '#aaaacc')

            # Uptime
            uptime = s.get('uptime_seconds', 0)
            if uptime:
                h = int(uptime // 3600)
                m = int((uptime % 3600) // 60)
                d = h // 24
                h = h % 24
                up_str = f'Uptime: {d}d {h:02d}h {m:02d}m'
                procs = s.get('process_count', 0)
                battery = s.get('battery_percent', -1)
                batt_str = f'  |  Battery: {battery:.0f}%{"[ZAP]" if s.get("battery_plugged") else "[BAT]"}' if battery >= 0 else ''
                cpu_name = f'  |  CPU: {s.get("cpu_cores_physical",0)}C/{s.get("cpu_cores",0)}T'
                gpu_name = f'  |  GPU: {s.get("gpu_name","N/A")[:20]}' if s.get('gpu_name') else ''
                self._perf_uptime_lbl.config(
                    text=f'{up_str}  |  {procs} processes{batt_str}{cpu_name}{gpu_name}')

        except Exception as e:
            error_logger.log('PerfFetch', 'Gauge update error', e)

    def _update_perf_ui_header(self, s: dict):
        """Update the uptime/GPU header label."""
        try:
            uptime = s.get('uptime_seconds', 0)
            h = int(uptime // 3600); m = int((uptime % 3600) // 60); d = h // 24; h = h % 24
            procs = s.get('process_count', 0)
            battery = s.get('battery_percent', -1)
            batt_str = f'  |  [BAT]{battery:.0f}%{"[ZAP]" if s.get("battery_plugged") else ""}' if battery >= 0 else ''
            gpu_name = s.get('gpu_name', '')
            gpu_str  = f'  |  GPU: {gpu_name}  {s.get("gpu_percent",0):.0f}%  {s.get("gpu_temp",0):.0f} degC' if gpu_name else ''
            self._perf_uptime_lbl.config(
                text=f'Uptime: {d}d {h:02d}h {m:02d}m  |  {procs} procs{batt_str}{gpu_str}')
        except Exception:
            pass

    def _harden_analyze(self):
        self._set_status("Running security analysis...")
        def do():
            results = self.hardening.analyze()
            score, max_score = self.hardening.get_score()
            summary = self.hardening.get_summary()
            self.after(1, lambda: self._update_harden_tree(results, score, max_score, summary))
            self.after(0, lambda: self._set_status(f"Hardening: {summary}"))
        self._executor.submit(do)

    def _update_harden_tree(self, results, score, max_score, summary):
        self._harden_tree.delete(*self._harden_tree.get_children())
        for r in results:
            status = "[OK] PASS" if r['passed'] else "[X] FAIL"
            tag = 'pass' if r['passed'] else ('crit' if r['severity'] == 'CRITICAL' else 'fail')
            self._harden_tree.insert('', 'end',
                values=(r['name'], r['severity'], r['points'], status), tags=(tag,))
        self._harden_tree.tag_configure('pass', foreground=Colors.GAUGE_GREEN)
        self._harden_tree.tag_configure('crit', foreground=Colors.GAUGE_RED)
        self._harden_tree.tag_configure('fail', foreground=Colors.GAUGE_ORANGE)
        # Score
        pct = score / max_score * 100 if max_score else 0
        color = Colors.GAUGE_GREEN if pct >= 70 else (Colors.GAUGE_ORANGE if pct >= 50 else Colors.GAUGE_RED)
        self._harden_score_lbl.config(text=f"Score: {score}/{max_score} ({pct:.0f}%)", fg=color)
        grade = summary.split('(')[0].strip() if '(' in summary else summary
        self._harden_grade_lbl.config(text=grade)

    def _harden_fix_all(self):
        if not messagebox.askyesno("Fix All Issues",
                                    "Apply all hardening fixes?\n\n"
                                    "Requires Administrator rights.\n"
                                    "Some changes require a restart.\n\nContinue?",
                                    icon='warning'):
            return
        def do():
            fixes = self.hardening.apply_all_fixes()
            self.after(0, lambda: self.winfo_exists() and self._harden_log.config(state='normal'))
            for name, ok, msg in fixes:
                result = f"{'[OK]' if ok else '[X]'} {name}: {msg}\n"
                self.after(0, lambda r=result: self._harden_log.insert('end', r) if self.winfo_exists() else None)
            self.after(0, lambda: self.winfo_exists() and self._harden_log.config(state='disabled'))
            self.after(500, self._harden_analyze)
        self._executor.submit(do)

    def _harden_fix_selected(self):
        sel = self._harden_tree.selection()
        if not sel:
            messagebox.showinfo("Select", "Select a check to fix first")
            return
        name = self._harden_tree.item(sel[0])['values'][0]
        def do():
            ok, msg = self.hardening.apply_fix(name)
            result = f"{'[OK]' if ok else '[X]'} {name}: {msg}\n"
            def _log_one(r=result):
                if not self.winfo_exists(): return
                self._harden_log.config(state='normal')
                self._harden_log.insert('end', r)
                self._harden_log.see('end')
                self._harden_log.config(state='disabled')
            self.after(1, _log_one)
            self.after(500, self._harden_analyze)
        self._executor.submit(do)

