    # ==========================================================================
    #  [MAIL] EMAIL ALERT ENGINE
    # ==========================================================================

    def _send_email_alert(self, subject: str, body: str = '', test: bool = False):
        """Send SMTP email alert for critical threats."""
        if not hasattr(self, '_smtp_enabled') or not self._smtp_enabled.get():
            if test:
                messagebox.showwarning("Email", "Enable email alerts in Settings first.")
            return
        def _send():
            import smtplib
            from email.mime.text import MIMEText
            from email.mime.multipart import MIMEMultipart
            try:
                msg = MIMEMultipart()
                msg['From']    = self._smtp_user.get()
                msg['To']      = self._smtp_to.get()
                msg['Subject'] = f"[Downpour] {subject}"
                body_text = body or (f"Downpour detected:\n\n{subject}\n\n"
                                     f"Time: {datetime.now()}\n"
                                     f"Host: {os.environ.get('COMPUTERNAME','unknown')}")
                msg.attach(MIMEText(body_text, 'plain'))
                with smtplib.SMTP(self._smtp_host.get(), int(self._smtp_port.get())) as srv:
                    srv.starttls()
                    srv.login(self._smtp_user.get(), self._smtp_pass.get())
                    srv.sendmail(self._smtp_user.get(), self._smtp_to.get(), msg.as_string())
                if test:
                    self.after(0, lambda: messagebox.showinfo("Email", "Test email sent!"))
                self._queue_alert(f"Alert emailed: {subject[:50]}", Colors.GAUGE_TEAL)
            except Exception as e:
                err = str(e)
                if test:
                    self.after(0, lambda: messagebox.showerror("Email failed", err))
                error_logger.log('Email', 'SMTP send failed', Exception(err))
        self._executor.submit(_send)

    def _maybe_send_alert_email(self, subject: str, body: str = ''):
        """Send email if enabled  -  called from threat detection paths."""
        if hasattr(self, '_smtp_enabled') and self._smtp_enabled.get():
            self._send_email_alert(subject, body)

    # ==========================================================================
    #  [BELL] SOUND ALARM ENGINE
    # ==========================================================================

    def _play_alarm(self, severity: str = 'CRITICAL'):
        """Play Windows system alarm sound based on threat severity."""
        if not hasattr(self, '_sound_enabled') or not self._sound_enabled.get():
            return
        threshold_val = self._sound_level.get() if hasattr(self, '_sound_level') else 'CRITICAL'
        if threshold_val == 'CRITICAL' and severity != 'CRITICAL':
            return
        if threshold_val == 'HIGH' and severity not in ('CRITICAL', 'HIGH'):
            return
        def _beep():
            try:
                import winsound
                if severity == 'CRITICAL':
                    for _ in range(3):
                        winsound.Beep(1000, 300)
                        winsound.Beep(750,  200)
                elif severity == 'HIGH':
                    winsound.Beep(880, 500)
                else:
                    winsound.Beep(660, 200)
            except Exception:
                pass
        threading.Thread(target=_beep, daemon=True).start()


    # ==========================================================================
    #  [LOCK] VPN CONNECTION TAB
    #  Uses VPN Gate public relay API (vpngate.net)  -  no account required.
    #  Pings all servers in parallel to find lowest latency, then connects
    #  via Windows built-in L2TP or OpenVPN (auto-detected).
    # ==========================================================================

    def _build_vpn_tab(self):
        import base64, csv, io, subprocess, threading, ipaddress
