    def _vpn_log_msg(self, msg: str, color: str = None):
        """Append message to VPN log panel."""
        if color is None: color = Colors.TEXT_DIM
        ts = datetime.now().strftime('%H:%M:%S')
        try:
            self._vpn_log.config(state='normal')
            self._vpn_log.insert('end', f'[{ts}] {msg}\n', ('col',))
            self._vpn_log.tag_configure('col', foreground=color)
            # Re-tag just the last line properly
            last = self._vpn_log.index('end-2l')
            end  = self._vpn_log.index('end-1l')
            tag = f'c{id(msg)%9999}'
            self._vpn_log.tag_configure(tag, foreground=color)
            self._vpn_log.tag_add(tag, last, end)
            self._vpn_log.see('end')
            if int(self._vpn_log.index('end').split('.')[0]) > 200:
                self._vpn_log.delete('1.0', '50.0')
        except Exception:
            pass
        finally:
            self._vpn_log.config(state='disabled')

    def _vpn_set_status(self, connected: bool, label: str = ''):
        """Update LED and status variable."""
        self._vpn_connected = connected
        if connected:
            self._vpn_led.config(fg=Colors.GAUGE_GREEN)
            self._vpn_status_var.set(f'Connected  -  {label}')
        else:
            self._vpn_led.config(fg=Colors.GAUGE_RED)
            self._vpn_status_var.set('Disconnected')

    def _vpn_fetch_public_ip(self):
        """Fetch public IP in background and update display."""
        def _fetch():
            try:
                import urllib.request
                ip = urllib.request.urlopen(
                    'https://api.ipify.org', timeout=5).read().decode().strip()
                if self.winfo_exists():
                    self.after(1, lambda _ip=ip: self._vpn_ip_var.set(f'Public IP: {_ip}'))
            except Exception:
                pass
        self._executor.submit(_fetch)

