    def _vpn_load_servers(self):
        """Load VPN server list from multiple sources in background."""
        self._vpn_progress_var.set('Loading VPN servers from all sources...')
        def _load():
            import urllib.request, csv, io, base64, json
            all_servers = []
            loaded_sources = []

            for src in self._VPN_SOURCES:
                try:
                    src_name = src['name']
                    src_type = src['type']

                    if src_type == 'static':
                        entries = src.get('static', [])
                        all_servers.extend(entries)
                        loaded_sources.append(f'{src_name} ({len(entries)})')
                        continue

                    req = urllib.request.Request(
                        src['url'],
                        headers={'User-Agent': 'Mozilla/5.0 (compatible; Downpour/26)'},
                    )
                    raw = urllib.request.urlopen(req, timeout=12).read().decode('utf-8', errors='replace')

                    if src_type == 'vpngate_csv':
                        lines = [l for l in raw.splitlines() if not l.startswith('*')]
                        reader = csv.DictReader(lines)
                        count = 0
                        for row in reader:
                            try:
                                speed_bps = int(row.get('Speed', 0) or 0)
                                speed_mbps = round(speed_bps / 1_000_000, 1)
                                sessions = int(row.get('NumVpnSessions', 0) or 0)
                                ovpn_b64 = row.get('OpenVPN_ConfigData_Base64', '')
                                ovpn_cfg = ''
                                if ovpn_b64:
                                    try: ovpn_cfg = base64.b64decode(ovpn_b64).decode('utf-8', errors='replace')
                                    except Exception: pass
                                entry = {
                                    'country':    row.get('CountryLong', '?').strip(),
                                    'country_s':  row.get('CountryShort', '?').strip(),
                                    'host':       row.get('HostName', '').strip(),
                                    'ip':         row.get('#HostName', row.get('IP', '')).strip(),
                                    'ping':       None,
                                    'speed_mbps': speed_mbps,
                                    'sessions':   sessions,
                                    'operator':   row.get('🏢 Operator', '').strip()[:40],
                                    'l2tp':       row.get('SupportL2TP', '0') == '1',
                                    'ovpn':       bool(ovpn_cfg),
                                    'ovpn_cfg':   ovpn_cfg,
                                    'sstp':       row.get('SupportSSTP', '0') == '1',
                                    'source':     src_name,
                                }
                                # deduplicate by IP
                                if not any(s['ip'] == entry['ip'] for s in all_servers):
                                    all_servers.append(entry)
                                    count += 1
                            except Exception:
                                continue
                        loaded_sources.append(f'{src_name} ({count})')

                    elif src_type == 'protonvpn_json':
                        data = json.loads(raw)
                        servers_raw = data.get('LogicalServers', [])
                        count = 0
                        for srv in servers_raw:
                            try:
                                # Only free-tier servers (Tier=0)
                                if srv.get('Tier', 1) != 0:
                                    continue
                                for sub in srv.get('Servers', []):
                                    ip = sub.get('EntryIP', '')
                                    if not ip:
                                        continue
                                    entry = {
                                        'country':    srv.get('ExitCountry', '?'),
                                        'country_s':  srv.get('ExitCountry', '?'),
                                        'host':       srv.get('Name', ip),
                                        'ip':         ip,
                                        'ping':       None,
                                        'speed_mbps': round(srv.get('Bandwidth', 0) / 1_000_000, 1),
                                        'sessions':   srv.get('Load', 0),
                                        'operator':   'ProtonVPN Free',
                                        'l2tp':       False,
                                        'ovpn':       True,
                                        'ovpn_cfg':   '',
                                        'sstp':       False,
                                        'source':     'ProtonVPN Free',
                                    }
                                    if not any(s['ip'] == entry['ip'] for s in all_servers):
                                        all_servers.append(entry)
                                        count += 1
                            except Exception:
                                continue
                        if count > 0:
                            loaded_sources.append(f'ProtonVPN Free ({count})')

                    elif src_type == 'generic_json':
                        try:
                            data = json.loads(raw)
                            if isinstance(data, list):
                                for item in data[:100]:
                                    try:
                                        ip = item.get('ip', item.get('host', ''))
                                        if not ip:
                                            continue
                                        entry = {
                                            'country':    item.get('country', '?'),
                                            'country_s':  item.get('country_short', '?'),
                                            'host':       ip,
                                            'ip':         ip,
                                            'ping':       None,
                                            'speed_mbps': float(item.get('speed', 0)),
                                            'sessions':   0,
                                            'operator':   item.get('operator', src_name),
                                            'l2tp':       False,
                                            'ovpn':       True,
                                            'ovpn_cfg':   '',
                                            'sstp':       False,
                                            'source':     src_name,
                                        }
                                        all_servers.append(entry)
                                    except Exception:
                                        continue
                        except Exception:
                            pass

                except Exception as e:
                    if self.winfo_exists():
                        self.after(0, lambda _n=src['name'], _e=str(e):
                            self._vpn_log_msg(f'{_n}: {_e[:60]}', Colors.GAUGE_ORANGE))

            # Sort by speed desc
            all_servers.sort(key=lambda s: s.get('speed_mbps', 0), reverse=True)
            summary = ', '.join(loaded_sources) if loaded_sources else 'No sources loaded'
            if self.winfo_exists():
                self.after(0, lambda sv=all_servers, sm=summary:
                    (self._vpn_populate_tree(sv),
                     self._vpn_log_msg(f'Sources: {sm}', Colors.GAUGE_TEAL)))

        self._executor.submit(_load)

    def _vpn_populate_tree(self, servers: list):
        """Fill treeview with server list."""
        self._vpn_servers = servers
        self._vpn_apply_filter()
        self._vpn_progress_var.set(
            f'Loaded {len(servers)} servers. Click "Ping All Servers" to find the fastest.')
        self._vpn_log_msg(f'Loaded {len(servers)} VPN Gate servers.', Colors.GAUGE_TEAL)

    def _vpn_apply_filter(self):
        """Re-populate treeview based on current filter settings."""
        proto  = self._vpn_proto_var.get()
        ctry   = self._vpn_country_var.get().lower().strip()
        source = getattr(self, '_vpn_source_var', None)
        src_flt = source.get() if source else 'All'
        try:   min_speed = float(self._vpn_speed_var.get())
        except Exception: min_speed = 0.0

        filtered = []
        for s in self._vpn_servers:
            if proto == 'L2TP'      and not s.get('l2tp'): continue
            if proto == 'OpenVPN'   and not s.get('ovpn'): continue
            if proto == 'SSTP'      and not s.get('sstp'): continue
            if proto == 'WireGuard' and not s.get('wireguard', False): continue
            if ctry and ctry not in s.get('country', '').lower(): continue
            if s.get('speed_mbps', 0) < min_speed: continue
            if src_flt != 'All' and src_flt not in s.get('source', ''): continue
            filtered.append(s)

        self._vpn_tree.delete(*self._vpn_tree.get_children())
        for s in filtered:
            ping_str = f"{s['ping']} ms" if s['ping'] is not None else ' - '
            proto_str = '/'.join(filter(None, [
                'L2TP' if s['l2tp'] else '',
                'OVPN' if s['ovpn'] else '',
                'SSTP' if s['sstp'] else '',
            ]))
            speed_str = f"{s['speed_mbps']} Mbps" if s['speed_mbps'] else ' - '
            tag = 'nodata'
            if s['ping'] is not None:
                tag = 'fast' if s['ping'] < 80 else ('ok' if s['ping'] < 200 else 'slow')
            iid = s['host']
            if iid in (self._vpn_tree.get_children() if False else []):
                iid = s['host'] + '_' + s['ip']
            src_lbl = s.get('source', 'VPN Gate')
            try:
                self._vpn_tree.insert('', 'end', iid=iid, tags=(tag,),
                    values=(s['country'], s['host'], ping_str, speed_str,
                            proto_str, s['sessions'], s['operator'], src_lbl))
            except Exception:
                self._vpn_tree.insert('', 'end', tags=(tag,),
                    values=(s['country'], s['host'], ping_str, speed_str,
                            proto_str, s['sessions'], s['operator'], src_lbl))

        self._vpn_progress_var.set(f'Showing {len(filtered)} of {len(self._vpn_servers)} servers.')

    def _vpn_toggle_killswitch(self):
        """Enable/disable VPN kill switch via Windows firewall.
        Requires admin  -  app must be run elevated (launch_downpour.bat handles this).
        Uses CREATE_NO_WINDOW on all netsh calls to avoid console flicker."""
        enabled = getattr(self, '_vpn_killswitch_var', None)
        if not enabled:
            return
        on = enabled.get()
        # Guard: netsh advfirewall requires admin rights
        try:
            import ctypes as _ct
            if not _ct.windll.shell32.IsUserAnAdmin():
                from tkinter import messagebox as _mb
                _mb.showwarning('Kill Switch',
                    'Kill Switch requires Administrator privileges.\n'
                    'Please re-launch via launch_downpour.bat (run as Admin).')
                if hasattr(self, '_vpn_killswitch_var'):
                    self._vpn_killswitch_var.set(False)
                return
        except Exception:
            pass
        try:
            _F = _NO_WIN  # CREATE_NO_WINDOW
            if on:
                # Block ALL internet traffic except local  -  must connect VPN first
                subprocess.run(['netsh', 'advfirewall', 'set', 'allprofiles', 'firewallpolicy',
                         'blockinbound,blockoutbound'], capture_output=True, check=False,
                         creationflags=_F)
                # Allow local loopback + DNS
                subprocess.run(['netsh', 'advfirewall', 'firewall', 'add', 'rule',
                         'name=Downpour_KS_Allow_DNS', 'dir=out', 'action=allow',
                         'protocol=UDP', 'remoteport=53'], capture_output=True, check=False,
                         creationflags=_F)
                self._vpn_log_msg('[KILL SWITCH] ENABLED - all traffic blocked until VPN connected.',
                                   Colors.GAUGE_RED)
            else:
                # Restore default inbound block / outbound allow
                subprocess.run(['netsh', 'advfirewall', 'set', 'allprofiles', 'firewallpolicy',
                         'blockinbound,allowoutbound'], capture_output=True, check=False,
                         creationflags=_F)
                subprocess.run(['netsh', 'advfirewall', 'firewall', 'delete', 'rule',
                         'name=Downpour_KS_Allow_DNS'], capture_output=True, check=False,
                         creationflags=_F)
                self._vpn_log_msg('[KILL SWITCH] DISABLED - normal traffic policy restored.',
                                   Colors.GAUGE_GREEN)
        except Exception as e:
            self._vpn_log_msg(f'Kill switch error: {e}', Colors.GAUGE_RED)

    def _vpn_import_ovpn(self):
        """Import a .ovpn config file and add it as a custom server entry."""
        from tkinter import filedialog as _fd
        path = _fd.askopenfilename(
            filetypes=[("OpenVPN Config", "*.ovpn *.conf"), ("All files", "*.*")],
            title="Import OpenVPN Config")
        if not path:
            return
        try:
            with open(path, 'r', errors='replace') as fh:
                cfg_text = fh.read()
            import re as _re, os.path as _op
            # Extract remote host from config
            m = _re.search(r'^remote\s+(\S+)\s+(\d+)', cfg_text, _re.MULTILINE)
            host = m.group(1) if m else _op.basename(path)
            port = m.group(2) if m else '1194'
            entry = {
                'country':    'Custom',
                'country_s':  'XX',
                'host':       host,
                'ip':         host,
                'ping':       None,
                'speed_mbps': 0,
                'sessions':   0,
                'operator':   f'Custom ({_op.basename(path)})',
                'l2tp':       False,
                'ovpn':       True,
                'ovpn_cfg':   cfg_text,
                'sstp':       False,
                'source':     'Custom Import',
            }
            self._vpn_servers.insert(0, entry)
            self._vpn_apply_filter()
            self._vpn_log_msg(
                f'[OK] Imported: {_op.basename(path)} -> {host}:{port}',
                Colors.GAUGE_GREEN)
        except Exception as e:
            self._vpn_log_msg(f'Import error: {e}', Colors.GAUGE_RED)

    def _vpn_ping_server(self, host: str) -> int:
        """Measure latency to a VPN server using TCP connect timing.
        Uses port 443 (HTTPS) so it appears as normal web traffic to routers/IDS.
        Falls back to port 80, then 1194 (OpenVPN), then 1723 (PPTP).
        No ICMP packets are sent — avoids router IDS flags entirely.
        Returns round-trip ms, or 9999 on failure.
        """
        import socket, time
        PROBE_PORTS = [443, 80, 1194, 1723]
        TIMEOUT     = 3.0   # seconds per attempt
        SAMPLES     = 2     # TCP handshakes to average (keeps traffic minimal)

        best_ms = 9999
        for port in PROBE_PORTS:
            readings = []
            for _ in range(SAMPLES):
                try:
                    t0 = time.perf_counter()
                    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
                        s.settimeout(TIMEOUT)
                        err = s.connect_ex((host, port))
                        elapsed = int((time.perf_counter() - t0) * 1000)
                    if err == 0 or err in (10061, 111):
                        # 10061/111 = connection refused — host is reachable,
                        # port just not listening.  Still a valid RTT.
                        readings.append(max(1, elapsed))
                except OSError:
                    pass
            if readings:
                avg = sum(readings) // len(readings)
                if avg < best_ms:
                    best_ms = avg
                break   # got a result from this port — no need to try others
        return best_ms

    def _vpn_test_connectivity(self):
        """Test basic network connectivity using TCP port 443 (HTTPS).
        No ICMP — avoids router IDS flags on rented/ISP routers."""
        # Use well-known HTTPS endpoints — TCP :443 looks like normal web browsing
        test_targets = [
            ('dns.google',      443),
            ('one.one.one.one', 443),
            ('www.google.com',  443),
        ]
        results = []
        import socket, time
        for host, port in test_targets:
            try:
                t0  = time.perf_counter()
                with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
                    s.settimeout(3.0)
                    err = s.connect_ex((host, port))
                    ms  = int((time.perf_counter() - t0) * 1000)
                if err == 0:
                    results.append(f"[OK] {host}:{port}  {ms}ms")
                else:
                    results.append(f"[X] {host}:{port}  unreachable (err {err})")
            except Exception as e:
                results.append(f"[X] {host}: error - {str(e)[:50]}")

        self._vpn_log_msg("Connectivity Test (TCP :443):", Colors.GAUGE_BLUE)
        for result in results:
            color = Colors.GAUGE_GREEN if "[OK]" in result else Colors.GAUGE_RED
            self._vpn_log_msg(f"  {result}", color)

    def _vpn_ping_all(self):
        """Ping all visible servers in parallel, update tree with latencies."""
        visible = list(self._vpn_servers)
        if not visible:
            self._vpn_log_msg('No servers loaded. Click Refresh List first.', Colors.GAUGE_ORANGE)
            return
        self._ts_var_set(self._vpn_progress_var, f'Pinging {len(visible)} servers... (this takes ~15 seconds)')
        self._ts(self._vpn_ping_btn.config, state='disabled', text='Pinging...')
        self._vpn_log_msg(f'Starting parallel ping of {len(visible)} servers...', Colors.GAUGE_TEAL)

        def _ping_worker(server):
            host = server.get('host') or server.get('ip')
            if not host:
                return
            try:
                ms = self._vpn_ping_server(host)
                server['ping'] = ms if 0 < ms < 9999 else None
                self._vpn_ping_results[host] = ms
                
                # Update progress occasionally
                completed = len(self._vpn_ping_results)
                total = len(self._vpn_servers)
                if completed % 10 == 0 or completed == total:
                    reachable = sum(1 for v in self._vpn_ping_results.values() if 0 < v < 9999)
                    self._ts_var_set(self._vpn_progress_var, f'Pinging {completed}/{total} servers... {reachable} reachable')
            except Exception as e:
                server['ping'] = None
                self._vpn_ping_results[host] = 9999

        def _do_all():
            import concurrent.futures
            _ncpu = __import__("os").cpu_count()
            _hwp = getattr(self, '_hw_profile', None)
            if _hwp:
                _workers = getattr(_hwp, 'workers_cpu', max(1, _ncpu // 2))
            else:
                _workers = max(1, _ncpu // 2)  # Conservative fallback
            with concurrent.futures.ThreadPoolExecutor(max_workers=_workers) as pool:
                list(pool.map(_ping_worker, visible))
            if self.winfo_exists():
                self.after(1, _done)

        def _done():
            self._vpn_servers.sort(key=lambda s: (s['ping'] or 9999, -s['speed_mbps']))
            self._vpn_apply_filter()
            reachable = sum(1 for s in visible if s['ping'] is not None)
            best = min((s for s in visible if s.get('ping') and s['ping'] > 0), key=lambda s: s['ping'], default=None)
            msg = f'Ping complete: {reachable}/{len(visible)} reachable.'
            if best:
                msg += f' Fastest: {best["country"]} ({best["host"]})  -  {best["ping"]} ms'
            
            if reachable == 0:
                msg += ' No servers reachable - testing basic connectivity...'
                self._vpn_progress_var.set(msg)
                self._vpn_log_msg(msg, Colors.GAUGE_RED)
                self.after(1000, self._vpn_test_connectivity)
            else:
                self._vpn_progress_var.set(msg)
                self._vpn_log_msg(msg, Colors.GAUGE_GREEN)
            
            self._vpn_ping_btn.config(state='normal', text='Ping All Servers')

        self._executor.submit(_do_all)

    def _vpn_connect_fastest(self):
        """Find lowest-ping server and connect to it."""
        pinged = [s for s in self._vpn_servers if s['ping'] is not None]
        if not pinged:
            # No pings yet  -  ping first then connect
            self._vpn_log_msg('No ping data yet. Pinging servers first...', Colors.GAUGE_ORANGE)
            def _after_ping():
                time.sleep(18)   # wait for pings to complete
                if self.winfo_exists():
                    self.after(1, self._vpn_connect_fastest)
            import threading
            threading.Thread(target=lambda: (self._vpn_ping_all(), _after_ping()), daemon=True).start()
            return

        pinged.sort(key=lambda s: (s['ping'], -s['speed_mbps']))
        best = pinged[0]
        self._vpn_log_msg(
            f'[ZAP] Fastest server: {best["country"]} {best["host"]} '
            f'({best["ping"]} ms, {best["speed_mbps"]} Mbps)',
            Colors.GAUGE_GREEN)
        self._vpn_connect_server(best)

    def _vpn_connect_selected(self):
        """Connect to the currently selected treeview row."""
        sel = self._vpn_tree.selection()
        if not sel:
            self._vpn_log_msg('Select a server first.', Colors.GAUGE_ORANGE)
            return
        iid = sel[0]
        # Find matching server
        vals = self._vpn_tree.item(iid, 'values')
        host = vals[1] if vals else ''
        server = next((s for s in self._vpn_servers if s['host'] == host), None)
        if not server:
            self._vpn_log_msg(f'Server not found: {host}', Colors.GAUGE_RED)
            return
        self._vpn_connect_server(server)

    def _vpn_connect_server(self, server: dict):
        """Connect using best available method: OpenVPN > Windows L2TP > rasdial."""
        if self._vpn_connected:
            self._vpn_disconnect()

        host    = server.get('host') or server.get('ip')
        country = server.get('country', '?')
        self._vpn_log_msg(f'Connecting to {country} ({host})...', Colors.GAUGE_TEAL)
        self._vpn_set_status(False, '')
        self._vpn_progress_var.set(f'Connecting to {country}  -  {host}...')

        def _do_connect():
            # -- Try OpenVPN if config available and openvpn.exe on PATH ----
            if server.get('ovpn') and server.get('ovpn_cfg'):
                try:
                    import shutil, tempfile
                    if shutil.which('openvpn'):
                        # FIX: Write to a secure temp location with restricted permissions
                        # then zero-wipe after use (previously left plaintext config in %TEMP%)
                        import stat as _stat
                        cfg_path = os.path.join(tempfile.gettempdir(),
                                                f'dpvpn_{os.getpid()}_{int(time.time())}.ovpn')
                        # Write clean config (strip existing auth-nocache to avoid dup)
                        cfg = server['ovpn_cfg']
                        cfg += '\nauth-nocache\npull-filter ignore redirect-gateway\n'
                        with open(cfg_path, 'w') as _vpnf:
                            _vpnf.write(cfg)
                        # Restrict to current user only
                        try:
                            subprocess.run(
                                ['icacls', cfg_path, '/inheritance:r',
                                 '/grant:r', f'{os.environ.get("USERNAME","user")}:(R)'],
                                capture_output=True, timeout=5,
                                creationflags=0x08000000)
                        except Exception:
                            pass
                        self._vpn_proc = subprocess.Popen(
                            ['openvpn', '--config', cfg_path, '--verb', '3'],
                            stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                            creationflags=0x08000000, text=True)
                        # Monitor for connected signal
                        conn_ok = False
                        for line in self._vpn_proc.stdout:
                            line = line.strip()
                            if self.winfo_exists():
                                self.after(1, lambda l=line: self._vpn_log_msg(l, Colors.TEXT_DIM))
                            if 'Initialization Sequence Completed' in line:
                                conn_ok = True
                                break
                            if self._vpn_proc.poll() is not None:
                                break
                        if conn_ok and self.winfo_exists():
                            self._vpn_current_name = f'OpenVPN:{host}'
                            self.after(1, lambda: (
                                self._vpn_set_status(True, f'{country} ({host}) via OpenVPN'),
                                self._vpn_progress_var.set(f'Connected via OpenVPN  -  {country}'),
                                self._vpn_log_msg('[OK] OpenVPN connected!', Colors.GAUGE_GREEN),
                                self._vpn_fetch_public_ip(),
                                self._vpn_highlight_row(host),
                            ))
                            return
                except Exception as e:
                    if self.winfo_exists():
                        self.after(1, lambda err=str(e): self._vpn_log_msg(
                            f'OpenVPN failed: {err}', Colors.GAUGE_ORANGE))

            # -- Fall back to Windows built-in L2TP (no auth needed for VPN Gate) -
            if server.get('l2tp'):
                try:
                    conn_name = f'DownpourVPN_{host}'
                    # Remove old connection with same name (ignore errors)
                    subprocess.run(
                        ['powershell', '-NoProfile', '-Command',
                         f'Remove-VpnConnection -Name "{conn_name}" -Force -ErrorAction SilentlyContinue'],
                        capture_output=True, timeout=10, creationflags=0x08000000)
                    # Add new L2TP connection
                    r = subprocess.run(
                        ['powershell', '-NoProfile', '-Command',
                         f'Add-VpnConnection -Name "{conn_name}" '
                         f'-ServerAddress "{host}" '
                         f'-TunnelType L2tp '
                         f'-AuthenticationMethod MSChapv2 '  # FIX: PAP sends credentials in cleartext  -  use MSChapv2
                         f'-L2tpPsk "" '
                         f'-Force '
                         f'-AllUserConnection'],
                        capture_output=True, text=True, timeout=20,
                        creationflags=0x08000000)
                    # Connect using rasdial
                    r2 = subprocess.run(
                        ['rasdial', conn_name, 'vpn', 'vpn'],
                        capture_output=True, text=True, timeout=30,
                        creationflags=0x08000000)
                    if r2.returncode == 0 or 'connected' in r2.stdout.lower():
                        self._vpn_current_name = conn_name
                        if self.winfo_exists():
                            self.after(1, lambda: (
                                self._vpn_set_status(True, f'{country} ({host}) via L2TP'),
                                self._vpn_progress_var.set(f'Connected via L2TP  -  {country}'),
                                self._vpn_log_msg('[OK] L2TP connected!', Colors.GAUGE_GREEN),
                                self._vpn_fetch_public_ip(),
                                self._vpn_highlight_row(host),
                            ))
                        return
                    else:
                        err = r2.stderr or r2.stdout
                        if self.winfo_exists():
                            self.after(1, lambda e=err: self._vpn_log_msg(
                                f'L2TP failed: {e[:120]}', Colors.GAUGE_ORANGE))
                except Exception as e:
                    if self.winfo_exists():
                        self.after(1, lambda err=str(e): self._vpn_log_msg(
                            f'L2TP error: {err}', Colors.GAUGE_RED))

            # -- Final fallback: SSTP -------------------------------------
            if server.get('sstp'):
                try:
                    conn_name = f'DownpourVPN_SSTP_{host}'
                    subprocess.run(
                        ['powershell', '-NoProfile', '-Command',
                         f'Remove-VpnConnection -Name "{conn_name}" -Force -ErrorAction SilentlyContinue'],
                        capture_output=True, timeout=10, creationflags=0x08000000)
                    subprocess.run(
                        ['powershell', '-NoProfile', '-Command',
                         f'Add-VpnConnection -Name "{conn_name}" '
                         f'-ServerAddress "{host}" '
                         f'-TunnelType Sstp -Force -AllUserConnection'],
                        capture_output=True, timeout=20, creationflags=0x08000000)
                    r2 = subprocess.run(
                        ['rasdial', conn_name],
                        capture_output=True, text=True, timeout=30,
                        creationflags=0x08000000)
                    if r2.returncode == 0:
                        self._vpn_current_name = conn_name
                        if self.winfo_exists():
                            self.after(1, lambda: (
                                self._vpn_set_status(True, f'{country} ({host}) via SSTP'),
                                self._vpn_log_msg('[OK] SSTP connected!', Colors.GAUGE_GREEN),
                                self._vpn_fetch_public_ip(),
                            ))
                        return
                except Exception as e:
                    if self.winfo_exists():
                        self.after(1, lambda err=str(e): self._vpn_log_msg(
                            f'SSTP error: {err}', Colors.GAUGE_RED))

            if self.winfo_exists():
                self.after(1, lambda: (
                    self._vpn_log_msg('[X] All connection methods failed for this server. Try another.', Colors.GAUGE_RED),
                    self._vpn_progress_var.set('Connection failed  -  try another server.'),
                ))

        self._executor.submit(_do_connect)

    def _vpn_disconnect(self):
        """Disconnect active VPN."""
        if self._vpn_proc:
            try:
                self._vpn_proc.terminate()
                self._vpn_proc = None
            except Exception:
                pass
        if self._vpn_current_name:
            def _disc():
                try:
                    subprocess.run(['rasdial', self._vpn_current_name, '/disconnect'],
                                   capture_output=True, timeout=10,
                                   creationflags=0x08000000)
                    subprocess.run(
                        ['powershell', '-NoProfile', '-Command',
                         f'Remove-VpnConnection -Name "{self._vpn_current_name}" '
                         f'-Force -ErrorAction SilentlyContinue'],
                        capture_output=True, timeout=10, creationflags=0x08000000)
                except Exception:
                    pass
                if self.winfo_exists():
                    self.after(1, lambda: (
                        self._vpn_set_status(False),
                        self._vpn_log_msg('[R] Disconnected.', Colors.GAUGE_RED),
                        self._vpn_progress_var.set('Disconnected.'),
                        self._vpn_fetch_public_ip(),
                    ))
            self._executor.submit(_disc)
            self._vpn_current_name = ''
        else:
            self._vpn_set_status(False)
            self._vpn_log_msg('Not connected.', Colors.TEXT_DIM)

    def _vpn_highlight_row(self, host: str):
        """Mark the connected row green in the treeview."""
        try:
            for iid in self._vpn_tree.get_children():
                vals = self._vpn_tree.item(iid, 'values')
                if vals and vals[1] == host:
                    self._vpn_tree.item(iid, tags=('connected',))
                else:
                    # Restore original tag
                    for s in self._vpn_servers:
                        if vals and s['host'] == vals[1] and s['ping'] is not None:
                            tag = 'fast' if s['ping'] < 80 else ('ok' if s['ping'] < 200 else 'slow')
                            self._vpn_tree.item(iid, tags=(tag,))
        except Exception:
            pass

    def _vpn_sort(self, col: str):
        """Sort treeview by column header click."""
        items = [(self._vpn_tree.set(k, col), k) for k in self._vpn_tree.get_children('')]
        # Numeric sort for ping/speed
        def key(x):
            v = x[0].replace(' ms','').replace(' Mbps','').replace(' - ','99999')
            try: return float(v)
            except Exception: return v.lower()
        items.sort(key=key)
        for idx, (_, k) in enumerate(items):
            self._vpn_tree.move(k, '', idx)

    # ==========================================================================
    #  [PLUG] USB DEVICE CONTROL
    # ==========================================================================

    def _get_drive_letters(self) -> set:
        """Return set of (letter, type) tuples for all current drives."""
        drives = set()
        try:
            r = subprocess.run(
                ['powershell','-Command',
                 'Get-PSDrive -PSProvider FileSystem | Select-Object Name,'
                 '@{N="Type";E={(Get-WmiObject Win32_LogicalDisk -Filter "DeviceID=\'$($_.Name):\'").DriveType}}'
                 ' | ConvertTo-Csv -NoTypeInformation'],
                capture_output=True, text=True, timeout=10,
                creationflags=subprocess.CREATE_NO_WINDOW)
            import csv, io
            type_map = {'2':'Removable','3':'Fixed','4':'Network','5':'CDROM','6':'RAM'}
            try:
                for row in csv.DictReader(io.StringIO(r.stdout)):
                    try:
                        name  = row.get('Name','').strip('"')
                        dtype = type_map.get(str(row.get('Type','')).strip('"').strip(), 'Unknown')
                        if name:
                            drives.add((name, dtype))
                    except (ValueError, KeyError, AttributeError) as e:
                        # Skip malformed rows
                        continue
            except Exception as e:
                # If CSV parsing fails, try fallback method
                try:
                    import psutil
                    for partition in psutil.disk_partitions():
                        if partition.device and partition.device.endswith('\\'):
                            drive = partition.device[0]  # Extract C from C:\
                            drives.add((drive, 'Unknown'))
                except Exception:
                    pass
        except Exception:
            pass
        return drives

    def _get_usb_device_id(self, drive_letter: str) -> str:
        try:
            r = subprocess.run(
                ['powershell','-Command',
                 f"(Get-WmiObject Win32_LogicalDisk -Filter \"DeviceID='{drive_letter}:'\").PNPDeviceID"],
                capture_output=True, text=True, timeout=8,
                creationflags=subprocess.CREATE_NO_WINDOW)
            return r.stdout.strip()
        except Exception:
            return ''

    def _block_usb_drive(self, drive_letter: str):
        try:
            key = winreg.CreateKey(winreg.HKEY_LOCAL_MACHINE,
                                   r'SYSTEM\CurrentControlSet\Control\StorageDevicePolicies')
            winreg.SetValueEx(key, 'WriteProtect', 0, winreg.REG_DWORD, 1)
            winreg.CloseKey(key)
            self._queue_alert(f"[LOCK] USB {drive_letter}: write-protected", Colors.GAUGE_RED)
        except Exception as e:
            error_logger.log('USB', 'Block failed', e)

    def _scan_drive(self, drive_letter: str):
        path = f'{drive_letter}:\\'
        if not os.path.isdir(path):
            return
        self._queue_alert(f"[SEARCH] Auto-scanning USB {drive_letter}:...", Colors.GAUGE_BLUE)
        def _do():
            import queue as _q
            _fq = _q.Queue()
            _hits = 0
            _lock = threading.Lock()
            # Collect all files first
            for root, dirs, files in os.walk(path):
                dirs[:] = [d for d in dirs if not d.startswith('.')]
                for fn in files:
                    _fq.put(os.path.join(root, fn))
            total_files = _fq.qsize()
            _ncpu = __import__('os').cpu_count() or 4
            _nw = min(max(_ncpu * 2, 4), 32)
            def _scan_one():
                nonlocal _hits
                while True:
                    try:
                        fp = _fq.get_nowait()
                    except Exception:
                        break
                    try:
                        if self.yara.scan_file(fp):
                            with _lock:
                                _hits += 1
                            _fp = fp; self._queue_alert(f"[ALERT] USB MALWARE: {_fp}", Colors.GAUGE_RED)
                            self._play_alarm('CRITICAL')
                            self._maybe_send_alert_email(f"USB malware found: {fp}")
                    except Exception:
                        pass
            from concurrent.futures import ThreadPoolExecutor as _UTPE, as_completed as _uac
            with _UTPE(max_workers=_nw, thread_name_prefix='usb-scan') as _up:
                futs = [_up.submit(_scan_one) for _ in range(_nw)]
                for _ in _uac(futs):
                    pass
            self._queue_alert(f"[OK] USB scan done: {drive_letter}:  -  {_hits} threats / {total_files} files | {_nw} threads",
                                         Colors.GAUGE_RED if _hits else Colors.GAUGE_TEAL)
        self._executor.submit(_do)

    # ==========================================================================
    #  [SHIELD] ZERO TRUST POSTURE SCORE
    # ==========================================================================

    def _compute_zero_trust_score(self):
        """Calculate a comprehensive Zero Trust security posture score (0-100)."""
        def _calc():
            score = 0; max_pts = 0; details = []
            def _chk(label, pts, passed, note=''):
                nonlocal score, max_pts
                max_pts += pts
                if passed: score += pts
                details.append(('[OK]' if passed else '[X]') + f" [{pts}pt] {label}" +
                                (f"  -  {note}" if note else ''))
            _chk('MFA / Conditional Access',         15, False,  'Enable MFA on all accounts')
            _chk('Privileged account separation',    10, self._check_privileged_separation())
            _chk('Guest account disabled',            5, not self._guest_account_active())
            _chk('Password policy (min 8 chars)',     5, self._check_password_policy())
            _chk('BitLocker drive encryption',
                 10 if not getattr(self,'_bypass_tpm_bitlocker',False) else 0,
                 self._check_bitlocker_active(),
                 '(bypassed by user)' if getattr(self,'_bypass_tpm_bitlocker',False) else '')
            _chk('Secure Boot enabled',
                 8 if not getattr(self,'_bypass_tpm_bitlocker',False) else 0,
                 self._check_secure_boot(),
                 '(bypassed by user)' if getattr(self,'_bypass_tpm_bitlocker',False) else '')
            _chk('HVCI / Memory Integrity',           8, self._check_hvci().get('hvci', False))
            _chk('Windows Defender enabled',          8, self._check_defender_enabled())
            _chk('Firewall all profiles ON',          5, self._check_firewall_all())
            _chk('SMBv1 disabled (EternalBlue)',      5, self._check_smb1_disabled())
            _chk('ASR rules active (3+)',             5, self._check_asr_active())
            _chk('UAC enabled',                       4, self._check_uac_enabled())
            _chk('DNS-over-HTTPS',                    4, self._check_dns_over_https())
            _chk('RDP disabled (if unused)',           3, self._check_rdp_disabled())
            _chk('No suspicious open ports (<1024)', 3, self._check_no_suspicious_listeners())
            _chk('PS ExecutionPolicy restricted',     3, self._check_ps_restricted())
            _chk('WSH / VBScript disabled',           3, self._check_wsh_disabled())
            _chk('AutoRun disabled',                  3, self._check_autorun_disabled())
            _chk('Driver Signature Enforcement',      3, self._check_driver_sig_enforcement())
            pct   = int(score / max_pts * 100) if max_pts else 0
            grade = 'A' if pct>=90 else 'B' if pct>=80 else 'C' if pct>=70 else 'D' if pct>=50 else 'F'
            color = Colors.GAUGE_TEAL if pct>=80 else Colors.GAUGE_ORANGE if pct>=60 else Colors.GAUGE_RED
            summary = f"Zero Trust Score: {pct}/100 (Grade {grade})\n{score}/{max_pts} points\n\n"
            summary += '\n'.join(details)
            self.after(0, lambda:
                self._zt_score_lbl.configure(
                    text=f"[SHIELD] Zero Trust Posture: {pct}/100  -  Grade {grade}", fg=color))
            self.after(0, lambda s=summary: messagebox.showinfo("Zero Trust Posture Score", s))
            self._queue_alert(f"[SHIELD] Zero Trust Score: {pct}/100 Grade {grade}", color)
        self._executor.submit(_calc)

    def _check_privileged_separation(self) -> bool:
        try:
            r = subprocess.run(['whoami','/groups'], capture_output=True, text=True,
                               creationflags=subprocess.CREATE_NO_WINDOW, timeout=5)
            return 'S-1-5-32-544' not in r.stdout
        except Exception:
            return False

    def _guest_account_active(self) -> bool:
        try:
            r = subprocess.run(['net','user','Guest'], capture_output=True, text=True,
                               creationflags=subprocess.CREATE_NO_WINDOW, timeout=5)
            return 'Account active               Yes' in r.stdout
        except Exception:
            return False

    def _check_password_policy(self) -> bool:
        try:
            r = subprocess.run(['net','accounts'], capture_output=True, text=True,
                               creationflags=subprocess.CREATE_NO_WINDOW, timeout=5)
            for line in r.stdout.splitlines():
                if 'Minimum password length' in line:
                    val = [x for x in line.split() if x.isdigit()]
                    if val and int(val[0]) >= 8:
                        return True
            return False
        except Exception:
            return False

    def _check_bitlocker_active(self) -> bool:
        if getattr(self, '_bypass_tpm_bitlocker', False):
            return True   # user-bypassed  -  not required on this machine
        try:
            r = subprocess.run(['manage-bde','-status','C:'], capture_output=True,
                               text=True, creationflags=subprocess.CREATE_NO_WINDOW, timeout=15)
            return 'Protection On' in r.stdout or 'Fully Encrypted' in r.stdout
        except Exception:
            return False

    def _check_secure_boot(self) -> bool:
        if getattr(self, '_bypass_tpm_bitlocker', False):
            return True   # user-bypassed
        try:
            r = subprocess.run(['powershell','-Command','Confirm-SecureBootUEFI'],
                               capture_output=True, text=True, timeout=8,
                               creationflags=subprocess.CREATE_NO_WINDOW)
            return 'True' in r.stdout
        except Exception:
            return False

    def _check_defender_enabled(self) -> bool:
        try:
            k = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                               r'SOFTWARE\Microsoft\Windows Defender', 0, winreg.KEY_READ)
            disabled, _ = winreg.QueryValueEx(k, 'DisableAntiSpyware')
            winreg.CloseKey(k)
            return not disabled
        except Exception:
            return True

    def _check_firewall_all(self) -> bool:
        try:
            r = subprocess.run(['netsh','advfirewall','show','allprofiles','state'],
                               capture_output=True, text=True, timeout=8,
                               creationflags=subprocess.CREATE_NO_WINDOW)
            return r.stdout.count('ON') >= 3
        except Exception:
            return False

    def _check_smb1_disabled(self) -> bool:
        try:
            r = subprocess.run(['powershell','-Command',
                                'Get-SmbServerConfiguration | Select EnableSMB1Protocol'],
                               capture_output=True, text=True, timeout=12,
                               creationflags=subprocess.CREATE_NO_WINDOW)
            return 'False' in r.stdout
        except Exception:
            return False

    def _check_asr_active(self) -> bool:
        try:
            r = subprocess.run(['powershell','-Command',
                                'Get-MpPreference | Select AttackSurfaceReductionRules_Ids'],
                               capture_output=True, text=True, timeout=12,
                               creationflags=subprocess.CREATE_NO_WINDOW)
            return len([l.strip() for l in r.stdout.splitlines()
                        if l.strip() and len(l.strip()) > 10]) >= 3
        except Exception:
            return False

    def _check_uac_enabled(self) -> bool:
        try:
            k = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                               r'SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System',
                               0, winreg.KEY_READ)
            lua, _ = winreg.QueryValueEx(k, 'EnableLUA')
            winreg.CloseKey(k)
            return lua == 1
        except Exception:
            return False

    def _check_rdp_disabled(self) -> bool:
        try:
            k = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                               r'SYSTEM\CurrentControlSet\Control\Terminal Server',
                               0, winreg.KEY_READ)
            deny, _ = winreg.QueryValueEx(k, 'fDenyTSConnections')
            winreg.CloseKey(k)
            return deny == 1
        except Exception:
            return False

    def _check_no_suspicious_listeners(self) -> bool:
        try:
            if not PSUTIL_AVAILABLE:
                return True
            return len([c for c in psutil.net_connections(kind='inet')
                        if c.status == 'LISTEN' and c.laddr
                        and 0 < c.laddr.port < 1024
                        and c.laddr.port not in (80, 443, 445, 135)]) == 0
        except Exception:
            return True

    def _check_ps_restricted(self) -> bool:
        try:
            r = subprocess.run(['powershell','-Command','Get-ExecutionPolicy'],
                               capture_output=True, text=True, timeout=8,
                               creationflags=subprocess.CREATE_NO_WINDOW)
            return r.stdout.strip() in ('AllSigned', 'RemoteSigned', 'Restricted')
        except Exception:
            return False

    def _check_wsh_disabled(self) -> bool:
        try:
            k = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                               r'SOFTWARE\Microsoft\Windows Script Host\Settings',
                               0, winreg.KEY_READ)
            val, _ = winreg.QueryValueEx(k, 'Enabled')
            winreg.CloseKey(k)
            return val == 0
        except Exception:
            return False

    def _check_autorun_disabled(self) -> bool:
        try:
            k = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                               r'SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\Explorer',
                               0, winreg.KEY_READ)
            val, _ = winreg.QueryValueEx(k, 'NoDriveTypeAutoRun')
            winreg.CloseKey(k)
            return val >= 0xFF
        except Exception:
            return False

    def _check_driver_sig_enforcement(self) -> bool:
        try:
            r = subprocess.run(['powershell','-Command',
                                'bcdedit /enum | Select-String "nointegritychecks"'],
                               capture_output=True, text=True, timeout=8,
                               creationflags=subprocess.CREATE_NO_WINDOW)
            return 'yes' not in r.stdout.lower()
        except Exception:
            return True

    # ==========================================================================
    #  [LOCK] HOSTS FILE  -  ELEVATED WRITE HELPER
    # ==========================================================================

    HOSTS_PATH = r'C:\Windows\System32\drivers\etc\hosts'

    def _write_hosts_elevated(self, new_content: str) -> bool:
        """Write new_content to the system hosts file, bypassing Windows Defender
        Controlled Folder Access (CFA) which blocks python.exe from writing to
        %SystemRoot%\\System32\\drivers\\etc\\ even as Administrator.

        Strategy:
          1. Try a direct open() write first (works if CFA is off or python.exe
             is already in the CFA allowlist).
          2. On PermissionError / OSError: write content to a temp file outside
             the protected folder, then use a PowerShell one-liner running under
             the SAME admin token (no new UAC prompt) to copy it into place.
             PowerShell/cmd are in the CFA default allowlist so this always works.
          3. Flush the DNS cache afterwards.

        Returns True on success, False on failure.
        """
        hosts = self.HOSTS_PATH
        # Backup before any write
        try:
            import shutil as _sh
            _sh.copy2(hosts, hosts + '.downpour.bak')
        except Exception:
            pass

        # --- Attempt 1: direct write (fast path) ---
        try:
            with open(hosts, 'w', encoding='utf-8', newline='\n') as _f:
                _f.write(new_content)
            self._dns_flush_cache()
            return True
        except (PermissionError, OSError):
            pass  # fall through to elevated copy

        # --- Attempt 2: write to temp, then PowerShell copy (bypasses CFA) ---
        try:
            import tempfile, os as _os
            # Write to a temp file in APPDATA (never a CFA-protected folder)
            tmp_fd, tmp_path = tempfile.mkstemp(prefix='dp_hosts_', suffix='.tmp',
                                                 dir=os.environ.get('TEMP', None))
            try:
                with os.fdopen(tmp_fd, 'w', encoding='utf-8', newline='\n') as _tf:
                    _tf.write(new_content)

                # PowerShell Copy-Item is in the CFA allowlist by default
                _NO_WIN = getattr(subprocess, 'CREATE_NO_WINDOW', 0x08000000)
                ps_cmd = (
                    f"Copy-Item -Path '{tmp_path}' -Destination '{hosts}' -Force; "
                    f"ipconfig /flushdns | Out-Null"
                )
                result = subprocess.run(
                    ['powershell', '-NoProfile', '-NonInteractive',
                     '-ExecutionPolicy', 'Bypass', '-Command', ps_cmd],
                    capture_output=True, text=True, timeout=15,
                    creationflags=_NO_WIN
                )
                if result.returncode == 0:
                    return True
                # Try cmd copy as fallback (cmd.exe also CFA-allowlisted)
                result2 = subprocess.run(
                    ['cmd', '/c', f'copy /y "{tmp_path}" "{hosts}"'],
                    capture_output=True, text=True, timeout=10,
                    creationflags=_NO_WIN
                )
                if result2.returncode == 0:
                    self._dns_flush_cache()
                    return True
                error_logger.log('HostsWrite', 'Elevated copy failed',
                                 Exception(result.stderr.strip()))
                return False
            finally:
                try: _os.unlink(tmp_path)
                except Exception: pass
        except Exception as _e:
            error_logger.log('HostsWrite', 'Temp-copy method failed', _e)
            return False

    def _append_hosts_elevated(self, line: str) -> bool:
        """Append a single line to the hosts file using the elevated write helper."""
        try:
            with open(self.HOSTS_PATH, 'r', encoding='utf-8', errors='ignore') as _f:
                current = _f.read()
        except Exception:
            current = ''
        if line.split()[1] in current if len(line.split()) >= 2 else False:
            return True  # already present
        new_content = current.rstrip('\n') + '\n' + line + '\n'
        return self._write_hosts_elevated(new_content)

    # ==========================================================================
    #  [CANARY] DNS CANARY TOKEN DETECTION
    # ==========================================================================

    def _deploy_dns_canary(self):
        """Deploy a canary DNS hostname in hosts file to detect enumeration/exfil."""
        canary_host = 'canary-' + secrets.token_hex(4) + '.internal.downpour'
        canary_ip   = '192.0.2.1'   # RFC5737  -  never routable
        try:
            ok = self._append_hosts_elevated(
                f'{canary_ip} {canary_host}  # DOWNPOUR_CANARY')
            if ok:
                if not hasattr(self, '_canary_hosts'):
                    self._canary_hosts = []
                self._canary_hosts.append(canary_host)
                self._queue_alert(f"DNS Canary deployed: {canary_host}", Colors.GAUGE_TEAL)
            else:
                messagebox.showwarning("Canary", "Could not write hosts file.\nCheck Windows Defender CFA settings.")
        except Exception as e:
            error_logger.log('Canary', 'Deploy failed', e)

    def _check_canary_resolution(self):
        """Check DNS cache for canary hostname resolution  -  triggers on exfil/recon."""
        if not hasattr(self, '_canary_hosts') or not self._canary_hosts:
            return
        try:
            r = subprocess.run(
                ['powershell','-Command','Get-DnsClientCache | ConvertTo-Csv -NoTypeInformation'],
                capture_output=True, text=True, timeout=10,
                creationflags=subprocess.CREATE_NO_WINDOW)
            for canary in self._canary_hosts:
                if canary.lower() in r.stdout.lower():
                    msg = f"[ALERT] CANARY TRIGGERED: {canary} was resolved  -  recon/exfil suspected!"
                    _m = msg; self._queue_alert(_m, Colors.GAUGE_RED)
                    self._play_alarm('CRITICAL')
                    self._maybe_send_alert_email(msg)
                    self.db.execute(
                        "INSERT OR IGNORE INTO threat_events"
                        " (timestamp,type,name,detail,severity) VALUES (?,?,?,?,?)",
                        (datetime.now().isoformat(), 'CanaryTriggered',
                         canary, 'Canary DNS hostname resolved', Colors.GAUGE_RED))
        except Exception:
            pass

    def _canary_monitor_loop(self):
        if not self.winfo_exists(): return
        self._executor.submit(self._check_canary_resolution)
        self._orig_after(60_000, self._canary_monitor_loop)

    # ==========================================================================
    #  [DARK] DARK WEB LEAK MONITOR
    # ==========================================================================

    def _check_darkweb_leaks(self, target: str):
        """Check HaveIBeenPwned + Pastebin dump search for email/domain leaks."""
        def _check():
            import urllib.request, urllib.parse
            results = []
            # HIBP breach list (public endpoint, no key required for breach listing)
            try:
                req = urllib.request.Request(
                    'https://haveibeenpwned.com/api/v3/breaches',
                    headers={'User-Agent': 'Downpour-SecuritySuite/20'})
                with urllib.request.urlopen(req, timeout=10) as resp:
                    try:
                        breaches = json.loads(resp.read())
                    except (json.JSONDecodeError, ValueError):
                        breaches = []
                domain_part = target.split('@')[-1].lower() if '@' in target else target.lower()
                hits = [b for b in breaches
                        if domain_part in b.get('Domain','').lower()]
                for h in hits[:8]:
                    results.append(
                        f"Breach: {h['Name']} ({h.get('BreachDate','?')})  -  "
                        f"{h.get('PwnCount',0):,} accounts  -  "
                        f"{', '.join((h.get('DataClasses') or [])[:3])}")
            except Exception:
                pass
            # Pastebin dump search (psbdmp public API)
            try:
                q   = urllib.parse.quote(target)
                req = urllib.request.Request(
                    f'https://psbdmp.ws/api/v3/search/{q}',
                    headers={'User-Agent': 'Downpour-SecuritySuite/20'})
                with urllib.request.urlopen(req, timeout=8) as resp:
                    raw = resp.read()
                try:
                    data = json.loads(raw)
                except (ValueError, TypeError):
                    data = {}
                if isinstance(data, dict) and data.get('data'):
                        results.append(f"Pastebin hits: {len(data['data'])} pastes mention '{target}'")
            except Exception:
                pass
            if results:
                for r in results:
                    _r = r; self._queue_alert(f"DARK WEB: {_r}", Colors.GAUGE_RED)
                self._play_alarm('HIGH')
                self._maybe_send_alert_email(f"Dark web leak: {target}", '\n'.join(results))
            else:
                self._queue_alert(f"Dark web: no known breaches for '{target}'",
                                    Colors.GAUGE_TEAL)
        self._executor.submit(_check)

    def _prompt_and_check_darkweb(self):
        import tkinter.simpledialog as sd
        target = sd.askstring("Dark Web Check",
                              "Enter email or domain to check\n(uses HaveIBeenPwned public API):",
                              parent=self)
        if target and target.strip():
            self._check_darkweb_leaks(target.strip())

    # ==========================================================================
    #  [FILES] FORENSIC EVIDENCE COLLECTOR (IR Kit)
    # ==========================================================================

    def _collect_forensic_evidence(self, reason: str = 'manual') -> str:
        """Comprehensive incident response evidence snapshot."""
        ts     = datetime.now().strftime('%Y%m%d_%H%M%S')
        ir_dir = DATA_DIR / 'ir_kits' / ts
        ir_dir.mkdir(parents=True, exist_ok=True)
        report = {'timestamp': datetime.now().isoformat(), 'reason': reason,
                  'hostname': os.environ.get('COMPUTERNAME','unknown'), 'sections': {}}

        # Processes
        try:
            procs = []
            for p in psutil.process_iter(['pid','name','exe','cmdline','username','create_time']):
                try:
                    info = dict(p.info)
                    info['create_time'] = datetime.fromtimestamp(
                        info.get('create_time',0)).isoformat()
                    procs.append(info)
                except Exception:
                    pass
            report['sections']['processes'] = procs
        except Exception:
            pass

        # Network connections
        try:
            report['sections']['network'] = [
                {'laddr': f"{c.laddr.ip}:{c.laddr.port}" if c.laddr else '',
                 'raddr': f"{c.raddr.ip}:{c.raddr.port}" if c.raddr else '',
                 'status': c.status, 'pid': c.pid}
                for c in psutil.net_connections(kind='inet')]
        except Exception:
            pass

        # Autoruns
        autoruns = {}
        for hkey, hname, subkey in [
            (winreg.HKEY_CURRENT_USER,  'HKCU', r'SOFTWARE\Microsoft\Windows\CurrentVersion\Run'),
            (winreg.HKEY_LOCAL_MACHINE, 'HKLM', r'SOFTWARE\Microsoft\Windows\CurrentVersion\Run'),
        ]:
            try:
                key = winreg.OpenKey(hkey, subkey, 0, winreg.KEY_READ)
                entries = {}; i = 0
                while True:
                    try:
                        n, v, _ = winreg.EnumValue(key, i); entries[n] = v; i += 1
                    except OSError:
                        break
                winreg.CloseKey(key)
                autoruns[f'{hname}\\Run'] = entries
            except Exception:
                pass
        report['sections']['autoruns'] = autoruns

        # Scheduled tasks (suspicious)
        report['sections']['suspicious_tasks'] = self._check_schtasks_suspicious()

        # DNS cache
        try:
            r = subprocess.run(
                ['powershell','-Command','Get-DnsClientCache | ConvertTo-Csv -NoTypeInformation'],
                capture_output=True, text=True, timeout=10,
                creationflags=subprocess.CREATE_NO_WINDOW)
            report['sections']['dns_cache'] = r.stdout[:30000]
        except Exception:
            pass

        # Security events (last 50)
        try:
            r = subprocess.run(
                ['wevtutil','qe','Security',
                 '/q:*[System[(EventID=4624 or EventID=4625 or EventID=4648 or EventID=4672)]]',
                 '/c:50','/f:Text'],
                capture_output=True, text=True, timeout=15,
                creationflags=subprocess.CREATE_NO_WINDOW)
            report['sections']['security_events'] = r.stdout[:80000]
        except Exception:
            pass

        # WMI subscriptions
        report['sections']['wmi_subscriptions'] = self._check_wmi_subscriptions()

        # ARP table
        try:
            r = subprocess.run(['arp','-a'], capture_output=True, text=True,
                               creationflags=subprocess.CREATE_NO_WINDOW, timeout=8)
            report['sections']['arp_table'] = r.stdout
        except Exception:
            pass

        # Save JSON
        report_path = ir_dir / 'ir_report.json'
        with open(report_path, 'w', encoding='utf-8') as f:
            json.dump(report, f, indent=2, default=str)

        # Text summary
        txt_path = ir_dir / 'ir_summary.txt'
        with open(txt_path, 'w', encoding='utf-8') as f:
            f.write(f"DOWNPOUR  -  INCIDENT RESPONSE SNAPSHOT\n{'='*55}\n")
            f.write(f"Time: {report['timestamp']}\nReason: {reason}\nHost: {report['hostname']}\n\n")
            procs_list = report['sections'].get('processes', [])
            f.write(f"PROCESSES ({len(procs_list)})\n{'-'*40}\n")
            for proc in sorted(procs_list, key=lambda x: x.get('pid',0)):
                f.write(f"  PID {proc.get('pid','?'):6}  {proc.get('name','?'):<28}  {str(proc.get('exe') or proc.get('cmdline',''))[:60]}\n")
            net_list = report['sections'].get('network', [])
            f.write(f"\nACTIVE CONNECTIONS ({len([c for c in net_list if c.get('raddr')])})\n{'-'*40}\n")
            for c in net_list:
                if c.get('raddr'):
                    f.write(f"  {c.get('status','?'):<12}  {c.get('laddr',''):<22} -> {c.get('raddr','')}\n")
            f.write(f"\nAUTORUNS\n{'-'*40}\n")
            for reg, entries in report['sections'].get('autoruns', {}).items():
                f.write(f"  [{reg}]\n")
                for n, v in entries.items():
                    f.write(f"    {n} = {str(v)[:80]}\n")
            susp = report['sections'].get('suspicious_tasks', [])
            if susp:
                f.write(f"\nSUSPICIOUS SCHEDULED TASKS ({len(susp)})\n{'-'*40}\n")
                for t in susp:
                    f.write(f"  {t.get('task','?')}\n    -> {t.get('action','')[:80]}\n")
            wmi = report['sections'].get('wmi_subscriptions', [])
            if wmi:
                f.write(f"\nWMI SUBSCRIPTIONS (PERSISTENCE)\n{'-'*40}\n")
                for s in wmi:
                    f.write(f"  {s}\n")

        self._queue_alert(f"IR kit collected -> {ir_dir}", Colors.GAUGE_TEAL)
        return str(ir_dir)

    def _run_ir_collect(self):
        def _do():
            ir_path = self._collect_forensic_evidence('user_initiated')
            self.after(0, lambda p=ir_path: [
                messagebox.showinfo("IR Kit",
                    f"Evidence collected:\n{p}\n\nContains: processes, network, autoruns,"
                    f"\nDNS cache, security events, WMI subscriptions, ARP table."),
                subprocess.Popen(['explorer', p])])
        self._executor.submit(_do)

