    def _build_vuln_tab(self):
        p = self._tab_vuln
        p.grid_rowconfigure(1, weight=1)
        p.grid_columnconfigure(0, weight=1)

        # Header + controls
        hdr = tk.Frame(p, bg=Colors.GLASS_CARD)
        hdr.grid(row=0, column=0, sticky='ew', padx=8, pady=(8,4))
        hdr.grid_columnconfigure(3, weight=1)
        tk.Label(hdr, text="🕳️ ZERO-DAY VULNERABILITY SCANNER",
                 font=('Consolas', 11, 'bold'), fg=Colors.GAUGE_RED, bg=Colors.GLASS_CARD
                 ).grid(row=0, column=0, padx=10, pady=6, sticky='w')

        self._vuln_score_lbl = tk.Label(hdr, text="Security Score: --",
                                         font=('Consolas', 12, 'bold'),
                                         fg=Colors.GAUGE_ORANGE, bg=Colors.GLASS_CARD)
        self._vuln_score_lbl.grid(row=0, column=1, padx=20)

        tk.Button(hdr, text="> RUN FULL SCAN", font=('Consolas', 9, 'bold'),
                  bg=Colors.GAUGE_RED, fg='white', relief='flat', padx=10, pady=4,
                  command=self._run_vuln_scan
                  ).grid(row=0, column=2, padx=8, pady=6)

        tk.Button(hdr, text="[HIGH] FIX ALL (Admin)", font=('Consolas', 9),
                  bg=Colors.GAUGE_ORANGE, fg='white', relief='flat', padx=10, pady=4,
                  command=self._vuln_fix_all
                  ).grid(row=0, column=3, padx=4, pady=6, sticky='w')

        # Results pane
        body = tk.Frame(p, bg=Colors.BG_VOID)
        body.grid(row=1, column=0, sticky='nsew', padx=8, pady=4)
        body.grid_rowconfigure(0, weight=1)
        body.grid_columnconfigure(0, weight=1)

        cols = ('Check', 'Status', 'Severity', 'Detail', 'Fix')
        self._vuln_tree = ttk.Treeview(body, style='Titan.Treeview', columns=cols, show='headings', height=22)
        for col, w in zip(cols, [200, 70, 70, 340, 200]):
            self._vuln_tree.heading(col, text=col)
            self._vuln_tree.column(col, width=w, minwidth=40, stretch=(col=='Detail'))
        self._vuln_tree.tag_configure('CRITICAL', foreground=Colors.GAUGE_RED)
        self._vuln_tree.tag_configure('HIGH',     foreground=Colors.GAUGE_ORANGE)
        self._vuln_tree.tag_configure('MEDIUM',   foreground=Colors.GAUGE_YELLOW)
        self._vuln_tree.tag_configure('LOW',      foreground=Colors.GAUGE_BLUE)
        self._vuln_tree.tag_configure('PASS',     foreground=Colors.GAUGE_TEAL)
        self._vuln_tree.tag_configure('INFO',     foreground=Colors.TEXT_DIM)
        self._vuln_tree.grid(row=0, column=0, sticky='nsew')
        sb = ttk.Scrollbar(body, orient='vertical', command=self._vuln_tree.yview, style='Vertical.TScrollbar')
        sb.grid(row=0, column=1, sticky='ns')
        self._vuln_tree.configure(yscrollcommand=sb.set)
        self._vuln_tree.bind('<Double-Button-1>', lambda e: self._vuln_apply_fix())

        self._vuln_checks: List[dict] = []

    def _run_vuln_scan(self):
        self._vuln_tree.delete(*self._vuln_tree.get_children())
        def _scan():
            # v28p35: rain no longer needs throttling — 24fps delta-time handles load
            pass
            checks = []
            score  = 100

            def _add(name, passed, severity, detail, fix_cmd=''):
                nonlocal score
                status = '[OK] PASS' if passed else '[X] FAIL'
                tag    = 'PASS' if passed else severity
                if not passed:
                    deduction = {'CRITICAL':25,'HIGH':15,'MEDIUM':8,'LOW':3,'INFO':0}.get(severity, 5)
                    score = max(0, score - deduction)
                checks.append({'name':name,'passed':passed,'severity':severity,
                                'detail':detail,'fix':fix_cmd,'tag':tag,'status':status})
                self.after_idle(lambda n=name, s=status, sv=severity, d=detail, f=fix_cmd, t=tag:
                    self._vuln_tree.insert('',  'end', values=(n, s, sv, d, f or 'Manual'), tags=(t,)))

            # -- 1. Windows Defender / AV ----------------------------------
            try:
                import winreg
                key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                     r'SOFTWARE\Microsoft\Windows Defender', 0, winreg.KEY_READ)
                disabled, _ = winreg.QueryValueEx(key, 'DisableAntiSpyware')
                winreg.CloseKey(key)
                _add('Windows Defender Enabled', not disabled, 'CRITICAL',
                     'Defender disabled  -  system unprotected', 'powershell Set-MpPreference -DisableRealtimeMonitoring $false')
            except Exception:
                _add('Windows Defender Enabled', True, 'INFO', 'Could not check (may be 3rd-party AV)')

            # -- 2. Windows Firewall ---------------------------------------
            try:
                r = subprocess.run(['netsh','advfirewall','show','allprofiles','state'],
                                   capture_output=True, text=True, creationflags=subprocess.CREATE_NO_WINDOW, timeout=10)
                fw_on = r.stdout.count('ON') >= 2
                _add('Windows Firewall Active', fw_on, 'HIGH',
                     f"Profiles with firewall ON: {r.stdout.count('ON')}/3",
                     'netsh advfirewall set allprofiles state on')
            except Exception as e:
                _add('Windows Firewall Active', False, 'HIGH', str(e))

            # -- 3. UAC Level ----------------------------------------------
            try:
                key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                     r'SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System',
                                     0, winreg.KEY_READ)
                lua, _  = winreg.QueryValueEx(key, 'EnableLUA')
                cpb, _  = winreg.QueryValueEx(key, 'ConsentPromptBehaviorAdmin')
                winreg.CloseKey(key)
                uac_ok = lua == 1 and cpb >= 2
                _add('UAC Enabled (Level >= 2)', uac_ok, 'HIGH',
                     f"EnableLUA={lua} ConsentPromptBehavior={cpb}",
                     'reg add HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\System /v EnableLUA /t REG_DWORD /d 1 /f')
            except Exception as e:
                _add('UAC Level Check', False, 'HIGH', str(e))

            # -- 4. SMBv1 disabled -----------------------------------------
            try:
                r = subprocess.run(['powershell','-Command','Get-SmbServerConfiguration | Select EnableSMB1Protocol'],
                                   capture_output=True, text=True, creationflags=subprocess.CREATE_NO_WINDOW, timeout=15)
                smb1_off = 'False' in r.stdout
                _add('SMBv1 Disabled (EternalBlue)', smb1_off, 'CRITICAL',
                     'SMBv1 enables WannaCry/EternalBlue attacks',
                     'powershell Disable-WindowsOptionalFeature -Online -FeatureName SMB1Protocol')
            except Exception as e:
                _add('SMBv1 Disabled', False, 'CRITICAL', str(e))

            # -- 5. BitLocker ----------------------------------------------
            try:
                r = subprocess.run(['manage-bde','-status','C:'],
                                   capture_output=True, text=True, creationflags=subprocess.CREATE_NO_WINDOW, timeout=10)
                bl_on = 'Protection On' in r.stdout or 'Fully Encrypted' in r.stdout
                if getattr(self,'_bypass_tpm_bitlocker',False):
                    _add('BitLocker Drive Encryption', True, 'INFO',
                         'Bypassed by user setting  -  hardware encryption not required')
                else:
                    _add('BitLocker Drive Encryption', bl_on, 'HIGH',
                         'C: drive unencrypted  -  data exposed if stolen',
                         'manage-bde -on C: -RecoveryPassword')
            except Exception as e:
                _add('BitLocker Encryption', False, 'MEDIUM', 'manage-bde not available')

            # -- 6. Secure Boot --------------------------------------------
            try:
                r = subprocess.run(['powershell','-Command','Confirm-SecureBootUEFI'],
                                   capture_output=True, text=True, creationflags=subprocess.CREATE_NO_WINDOW, timeout=10)
                sb_on = 'True' in r.stdout
                if getattr(self,'_bypass_tpm_bitlocker',False):
                    _add('Secure Boot Enabled', True, 'INFO',
                         'Bypassed by user setting  -  UEFI enforcement not required')
                else:
                    _add('Secure Boot Enabled', sb_on, 'HIGH',
                         'Secure Boot prevents bootkit/rootkit attacks',
                         'Enable in BIOS/UEFI firmware settings')
            except Exception:
                _add('Secure Boot', False, 'INFO', 'UEFI check requires PS admin')

            # -- 7. Credential Guard ---------------------------------------
            try:
                key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                     r'SYSTEM\CurrentControlSet\Control\DeviceGuard',
                                     0, winreg.KEY_READ)
                try:
                    cg, _ = winreg.QueryValueEx(key, 'EnableVirtualizationBasedSecurity')
                    cg_on = cg == 1
                except Exception:
                    cg_on = False
                winreg.CloseKey(key)
                _add('Credential Guard / VBS', cg_on, 'HIGH',
                     'Protects LSASS from mimikatz-style attacks',
                     'Enable via Group Policy: Computer Config > Admin Templates > System > Device Guard')
            except Exception:
                _add('Credential Guard', False, 'INFO', 'Requires Win10 Enterprise or domain-joined')

            # -- 8. ASLR / DEP ---------------------------------------------
            try:
                key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                     r'SYSTEM\CurrentControlSet\Control\Session Manager\Memory Management',
                                     0, winreg.KEY_READ)
                try:
                    move_images, _ = winreg.QueryValueEx(key, 'MoveImages')
                    aslr_on = move_images == 1
                except Exception:
                    aslr_on = True  # Default on modern Windows
                winreg.CloseKey(key)
                _add('ASLR (Address Space Randomization)', aslr_on, 'HIGH',
                     'ASLR randomizes memory to defeat exploit targeting',
                     'reg add "HKLM\\SYSTEM\\...\\Memory Management" /v MoveImages /t REG_DWORD /d 1 /f')
            except Exception:
                _add('ASLR Status', True, 'INFO', 'ASLR enabled by default on Win10/11')

            # -- 9. Windows Update / Patches -------------------------------
            try:
                r = subprocess.run(['powershell','-Command',
                                    '(New-Object -ComObject Microsoft.Update.Session).CreateUpdateSearcher().Search("IsInstalled=0 and Type=\'Software\'").Updates.Count'],
                                   capture_output=True, text=True, creationflags=subprocess.CREATE_NO_WINDOW, timeout=20)
                pending = r.stdout.strip()
                if pending.isdigit():
                    ok = int(pending) == 0
                    _add('Windows Updates Current', ok, 'HIGH',
                         f"{pending} pending security updates",
                         'Start > Settings > Windows Update > Check for updates')
                else:
                    _add('Windows Updates', True, 'INFO', 'Could not query (non-admin)')
            except Exception:
                _add('Windows Updates', True, 'INFO', 'WUA query failed (non-admin)')

            # -- 10. Guest account disabled --------------------------------
            try:
                r = subprocess.run(['net','user','Guest'],
                                   capture_output=True, text=True, creationflags=subprocess.CREATE_NO_WINDOW,
                             timeout=15)
                guest_off = 'Account active' not in r.stdout or 'No' in r.stdout
                _add('Guest Account Disabled', guest_off, 'MEDIUM',
                     'Guest accounts can be exploited for unauthorized access',
                     'net user Guest /active:no')
            except Exception:
                _add('Guest Account', True, 'INFO', 'Could not check guest account')

            # -- 11. RDP access --------------------------------------------
            try:
                key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                     r'SYSTEM\CurrentControlSet\Control\Terminal Server',
                                     0, winreg.KEY_READ)
                deny, _ = winreg.QueryValueEx(key, 'fDenyTSConnections')
                winreg.CloseKey(key)
                rdp_off = deny == 1
                _add('RDP Disabled (if unused)', rdp_off, 'MEDIUM',
                     'Open RDP is a top attack vector. Disable if not needed.',
                     'reg add "HKLM\\SYSTEM\\...\\Terminal Server" /v fDenyTSConnections /t REG_DWORD /d 1 /f')
            except Exception:
                _add('RDP Status', True, 'INFO', 'Registry check failed')

            # -- 12. PowerShell execution policy ---------------------------
            try:
                r = subprocess.run(['powershell','-Command','Get-ExecutionPolicy'],
                                   capture_output=True, text=True, creationflags=subprocess.CREATE_NO_WINDOW, timeout=10)
                policy = r.stdout.strip()
                safe   = policy in ('AllSigned', 'RemoteSigned', 'Restricted')
                _add(f'PS ExecutionPolicy ({policy})', safe, 'HIGH' if not safe else 'PASS',
                     f'Current: {policy}. Unrestricted allows all scripts.',
                     'powershell Set-ExecutionPolicy RemoteSigned -Scope LocalMachine -Force')
            except Exception as e:
                _add('PS ExecutionPolicy', False, 'MEDIUM', str(e))

            # -- 13. AutoRun disabled --------------------------------------
            try:
                key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                     r'SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\Explorer',
                                     0, winreg.KEY_READ)
                try:
                    ar, _ = winreg.QueryValueEx(key, 'NoDriveTypeAutoRun')
                    ar_off = ar >= 0xFF
                except Exception:
                    ar_off = False
                winreg.CloseKey(key)
                _add('AutoRun/AutoPlay Disabled', ar_off, 'HIGH',
                     'AutoRun enables USB-drop attacks (like Stuxnet)',
                     'reg add HKLM\\SOFTWARE\\...\\Explorer /v NoDriveTypeAutoRun /t REG_DWORD /d 0xFF /f')
            except Exception:
                _add('AutoRun Disabled', False, 'HIGH', 'Registry query failed')

            # -- 14. Windows Script Host -----------------------------------
            try:
                key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                     r'SOFTWARE\Microsoft\Windows Script Host\Settings',
                                     0, winreg.KEY_READ)
                try:
                    enabled, _ = winreg.QueryValueEx(key, 'Enabled')
                    wsh_off = enabled == 0
                except Exception:
                    wsh_off = False
                winreg.CloseKey(key)
                _add('Windows Script Host Disabled', wsh_off, 'HIGH',
                     'WSH enables VBScript/JScript malware (.vbs, .js files)',
                     'reg add "HKLM\\SOFTWARE\\Microsoft\\Windows Script Host\\Settings" /v Enabled /t REG_DWORD /d 0 /f')
            except Exception:
                _add('Windows Script Host', False, 'MEDIUM', 'Could not check WSH settings')

            # -- 15. Suspicious startup items ------------------------------
            startup_dirs = [
                os.path.join(os.environ.get('APPDATA',''), r'Microsoft\Windows\Start Menu\Programs\Startup'),
                r'C:\ProgramData\Microsoft\Windows\Start Menu\Programs\Startup',
            ]
            startup_items = []
            for d in startup_dirs:
                if os.path.isdir(d):
                    for f in os.listdir(d):
                        if not f.startswith('.'):
                            startup_items.append(f)
            _add(f'Startup Folder ({len(startup_items)} items)', len(startup_items) < 5, 'MEDIUM',
                 f"Items: {', '.join(startup_items[:5]) or 'none'}" + (' (+more)' if len(startup_items)>5 else ''),
                 'Review startup folder items manually')

            # -- 16. HVCI / Memory Integrity ------------------------------
            hvci = self._check_hvci()
            _add('HVCI / Memory Integrity', hvci['hvci'], 'HIGH',
                 f"HVCI: {'ON' if hvci['hvci'] else 'OFF'} | PPL-LSASS: {'ON' if hvci['ppl_lsass'] else 'OFF'} | VBS: {'ON' if hvci['vbs'] else 'OFF'}",
                 'Enable in Windows Security > Core Isolation > Memory Integrity')

            # -- 17. LSASS PPL (Protected Process Light) ------------------
            _add('LSASS PPL (Anti-Mimikatz)', hvci['ppl_lsass'], 'CRITICAL',
                 'RunAsPPL prevents mimikatz credential dumping' if hvci['ppl_lsass'] else 'LSASS unprotected  -  mimikatz can dump credentials',
                 'reg add HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa /v RunAsPPL /t REG_DWORD /d 2 /f')

            # -- 18. Spectre/Meltdown Mitigations -------------------------
            sm = self._check_spectre_meltdown()
            _add('Spectre/Meltdown Mitigations', sm['kva_shadow'],
                 'MEDIUM', sm['detail'][:100] if sm['detail'] else 'Install SpeculationControl PS module to verify',
                 'Install-Module -Name SpeculationControl')

            # -- 19. LOLBin abuse check ------------------------------------
            lolbins = self._detect_lolbin_abuse()
            _add(f'LOLBin Abuse ({len(lolbins)} found)', len(lolbins) == 0, 'HIGH',
                 f"Suspicious: {', '.join(h['name'] for h in lolbins[:3])}" if lolbins else 'No LOLBin abuse detected',
                 'Review listed process command lines immediately [MITRE T1218]')

            # -- 20. Log Clearing ------------------------------------------
            log_hits = self._detect_log_clearing()
            _add('Event Log Integrity', len(log_hits) == 0, 'CRITICAL',
                 f"{len(log_hits)} log-clearing events: {', '.join(h['event'] for h in log_hits[:2])}" if log_hits else 'No log clearing detected',
                 'Investigate cleared logs  -  likely active attacker [MITRE T1070.001]')

            # -- 21. Kernel driver in suspicious path ---------------------
            drv = self._audit_kernel_drivers()
            _add('Kernel Driver Integrity', len(drv) == 0, 'CRITICAL',
                 f"{len(drv)} drivers in suspicious paths" if drv else 'All drivers in standard locations',
                 'Remove or inspect listed drivers  -  possible rootkit [MITRE T1014]')

            # -- 22. DLL hijack check -------------------------------------
            dll_hits = self._detect_dll_hijack()
            _add('DLL Search Order Hijacking', len(dll_hits) == 0, 'HIGH',
                 f"{len(dll_hits)} PATH-shadowing DLLs" if dll_hits else 'No DLL hijack detected',
                 'Remove non-system DLLs from PATH directories [MITRE T1574.001]')

            # -- 23. WMI subscriptions -------------------------------------
            wmi_subs = self._check_wmi_subscriptions()
            _add('WMI Persistence', len(wmi_subs) == 0, 'HIGH',
                 f"Active subscriptions: {', '.join(wmi_subs[:3])}" if wmi_subs else 'No WMI subscriptions',
                 'Remove via: Get-WMIObject -NS root\\subscription -Class __FilterToConsumerBinding | Remove-WmiObject')

            # -- 24. NTLM / Brute-force ------------------------------------
            ntlm = self._detect_ntlm_brute_force()
            _add('Brute Force / NTLM Events', ntlm['brute_force_attempts'] < 50, 'HIGH',
                 f"Failed logons (EID 4625): {ntlm['brute_force_attempts']} | NTLM: {ntlm['ntlm_validations']}",
                 'Enable account lockout policy and audit authentication logs [MITRE T1110]')

            # -- 25. ARP spoofing ------------------------------------------
            arp_hits = self._check_arp_spoofing()
            _add('ARP Spoof / MITM Detection', len(arp_hits) == 0, 'HIGH',
                 f"{len(arp_hits)} MAC collision(s)  -  possible MITM" if arp_hits else 'ARP table clean',
                 'Use static ARP entries for gateway: arp -s <gateway_ip> <gateway_mac>')

            # -- 26. DoH configured ----------------------------------------
            doh = self._check_dns_over_https()
            _add('DNS-over-HTTPS (DoH)', doh, 'MEDIUM',
                 'DoH enabled  -  DNS encrypted' if doh else 'DNS unencrypted  -  susceptible to monitoring/poisoning',
                 'Settings > Network > DNS > Set custom DoH server (1.1.1.1 or 8.8.8.8)')

            # -- 27. Exploit Protection (WDEG) ----------------------------
            try:
                r = subprocess.run(
                    ['powershell','-Command',
                     '(Get-ProcessMitigation -System).DEP.Enable'],
                    capture_output=True, text=True, timeout=10,
                    creationflags=subprocess.CREATE_NO_WINDOW)
                dep_on = 'ON' in r.stdout.upper() or 'True' in r.stdout
                _add('Windows DEP / Exploit Protection', dep_on, 'HIGH',
                     'DEP (Data Execution Prevention) hardens against shellcode',
                     'powershell Set-ProcessMitigation -System -Enable DEP,SEHOP,CFG')
            except Exception:
                _add('Exploit Protection (WDEG)', False, 'MEDIUM', 'PowerShell query failed (non-admin)')

            # -- 28. Attack Surface Reduction (ASR) Rules ------------------
            try:
                r = subprocess.run(
                    ['powershell','-Command',
                     'Get-MpPreference | Select-Object -ExpandProperty AttackSurfaceReductionRules_Ids'],
                    capture_output=True, text=True, timeout=15,
                    creationflags=subprocess.CREATE_NO_WINDOW)
                asr_rules = [l.strip() for l in r.stdout.splitlines() if l.strip() and len(l.strip()) > 10]
                asr_ok = len(asr_rules) >= 5
                _add(f'ASR Rules Active ({len(asr_rules)})', asr_ok, 'HIGH',
                     f"{len(asr_rules)} ASR rule(s) enabled  -  recommend 14+ for full coverage",
                     'powershell Add-MpPreference -AttackSurfaceReductionRules_Ids <GUID> -AttackSurfaceReductionRules_Actions Enabled')
            except Exception:
                _add('Attack Surface Reduction (ASR)', False, 'MEDIUM', 'Requires Windows Defender + Admin')

            # -- 29. Controlled Folder Access -----------------------------
            try:
                r = subprocess.run(
                    ['powershell','-Command',
                     'Get-MpPreference | Select-Object -ExpandProperty EnableControlledFolderAccess'],
                    capture_output=True, text=True, timeout=10,
                    creationflags=subprocess.CREATE_NO_WINDOW)
                cfa_on = '1' in r.stdout or 'Enabled' in r.stdout or 'AuditMode' in r.stdout
                _add('Controlled Folder Access (Anti-Ransomware)', cfa_on, 'HIGH',
                     'Blocks unauthorized apps from modifying protected folders',
                     'powershell Set-MpPreference -EnableControlledFolderAccess Enabled')
            except Exception:
                _add('Controlled Folder Access', False, 'MEDIUM', 'Requires Windows Defender + Admin')

            # -- 30. PatchGuard / KPP (Kernel Patch Protection) -----------
            try:
                key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                     r'SYSTEM\CurrentControlSet\Control\CI\Config',
                                     0, winreg.KEY_READ)
                try:
                    ci_val, _ = winreg.QueryValueEx(key, 'VulnerableDriverBlocklistEnable')
                    pg_ok = ci_val == 1
                except Exception:
                    pg_ok = True  # Default enabled on Win10+
                winreg.CloseKey(key)
                _add('Kernel Patch Protection (PatchGuard)', pg_ok, 'CRITICAL',
                     'PatchGuard prevents rootkits from patching kernel structures',
                     'PatchGuard is enabled by default  -  do not disable via 3rd party tools')
            except Exception:
                # PatchGuard enabled by default on 64-bit Windows
                _add('Kernel Patch Protection (PatchGuard)', True, 'INFO',
                     'PatchGuard active by default on 64-bit Windows')

            # -- 31. Signed driver enforcement (WHQL) ---------------------
            try:
                r = subprocess.run(
                    ['powershell','-Command',
                     'bcdedit /enum | Select-String "nointegritychecks"'],
                    capture_output=True, text=True, timeout=10,
                    creationflags=subprocess.CREATE_NO_WINDOW)
                integrity_disabled = 'yes' in r.stdout.lower() or 'nointegritychecks' in r.stdout.lower()
                _add('Driver Signature Enforcement', not integrity_disabled, 'CRITICAL',
                     'DSE disabled  -  rootkits can load unsigned drivers!' if integrity_disabled else 'Driver Signature Enforcement ON',
                     'bcdedit /set nointegritychecks off')
            except Exception:
                _add('Driver Signature Enforcement', True, 'INFO', 'Check via: bcdedit /enum')

            # -- 32. AV product enumeration --------------------------------
            av = self._get_av_status()
            av_ok = av and av != 'None detected' and av != 'Query failed'
            _add(f'Antivirus Installed ({av})', av_ok, 'CRITICAL',
                 f"Detected: {av}",
                 'Install and enable antivirus protection immediately')

            # Final score render
            color = Colors.GAUGE_TEAL if score>=80 else Colors.GAUGE_ORANGE if score>=50 else Colors.GAUGE_RED
            grade = 'A' if score>=90 else 'B' if score>=80 else 'C' if score>=70 else 'D' if score>=50 else 'F'
            self.after(0, lambda sc=score, c=color, g=grade:
                self._vuln_score_lbl.configure(
                    text=f"Security Score: {sc}/100 (Grade {g})", fg=c))
            self._vuln_checks = checks
            _fail_n = sum(1 for _ch in checks if not _ch['passed'])
            _sc = score; _g = grade; _fn = _fail_n; _c = color; self._queue_alert(f"[HOLE] Vuln Scan complete  -  score {_sc}/100 grade {_g}  -  {_fn} failures", _c)

        self._executor.submit(_scan)

    def _vuln_fix_all(self):
        if not messagebox.askyesno("Fix All",
                "Apply all automated fixes?\nThis requires Administrator privileges and will make system changes."):
            return
        fixes = [c['fix'] for c in self._vuln_checks if not c['passed'] and c.get('fix')]
        _SAFE_PREFIXES = ('netsh ','reg ','sc ','bcdedit ','auditpol ','secedit ',
                          'wmic ','powershell ','Set-','Disable-','Enable-')
        import re as _re2
        for fix in fixes:
            fix_clean = _re2.sub(r'[;&|`\n\r]|&&|\|\|', '', fix).strip()
            if not any(fix_clean.lower().startswith(p.lower()) for p in _SAFE_PREFIXES):
                continue  # skip unknown commands
            if len(fix_clean) > 512:
                continue  # reject suspiciously long commands
            fix = fix_clean
            try:
                subprocess.run(fix, shell=True, capture_output=True, timeout=30,
                               creationflags=subprocess.CREATE_NO_WINDOW)
            except Exception:
                pass
        messagebox.showinfo("Fixes Applied",
                            f"{len(fixes)} fixes applied.\nRe-run scan to verify results.")
        self._run_vuln_scan()

    def _vuln_apply_fix(self):
        sel = self._vuln_tree.selection()
        if not sel: return
        idx = self._vuln_tree.index(sel[0])
        if idx < len(self._vuln_checks):
            c = self._vuln_checks[idx]
            if c.get('fix') and not c['passed']:
                if messagebox.askyesno("Apply Fix", f"Apply fix for:\n{c['name']}\n\nCommand:\n{c['fix'][:200]}"):
                    try:
                        fix_cmd = c['fix']
                        _SAFE = ('netsh ','reg ','sc ','bcdedit ','auditpol ','secedit ',
                                 'wmic ','powershell ','Set-','Disable-','Enable-')
                        import re as _re3
                        fix_cmd = _re3.sub(r'[;&|`\n\r]|&&|\|\|', '', fix_cmd).strip()
                        if len(fix_cmd) > 512 or not any(
                                fix_cmd.lower().startswith(p.lower()) for p in _SAFE):
                            messagebox.showerror("Blocked", "Unknown fix command type - not applied for safety.")
                            return
                        subprocess.run(fix_cmd, shell=True, capture_output=True, timeout=30,
                                       creationflags=subprocess.CREATE_NO_WINDOW)
                        messagebox.showinfo("Done", "Fix applied. Re-run scan to verify.")
                    except Exception as e:
                        messagebox.showerror("Failed", str(e))

    # ==========================================================================
    #  [PKG] FILE SANDBOX TAB
    # ==========================================================================

    def _build_sandbox_tab(self):
        p = self._tab_sandbox
        p.grid_rowconfigure(1, weight=1)
        p.grid_columnconfigure(0, weight=1)

        # -- Header ---------------------------------------------------------
        hdr = tk.Frame(p, bg=Colors.GLASS_CARD)
        hdr.grid(row=0, column=0, sticky='ew', padx=8, pady=(8,4))
        hdr.grid_columnconfigure(2, weight=1)
        tk.Label(hdr, text="📦 FILE SANDBOX  -  Safe Detonation Chamber",
                 font=('Consolas', 11, 'bold'), fg=Colors.GAUGE_PURPLE, bg=Colors.GLASS_CARD
                 ).grid(row=0, column=0, padx=10, pady=6, sticky='w')
        tk.Label(hdr,
                 text="Run suspicious files in a monitored, isolated environment. Captures all file/network/registry activity.",
                 font=('Consolas', 8), fg=Colors.TEXT_DIM, bg=Colors.GLASS_CARD
                 ).grid(row=1, column=0, columnspan=3, padx=10, sticky='w')

        # -- Drop zone ------------------------------------------------------
        drop = tk.Frame(p, bg=Colors.GLASS_PANEL)
        drop.grid(row=1, column=0, sticky='nsew', padx=8, pady=4)
        drop.grid_rowconfigure(2, weight=1)
        drop.grid_columnconfigure(0, weight=1)

        file_bar = tk.Frame(drop, bg=Colors.GLASS_PANEL)
        file_bar.grid(row=0, column=0, sticky='ew', padx=8, pady=8)
        file_bar.grid_columnconfigure(1, weight=1)
        tk.Label(file_bar, text="📂 File:", font=('Consolas', 10),
                 fg=Colors.GAUGE_ORANGE, bg=Colors.GLASS_PANEL).grid(row=0, column=0, padx=(0,8))
        self._sandbox_path = tk.StringVar()
        tk.Entry(file_bar, textvariable=self._sandbox_path,
                 font=('Consolas', 10), bg=Colors.GLASS_DARK,
                 fg=Colors.GAUGE_TEAL, relief='flat', bd=4
                 ).grid(row=0, column=1, sticky='ew', padx=4)
        tk.Button(file_bar, text="Browse...", font=('Consolas', 9),
                  bg=Colors.CHROME_MID, fg=Colors.TEXT_LIGHT, relief='flat', padx=8,
                  command=self._sandbox_browse).grid(row=0, column=2, padx=4)

        opt_bar = tk.Frame(drop, bg=Colors.GLASS_PANEL)
        opt_bar.grid(row=1, column=0, sticky='ew', padx=8, pady=4)
        self._sandbox_timeout = tk.IntVar(value=30)
        self._sandbox_net_block = tk.BooleanVar(value=True)
        self._sandbox_capture_reg = tk.BooleanVar(value=True)
        tk.Label(opt_bar, text="Timeout (s):", font=('Consolas', 9),
                 fg=Colors.TEXT_DIM, bg=Colors.GLASS_PANEL).pack(side='left', padx=4)
        tk.Spinbox(opt_bar, from_=5, to=300, textvariable=self._sandbox_timeout,
                   width=5, font=('Consolas', 9), bg=Colors.GLASS_DARK,
                   fg=Colors.TEXT_LIGHT, relief='flat').pack(side='left', padx=4)
        tk.Checkbutton(opt_bar, text="Block Network", variable=self._sandbox_net_block,
                       font=('Consolas', 9), fg=Colors.TEXT_LIGHT,
                       bg=Colors.GLASS_PANEL, selectcolor=Colors.GLASS_DARK,
                       activebackground=Colors.GLASS_PANEL).pack(side='left', padx=12)
        tk.Checkbutton(opt_bar, text="Capture Registry", variable=self._sandbox_capture_reg,
                       font=('Consolas', 9), fg=Colors.TEXT_LIGHT,
                       bg=Colors.GLASS_PANEL, selectcolor=Colors.GLASS_DARK,
                       activebackground=Colors.GLASS_PANEL).pack(side='left', padx=4)

        btn_bar = tk.Frame(drop, bg=Colors.GLASS_PANEL)
        btn_bar.grid(row=2, column=0, sticky='ew', padx=8, pady=4)
        tk.Button(btn_bar, text="🔬 DETONATE IN SANDBOX", font=('Consolas', 10, 'bold'),
                  bg=Colors.GAUGE_RED, fg='white', relief='flat', padx=16, pady=6,
                  command=self._sandbox_run).pack(side='left', padx=4)
        tk.Button(btn_bar, text="📊 Static Analysis Only", font=('Consolas', 9),
                  bg=Colors.GAUGE_BLUE, fg='white', relief='flat', padx=10,
                  command=self._sandbox_static_only).pack(side='left', padx=4)
        tk.Button(btn_bar, text="🗑️ Clear", font=('Consolas', 9),
                  bg=Colors.CHROME_MID, fg=Colors.TEXT_LIGHT, relief='flat', padx=8,
                  command=self._sandbox_clear).pack(side='left', padx=4)

        # Results
        res_pane = ttk.PanedWindow(drop, orient='horizontal')
        res_pane.grid(row=3, column=0, sticky='nsew', padx=8, pady=4)
        drop.grid_rowconfigure(3, weight=1)

        # Activity log
        log_f = tk.Frame(res_pane, bg=Colors.GLASS_DARK)
        log_f.grid_rowconfigure(1, weight=1)
        log_f.grid_columnconfigure(0, weight=1)
        tk.Label(log_f, text="📋 ACTIVITY LOG", font=('Consolas', 9, 'bold'),
                 fg=Colors.GAUGE_PURPLE, bg=Colors.GLASS_DARK).grid(row=0, column=0, sticky='w', padx=6, pady=4)
        self._sandbox_log = tk.Text(log_f, bg=Colors.GLASS_DARK, fg=Colors.TEXT_LIGHT,
                                     font=('Consolas', 8), wrap='word', state='disabled', relief='flat')
        self._sandbox_log.grid(row=1, column=0, sticky='nsew')
        sb2 = ttk.Scrollbar(log_f, orient='vertical', command=self._sandbox_log.yview, style='Vertical.TScrollbar')
        sb2.grid(row=1, column=1, sticky='ns')
        self._sandbox_log.configure(yscrollcommand=sb2.set)
        res_pane.add(log_f, weight=2)

        # Threat report
        rep_f = tk.Frame(res_pane, bg=Colors.GLASS_CARD)
        rep_f.grid_rowconfigure(1, weight=1)
        rep_f.grid_columnconfigure(0, weight=1)
        tk.Label(rep_f, text="[WARN] THREAT REPORT", font=('Consolas', 9, 'bold'),
                 fg=Colors.GAUGE_RED, bg=Colors.GLASS_CARD).grid(row=0, column=0, sticky='w', padx=6, pady=4)
        self._sandbox_report = tk.Text(rep_f, bg=Colors.GLASS_CARD, fg=Colors.TEXT_LIGHT,
                                        font=('Consolas', 8), wrap='word', state='disabled', relief='flat')
        self._sandbox_report.grid(row=1, column=0, sticky='nsew')
        sb3 = ttk.Scrollbar(rep_f, orient='vertical', command=self._sandbox_report.yview, style='Vertical.TScrollbar')
        sb3.grid(row=1, column=1, sticky='ns')
        self._sandbox_report.configure(yscrollcommand=sb3.set)
        res_pane.add(rep_f, weight=1)

    def _sandbox_browse(self):
        path = filedialog.askopenfilename(
            title="Select Suspicious File",
            filetypes=[('Executables','*.exe *.dll *.bat *.ps1 *.vbs *.js *.hta *.scr *.com *.pif'),
                       ('All files','*.*')])
        if path:
            self._sandbox_path.set(path)

    def _sandbox_log_msg(self, msg: str, color: str = None):
        def _do():
            self._sandbox_log.configure(state='normal')
            self._sandbox_log.insert('end', msg + '\n')
            if color:
                s = self._sandbox_log.index(f'end-{len(msg)+2}c')
                e = self._sandbox_log.index('end-1c')
                tag = f'sb_{color.replace("#","")}'
                self._sandbox_log.tag_configure(tag, foreground=color)
                self._sandbox_log.tag_add(tag, s, e)
            self._sandbox_log.see('end')
            self._sandbox_log.configure(state='disabled')
        self.after(0, _do)

    def _sandbox_set_report(self, text: str, color: str = Colors.TEXT_LIGHT):
        def _do():
            self._sandbox_report.configure(state='normal')
            self._sandbox_report.delete('1.0', 'end')
            self._sandbox_report.insert('1.0', text)
            self._sandbox_report.configure(state='disabled', fg=color)
        self.after(0, _do)

    def _sandbox_static_only(self):
        path = self._sandbox_path.get().strip()
        # Resolve path before any file operation  -  prevents symlink/traversal attacks
        try:
            path = os.path.realpath(os.path.abspath(path)) if path else ''
        except Exception:
            path = ''
        if not path or not os.path.isfile(path):
            messagebox.showwarning("Sandbox", "Select a valid file first.")
            return
        def _static():
            self._sandbox_log_msg(f"[STATIC] Analyzing: {os.path.basename(path)}", Colors.GAUGE_BLUE)
            report_lines = ["=== STATIC ANALYSIS REPORT ===",
                            f"File: {path}",
                            f"Size: {os.path.getsize(path):,} bytes",
                            f"Time: {datetime.now().isoformat()}",
                            ""]
            # Hash
            try:
                with open(path,'rb') as _f:
                    data = _f.read()
                report_lines.append(f"SHA256: {hashlib.sha256(data).hexdigest()}")
                report_lines.append(f"SHA1:   {hashlib.sha1(data).hexdigest()}")
                report_lines.append(f"MD5:    {hashlib.md5(data).hexdigest()}  (legacy IOC matching)")
                report_lines.append("")
            except Exception as e:
                report_lines.append(f"Hash error: {e}")

            # Entropy
            try:
                entropy = self.yara.compute_entropy(data)
                packed  = entropy > 7.0
                report_lines.append(f"Entropy: {entropy:.3f} {'[PACKED/ENCRYPTED [!]]' if packed else '[Normal]'}")
                report_lines.append("")
            except Exception:
                pass

            # YARA
            yara_hits = self.yara.scan_file(path)
            report_lines.append(f"YARA Rules Triggered: {len(yara_hits)}")
            for y in yara_hits:
                report_lines.append(f"  [X] {y['rule']} (score {y['score']})")
                self._sandbox_log_msg(f"  YARA HIT: {y['rule']}", Colors.GAUGE_RED)
            report_lines.append("")

            # Behaviors from bytes
            behaviors = self.yara.check_behaviors(data)
            report_lines.append(f"Behavioral Indicators: {len(behaviors)}")
            for b in behaviors:
                report_lines.append(f"  [!]  {b}")

            # PE analysis
            try:
                import pefile
                pe = pefile.PE(path, fast_load=True)
                report_lines.append("\nPE Info:")
                report_lines.append(f"  Sections: {len(pe.sections)}")
                report_lines.append(f"  Imports: {len(pe.DIRECTORY_ENTRY_IMPORT) if hasattr(pe,'DIRECTORY_ENTRY_IMPORT') else 0}")
                # Check for suspicious imports
                if hasattr(pe, 'DIRECTORY_ENTRY_IMPORT'):
                    for entry in pe.DIRECTORY_ENTRY_IMPORT:
                        dll = entry.dll.decode('utf-8','ignore').lower()
                        for imp in entry.imports:
                            if imp.name:
                                iname = imp.name.decode('utf-8','ignore')
                                for kapi in _dbs_list([
                                    'VmlydHVhbEFsbG9jRXg=',    # VirtualAllocEx
                                    'V3JpdGVQcm9jZXNzTWVtb3J5', # WriteProcessMemory
                                    'Q3JlYXRlUmVtb3RlVGhyZWFk', # CreateRemoteThread
                                    'R2V0QXN5bmNLZXlTdGF0ZQ==', # GetAsyncKeyState
                                    'U2V0V2luZG93c0hvb2tFeA==', # SetWindowsHookEx
                                ]):
                                    if kapi.decode() in iname:
                                        report_lines.append(f"  [R] Suspicious import: {iname}")
                                        self._sandbox_log_msg(f"  SUSPICIOUS IMPORT: {iname}", Colors.GAUGE_RED)
                pe.close()
            except Exception:
                pass

            # IOC DB check
            try:
                sha256 = hashlib.sha256(data).hexdigest()
                rows = self.db.execute("SELECT hash, threat_name, source FROM malicious_hashes WHERE hash=?", (sha256,))
                if rows:
                    report_lines.append(f"\n[ALERT] HASH IN THREAT DATABASE: {rows[0][1]} ({rows[0][2]})")
                    self._sandbox_log_msg(f"  KNOWN MALWARE: {rows[0][1]}", Colors.GAUGE_RED)
            except Exception:
                pass

            risk = len(yara_hits) * 20 + len(behaviors) * 10
            risk = min(100, risk)
            color = Colors.GAUGE_RED if risk > 50 else Colors.GAUGE_ORANGE if risk > 20 else Colors.GAUGE_TEAL
            report_lines.append(f"\n=== RISK SCORE: {risk}/100 ===")
            self._sandbox_set_report('\n'.join(report_lines), color)
            self._sandbox_log_msg(f"[STATIC] Complete. Risk: {risk}/100", color)
            _path = path; _r = risk; _c = color; self._queue_alert(f"[PKG] Sandbox static: {os.path.basename(_path)}  -  Risk {_r}/100", _c)
        self._executor.submit(_static)

    def _sandbox_run(self):
        path = self._sandbox_path.get().strip()
        if not path or not os.path.isfile(path):
            messagebox.showwarning("Sandbox", "Select a valid file first.")
            return
        if not messagebox.askyesno("[!] Detonate",
                f"Run this file in a monitored sandbox?\n\n{path}\n\n"
                "The file will execute on this machine in a restricted context.\n"
                "Network will be monitored. Kill on timeout."):
            return

        def _run():
            timeout = self._sandbox_timeout.get()
            block_net = self._sandbox_net_block.get()
            self._sandbox_log_msg("", None)
            self._sandbox_log_msg(f"[DETONATE] Starting sandbox: {os.path.basename(path)}", Colors.GAUGE_RED)
            self._sandbox_log_msg(f"[CONFIG] Timeout: {timeout}s | Net block: {block_net}", Colors.TEXT_DIM)

            # Baseline snapshot
            baseline_procs = {p.pid for p in psutil.process_iter()} if PSUTIL_AVAILABLE else set()
            baseline_conns = set()
            if PSUTIL_AVAILABLE:
                try:
                    baseline_conns = {(c.laddr.port if c.laddr else 0, c.raddr.ip if c.raddr else '')
                                      for c in psutil.net_connections(kind='inet') if c.raddr}
                except Exception:
                    pass

            # Optionally block network via firewall
            fw_rule_added = False
            if block_net:
                try:
                    subprocess.run(['netsh','advfirewall','firewall','add','rule',
                                    'name=DOWNPOUR_SANDBOX_BLOCK','dir=out','action=block',
                                    'protocol=any', f'program={path}'],
                                   capture_output=True, creationflags=subprocess.CREATE_NO_WINDOW,
                             timeout=15)
                    fw_rule_added = True
                    self._sandbox_log_msg("[FW] Network block rule added", Colors.GAUGE_ORANGE)
                except Exception:
                    pass

            # Run the file
            proc = None
            activity = {'new_files':[], 'new_conns':[], 'new_procs':[], 'errors':[]}
            try:
                self._sandbox_log_msg("[EXEC] Launching process...", Colors.GAUGE_ORANGE)
                proc = subprocess.Popen([path], shell=False,
                                        stdout=subprocess.PIPE, stderr=subprocess.PIPE, creationflags=_NO_WIN)
                self._sandbox_log_msg(f"[EXEC] PID: {proc.pid}", Colors.GAUGE_TEAL)

                # Monitor during execution
                import time as _time
                start = _time.time()
                while _time.time() - start < timeout:
                    if proc.poll() is not None:
                        self._sandbox_log_msg(f"[EXEC] Process exited: code {proc.returncode}", Colors.TEXT_DIM)
                        break
                    # Check new connections
                    if PSUTIL_AVAILABLE:
                        try:
                            current_conns = {(c.laddr.port if c.laddr else 0, c.raddr.ip if c.raddr else '')
                                             for c in psutil.net_connections() if c.raddr}
                            new_c = current_conns - baseline_conns
                            for nc in new_c:
                                if nc not in activity['new_conns']:
                                    activity['new_conns'].append(nc)
                                    self._sandbox_log_msg(f"  [NET] NEW CONNECTION: {nc[1]}:{nc[0]}", Colors.GAUGE_RED)
                        except Exception:
                            pass
                        # Check new processes
                        try:
                            current_procs = {p.pid for p in psutil.process_iter()}
                            for np in current_procs - baseline_procs:
                                if np not in activity['new_procs']:
                                    activity['new_procs'].append(np)
                                    try:
                                        pname = psutil.Process(np).name()
                                        self._sandbox_log_msg(f"  [FWD] NEW PROCESS: {pname} (PID {np})", Colors.GAUGE_ORANGE)
                                    except Exception:
                                        pass
                        except Exception:
                            pass
                    _time.sleep(0.5)

                # Kill if still running
                if proc.poll() is None:
                    proc.kill()
                    self._sandbox_log_msg(f"[EXEC] Killed after {timeout}s timeout", Colors.GAUGE_RED)

            except Exception as e:
                self._sandbox_log_msg(f"[ERROR] {e}", Colors.GAUGE_RED)
                activity['errors'].append(str(e))
            finally:
                # Remove firewall rule
                if fw_rule_added:
                    try:
                        subprocess.run(['netsh','advfirewall','firewall','delete','rule',
                                        'name=DOWNPOUR_SANDBOX_BLOCK'],
                                       capture_output=True, creationflags=subprocess.CREATE_NO_WINDOW,
                             timeout=15)
                        self._sandbox_log_msg("[FW] Network block rule removed", Colors.GAUGE_TEAL)
                    except Exception:
                        pass

            # Build report
            report = ["=== DYNAMIC ANALYSIS REPORT ===",
                      f"File: {path}",
                      f"Duration: {timeout}s",
                      "",
                      f"New Connections: {len(activity['new_conns'])}"]
            for c in activity['new_conns']:
                report.append(f"  [R] {c[1]}:{c[0]}")
            report.append(f"\nNew Child Processes: {len(activity['new_procs'])}")
            for pid in activity['new_procs']:
                try:
                    report.append(f"  [!]  PID {pid}: {psutil.Process(pid).name()}")
                except Exception:
                    report.append(f"  PID {pid}: (exited)")
            if activity['errors']:
                report.append("\nErrors:\n  " + '\n  '.join(activity['errors']))

            risk = min(100, len(activity['new_conns'])*30 + len(activity['new_procs'])*15)
            report.append(f"\n=== DYNAMIC RISK SCORE: {risk}/100 ===")
            color = Colors.GAUGE_RED if risk>50 else Colors.GAUGE_ORANGE if risk>20 else Colors.GAUGE_TEAL
            self._sandbox_set_report('\n'.join(report), color)
            self._sandbox_log_msg(f"[DONE] Dynamic analysis complete. Risk: {risk}/100", color)
            _path = path; _r = risk; _c = color; self._queue_alert(f"[PKG] Sandbox detonation: {os.path.basename(_path)}  -  Risk {_r}/100", _c)

        self._executor.submit(_run)

    def _sandbox_clear(self):
        self._sandbox_path.set('')
        self._sandbox_log.configure(state='normal')
        self._sandbox_log.delete('1.0','end')
        self._sandbox_log.configure(state='disabled')
        self._sandbox_report.configure(state='normal')
        self._sandbox_report.delete('1.0','end')
        self._sandbox_report.configure(state='disabled')

    # ==========================================================================
    #  [LOCK] SECURITY HARDENING  -  NSA/CISA level checks (added to existing tab)
    # ==========================================================================

    _sig_cache = {}  # path -> (result, timestamp)

    def _check_signed_binary(self, path: str) -> bool:
        import time as _time
        cached = self._sig_cache.get(path)
        if cached and (_time.time() - cached[1]) < 300:
            return cached[0]
        """Verify Authenticode signature using Windows API (WinVerifyTrust)."""
        if not path or not os.path.isfile(path):
            self._sig_cache[path] = (False, __import__('time').time())
            return False
        try:
            WINTRUST_ACTION_GENERIC_VERIFY_V2 = ctypes.c_char_p(
                b'\xaa\xaa\xaa\xaa\xaa\xaa\xaa\xaa\xaa\xaa\xaa\xaa\xaa\xaa\xaa\xaa')
            # Use simpler signtool approach via powershell
            r = subprocess.run(
                ['powershell','-Command',
                 f"(Get-AuthenticodeSignature '{path}').Status"],
                capture_output=True, text=True, timeout=10,
                creationflags=subprocess.CREATE_NO_WINDOW)
            return 'Valid' in r.stdout
        except Exception:
            return False

    def _fim_check_critical_files(self) -> List[dict]:
        """File Integrity Monitoring  -  check SHA256 of critical system files."""
        CRITICAL = [
            r'C:\Windows\System32\ntoskrnl.exe',
            r'C:\Windows\System32\lsass.exe',
            r'C:\Windows\System32\csrss.exe',
            r'C:\Windows\System32\winlogon.exe',
            r'C:\Windows\System32\services.exe',
            r'C:\Windows\System32\svchost.exe',
        ]
        results = []
        for fp in CRITICAL:
            if os.path.isfile(fp):
                try:
                    with open(fp, 'rb') as _shaf:
                        sha = hashlib.sha256(_shaf.read()).hexdigest()
                    # Check against known-bad DB
                    rows = self.db.execute("SELECT hash FROM malicious_hashes WHERE hash=?", (sha,))
                    tampered = len(rows) > 0
                    results.append({'file': fp, 'sha256': sha, 'tampered': tampered})
                except PermissionError:
                    results.append({'file': fp, 'sha256': 'ACCESS DENIED', 'tampered': False})
                except Exception as e:
                    results.append({'file': fp, 'sha256': str(e), 'tampered': False})
        return results

    def _check_wmi_subscriptions(self) -> List[str]:
        """Check for malicious WMI event subscriptions (persistence technique)."""
        found = []
        try:
            r = subprocess.run(
                ['powershell','-Command',
                 'Get-WMIObject -Namespace root\\subscription -Class __FilterToConsumerBinding | '
                 'Select-Object -ExpandProperty Filter | ForEach-Object {$_.Name}'],
                capture_output=True, text=True, timeout=15,
                creationflags=subprocess.CREATE_NO_WINDOW)
            for line in r.stdout.splitlines():
                s = line.strip()
                if s:
                    found.append(s)
        except Exception:
            pass
        return found

    def _check_arp_spoofing(self) -> List[dict]:
        """Detect ARP spoofing  -  multiple IPs mapping to same MAC (MITM indicator)."""
        mac_to_ips: Dict[str, List[str]] = defaultdict(list)
        try:
            r = subprocess.run(['arp','-a'], capture_output=True, text=True,
                               creationflags=subprocess.CREATE_NO_WINDOW, timeout=10)
            for line in r.stdout.splitlines():
                parts = line.split()
                if len(parts) >= 2:
                    ip, mac = parts[0], parts[1]
                    if re.match(r'\d+\.\d+\.\d+\.\d+', ip) and '-' in mac:
                        mac_to_ips[mac].append(ip)
        except Exception:
            pass
        # Flag MACs with more than 1 non-broadcast IP
        suspicious = []
        for mac, ips in mac_to_ips.items():
            if len(ips) > 1 and mac not in ('ff-ff-ff-ff-ff-ff',):
                suspicious.append({'mac': mac, 'ips': ips})
        return suspicious

    def _check_dns_over_https(self) -> bool:
        """Test if DoH is configured (Windows 11 native DoH or custom)."""
        try:
            key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                 r'SYSTEM\CurrentControlSet\Services\Dnscache\Parameters',
                                 0, winreg.KEY_READ)
            try:
                val, _ = winreg.QueryValueEx(key, 'EnableAutoDoh')
                winreg.CloseKey(key)
                return val == 2
            except Exception:
                winreg.CloseKey(key)
                return False
        except Exception:
            return False

    def _check_schtasks_suspicious(self) -> List[dict]:
        """Enumerate scheduled tasks and flag suspicious ones."""
        suspicious = []
        try:
            r = subprocess.run(['schtasks','/query','/fo','CSV','/v'],
                               capture_output=True, text=True, timeout=20,
                               creationflags=subprocess.CREATE_NO_WINDOW)
            import csv, io
            reader = csv.DictReader(io.StringIO(r.stdout))
            for row in reader:
                action = row.get('Task To Run','').lower()
                task   = row.get('TaskName','')
                # Flag tasks running from temp/user dirs with scripting engines
                safe_prefixes = [r'\Microsoft', r'\Windows']
                susp = (any(kw in action for kw in ['\\temp\\', '\\appdata\\', 'powershell -enc',
                                                     'mshta', 'wscript', 'cscript', 'certutil']) and
                        not any(task.startswith(sp) for sp in safe_prefixes))
                if susp:
                    suspicious.append({'task': task, 'action': action[:120]})
        except Exception:
            pass
        return suspicious

    def _get_av_status(self) -> str:
        """Query installed antivirus via WMI SecurityCenter2."""
        try:
            r = subprocess.run(
                ['powershell','-Command',
                 "Get-WmiObject -Namespace root\\SecurityCenter2 -Class AntiVirusProduct | "
                 "Select-Object -ExpandProperty displayName"],
                capture_output=True, text=True, timeout=10,
                creationflags=subprocess.CREATE_NO_WINDOW)
            avs = [l.strip() for l in r.stdout.splitlines() if l.strip()]
            return ', '.join(avs) if avs else 'None detected'
        except Exception:
            return 'Query failed'

    # ==========================================================================
    #  SECURITY HARDENING: AUTO-QUARANTINE + FIM ON HIGH-RISK PROCESS
    # ==========================================================================

    def _maybe_auto_quarantine(self, proc_info, score: int):
        """Auto-quarantine process if score > 85 and auto-quarantine is enabled."""
        if score < 85:
            return
        try:
            auto_q = self.cfg.get('modules', 'auto_quarantine') if hasattr(self, 'cfg') else False
            if not auto_q:
                return
            ok, msg = self.scanner.mitigate(proc_info.pid, 'quarantine', QUARANTINE_DIR)
            if ok:
                self._queue_alert(f"[ALERT] AUTO-QUARANTINE: {proc_info.name} (score {score})  -  {msg}", Colors.GAUGE_RED)
                self.db.execute(
                    "INSERT OR IGNORE INTO quarantine (original_path,quarantine_path,threat_type,quarantined_at) VALUES (?,?,?,?)",
                    (proc_info.path, str(QUARANTINE_DIR/'locked'), f'AutoQ:score={score}', datetime.now().isoformat()))
        except Exception:
            pass

