    #  BACKGROUND LOOPS & AUTO-START
    # ==========================================================================

    # --------------------------------------------------------------------------
    #  IOC TIMELINE   -  chronological event history with IOC search
    # --------------------------------------------------------------------------

    def _get_ioc_timeline(self, limit: int = 200) -> List[dict]:
        """Return chronological list of threat events from the DB for timeline view."""
        events = []
        try:
            for table, label, col in [
                ('detections',       'Detection',   'threat_name'),
                ('network_events',   'Network',     'remote_ip'),
                ('quarantine',       'Quarantine',  'threat_type'),
            ]:
                rows = self.db.execute(
                    f"SELECT {col}, timestamp FROM {table} ORDER BY timestamp DESC LIMIT {limit}")
                for row in rows:
                    events.append({'label': label, 'value': str(row[0]), 'ts': str(row[1])})
        except Exception:
            pass
        events.sort(key=lambda e: e['ts'], reverse=True)
        return events[:limit]

    def _ioc_search_db(self, query: str) -> List[dict]:
        """Search the IOC database for an IP, hash, domain, or URL fragment."""
        hits = []
        q = f'%{query.lower()}%'
        for table, col, kind in [
            ('malicious_ips',     'ip',     'IP'),
            ('malicious_domains', 'domain', 'Domain'),
            ('malicious_urls',    'url',    'URL'),
            ('malicious_hashes',  'hash',   'Hash'),
        ]:
            try:
                rows = self.db.execute(
                    f"SELECT {col}, source, threat_name FROM {table} WHERE {col} LIKE ? LIMIT 50",
                    (q,))
                for row in rows:
                    hits.append({'type': kind, 'ioc': str(row[0]),
                                 'source': str(row[1]) if row[1] else '',
                                 'name': str(row[2]) if len(row) > 2 and row[2] else ''})
            except Exception:
                pass
        return hits

    # --------------------------------------------------------------------------
    #  [NET] PACKET CAPTURE  -  raw socket passive sniffer (admin required)
    # --------------------------------------------------------------------------

    def _start_packet_capture(self, max_packets: int = 500, callback=None):
        """
        Passive raw-socket packet sniffer.  Runs in a background thread.
        Captures IP headers and detects port-scan patterns, SYN floods,
        unusual protocol flags and large payload bursts.
        Requires elevated (Administrator) privileges on Windows.
        """
        stop_evt = threading.Event()
        self._pcap_stop = stop_evt

        def _capture():
            import socket, struct
            try:
                # AF_INET raw socket  -  captures all IP traffic on the default NIC
                sniffer = socket.socket(socket.AF_INET, socket.SOCK_RAW, socket.IPPROTO_IP)
                sniffer.bind((socket.gethostbyname(socket.gethostname()), 0))
                sniffer.setsockopt(socket.IPPROTO_IP, socket.IP_HDRINCL, 1)
                # Enable promiscuous mode (Windows SIO_RCVALL)
                SIO_RCVALL = 0x98000001
                sniffer.ioctl(SIO_RCVALL, 1)
            except PermissionError:
                if callback:
                    self.after(0, lambda: callback(None, error='Admin required for packet capture'))
                return
            except Exception as e:
                if callback:
                    self.after(0, lambda _e=e: callback(None, error=str(_e)))
                return

            count        = 0
            syn_counter: Dict[str, int] = defaultdict(int)
            port_counter: Dict[str, set] = defaultdict(set)

            try:
                while not stop_evt.is_set() and count < max_packets:
                    try:
                        raw, addr = sniffer.recvfrom(65535)
                    except Exception:
                        break

                    # Parse IP header (first 20 bytes)
                    if len(raw) < 20:
                        continue
                    iph = struct.unpack('!BBHHHBBH4s4s', raw[:20])
                    ihl      = (iph[0] & 0xF) * 4
                    proto    = iph[6]
                    src_ip   = socket.inet_ntoa(iph[8])
                    dst_ip   = socket.inet_ntoa(iph[9])
                    pkt_info = {'src': src_ip, 'dst': dst_ip, 'proto': proto,
                                'len': iph[2], 'flags': []}

                    # TCP analysis
                    if proto == 6 and len(raw) >= ihl + 14:
                        tcp_hdr = struct.unpack('!HHLLBBHHH', raw[ihl:ihl+20])
                        src_port = tcp_hdr[0]
                        dst_port = tcp_hdr[1]
                        flags    = tcp_hdr[5]
                        pkt_info['src_port'] = src_port
                        pkt_info['dst_port'] = dst_port

                        # SYN (0x02) without ACK (0x10) = SYN scan indicator
                        if (flags & 0x02) and not (flags & 0x10):
                            syn_counter[src_ip] += 1
                            port_counter[src_ip].add(dst_port)
                            pkt_info['flags'].append('SYN')
                            # SYN flood / port scan heuristic
                            if syn_counter[src_ip] > 20 and len(port_counter[src_ip]) > 10:
                                pkt_info['alert'] = f'PORT_SCAN src={src_ip} ports={len(port_counter[src_ip])}'

                        # RST flood
                        if (flags & 0x04) and syn_counter.get(src_ip, 0) > 30:
                            pkt_info['flags'].append('RST_FLOOD')
                            pkt_info['alert'] = f'RST_FLOOD src={src_ip}'

                        # XMAS scan (FIN+PSH+URG)
                        if (flags & 0x29) == 0x29:
                            pkt_info['flags'].append('XMAS')
                            pkt_info['alert'] = f'XMAS_SCAN src={src_ip}'

                    # UDP analysis
                    elif proto == 17 and len(raw) >= ihl + 8:
                        udp_hdr  = struct.unpack('!HHHH', raw[ihl:ihl+8])
                        pkt_info['src_port'] = udp_hdr[0]
                        pkt_info['dst_port'] = udp_hdr[1]

                    count += 1
                    if callback:
                        self.after(0, lambda p=pkt_info: callback(p))

            finally:
                try:
                    sniffer.ioctl(SIO_RCVALL, 0)
                    sniffer.close()
                except Exception:
                    pass

        self._executor.submit(_capture)

    def _stop_packet_capture(self):
        if hasattr(self, '_pcap_stop'):
            self._pcap_stop.set()
        if hasattr(self, '_pcap_status'):
            self._pcap_status.configure(text="Stopped", fg=Colors.TEXT_DIM)

    def _ui_start_pcap(self):
        """Start packet capture with UI feedback and alert on suspicious packets."""
        if hasattr(self, '_pcap_status'):
            self._pcap_status.configure(text="Capturing...", fg=Colors.GAUGE_PURPLE)

        def _on_packet(pkt, error=None):
            if error:
                if hasattr(self, '_pcap_status'):
                    self._pcap_status.configure(text=f"Error: {error}", fg=Colors.GAUGE_RED)
                return
            if pkt and pkt.get('alert'):
                self._queue_alert(f"[NET] PCAP: {pkt['alert']}", Colors.GAUGE_RED)
                if hasattr(self, '_pcap_status'):
                    self._pcap_status.configure(text=pkt['alert'][:60], fg=Colors.GAUGE_RED)

        self._start_packet_capture(max_packets=500, callback=_on_packet)

    # --------------------------------------------------------------------------
    #  [SIG] ROGUE DHCP DETECTION  -  detect unauthorized DHCP servers on LAN
    # --------------------------------------------------------------------------

    def _detect_rogue_dhcp(self) -> List[dict]:
        """
        Detect unauthorized DHCP servers by comparing the current DHCP lease
        server against known/authorized servers.  Also checks via `ipconfig /all`
        and ARP table cross-reference.
        """
        rogue_servers = []
        try:
            r = subprocess.run(
                ['ipconfig', '/all'],
                capture_output=True, text=True, timeout=10,
                creationflags=subprocess.CREATE_NO_WINDOW)
            dhcp_servers: List[str] = []
            for line in r.stdout.splitlines():
                if 'DHCP Server' in line and ':' in line:
                    ip = line.split(':')[-1].strip()
                    if re.match(r'\d+\.\d+\.\d+\.\d+', ip):
                        dhcp_servers.append(ip)

            # Load authorized DHCP servers from config (or default to current gateway)
            authorized: set = set()
            try:
                r2 = subprocess.run(
                    ['ipconfig'], capture_output=True, text=True,
                    creationflags=subprocess.CREATE_NO_WINDOW, timeout=8)
                for line in r2.stdout.splitlines():
                    if 'Default Gateway' in line and ':' in line:
                        gw = line.split(':')[-1].strip()
                        if re.match(r'\d+\.\d+\.\d+\.\d+', gw):
                            authorized.add(gw)
            except Exception:
                pass

            for srv in dhcp_servers:
                if srv not in authorized and srv not in ('0.0.0.0', ''):
                    rogue_servers.append({
                        'ip': srv,
                        'reason': 'DHCP server not matching default gateway',
                        'severity': 'HIGH',
                        'description': 'Possible MITM / rogue DHCP server detected on LAN'
                    })
                    self._queue_alert(
                        f"[ALERT] ROGUE DHCP SERVER DETECTED: {srv}",
                        Colors.GAUGE_RED)

        except Exception:
            pass
        return rogue_servers

    def _run_rogue_dhcp_check(self):
        """Run rogue DHCP check and add alerts if found."""
        def _check():
            rogues = self._detect_rogue_dhcp()
            if rogues:
                for r in rogues:
                    self._queue_alert(
                        f"[!] Rogue DHCP: {r['ip']}  -  {r['reason']}",
                        Colors.GAUGE_RED)
            else:
                self._queue_alert(
                    "[OK] DHCP Check: No rogue servers detected", Colors.GAUGE_TEAL)
        self._executor.submit(_check)

    # --------------------------------------------------------------------------
    #  [FIX] SERVICE CREATION MONITOR  -  detect new Windows services (persistence)
    # --------------------------------------------------------------------------

    def _snapshot_services(self) -> set:
        """Return the current set of installed service names."""
        names: set = set()
        try:
            key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                 r'SYSTEM\CurrentControlSet\Services',
                                 0, winreg.KEY_READ)
            i = 0
            while True:
                try:
                    names.add(winreg.EnumKey(key, i))
                    i += 1
                except OSError:
                    break
            winreg.CloseKey(key)
        except Exception:
            pass
        return names

    def _start_service_monitor(self):
        """
        Monitor Windows service registry for new service creation.
        New services are a classic persistence / privilege escalation vector.
        Polls every 30 seconds; alerts immediately on new service detection.
        """
        if getattr(self, '_svc_monitor_running', False):
            return
        self._svc_monitor_running = True
        self._svc_baseline: set = self._snapshot_services()

        def _monitor():
            import time as _t
            while self._svc_monitor_running:
                _t.sleep(30)
                try:
                    current = self._snapshot_services()
                    new_svcs = current - self._svc_baseline
                    removed  = self._svc_baseline - current
                    for svc in new_svcs:
                        # Look up the service binary
                        binary = ''
                        try:
                            sk = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                                fr'SYSTEM\CurrentControlSet\Services\{svc}',
                                                0, winreg.KEY_READ)
                            try:
                                binary, _ = winreg.QueryValueEx(sk, 'ImagePath')
                            except Exception:
                                pass
                            winreg.CloseKey(sk)
                        except Exception:
                            pass

                        # Suspicious heuristics: temp dir, unsigned, powershell
                        susp = any(kw in binary.lower() for kw in
                                   ['\\temp\\', '\\appdata\\', 'powershell', 'cmd.exe', 'wscript',
                                    'mshta', 'certutil', 'bitsadmin'])
                        color = Colors.GAUGE_RED if susp else Colors.GAUGE_ORANGE
                        self._queue_alert(
                                f"[FIX] NEW SERVICE: '{svc}'  -  {binary[:80] or 'no binary path'}",
                                color)

                        # Auto-log to DB
                        try:
                            self.db.execute(
                                "INSERT OR IGNORE INTO detections "
                                "(threat_name, threat_type, severity, details, timestamp, pid) "
                                "VALUES (?,?,?,?,?,?)",
                                (svc, 'new_service',
                                 'CRITICAL' if susp else 'HIGH',
                                 f"Binary: {binary}",
                                 datetime.now().isoformat(), 0))
                        except Exception:
                            pass

                    for svc in removed:
                        self._queue_alert(
                                f"[FIX] SERVICE REMOVED: '{svc}'",
                                Colors.GAUGE_YELLOW)

                    self._svc_baseline = current
                except Exception:
                    pass

        self._executor.submit(_monitor)

    def _stop_service_monitor(self):
        self._svc_monitor_running = False

