    def _tag_mitre(self, alert_text: str) -> str:
        """Append MITRE ATT&CK tag to an alert string based on content keywords."""
        text_lower = alert_text.lower()
        for key, (tid, name) in self.MITRE_MAP.items():
            kw = key.replace('_', ' ')
            if any(kw_part in text_lower for kw_part in kw.split()):
                return f"{alert_text} [MITRE {tid}: {name}]"
        return alert_text

    # -- HVCI + PPL + Spectre/Meltdown Checks --------------------------------

    def _check_hvci(self) -> dict:
        """Check Hypervisor-Protected Code Integrity (HVCI) / Memory Integrity."""
        result = {'hvci': False, 'ppl_lsass': False, 'vbs': False, 'detail': ''}
        try:
            key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                 r'SYSTEM\CurrentControlSet\Control\DeviceGuard\Scenarios\HypervisorEnforcedCodeIntegrity',
                                 0, winreg.KEY_READ)
            try:
                enabled, _ = winreg.QueryValueEx(key, 'Enabled')
                result['hvci'] = enabled == 1
            except Exception:
                pass
            winreg.CloseKey(key)
        except Exception:
            pass
        # PPL for LSASS
        try:
            key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE,
                                 r'SYSTEM\CurrentControlSet\Control\Lsa',
                                 0, winreg.KEY_READ)
            try:
                ppl, _ = winreg.QueryValueEx(key, 'RunAsPPL')
                result['ppl_lsass'] = ppl >= 1
            except Exception:
                pass
            # LSA Protection level
            try:
                lsa_cfg, _ = winreg.QueryValueEx(key, 'LsaCfgFlags')
                result['vbs'] = lsa_cfg >= 1
            except Exception:
                pass
            winreg.CloseKey(key)
        except Exception:
            pass
        parts = []
        if result['hvci']:   parts.append('HVCI ON')
        if result['ppl_lsass']: parts.append('PPL-LSASS ON')
        if result['vbs']:    parts.append('VBS-LSA ON')
        result['detail'] = ', '.join(parts) if parts else 'All disabled'
        return result

    def _check_spectre_meltdown(self) -> dict:
        """Check Spectre/Meltdown (KVA Shadow + Branch Prediction mitigations)."""
        result = {'kva_shadow': False, 'ibrs': False, 'ssbd': False, 'detail': ''}
        try:
            r = subprocess.run(
                ['powershell','-Command',
                 'Get-SpeculationControlSettings | Select-Object -Property *'],
                capture_output=True, text=True, timeout=15,
                creationflags=subprocess.CREATE_NO_WINDOW)
            out = r.stdout
            result['kva_shadow'] = 'KernelVaShadowEnabled' in out and 'True' in out
            result['ibrs']       = 'ibrs' in out.lower()
            result['ssbd']       = 'ssbd' in out.lower()
            result['detail']     = out[:200].strip() if out else 'Module not available'
        except Exception as e:
            result['detail'] = f'SpeculationControl module needed: {e}'
        return result

    # -- Timestomp / Anti-Forensics Detection --------------------------------

    def _detect_timestomping(self, check_dirs: list = None) -> List[dict]:
        """
        MITRE T1070.006  -  Detect timestomping: files where $STANDARD_INFO
        timestamps are much earlier than $FILE_NAME timestamps (Windows NTFS).
        Also flags files with creation time > modification time (impossible normally).
        """
        if check_dirs is None:
            check_dirs = [os.environ.get('TEMP',''), os.environ.get('APPDATA',''),
                          r'C:/Windows/Temp', r'C:\Users\Public']
        hits = []
        for d in check_dirs:
            if not d or not os.path.isdir(d): continue
            try:
                for root, dirs, files in os.walk(d):
                    dirs[:] = [dd for dd in dirs if not dd.startswith('.')]
                    for fn in files:
                        fp = os.path.join(root, fn)
                        if _is_own_path(fp):
                            continue  # skip own suite files
                        try:
                            stat = os.stat(fp)
                            ctime = stat.st_ctime  # creation (Windows)
                            mtime = stat.st_mtime  # last modified
                            # Flag: creation time is AFTER modification time (impossible without stomping)
                            if ctime > mtime + 1:
                                hits.append({
                                    'path': fp,
                                    'issue': 'Creation > Modification (timestomped)',
                                    'ctime': datetime.fromtimestamp(ctime).isoformat(),
                                    'mtime': datetime.fromtimestamp(mtime).isoformat(),
                                    'mitre': 'T1070.006'
                                })
                            # Flag: modification time is suspiciously old (e.g. year 2000) on a new file
                            if mtime < 978307200 and ctime > 1577836800:  # mtime before 2001, ctime after 2020
                                hits.append({
                                    'path': fp,
                                    'issue': 'Suspiciously old mtime on recent file',
                                    'ctime': datetime.fromtimestamp(ctime).isoformat(),
                                    'mtime': datetime.fromtimestamp(mtime).isoformat(),
                                    'mitre': 'T1070.006'
                                })
                        except (PermissionError, FileNotFoundError):
                            pass
            except PermissionError:
                pass
        return hits

    # -- Log Clearing Detection -----------------------------------------------

    def _detect_log_clearing(self) -> List[dict]:
        """
        MITRE T1070.001  -  Detect Windows Event Log clearing.
        Checks Security log for Event ID 1102 (log cleared) and 104 (system log cleared).
        Also checks for wevtutil cl / Clear-EventLog executions in process list.
        """
        hits = []
        # Method 1: Check Security event log for EID 1102 / 104
        try:
            r = subprocess.run(
                ['powershell','-Command',
                 'Get-WinEvent -FilterHashtable @{LogName="Security";Id=1102} -MaxEvents 5 -ErrorAction SilentlyContinue | '
                 'Select-Object TimeCreated,Message | ConvertTo-Json -Depth 1'],
                capture_output=True, text=True, timeout=15,
                creationflags=subprocess.CREATE_NO_WINDOW)
            if r.stdout.strip() and r.stdout.strip() != 'null':
                hits.append({'event': 'Security Log Cleared (EID 1102)',
                             'data': r.stdout.strip()[:200], 'mitre': 'T1070.001'})
        except Exception:
            pass
        try:
            r = subprocess.run(
                ['powershell','-Command',
                 'Get-WinEvent -FilterHashtable @{LogName="System";Id=104} -MaxEvents 5 -ErrorAction SilentlyContinue | '
                 'Select-Object TimeCreated,Message | ConvertTo-Json -Depth 1'],
                capture_output=True, text=True, timeout=15,
                creationflags=subprocess.CREATE_NO_WINDOW)
            if r.stdout.strip() and r.stdout.strip() != 'null':
                hits.append({'event': 'System Log Cleared (EID 104)',
                             'data': r.stdout.strip()[:200], 'mitre': 'T1070.001'})
        except Exception:
            pass
        # Method 2: Check running processes for log-clearing tools
        if PSUTIL_AVAILABLE:
            log_clear_tools = {'wevtutil', 'eventcreate', 'wmic', 'powershell'}
            log_clear_args  = {'cl ', 'clear-eventlog', 'clearev', 'cleareventlog'}
            for proc in psutil.process_iter(['pid','name','cmdline']):
                try:
                    name = (proc.info.get('name') or '').lower()
                    cmd  = ' '.join(proc.info.get('cmdline') or []).lower()
                    if name in log_clear_tools and any(a in cmd for a in log_clear_args):
                        hits.append({'event': f'Log-clearing process: {name}',
                                     'data': cmd[:120], 'mitre': 'T1070.001',
                                     'pid': proc.pid})
                except (psutil.NoSuchProcess, psutil.AccessDenied):
                    pass
        return hits

    # -- DLL Hijack Detection -------------------------------------------------

    def _detect_dll_hijack(self) -> List[dict]:
        """
        MITRE T1574.001  -  DLL Search Order Hijacking.
        Scans writable directories on the PATH for DLLs that shadow System32 DLLs.
        """
        hits = []
        system32 = r'C:\Windows\System32'
        path_dirs = os.environ.get('PATH','').split(';')
        try:
            sys32_dlls = {f.lower() for f in os.listdir(system32) if f.lower().endswith('.dll')}
        except Exception:
            return hits
        for d in path_dirs:
            d = d.strip()
            if not d or not os.path.isdir(d): continue
            if d.lower().startswith(r'c:\windows'): continue  # skip Windows dirs
            try:
                for fn in os.listdir(d):
                    if fn.lower() in sys32_dlls:
                        fp = os.path.join(d, fn)
                        hits.append({
                            'path': fp,
                            'shadows': os.path.join(system32, fn),
                            'issue': 'PATH-hijacking DLL shadows System32 version',
                            'mitre': 'T1574.001'
                        })
            except PermissionError:
                pass
        return hits

    # -- Network Share Monitoring ---------------------------------------------

    def _check_network_shares(self) -> List[dict]:
        """
        MITRE T1021.002  -  Enumerate all Windows network shares.
        Flags shares that are world-readable / administrative shares opened to non-admin.
        """
        shares = []
        try:
            r = subprocess.run(['net','share'],
                               capture_output=True, text=True, timeout=10,
                               creationflags=subprocess.CREATE_NO_WINDOW)
            admin_shares = {'IPC$', 'C$', 'ADMIN$', 'PRINT$'}
            lines_s = r.stdout.splitlines()
            for line in lines_s[4:]:  # Skip header
                parts = line.split()
                if not parts: continue
                name = parts[0]
                path = parts[1] if len(parts) > 1 else '(no path)'
                is_admin = name in admin_shares or name.endswith('$')
                suspicious = not is_admin and path not in ('', 'Remote')
                shares.append({
                    'name': name, 'path': path,
                    'admin_share': is_admin,
                    'suspicious': suspicious,
                    'mitre': 'T1021.002' if suspicious else ''
                })
        except Exception:
            pass
        return shares

    # -- NTLM Relay / Brute Force Detection ----------------------------------

    def _detect_ntlm_brute_force(self) -> dict:
        """
        MITRE T1110 Brute Force + T1557.001 NTLM Relay.
        Checks Security event log for:
          EID 4625  -  Failed logon (brute force indicator)
          EID 4776  -  NTLM credential validation (relay indicator)
          EID 4648  -  Explicit credential use (lateral movement)
        """
        results = {'brute_force_attempts': 0, 'ntlm_validations': 0,
                   'explicit_cred_use': 0, 'details': []}
        event_checks = [
            (4625, 'brute_force_attempts', 'Failed Logon (T1110)'),
            (4776, 'ntlm_validations',     'NTLM Credential Validation (T1557.001)'),
            (4648, 'explicit_cred_use',    'Explicit Cred Use (T1021)'),
        ]
        for eid, key, label in event_checks:
            try:
                r = subprocess.run(
                    ['powershell','-Command',
                     f'(Get-WinEvent -FilterHashtable @{{LogName="Security";Id={eid}}} '
                     f'-MaxEvents 100 -ErrorAction SilentlyContinue).Count'],
                    capture_output=True, text=True, timeout=15,
                    creationflags=subprocess.CREATE_NO_WINDOW)
                count = int(r.stdout.strip()) if r.stdout.strip().isdigit() else 0
                results[key] = count
                if count > 10:
                    results['details'].append(f'{label}: {count} events (threshold >10)')
            except Exception:
                pass
        return results

