    # -- Service creation monitor -------------------------------------------

    def _svc_monitor_loop(self):
        """Monitor for new Windows service creation  -  common persistence/rootkit technique.

        Only alerts on services from suspicious paths or unsigned binaries.
        Normal Windows services from System32, DriverStore, etc. are silently added
        to the known set without generating alerts or DB entries.
        """
        def _scan():
            if not hasattr(self, '_known_services'):
                # First run: snapshot all existing services without alerting
                self._known_services = self._get_service_names()
                return
            current = self._get_service_names()
            new_svcs = current - self._known_services
            for svc in new_svcs:
                try:
                    r = subprocess.run(['sc','qc', svc], capture_output=True, text=True,
                                       creationflags=subprocess.CREATE_NO_WINDOW, timeout=5)
                    binary = ''
                    for line in r.stdout.splitlines():
                        if 'BINARY_PATH_NAME' in line:
                            binary = line.split(':', 1)[-1].strip()
                    bin_lower = binary.lower()
                    # Safe locations — do NOT alert for services from these paths
                    safe_locations = (
                        '\\systemroot\\', '\\windows\\', '\\system32\\',
                        '\\driverstore\\', 'c:\\windows\\',
                        '\\program files\\', '\\program files (x86)\\',
                        '\\programdata\\microsoft\\',
                        'svchost.exe',
                    )
                    is_safe = any(sp in bin_lower for sp in safe_locations) or not binary.strip()
                    # Suspicious locations
                    susp_paths = ('\\temp\\', '\\appdata\\local\\temp\\',
                                  '\\public\\', '\\downloads\\')
                    is_susp = any(sp in bin_lower for sp in susp_paths)
                    if is_susp:
                        # Suspicious path — alert and log
                        self._queue_alert(
                            f"[!] NEW SERVICE FROM SUSPICIOUS PATH: '{svc}' - {binary[:80]}",
                            Colors.GAUGE_RED)
                        self.db.execute(
                            "INSERT OR IGNORE INTO threat_events "
                            "(timestamp,type,name,detail,severity) VALUES (?,?,?,?,?)",
                            (datetime.now().isoformat(), 'ServiceCreation', svc, binary, 'HIGH'))
                        # Verify signature
                        if not self._check_signed_binary(binary):
                            self._queue_alert(
                                f"[ALERT] UNSIGNED SERVICE BINARY: {binary}",
                                Colors.GAUGE_RED)
                    elif not is_safe:
                        # Unknown location — low-priority informational only, no DB log
                        self._queue_alert(
                            f"[INFO] New service: '{svc}' - {binary[:80]}",
                            Colors.TEXT_DIM)
                    # Safe services: silently add to known set (no alert, no DB)
                except Exception:
                    pass
            self._known_services = current
        self._executor.submit(_scan)
        self._orig_after(60_000, self._svc_monitor_loop)

    def _get_service_names(self) -> set:
        """Get all current Windows service names."""
        try:
            r = subprocess.run(['sc','query','type=','all','state=','all'],
                               capture_output=True, text=True,
                               creationflags=subprocess.CREATE_NO_WINDOW, timeout=10)
            return {line.split(':',1)[-1].strip()
                    for line in r.stdout.splitlines()
                    if line.strip().startswith('SERVICE_NAME')}
        except Exception:
            return set()

    # -- ARP spoofing monitor -----------------------------------------------

    def _arp_monitor_loop(self):
        """Periodic ARP spoofing / MITM detection."""
        def _scan():
            suspicious = self._check_arp_spoofing()
            for s in suspicious:
                msg = f"[!] ARP SPOOF? MAC {s['mac']} maps to multiple IPs: {', '.join(s['ips'])}"
                _m = msg; self._queue_alert(_m, Colors.GAUGE_RED)
        self._executor.submit(_scan)
        self._orig_after(120_000, self._arp_monitor_loop)

    # -- WMI subscription monitor -------------------------------------------

    def _wmi_monitor_loop(self):
        """Check for malicious WMI persistence subscriptions."""
        def _scan():
            subs = self._check_wmi_subscriptions()
            if subs:
                msg = f"[ALERT] WMI SUBSCRIPTIONS DETECTED: {', '.join(subs[:3])}"
                _m = msg; self._queue_alert(_m, Colors.GAUGE_RED)
        self._executor.submit(_scan)
        self._orig_after(300_000, self._wmi_monitor_loop)

    # -- FIM (File Integrity Monitor) loop ---------------------------------

    def _fim_loop(self):
        """Periodically verify critical system file integrity."""
        def _scan():
            results = self._fim_check_critical_files()
            for r in results:
                if r['tampered']:
                    msg = f"[ALERT] FIM ALERT: {r['file']} hash matches KNOWN MALWARE"
                    _m = msg; self._queue_alert(_m, Colors.GAUGE_RED)
        self._executor.submit(_scan)
        self._orig_after(300_000, self._fim_loop)

    def _expire_old_iocs(self):
        """Purge IOC entries older than 30 days to keep DB lean."""
        try:
            from datetime import datetime, timedelta
            cutoff = (datetime.now() - timedelta(days=30)).isoformat()
            tables = ['malicious_urls', 'malicious_ips',
                      'malicious_hashes', 'malicious_domains']
            total = 0
            for tbl in tables:
                try:
                    r = self.db.execute(
                        f'DELETE FROM {tbl} WHERE added < ?', (cutoff,))
                    if r and hasattr(r, 'rowcount') and r.rowcount:
                        total += r.rowcount
                except Exception:
                    pass
            if total > 0:
                logger.info(f'[IOC_EXPIRE] Purged {total} entries older than 30 days')
                self._queue_alert(f'[DB] Purged {total} stale IOCs (>30 days)', Colors.GAUGE_TEAL)
        except Exception as e:
            logger.error(f'IOC expiration failed: {e}')

    def _auto_start(self):
        """Actions after window is shown — MINIMAL startup, everything else manual."""
        # FIX-v28p38: NOTHING starts automatically except essential UI plumbing.
        # All engines, monitors, and scanners are started by the user via
        # the Engine Control Panel buttons on the Dashboard tab.

        # Start loops (now only heartbeat)
        try:
            self.after(2000, self._start_loops_safe)
        except Exception as e:
            error_logger.log('AutoStart', 'Failed to schedule start_loops', e)

        # Alert drainer — essential for UI (thread-safe alert queue → listbox)
        try:
            self.after(2000, self._drain_alert_queue)
        except Exception:
            pass

        # Wire AEGIS alert callbacks (just wiring, no starting)
        def _aegis_alert(msg: str, level: str = 'HIGH'):
            color = (Colors.GAUGE_RED if level == 'CRITICAL' else
                     Colors.GAUGE_ORANGE if level == 'HIGH' else Colors.GAUGE_YELLOW)
            self._queue_alert(msg, color)
        for layer in (self.aegis_physical, self.aegis_tcp, self.aegis_ingest,
                      self.aegis_nlp, self.aegis_memory):
            layer.alert_cb = _aegis_alert
        if hasattr(self, 'aegis') and hasattr(self.aegis, 'tor_router'):
            self.aegis.tor_router.alert_cb = _aegis_alert
        self._aegis_refresh_running = False

        # Defender exclusion status
        if _DEFENDER_EXCLUSION_ADDED:
            self._queue_alert(
                "[SHIELD] AV Safe-Mode: Defender exclusions added",
                '#00e5ff')

        # Freeze diagnostic (lightweight — 200ms check, no work)
        import time as _fdt
        self._freeze_diag_last = _fdt.perf_counter()
        def _freeze_check():
            if not self.winfo_exists(): return
            now = _fdt.perf_counter()
            elapsed = now - self._freeze_diag_last
            if elapsed > 1.5:
                logger.warning('[FREEZE] GUI blocked %.1fs', elapsed)
            self._freeze_diag_last = now
            self._orig_after(500, _freeze_check)
        self._orig_after(500, _freeze_check)

        # Initial intel stats (one-shot, lightweight)
        self.after(500, lambda: self._stat_labels['iocs'].config(
            text=f"{self.db.count_intel():,}"))

        # Feed refresh loop (lightweight UI update, 30s interval)
        self.after(20_000, self._feed_refresh_loop)

        # Status pills (one-shot UI refresh)
        self.after(10_000, self._refresh_status_pills)

        # Welcome message
        self._queue_alert(
            '[READY] Downpour v29 Titanium loaded. '
            'Use the Engine Control Panel on the Dashboard to start engines.',
            Colors.GAUGE_TEAL)

    def _scheduled_nsa_check(self):
        """Run security assessment on startup and reschedule every 6 hours."""
        self._run_nsa_security_report()
        self.after(6 * 3600 * 1000, self._scheduled_nsa_check)  # 6 hours

    def _update_health_score(self):
        """Compute real-time security health score (0-100) from multiple signals."""
        try:
            if not self.winfo_exists():
                return
            score = 100
            details = []

            # Deduct for active threats
            threat_count = len([p for p in getattr(self, '_processes', [])
                               if getattr(p, 'is_suspicious', False)])
            if threat_count > 0:
                penalty = min(40, threat_count * 8)
                score -= penalty
                details.append(f"{threat_count} threats (-{penalty})")

            # Deduct for stale intel feeds (not updated in 24h)
            if hasattr(self, 'intel'):
                last = getattr(self.intel, 'last_update', None)
                if last and (datetime.now() - last).total_seconds() > 86400:
                    score -= 10
                    details.append("Intel stale (-10)")
                elif last is None:
                    score -= 15
                    details.append("Intel not loaded (-15)")

            # Deduct if Defender exclusion not set
            if not _DEFENDER_EXCLUSION_ADDED:
                score -= 5
                details.append("No AV exclusion (-5)")

            # Deduct for high alert count
            alert_count = getattr(self, '_alert_list', None)
            if alert_count and hasattr(alert_count, 'size') and alert_count.size() > 30:
                score -= 10
                details.append(f"Alert backlog (-10)")

            # Bonus for active monitoring
            if hasattr(self, '_kimwolf_detector') and getattr(self._kimwolf_detector, '_running', False):
                score = min(100, score + 3)

            score = max(0, min(100, score))

            # Grade mapping
            if score >= 95:
                grade, color = "A+  EXCELLENT", Colors.GAUGE_GREEN
            elif score >= 85:
                grade, color = "A   STRONG", Colors.GAUGE_GREEN
            elif score >= 70:
                grade, color = "B   GOOD", Colors.GAUGE_TEAL
            elif score >= 55:
                grade, color = "C   FAIR", Colors.GAUGE_YELLOW
            elif score >= 40:
                grade, color = "D   AT RISK", Colors.GAUGE_ORANGE
            else:
                grade, color = "F   CRITICAL", Colors.GAUGE_RED

            self._health_score_lbl.config(text=str(score), fg=color)
            self._health_grade_lbl.config(text=grade, fg=color)
            detail_text = " | ".join(details) if details else "All systems nominal"
            self._health_detail_lbl.config(text=detail_text[:60])

            # Also update rain storm level from health score
            if hasattr(self, 'rain'):
                self.rain.set_threat_level(100 - score)

            # Update threat pulse indicator in title bar
            if hasattr(self, '_threat_pulse_lbl'):
                if score >= 85:
                    self._threat_pulse_lbl.config(fg=Colors.GAUGE_GREEN)
                elif score >= 55:
                    self._threat_pulse_lbl.config(fg=Colors.GAUGE_YELLOW)
                elif score >= 40:
                    self._threat_pulse_lbl.config(fg=Colors.GAUGE_ORANGE)
                else:
                    # Blink red when critical
                    _pulse_on = (self._frame if hasattr(self, '_frame') else 0) % 2 == 0
                    self._threat_pulse_lbl.config(
                        fg=Colors.GAUGE_RED if _pulse_on else Colors.GLASS_DARK)
        except Exception:
            pass
        try:
            self._orig_after(10000, self._update_health_score)
        except Exception:
            pass

    def _update_uptime_ticker(self):
        """Update the uptime counter in the status bar every second."""
        try:
            if not self.winfo_exists():
                return
            elapsed = int(time.time() - self._uptime_start)
            h, m, s = elapsed // 3600, (elapsed % 3600) // 60, elapsed % 60
            self._sb_uptime.config(text=f"\u23f1 {h:02d}:{m:02d}:{s:02d}")
        except Exception:
            pass
        try:
            self._orig_after(1000, self._update_uptime_ticker)
        except Exception:
            pass

    def _refresh_status_pills(self):
        """Refresh the AV-Safe and threat-count status bar pills every 10 s."""
        try:
            # Defender exclusion indicator
            if hasattr(self, '_sb_defender'):
                if _DEFENDER_EXCLUSION_ADDED:
                    self._sb_defender.config(text="AV-Safe [OK]", fg='#00e5ff')
                else:
                    self._sb_defender.config(text="No AV Excl [WARN]", fg='#ff9800')
            # Live threat count
            if hasattr(self, '_sb_threats'):
                try:
                    rows = self.db.execute(
                        "SELECT COUNT(*) FROM threats WHERE status='active'")
                    count = rows[0][0] if rows else 0
                except Exception:
                    count = len(getattr(self, '_active_threats', {}))
                if count == 0:
                    self._sb_threats.config(text="\u2714 Threats: 0", fg='#00e5ff')
                    # v28p35: calm rain when no threats
                    if hasattr(self, 'rain') and hasattr(self.rain, 'set_threat_level'):
                        self.rain.set_threat_level(0)
                elif count < 5:
                    self._sb_threats.config(text=f"\u26a0 Threats: {count}", fg='#ff9800')
                    if hasattr(self, 'rain') and hasattr(self.rain, 'set_threat_level'):
                        self.rain.set_threat_level(min(count * 15, 60))
                else:
                    self._sb_threats.config(text=f"\u2622 Threats: {count} [RED]", fg='#ff1744')
                    if hasattr(self, 'rain') and hasattr(self.rain, 'set_threat_level'):
                        self.rain.set_threat_level(min(count * 10, 100))
        except Exception:
            pass
        self.after(10000, self._refresh_status_pills)

    def _on_aegis_alert(self, msg: str, level: str = 'HIGH'):
        color = (Colors.GAUGE_RED if level == 'CRITICAL' else
                 Colors.GAUGE_ORANGE if level == 'HIGH' else Colors.GAUGE_YELLOW)
        _m = msg; _c = color; self._queue_alert(_m, _c)

    def _background_harden_check(self):
        try:
            results = self.hardening.analyze()
            score, max_score = self.hardening.get_score()
            pct = int(score / max_score * 100) if max_score else 0
            color = Colors.GAUGE_RED if pct < 50 else (Colors.GAUGE_ORANGE if pct < 75 else Colors.GAUGE_GREEN)
            self._queue_alert(
                f"[SHIELD] Security Score: {pct}% ({score}/{max_score})  -  {'NEEDS HARDENING' if pct < 50 else 'Good'}",
                color)
        except Exception as e:
            error_logger.log('Hardening', 'Background check failed', e)

    def _feed_refresh_loop(self):
        """Periodically show feed/IOC counts"""
        if not self.winfo_exists():
            return  # Window destroyed — stop rescheduling
        try:
            if hasattr(self, '_stat_labels') and self._stat_labels:
                if 'feeds' in self._stat_labels:
                    self._stat_labels['feeds'].config(text=str(len(self.intel.FEEDS)))
                if 'iocs' in self._stat_labels:
                    # FIX: db.count_intel() acquires db._lock which background threads
                    # also hold during bulk inserts — calling it on the main thread can
                    # block for many seconds. Run it in the executor instead.
                    def _update_ioc_count():
                        try:
                            n = self.db.count_intel()
                            self.after(0, lambda c=n: (
                                hasattr(self, '_stat_labels') and
                                'iocs' in self._stat_labels and
                                self._stat_labels['iocs'].config(text=f"{c:,}")
                            ))
                        except Exception:
                            pass
                    self._executor.submit(_update_ioc_count)
        except Exception:
            pass
        self._orig_after(self._adaptive_feed_ms, self._feed_refresh_loop)

    def _hw_loop(self):
        if not self.winfo_exists():
            return
        try:
            if self.winfo_viewable() == 0:
                self._orig_after(2000, self._hw_loop)
                return
        except Exception:
            pass
        try:
            # FIX-v28p9: ONLY use cached stats, never sync fetch on main thread
            with self.hw._lock:
                if not self.hw._cache:
                    self.after(1000, self._hw_loop)
                    return  # bg thread hasn't warmed cache yet
                s = dict(self.hw._cache)
            cpu_pct = s.get('cpu_percent', 0) or 0
            cpu_temp = s.get('cpu_temp', 0) or 0
            ram_pct  = s.get('ram_percent', 0) or 0
            gpu_pct  = s.get('gpu_percent', 0) or 0
            gpu_temp = s.get('gpu_temp', 0) or 0
            net_up   = s.get('net_send_rate', 0) or 0
            net_dn   = s.get('net_recv_rate', 0) or 0
            disk_pct = s.get('disk_used_percent', 0) or 0

            cpu_color = Colors.GAUGE_RED if cpu_pct > 85 else (Colors.GAUGE_ORANGE if cpu_pct > 60 else Colors.GAUGE_BLUE)
            ram_color = Colors.GAUGE_RED if ram_pct > 90 else (Colors.GAUGE_ORANGE if ram_pct > 75 else Colors.GAUGE_PURPLE)
            gpu_color = Colors.GAUGE_RED if gpu_pct > 90 else Colors.GAUGE_ORANGE
            tmp_color = Colors.GAUGE_RED if cpu_temp > 85 else (Colors.GAUGE_ORANGE if cpu_temp > 65 else Colors.GAUGE_GREEN)

            if not hasattr(self, '_cpu_lbl'):
                self.after(2000, self._hw_loop)
                return
            self._cpu_lbl.config(text=f"{cpu_pct:.1f}%", fg=cpu_color)
            self._ram_lbl.config(text=f"{ram_pct:.1f}%", fg=ram_color)
            self._gpu_lbl.config(text=f"{gpu_pct:.0f}%" if gpu_pct else "N/A", fg=gpu_color)
            self._tmp_lbl.config(text=f"{cpu_temp:.0f} degC" if cpu_temp else "--", fg=tmp_color)
            # Net: show rate in KB/s or MB/s
            def _rate(kbs):
                if kbs >= 1024: return f"{kbs/1024:.1f}M"
                return f"{kbs:.0f}K"
            self._net_lbl.config(text=f"^{_rate(net_up)} v{_rate(net_dn)}")
            try:
                # FIX-v28p23: Show disk I/O rates instead of just used%
                dr = s.get('disk_read_rate', 0) or 0
                dw = s.get('disk_write_rate', 0) or 0
                if dr > 0 or dw > 0:
                    disk_str = f'R{dr:.0f} W{dw:.0f}'
                    disk_color = Colors.GAUGE_TEAL if (dr+dw) > 50 else Colors.GAUGE_YELLOW
                else:
                    disk_str = f'{disk_pct:.0f}% used'
                    disk_color = Colors.GAUGE_RED if disk_pct > 90 else Colors.GAUGE_YELLOW
                self._disk_lbl.config(text=disk_str, fg=disk_color)
            except Exception:
                pass
            # FIX-v28p23: Show process count
            try:
                proc_ct = s.get('process_count', 0) or 0
                if hasattr(self, '_prc_lbl'):
                    self._prc_lbl.config(text=f'{proc_ct}')
            except Exception:
                pass
        except Exception:
            pass
        self.after(self._adaptive_hw_ms, self._hw_loop)

    def _proc_loop(self):
        # FIX: Use a dedicated lock for process list, not self._lock which is
        # the tkapp internal lock and not safely accessible from background threads
        # on Python 3.13+. Create it lazily once.
        if not hasattr(self, '_proc_list_lock'):
            self._proc_list_lock = threading.Lock()
        _lock = self._proc_list_lock

        def do_scan():
            try:
                import pythoncom; pythoncom.CoInitialize()
            except Exception:
                pass
            try:
                procs = self.scanner.scan_all()
                with _lock:
                    self._processes = procs
                threats = [p for p in procs if p.is_suspicious]
                # FIX: guard self.after() — "main thread is not in main loop"
                # fires when the executor thread runs during Tk shutdown.
                try:
                    self.after(50, lambda p=procs, t=threats: self._update_proc_ui(p, t))
                except RuntimeError:
                    pass  # App shutting down
            except Exception as e:
                error_logger.log('ProcLoop', 'Scan error', e)
        self._executor.submit(do_scan)
        try:
            self._orig_after(self._adaptive_prc_ms, self._proc_loop)
        except RuntimeError:
            pass  # App shutting down

    def _net_loop(self):
        def do_net():
            try:
                conns = self.net_monitor.get_all_connections()
                alerts = self.net_monitor.analyze_connections(conns)
                # Build proc_map here in background (not on UI thread)
                proc_map = {}
                if PSUTIL_AVAILABLE:
                    try:
                        for proc in psutil.process_iter(['pid', 'name']):
                            try: proc_map[proc.pid] = proc.name()
                            except Exception: pass
                    except Exception: pass
                self._cached_proc_map = proc_map
                # FIX-v28p35: Pre-compute threat lookups in background thread
                # Uses batch IP check for single SQL query instead of N individual calls
                threat_cache = {}
                public_ips = []
                for conn in conns:
                    if not conn.raddr:
                        continue
                    rip = conn.raddr.ip
                    if rip in threat_cache:
                        continue
                    _priv_172 = False
                    if rip.startswith('172.'):
                        try: _priv_172 = 16 <= int(rip.split('.')[1]) <= 31
                        except (ValueError, IndexError): pass
                    _is_priv = (
                        rip.startswith('192.168.') or rip.startswith('10.')
                        or _priv_172 or rip in ('127.0.0.1', '::1')
                        or rip.startswith('169.254.')
                    )
                    if _is_priv:
                        threat_cache[rip] = False
                    else:
                        public_ips.append(rip)
                # Single batch query for all public IPs
                if public_ips:
                    try:
                        batch_results = self.intel.check_ip_batch(public_ips)
                        threat_cache.update(batch_results)
                    except Exception:
                        for ip in public_ips:
                            try:
                                threat_cache[ip] = bool(self.intel.check_ip(ip))
                            except Exception:
                                threat_cache[ip] = False
                # FIX: guard self.after() calls — "main thread is not in main loop"
                try:
                    self.after(50, lambda c=conns, m=proc_map, tc=threat_cache:
                               self._update_network_ui(c, m, tc))
                    if alerts:
                        def _dispatch_net_alerts(al=alerts):
                            for a in al[:20]:
                                self._on_network_alert(a)
                        self.after(0, _dispatch_net_alerts)
                except RuntimeError:
                    pass
            except Exception as e:
                error_logger.log('NetLoop', 'Net error', e)
        self._executor.submit(do_net)
        try:
            self._orig_after(30_000, self._net_loop)  # FIX-v28p16: was 8s
        except RuntimeError:
            pass  # App shutting down

    def _ctrl_loop(self):
        state = None  # FIX: initialise before try so interval calc below never NameErrors
        try:
            state = self.controller.get()
            if state:
                self._ctrl_label.config(text="🎮 Controller: Connected",
                                         fg=Colors.GAUGE_GREEN)
                # Controller shortcuts
                if state.get('start') and state.get('back'):
                    self._panic_button()
            else:
                self._ctrl_label.config(text="Controller: --", fg=Colors.TEXT_INACTIVE)
        except Exception:
            pass
        # FIX-v28p9: 2s poll (was 200-500ms, too frequent for main thread)
        _ctrl_interval = 1000 if (state and any(state.values())) else 2000
        self.after(_ctrl_interval, self._ctrl_loop)

    def _adaptive_load_loop(self):
        """Re-tune scan intervals every 60s based on CPU/RAM pressure."""
        if not self.winfo_exists():
            return
        self._executor.submit(lambda: (
            HardwareProfiler.adapt_to_load(self)
        ))
        self.after(60000, self._adaptive_load_loop)

    def _intel_auto_loop(self):
        if self.cfg.get('intel', 'auto_update'):
            interval_h = self.cfg.get('intel', 'update_interval_hours') or 6
            if (self.intel.last_update is None or
                    (datetime.now() - self.intel.last_update).seconds > interval_h * 3600):
                self._executor.submit(lambda: self.intel.update_all(
                    lambda msg: self.after(0, lambda m=msg: self._intel_progress_var.set(m))))
        self.after(600000, self._intel_auto_loop)  # check every 10 min (manual trigger only now)

    # --------------------------------------------------------------------------
    #  UI UPDATERS
    # --------------------------------------------------------------------------

    def _update_proc_ui(self, procs: list, threats: list):
        """Diff-based treeview update  -  only insert/delete/update changed rows.
        Avoids full delete+reinsert of 100+ rows on every 30s scan (major freeze cause)."""
        if not self.winfo_exists(): return
        try:
            flt = self._proc_filter.get().lower() if hasattr(self, '_proc_filter') else ''
            # Build target dict: pid -> row values
            target = {}
            for p in procs:
                if flt and flt not in p.name.lower() and flt not in str(p.pid):
                    continue
                reasons = '; '.join(p.risk_reasons[:3])
                tag = 'danger' if p.risk_score >= 70 else ('warn' if p.risk_score >= 40 else 'ok')
                target[str(p.pid)] = (
                    (p.pid, p.name, p.risk_score, reasons,
                     f"{len(p.connections)} conn", f"{p.memory_mb:.1f}MB", p.c2_framework),
                    tag)

            # Current rows in tree
            existing = set(self._proc_tree.get_children())
            target_ids = set(target.keys())

            # Remove rows no longer present (batch)
            to_remove = existing - target_ids
            if to_remove:
                self._proc_tree.delete(*to_remove)

            # Add or update rows
            for pid_s, (vals, tag) in target.items():
                if pid_s in existing:
                    cur_vals = self._proc_tree.item(pid_s, 'values')
                    if tuple(str(v) for v in cur_vals) != tuple(str(v) for v in vals):
                        self._proc_tree.item(pid_s, values=vals, tags=(tag,))
                else:
                    self._proc_tree.insert('', 'end', iid=pid_s, values=vals, tags=(tag,))

            # Stats (lightweight)
            self._stat_labels['procs'].config(text=str(len(procs)))
            self._stat_labels['threats'].config(text=str(len(threats)))
            self._threat_count_lbl.config(
                text=f"Threats: {len(threats)}",
                fg=Colors.GAUGE_RED if threats else Colors.TEXT_DIM)

            # Alert only on NEW high-risk threats (track seen set)
            if not hasattr(self, '_alerted_pids'):
                self._alerted_pids = set()
            for t in threats:
                if t.risk_score >= 70 and t.pid not in self._alerted_pids:
                    self._alerted_pids.add(t.pid)
                    self._add_alert(
                        f"[!] {t.name} (PID {t.pid}) - Risk {t.risk_score}%",
                        Colors.GAUGE_ORANGE)
                    if t.c2_framework:
                        self._add_alert(
                            f"[R] C2 DETECTED: {t.c2_framework} in {t.name}",
                            Colors.GAUGE_RED)
            # Clean up alerted pids that are gone
            self._alerted_pids &= target_ids

        except Exception as e:
            error_logger.log('ProcUI', 'Update error', e)

    def _update_network_ui(self, conns, proc_map: dict = None, threat_cache: dict = None):
        """Diff-based network treeview. proc_map + threat_cache pre-built in background."""
        if not self.winfo_exists(): return
        try:
            if proc_map is None:
                proc_map = getattr(self, '_cached_proc_map', {})
            if threat_cache is None:
                threat_cache = {}

            target = {}
            for conn in conns:
                if not conn.raddr:
                    continue
                rip       = conn.raddr.ip
                rport     = conn.raddr.port
                proc_name = proc_map.get(conn.pid, 'Unknown')
                threat    = ''
                # FIX-v28p35: use pre-computed threat cache (no blocking calls on main thread)
                if threat_cache.get(rip, False):
                    threat = '[!] Blacklisted IP'
                elif rport in KnownThreats.RAT_PORTS:
                    threat = f"RAT:{KnownThreats.RAT_PORTS[rport]}"
                lip  = f"{conn.laddr.ip}:{conn.laddr.port}" if conn.laddr else ''
                key  = f"{conn.pid}_{rip}_{rport}"
                tag  = 'threat' if threat else 'normal'
                target[key] = ((conn.pid, proc_name, lip, rip, rport,
                                conn.status, threat, ''), tag)

            existing = set(self._net_tree.get_children())
            target_ids = set(target.keys())

            to_remove = existing - target_ids
            if to_remove:
                self._net_tree.delete(*to_remove)

            for k, (vals, tag) in target.items():
                if k in existing:
                    # Update existing row if values changed
                    cur = self._net_tree.item(k, 'values')
                    if tuple(str(v) for v in cur) != tuple(str(v) for v in vals):
                        self._net_tree.item(k, values=vals, tags=(tag,))
                else:
                    self._net_tree.insert('', 'end', iid=k, values=vals, tags=(tag,))

            self._stat_labels['iocs'].config(text=f"{self.db.count_intel():,}")
        except Exception as e:
            error_logger.log('NetUI', 'Update error', e)

    def _on_tk_callback_error(self, exc_type, exc_value, exc_tb):
        """Catch Tkinter callback errors — log them instead of crashing."""
        import traceback, logging
        logging.getLogger('Downpour.TkCallback').error(
            "Tkinter callback error: %s: %s\n%s", exc_type.__name__, exc_value,
            ''.join(traceback.format_exception(exc_type, exc_value, exc_tb)))

    def _ts(self, fn, *a, **kw):
        """Thread-safe GUI call: marshals fn(*a, **kw) to the main thread.
        Safe to call from ANY thread — if already on main thread, runs directly."""
        import threading
        if threading.current_thread() is threading.main_thread():
            try: fn(*a, **kw)
            except Exception: pass
        else:
            try: self.after(0, lambda: fn(*a, **kw))
            except Exception: pass

    def _ts_var_set(self, var, value):
        """Thread-safe StringVar.set() — safe from any thread."""
        self._ts(var.set, value)

    _ALERT_MAX = 500   # hard cap on alert list entries to prevent memory/redraw bloat

    def _add_alert(self, msg: str, color: str = Colors.TEXT_LIGHT):
        # FIX: _add_alert is called from background threads (KimwolfDetector,
        # AegisTCP, etc.). Direct Tkinter widget calls from non-main threads
        # cause fatal C-level crashes (TclError / access violation).
        # Route all widget updates through self.after(0) to marshal back to
        # the main thread safely.
        import threading as _th
        if _th.current_thread() is not _th.main_thread():
            # FIX-v28p16: Route bg thread alerts through _queue_alert for dedup
            self._queue_alert(msg, color)
            return
        # --- Main thread path ---
        # Update status bar ticker (trim to 80 chars)
        try:
            short = msg.replace('\n', ' ')
            if len(short) > 80:
                short = short[:77] + '...'
            self._last_alert_var.set(short)
        except Exception:
            pass
        ts = datetime.now().strftime('%H:%M:%S')
        full_msg = f"[{ts}] {msg}"
        self._alert_queue.append((full_msg, color))
        # Feed structured threat log for the Threats tab
        # Skip purely informational/action messages (TEXT_LIGHT, TEXT_DIM)
        if color in (Colors.GAUGE_RED, Colors.GAUGE_ORANGE,
                     Colors.GAUGE_YELLOW, Colors.GAUGE_TEAL):
            try:
                severity = ('CRITICAL' if color == Colors.GAUGE_RED
                            else 'HIGH'     if color == Colors.GAUGE_ORANGE
                            else 'MEDIUM'   if color == Colors.GAUGE_YELLOW
                            else 'INFO')
                # Parse category from bracketed prefix e.g. [BOTNET], [PROCESS]
                import re as _re
                _m = _re.match(r'\[([A-Z0-9_\-]+)\]', msg.lstrip())
                category = _m.group(1).title() if _m else 'General'
                _cat_map = {
                    'Process': 'Process', 'Proc': 'Process',
                    'Web': 'Network', 'Net': 'Network',
                    'Botnet': 'Botnet', 'Kimwolf': 'Botnet',
                    'Mozi': 'Botnet', 'Mirai': 'Botnet',
                    'Ransom': 'Ransomware',
                    'Imsi': 'WiFi/RF', 'Wifi': 'WiFi/RF',
                    'Iot': 'IoT',
                    'Dns': 'DNS',
                    'Zero-Day': 'Zero-Day', 'Zeroday': 'Zero-Day',
                    'Port': 'Port Scan',
                    'Win11': 'Hardening', 'Hardening': 'Hardening',
                    'Action': 'Action',
                }
                category = _cat_map.get(category, category)
                entry = {
                    'idx':         self._threat_log_idx,
                    'time':        ts,
                    'severity':    severity,
                    'category':    category,
                    'description': msg,
                    'status':      'New',
                    'color':       color,
                }
                self._threat_log.append(entry)
                self._threat_log_idx += 1
                # Cap log at 2000 entries
                if len(self._threat_log) > 2000:
                    self._threat_log = self._threat_log[-2000:]
                self._threat_log_dirty = True
            except Exception:
                pass
        # -- Sound alarm on CRITICAL / HIGH ------------------------------
        # FIX-v28p21: Re-enabled alarm via executor (non-blocking)
        if color == Colors.GAUGE_RED:
            try: self._io_executor.submit(self._play_alarm, 'CRITICAL')
            except Exception: pass
        elif color == Colors.GAUGE_ORANGE:
            try: self._io_executor.submit(self._play_alarm, 'HIGH')
            except Exception: pass
        try:
            self._alert_list.insert('end', full_msg)
            self._alert_list.itemconfig('end', fg=color)
            self._alert_list.see('end')
            if self._alert_list.size() > 100:  # FIX-v28p15: was 300
                self._alert_list.delete(0, 30)
        except Exception:
            pass

    def _queue_alert(self, msg: str, color: str = None):
        """Thread-safe fast path with rate limiting."""
        if color is None:
            color = Colors.TEXT_LIGHT
        import time as _t
        now = _t.monotonic()
        # FIX-v28p16: Hard rate limit - max 2 alerts per second globally
        if now - self._alert_rate_reset > 1.0:
            self._alert_rate_reset = now
            self._alert_rate_count = 0
        self._alert_rate_count += 1
        if self._alert_rate_count > 2:
            return  # Drop alert - rate limited
        # Dedup: skip if same prefix fired within last 4 seconds
        prefix = msg[:40]
        last = self._alerted_dedup.get(prefix, 0)
        if now - last < 30.0:  # FIX-v28p16: was 4s, alert flood was 100+/min
            return
        self._alerted_dedup[prefix] = now
        # Prune old dedup entries every ~200 alerts
        if len(self._alerted_dedup) > 200:
            cutoff = now - 60.0  # FIX-v28p16: match dedup window
            self._alerted_dedup = {k: v for k, v in self._alerted_dedup.items() if v > cutoff}
        # FIX-v28p21: Run MITRE tagging here (bg thread, not main thread)
        if color in (Colors.GAUGE_RED, Colors.GAUGE_ORANGE):
            try: msg = self._tag_mitre(msg)
            except Exception: pass
        self._pending_alerts.append((msg, color))

    _alert_rate_count = 0
    _alert_rate_reset = 0.0

    def _drain_alert_queue(self):
        """Drain pending alerts at 100ms rate — max 8 per cycle to avoid jank.
        Also drains _pending_after callbacks queued by background threads."""
        try:
            if not self.winfo_exists():
                return  # Window destroyed — stop rescheduling
            # -- Drain deferred self.after() calls from background threads --
            for _ in range(20):  # FIX-v28p19: drain more pending_after per cycle
                if not self._pending_after:
                    break
                try:
                    ms, func, args = self._pending_after.popleft()
                    self._orig_after(ms, func, *args)
                except Exception:
                    pass
            # -- Drain alert queue --
            drained = 0
            for _ in range(12):  # FIX-v28p35: 12 per cycle (was 4)
                if not self._pending_alerts:
                    break
                msg, color = self._pending_alerts.popleft()
                try:
                    self._add_alert(msg, color)
                except Exception:
                    pass  # Widget may not exist yet — skip this alert
                drained += 1
            # Refresh threats tab treeview if new entries arrived.
            # FIX: throttle to max once per 2s AND only when tab is visible,
            # to avoid rebuilding 2000-row treeview on every 150ms drain cycle.
            # Only clear dirty flag after an actual refresh so tab is fresh on open.
            if getattr(self, '_threat_log_dirty', False):
                import time as _trt
                _now = _trt.monotonic()
                _last = getattr(self, '_threat_log_refresh_ts', 0.0)
                if _now - _last >= 2.0:
                    try:
                        # Only rebuild if Threats tab is selected
                        _sel = getattr(self, 'nb', None) and self.nb.select()
                        _thr_outer = getattr(self, '_nb_outer', {}).get('_tab_threats')
                        _visible = (not _thr_outer) or (str(_thr_outer) == _sel)
                        if _visible:
                            self._threat_log_dirty = False
                            self._threat_log_refresh_ts = _now
                            self._threats_tab_refresh()
                        else:
                            # Tab not visible — update timestamp to enforce rate limit
                            # but keep dirty=True so tab refreshes when next opened
                            self._threat_log_refresh_ts = _now
                    except Exception:
                        pass
            self._orig_after(150, self._drain_alert_queue)  # FIX-v28p35: 150ms (was 300ms)
        except tk.TclError:
            pass  # Tk destroyed — stop cleanly
        except Exception:
            # Reschedule even on error to keep drain alive
            try:
                self._orig_after(500, self._drain_alert_queue)
            except Exception:
                pass

    def _on_network_alert(self, alert: dict):
        # FIX: called from background threads — all Tkinter calls must be on main thread
        import threading as _th
        if _th.current_thread() is not _th.main_thread():
            msg = f"[WEB] {alert.get('msg', 'Network alert')}"
            self._pending_alerts.append((msg, Colors.GAUGE_ORANGE))
            return
        self._queue_alert(f"[WEB] {alert.get('msg', 'Network alert')}", Colors.GAUGE_ORANGE)
        try:
            self._net_alert_box.config(state='normal')
            self._net_alert_box.insert('end', f"[{datetime.now().strftime('%H:%M:%S')}] {alert.get('msg','')}\n")
            self._net_alert_box.see('end')
            self._net_alert_box.config(state='disabled')
        except Exception:
            pass

    def _on_emergency_event(self, msg: str):
        # FIX: called from background threads (ransomware, mem_forensics, emergency).
        # Use _pending_alerts deque (thread-safe) instead of self.after() which can
        # crash if called from a thread while Tkinter is mid-operation.
        import threading as _th
        if _th.current_thread() is not _th.main_thread():
            # Enqueue for _drain_alert_queue to process on main thread
            self._pending_alerts.append((msg, Colors.GAUGE_RED))
            return
        self._queue_alert(msg, Colors.GAUGE_RED)
        try:
            self._emergency_log.config(state='normal')
            self._emergency_log.insert('end', f"{msg}\n")
            self._emergency_log.see('end')
            self._emergency_log.config(state='disabled')
        except Exception:
            pass

    def _show_proc_detail(self, event=None):
        sel = self._proc_tree.selection()
        if not sel:
            return
        pid = int(sel[0])
        proc = next((p for p in self._processes if p.pid == pid), None)
        if not proc:
            return
        detail = (
            f"PID:     {proc.pid}\n"
            f"Name:    {proc.name}\n"
            f"Path:    {proc.path or 'Unknown'}\n"
            f"User:    {proc.username or 'Unknown'}\n"
            f"Parent:  {proc.parent_name} ({proc.parent_pid})\n"
            f"Memory:  {proc.memory_mb:.1f} MB\n"
            f"CPU:     {proc.cpu_percent:.1f}%\n"
            f"Cmdline: {proc.cmdline[:100] or 'N/A'}\n\n"
            f"Risk Score: {proc.risk_score}/100\n"
            f"Reasons:\n"
        )
        for r in proc.risk_reasons:
            detail += f"  - {r}\n"
        if proc.yara_hits:
            detail += "\nYARA Hits:\n"
            for h in proc.yara_hits:
                detail += f"  [TARGET] {h}\n"
        if proc.c2_framework:
            detail += f"\n[!] C2 FRAMEWORK: {proc.c2_framework}\n"
        if _proc_has_connections(proc):
            detail += f"\nConnections ({len(_proc_has_connections(proc))}):\n"
            for c in _proc_has_connections(proc)[:5]:
                detail += f"  {c['remote_ip']}:{c['remote_port']}\n"
        try:
            self._proc_detail.config(state='normal')
            self._proc_detail.delete('1.0', 'end')
            self._proc_detail.insert('1.0', detail)
            self._proc_detail.config(state='disabled')
        except Exception:
            pass


    # --------------------------------------------------------------------------
    #  ACTIONS
    # --------------------------------------------------------------------------

    def _scan_processes_now(self):
        self._set_status("Scanning processes...")
        def do():
            procs = self.scanner.scan_all()
            threats = [p for p in procs if p.is_suspicious]
            with self._lock:
                self._processes = procs
            self.after(50, lambda: self._update_proc_ui(procs, threats))
            self.after(50, lambda: self._set_status(f"Scan done: {len(procs)} processes, {len(threats)} suspicious"))
        self._executor.submit(do)

    def _mitigate_selected(self, action: str):
        sel = self._proc_tree.selection()
        if not sel:
            messagebox.showinfo("Select Process", "Select a process first")
            return
        pid = int(sel[0])
        proc = next((p for p in self._processes if p.pid == pid), None)
        name = proc.name if proc else str(pid)
        _destructive = (
            'kill_tree', 'quarantine', 'network_isolate',
            'firewall_block', 'clean_persistence',
        )
        if action in _destructive:
            label = action.replace('_', ' ').title()
            if not messagebox.askyesno('Confirm', f"{label} '{name}'?"):
                return
        # Long-running actions go to background thread to avoid main-thread freeze
        _bg_actions = {'full_remediation', 'root_cause', 'dump_memory'}
        if action in _bg_actions:
            self._set_status(f'⏳ Running {action.replace("_"," ")} on {name}…')
            def _bg():
                ok, m = self.scanner.mitigate(pid, action, QUARANTINE_DIR)
                col = Colors.GAUGE_GREEN if ok else Colors.GAUGE_RED
                self.after(0, lambda: self._queue_alert(
                    f"{'[OK]' if ok else '[X]'} {m}", col))
                self.after(0, lambda: self._set_status(m))
                if ok:
                    self.after(500, self._scan_processes_now)
            import threading
            threading.Thread(target=_bg, daemon=True).start()
            return

        success, msg = self.scanner.mitigate(pid, action, QUARANTINE_DIR)
        color = Colors.GAUGE_GREEN if success else Colors.GAUGE_RED
        self._queue_alert(f"{'[OK]' if success else '[X]'} {msg}", color)
        self._set_status(msg)
        if success:
            self._scan_processes_now()
            # Update quarantine count
            try:
                q = len(list((QUARANTINE_DIR / "locked").glob("*.locked")))
                self._stat_labels['quarantine'].config(text=str(q))
            except Exception:
                pass

    def _refresh_network(self):
        self._executor.submit(lambda: [
            self.after(0, lambda: self._update_network_ui(self.net_monitor.get_all_connections()))
        ])

    def _block_selected_ip(self):
        sel = self._net_tree.selection()
        if not sel:
            return
        item = self._net_tree.item(sel[0])
        ip = item['values'][3] if item['values'] else None
        if not ip:
            return
        if messagebox.askyesno("Block IP", f"Block {ip} via Windows Firewall?"):
            try:
                # Validate IP format before using in command (injection guard)
                import ipaddress
                try:
                    ipaddress.ip_address(ip)
                except ValueError:
                    messagebox.showerror("Invalid IP", f"'{ip}' is not a valid IP address.")
                    return
                # Use list form to avoid shell injection
                subprocess.run(
                    ['netsh','advfirewall','firewall','add','rule',
                     f'name=DOWNPOUR_BLOCK_{ip}','dir=out','action=block',
                     f'remoteip={ip}'],
                    capture_output=True, timeout=10,
                    creationflags=subprocess.CREATE_NO_WINDOW)
                self._queue_alert(f"[BLOCK] Blocked IP: {ip}", Colors.GAUGE_ORANGE)
            except Exception as e:
                messagebox.showerror("Error", str(e))

    def _update_intel_now(self):
        self._set_status("Updating threat intelligence...")
        def do():
            self.intel.update_all(
                lambda msg: self.after(0, lambda m=msg: [
                    self._intel_progress_var.set(m),
                    self._intel_status.config(text=m),
                ]))
            self.after(0, lambda: [
                self._set_status(self.intel.status),
                self._stat_labels['iocs'].config(text=f"{self.db.count_intel():,}"),
            ])
        self._executor.submit(do)

    def _quick_file_scan(self):
        path = filedialog.askdirectory(title="Select folder to scan", initialdir=os.path.expanduser('~'))
        if path:
            self._scan_path.set(path)
            self._select_tab(self._tab_scanner)
            self._start_file_scan()

    def _browse_scan_path(self):
        p = filedialog.askdirectory(title="Select folder", initialdir=self._scan_path.get())
        if p:
            self._scan_path.set(p)

    def _start_file_scan(self):
        if self._scan_active:
            return
        self._scan_active = True
        self._scan_stop.clear()
        self._files_scanned = 0
        self._threats_found = 0
        self._scan_tree.delete(*self._scan_tree.get_children())
        self._hw_turbo_start('File Scan')
        def _run_scan_turbo():
            try:
                self._do_file_scan()
            finally:
                self._hw_turbo_stop()
        self._executor.submit(_run_scan_turbo)

    def _stop_file_scan(self):
        self._scan_stop.set()
        self._scan_active = False

