    def _panic_button(self):
        if not messagebox.askyesno("[!] EMERGENCY LOCKDOWN",
                                    "Activate full emergency response?\n\n"
                                    "This will:\n"
                                    "- Take a system snapshot\n"
                                    "- Kill suspicious processes\n"
                                    "- Block all network traffic\n\n"
                                    "Continue?",
                                    icon='warning'):
            return
        self._select_tab(self._tab_emergency)
        self._on_emergency_event("[ALERT] EMERGENCY RESPONSE STARTING...")
        self.controller.vibrate(1.0, 1.0, 1.0)

        def do():
            results = self.emergency.panic_button(
                isolate_network=self._opt_isolate.get() if hasattr(self, '_opt_isolate') else True,
                kill_suspicious=self._opt_kill.get()    if hasattr(self, '_opt_kill')    else True,
                snapshot=self._opt_snapshot.get()       if hasattr(self, '_opt_snapshot') else True,
            )
            for line in results:
                self.after(0, lambda l=line: self._on_emergency_event(l))
            # Auto-collect forensic IR evidence on panic
            try:
                ir_path = self._collect_forensic_evidence('PANIC_BUTTON')
                self.after(0, lambda p=ir_path:
                    self._on_emergency_event(f"[FILES] IR Evidence collected -> {p}"))
            except Exception as e:
                error_logger.log('Panic', 'IR collection failed', e)
            # Sound alarm
            self._play_alarm('CRITICAL')
            # Email alert
            self._maybe_send_alert_email(
                "EMERGENCY LOCKDOWN ACTIVATED",
                f"Full panic response triggered at {datetime.now()}\n"
                f"Host: {os.environ.get('COMPUTERNAME','unknown')}")
        self._executor.submit(do)

    def _take_snapshot_only(self):
        def do():
            path = self.emergency.take_snapshot()
            self.after(0, lambda: self._on_emergency_event(f"[CAM] Snapshot saved: {path}"))
        self._executor.submit(do)

    def _isolate_only(self):
        if messagebox.askyesno("Isolate Network", "Block ALL network traffic now?", icon='warning'):
            def do():
                msg = self.emergency.isolate_network()
                self.after(0, lambda: self._on_emergency_event(f"[PLUG] {msg}"))
            self._executor.submit(do)

    def _restore_network(self):
        def do():
            msg = self.emergency.restore_network()
            self.after(0, lambda: self._on_emergency_event(f"[UNLOCK] {msg}"))
            self._queue_alert(f"[UNLOCK] {msg}", Colors.GAUGE_GREEN)
        self._executor.submit(do)

    def _kill_suspicious_only(self):
        if messagebox.askyesno("Kill Processes", "Kill all suspicious processes?", icon='warning'):
            def do():
                n = self.emergency.kill_suspicious_processes()
                msg = f"Killed {n} suspicious processes"
                self.after(0, lambda: self._on_emergency_event(f"[SKULL] {msg}"))
                self.after(0, lambda: self._scan_processes_now())
            self._executor.submit(do)

