    def _refresh_parental_log(self):
        logs = self.parental.get_recent_log(50)
        try:
            self._parental_log.config(state='normal')
            self._parental_log.delete('1.0', 'end')
            for entry in logs:
                self._parental_log.insert('end', f"[{entry['time'][:16]}] {entry['type']}: {entry['detail']}\n")
            self._parental_log.config(state='disabled')
        except Exception:
            pass

