    def _toggle_widget(self):
        if self._widget and self._widget.winfo_exists():
            self._widget.destroy()
            self._widget = None
        else:
            self._widget = FloatingWidget(self.hw)

    def _save_settings(self):
        for key, var in self._cfg_vars.items():
            section, k = key.split('.', 1)
            self.cfg.set(section, k, var.get())
        # Update rain intensity
        new_intensity = self._rain_var.get()
        self.cfg.set('general', 'rain_intensity', new_intensity)
        self.rain.intensity = new_intensity
        self.rain._init_drops()
        # Update worker count
        if hasattr(self, '_worker_var'):
            self.cfg.set('general', 'worker_count', self._worker_var.get())
        messagebox.showinfo("Saved", "Settings saved.")

    def _export_config(self):
        """Export current configuration to a JSON file."""
        from tkinter import filedialog
        path = filedialog.asksaveasfilename(
            defaultextension='.json', title='Export Configuration',
            filetypes=[('JSON files', '*.json'), ('All files', '*.*')])
        if not path:
            return
        try:
            import json
            config_data = {}
            if hasattr(self.cfg, '_sections'):
                for section, vals in self.cfg._sections.items():
                    config_data[section] = dict(vals)
            elif hasattr(self.cfg, 'items'):
                for section in self.cfg.sections():
                    config_data[section] = dict(self.cfg.items(section))
            # Include current UI variable values
            ui_state = {}
            for key, var in self._cfg_vars.items():
                try: ui_state[key] = var.get()
                except Exception: pass
            config_data['_ui_state'] = ui_state
            config_data['_rain_intensity'] = self._rain_var.get()
            if hasattr(self, '_worker_var'):
                config_data['_worker_count'] = self._worker_var.get()
            with open(path, 'w', encoding='utf-8') as f:
                json.dump(config_data, f, indent=2, default=str)
            messagebox.showinfo('Export', f'Configuration exported to:\n{path}')
        except Exception as e:
            messagebox.showerror('Export Failed', f'Failed to export config:\n{e}')

    def _import_config(self):
        """Import configuration from a JSON file."""
        from tkinter import filedialog
        path = filedialog.askopenfilename(
            title='Import Configuration',
            filetypes=[('JSON files', '*.json'), ('All files', '*.*')])
        if not path:
            return
        try:
            import json
            with open(path, 'r', encoding='utf-8') as f:
                config_data = json.load(f)
            # Apply UI state
            ui_state = config_data.pop('_ui_state', {})
            for key, val in ui_state.items():
                if key in self._cfg_vars:
                    try: self._cfg_vars[key].set(val)
                    except Exception: pass
            if '_rain_intensity' in config_data:
                self._rain_var.set(config_data.pop('_rain_intensity'))
            if '_worker_count' in config_data and hasattr(self, '_worker_var'):
                self._worker_var.set(config_data.pop('_worker_count'))
            # Apply config sections
            for section, vals in config_data.items():
                if section.startswith('_'): continue
                if isinstance(vals, dict):
                    for k, v in vals.items():
                        try: self.cfg.set(section, k, v)
                        except Exception: pass
            messagebox.showinfo('Import', 'Configuration imported.\nClick Save to persist.')
        except Exception as e:
            messagebox.showerror('Import Failed', f'Failed to import config:\n{e}')

    # --------------------------------------------------------------------------
    #  NETWORK TAB ACTIONS
    # --------------------------------------------------------------------------

    def _get_net_selected_ip(self) -> str:
        sel = self._net_tree.selection()
        if not sel:
            return ''
        vals = self._net_tree.item(sel[0])['values']
        return str(vals[3]) if vals and len(vals) > 3 else ''

    def _lookup_selected_ip(self):
        ip = self._get_net_selected_ip()
        if not ip:
            messagebox.showinfo("No Selection", "Select a connection row first")
            return
        in_db = self.intel.check_ip(ip)
        msg = (f"IP: {ip}\n\n"
               f"In threat database: {'[!] YES  -  BLACKLISTED' if in_db else '[OK] Not found'}\n\n"
               f"Actions:\n- Block via firewall?\n- Geo-locate?\n- Copy to clipboard?")
        if messagebox.askyesno("IP Lookup", msg + "\n\nBlock this IP now?"):
            self._executor.submit(lambda: self._do_block_ip(ip))

    def _copy_selected_ip(self):
        ip = self._get_net_selected_ip()
        if ip:
            self.clipboard_clear()
            self.clipboard_append(ip)
            self._set_status(f"Copied: {ip}")

    def _geolocate_ip(self):
        ip = self._get_net_selected_ip()
        if not ip:
            messagebox.showinfo("No Selection", "Select a connection row first")
            return
        def do():
            try:
                req = urllib.request.Request(
                    f"http://ip-api.com/json/{ip}?fields=status,country,regionName,city,isp,org,as,threat",
                    headers={'User-Agent': 'Downpour/1.0'})
                with urllib.request.urlopen(req, timeout=8) as r:
                    data = json.loads(r.read().decode())
                if data.get('status') == 'success':
                    info = (f"IP:      {ip}\n"
                            f"Country: {data.get('country','?')}\n"
                            f"Region:  {data.get('regionName','?')}\n"
                            f"City:    {data.get('city','?')}\n"
                            f"ISP:     {data.get('isp','?')}\n"
                            f"Org:     {data.get('org','?')}\n"
                            f"AS:      {data.get('as','?')}")
                else:
                    info = f"IP: {ip}\nGeo lookup failed"
                self.after(0, lambda: messagebox.showinfo("GeoIP Result", info))
            except Exception as e:
                self.after(0, lambda _e=e: messagebox.showerror("GeoIP Error", str(_e)))
        self._executor.submit(do)

    def _portscan_selected(self):
        ip = self._get_net_selected_ip()
        if not ip:
            messagebox.showinfo("No Selection", "Select a connection row first")
            return
        def do():
            common_ports = [21,22,23,25,53,80,110,135,139,143,443,445,
                            3389,4444,4445,5900,6667,8080,8443,9999]
            open_ports = []
            for port in common_ports:
                try:
                    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
                        s.settimeout(0.5)
                        if s.connect_ex((ip, port)) == 0:
                            svc = KnownThreats.RAT_PORTS.get(port, 'unknown')
                            open_ports.append(f"  {port:5d}  {svc}")
                except Exception:
                    pass
            result = f"Port scan: {ip}\n\nOpen ports:\n" + ("\n".join(open_ports) if open_ports else "  None found")
            self.after(0, lambda: messagebox.showinfo("Port Scan Results", result))
            self._queue_alert(
                f"[NET] Port scan {ip}: {len(open_ports)} open ports", Colors.GAUGE_BLUE)
        self._set_status(f"Port scanning {ip}...")
        self._executor.submit(do)

    def _kill_conn_proc(self):
        sel = self._net_tree.selection()
        if not sel:
            return
        vals = self._net_tree.item(sel[0])['values']
        if not vals:
            return
        pid = int(vals[0]) if vals[0] else 0
        if not pid:
            return
        proc_name = vals[1]
        if messagebox.askyesno("Kill Process",
                                f"Kill process '{proc_name}' (PID {pid})?"):
            ok, msg = self.scanner.mitigate(pid, 'kill_tree', QUARANTINE_DIR)
            self._queue_alert(f"{'[OK]' if ok else '[X]'} {msg}", Colors.GAUGE_RED if ok else Colors.GAUGE_RED)
            self._refresh_network()

    def _sort_tree(self, tree: ttk.Treeview, col: str):
        """Generic sortable treeview column click handler"""
        try:
            items = [(tree.set(k, col), k) for k in tree.get_children('')]
            try:
                items.sort(key=lambda x: float(x[0]))
            except ValueError:
                items.sort(key=lambda x: x[0].lower())
            for i, (_, k) in enumerate(items):
                tree.move(k, '', i)
        except Exception:
            pass

    def _do_block_ip(self, ip: str):
        """Block an IP  -  tries Aegis WFP kernel blocker, falls back to netsh."""
        try:
            if self.aegis:
                ok, msg = self.aegis.block_ip(ip)
            else:
                ok, msg = AegisWFPBlocker.block_ip_kernel(ip)
            color = Colors.GAUGE_ORANGE if ok else Colors.GAUGE_RED
            self._queue_alert(f"{'[LOCK]' if ok else '[X]'} {msg}", color)
            if ok:
                try:
                    blocked = AegisWFPBlocker.get_blocked_ips()
                    self.after(0, lambda: self.winfo_exists() and self._stat_labels['blocked'].config(
                        text=str(len(blocked))))
                except Exception:
                    pass
        except Exception as e:
            self._queue_alert(
                f"[X] Block failed {ip}: {e}", Colors.GAUGE_RED)

