    def _show_threat_action_panel(self, alert_text: str):
        """Open a detailed threat response window for a selected alert"""
        win = tk.Toplevel(self)
        win.title("[HIGH] Downpour  -  Threat Response")
        win.configure(bg=Colors.BG_STORM)
        win.geometry("600x520")
        win.resizable(True, True)
        win.attributes('-topmost', True)
        win.lift()

        # Header
        hdr = tk.Frame(win, bg=Colors.GLASS_DARK)
        hdr.pack(fill='x', padx=0, pady=0)
        tk.Label(hdr, text="[HIGH] THREAT RESPONSE CENTER",
                 font=('Consolas', 12, 'bold'), fg=Colors.GAUGE_RED,
                 bg=Colors.GLASS_DARK).pack(side='left', padx=12, pady=8)

        # Alert text display
        alert_f = tk.Frame(win, bg=Colors.GLASS_CARD)
        alert_f.pack(fill='x', padx=8, pady=6)
        tk.Label(alert_f, text="ALERT:", font=('Consolas', 8, 'bold'),
                 fg=Colors.TEXT_DIM, bg=Colors.GLASS_CARD).pack(anchor='w', padx=6)
        tk.Label(alert_f, text=alert_text[:120], font=('Consolas', 9),
                 fg=Colors.GAUGE_RED, bg=Colors.GLASS_CARD,
                 wraplength=560, justify='left').pack(anchor='w', padx=6, pady=(0,6))

        # Extract IOCs from alert
        ips = re.findall(r'\b(\d{1,3}(?:\.\d{1,3}){3})\b', alert_text)
        pids = re.findall(r'PID\s+(\d+)', alert_text)
        hashes_found = re.findall(r'\b([0-9a-fA-F]{32,64})\b', alert_text)

        # IOC Summary
        ioc_f = tk.Frame(win, bg=Colors.GLASS_DARK)
        ioc_f.pack(fill='x', padx=8, pady=2)
        tk.Label(ioc_f, text=f"IPs: {', '.join(ips) or 'none'}   PIDs: {', '.join(pids) or 'none'}   Hashes: {len(hashes_found)}",
                 font=('Consolas', 8), fg=Colors.GAUGE_TEAL, bg=Colors.GLASS_DARK).pack(padx=6, pady=4)

        # Action buttons grid
        btn_f = tk.Frame(win, bg=Colors.BG_VOID)
        btn_f.pack(fill='x', padx=8, pady=6)

        actions = [
            ("[BLOCK] Block All IPs",       Colors.GAUGE_RED,    lambda: [self._executor.submit(lambda i=ip: self._do_block_ip(i)) for ip in ips] or self._add_alert(f"[BLOCK] Blocking {len(ips)} IPs from alert", Colors.GAUGE_ORANGE)),
            ("[SKULL] Kill PIDs",           Colors.GAUGE_RED,    lambda: [self.scanner.mitigate(int(p), 'kill_tree', QUARANTINE_DIR) for p in pids if p.isdigit()]),
            ("[LOCK] Quarantine Process",  Colors.GAUGE_ORANGE, lambda: [self.scanner.mitigate(int(p), 'quarantine', QUARANTINE_DIR) for p in pids if p.isdigit()]),
            ("[PAUSE] Suspend Process",     Colors.GAUGE_YELLOW, lambda: [self.scanner.mitigate(int(p), 'suspend', QUARANTINE_DIR) for p in pids if p.isdigit()]),
            ("[WEB] Geo-Locate IPs",      Colors.GAUGE_TEAL,   lambda: [self._executor.submit(lambda i=ip: self._geolocate_one(i)) for ip in ips[:3]]),
            ("[CLIP] Copy All IOCs",       Colors.TEXT_DIM,     lambda: (self.clipboard_clear(), self.clipboard_append('\n'.join(ips + pids + hashes_found)))),
            ("[SCAN] Full Root Cause",     Colors.GAUGE_PURPLE, lambda: [self.scanner.mitigate(int(p), 'root_cause', QUARANTINE_DIR) for p in pids if p.isdigit()]),
            ("[SHIELD] Run Harden Check",    Colors.GAUGE_GREEN,  self._harden_analyze),
            ("[ALERT] FULL LOCKDOWN",       Colors.GAUGE_RED,    self._panic_button),
            ("[DIR] Scan Threat Path",    Colors.GAUGE_BLUE,   self._quick_file_scan),
        ]

        for i, (label, color, cmd) in enumerate(actions):
            r, c = divmod(i, 2)
            tk.Button(btn_f, text=label, font=('Consolas', 9, 'bold'),
                      fg=color, bg=Colors.GLASS_CARD, relief='flat',
                      activebackground=Colors.GLASS_LIGHT, padx=8, pady=4,
                      command=lambda f=cmd: (f(), win.destroy()) if label != "[ALERT] FULL LOCKDOWN" else f()
                      ).grid(row=r, column=c, sticky='ew', padx=4, pady=3)
        btn_f.grid_columnconfigure(0, weight=1)
        btn_f.grid_columnconfigure(1, weight=1)

        # Response log
        log_f = tk.Frame(win, bg=Colors.GLASS_CARD)
        log_f.pack(fill='both', expand=True, padx=8, pady=6)
        tk.Label(log_f, text="RESPONSE LOG", font=('Consolas', 8, 'bold'),
                 fg=Colors.TEXT_DIM, bg=Colors.GLASS_CARD).pack(anchor='w', padx=4)
        log_txt = tk.Text(log_f, height=6, bg=Colors.GLASS_DARK, fg=Colors.TEXT_LIGHT,
                          font=('Consolas', 8), wrap='word', state='disabled', relief='flat')
        log_txt.pack(fill='both', expand=True, padx=4, pady=4)

        def log_msg(m):
            log_txt.config(state='normal')
            log_txt.insert('end', f"[{datetime.now().strftime('%H:%M:%S')}] {m}\n")
            log_txt.see('end')
            log_txt.config(state='disabled')

        if ips:
            log_msg(f"Extracted {len(ips)} IP(s): {', '.join(ips[:5])}")
        if pids:
            log_msg(f"Extracted {len(pids)} PID(s): {', '.join(pids[:5])}")
        if hashes_found:
            log_msg(f"Extracted {len(hashes_found)} hash(es)")
        log_msg("Ready  -  click an action above to respond to this threat.")

        tk.Button(win, text="❌ Close", font=('Consolas', 9),
                  fg=Colors.TEXT_DIM, bg=Colors.GLASS_CARD, relief='flat',
                  command=win.destroy).pack(pady=6)

    def _geolocate_one(self, ip: str):
        """Silent geo-lookup that logs to alert feed"""
        try:
            req = urllib.request.Request(
                f"http://ip-api.com/json/{ip}?fields=status,country,city,isp",
                headers={'User-Agent': 'Downpour/1.0'})
            with urllib.request.urlopen(req, timeout=6) as r:
                data = json.loads(r.read().decode())
            if data.get('status') == 'success':
                self._queue_alert(
                    f"[WEB] {ip} -> {data['country']}, {data['city']} ({data['isp']})",
                    Colors.GAUGE_TEAL)
        except Exception:
            pass

