    def _aegis_log_event(self, msg: str, level: str = 'INFO'):
        """Write a message to the Aegis event log with color coding"""
        try:
            ts = datetime.now().strftime('%H:%M:%S')
            full = f"[{ts}][{level:8}] {msg}\n"
            self._aegis_log.config(state='normal')
            self._aegis_log.insert('end', full, level)
            self._aegis_log.see('end')
            self._aegis_log.config(state='disabled')
        except Exception:
            pass

    # -- Aegis log line cap  -  prevents unbounded Text widget growth (BUG-C2) -
    _AEGIS_LOG_MAX_LINES = 2000

    def _refresh_aegis_stats(self):
        """
        Pull stats from all 5 Aegis layers and refresh the AEGIS tab UI.

        FIX-C2 (Text widget memory leak):
        PREVIOUS BUG: Every call appended 10 DB rows to self._aegis_log without
        ever trimming. At 15-second intervals this adds 40 lines/minute ->
        57,600 lines/day. Tkinter Text widget redraw complexity is O(n) in visible
        lines; after a few hours the main thread froze on every `insert` call.

        FIX: After each insert batch, check the current line count. If it exceeds
        _AEGIS_LOG_MAX_LINES, delete the oldest lines from the top so the widget
        never holds more than the cap. This is O(1) in steady state.

        FIX-C2b (double-scheduling):
        PREVIOUS BUG: _auto_start called `self.after(3000, self._refresh_aegis_stats)`
        and _aegis_full_sweep also called `self._refresh_aegis_stats()` directly,
        which schedules another `self.after(15000, ...)`  -  spawning two concurrent
        refresh loops after the first full sweep.

        FIX: Guard with `_aegis_refresh_running` flag; only allow one active
        refresh at a time. The flag is True while refresh is executing, False otherwise.
        """
        if getattr(self, '_aegis_refresh_running', False):
            return   # refresh already in progress — don't double-enter
        self._aegis_refresh_running = True
        try:
            s1 = self.aegis_physical.get_stats()
            s2 = self.aegis_tcp.get_stats()
            s3 = self.aegis_ingest.get_stats()
            s4 = self.aegis_nlp.get_stats()
            s5 = self.aegis_memory.get_stats()
            self._aegis_stat_labels['imsi_alerts'].config(text=str(s1['imsi_alerts']))
            self._aegis_stat_labels['sensor_blocks'].config(text=str(s1['sensor_blocks']))
            self._aegis_stat_labels['port_violations'].config(text=str(s2['port_violations']))
            self._aegis_stat_labels['ueba_anomalies'].config(text=str(s2['ueba_anomalies']))
            self._aegis_stat_labels['mem_hits'].config(text=str(s3['mem_scan_hits']))
            self._aegis_stat_labels['dns_blocked'].config(text=str(s2['dns_blocked']))
            self._aegis_stat_labels['phishing_caught'].config(text=str(s4['phishing_caught']))
            self._aegis_stat_labels['blob_blocked'].config(text=str(s4['blob_blocked']))
            # Event count from DB
            try:
                rows = self.db.execute("SELECT COUNT(*) FROM aegis_events")
                self._aegis_event_count.config(text=f"Events: {rows[0][0]:,}")
            except Exception:
                pass
            # Load the 10 most-recent DB events  -  append to log, then trim top
            try:
                recent = self.db.execute(
                    "SELECT ts, layer, event, severity FROM aegis_events ORDER BY id DESC LIMIT 10")
                for row in reversed(recent):
                    ts, layer, event, severity = row
                    self._aegis_log_event(f"[{layer.upper()}] {event}", severity or 'INFO')
                # FIX-C2: Trim widget to cap  -  delete excess lines from the top
                try:
                    line_count = int(self._aegis_log.index('end-1c').split('.')[0])
                    if line_count > self._AEGIS_LOG_MAX_LINES:
                        excess = line_count - self._AEGIS_LOG_MAX_LINES
                        self._aegis_log.config(state='normal')
                        self._aegis_log.delete('1.0', f'{excess + 1}.0')
                        self._aegis_log.config(state='disabled')
                except Exception:
                    pass
            except Exception:
                pass
        except Exception as e:
            error_logger.log('AegisUI', 'Stats refresh failed', e)
        # FIX-v28p35: release guard, then schedule the next tick
        self._aegis_refresh_running = False
        self.after(15000, self._refresh_aegis_stats)

    # -- Aegis action methods -------------------------------------------------

    def _aegis_scan_clipboard(self):
        def do():
            result = self.aegis_nlp.scan_clipboard()
            score   = result['score']
            verdict = result['verdict']
            reasons = '; '.join(result['reasons'][:3])
            color   = (Colors.GAUGE_RED    if verdict == 'PHISHING' else
                       Colors.GAUGE_ORANGE if verdict == 'SUSPICIOUS' else
                       Colors.GAUGE_GREEN)
            self._queue_alert(f"[PHISH] Clipboard: {score}/100 [{verdict}]", color)
        self._executor.submit(do)

    def _aegis_analyze_text(self):
        """Analyze text typed in the NLP input box"""
        text = self._nlp_input.get('1.0', 'end').strip()
        if not text:
            return
        result  = self.aegis_nlp.score_text(text, 'manual_input')
        score   = result['score']
        verdict = result['verdict']
        reasons = result['reasons']
        color   = (Colors.GAUGE_RED    if verdict == 'PHISHING' else
                   Colors.GAUGE_ORANGE if verdict == 'SUSPICIOUS' else
                   Colors.GAUGE_GREEN)
        self._nlp_result.config(text=f"Score: {score}/100 | Verdict: {verdict}", fg=color)
        self._aegis_log_event(
            f"Manual text scan: {score}/100 [{verdict}] " + '; '.join(reasons[:3]),
            'CRITICAL' if verdict == 'PHISHING' else 'HIGH' if verdict == 'SUSPICIOUS' else 'INFO')
        self._queue_alert(f"[PHISH] NLP Phishing scan: {score}/100 [{verdict}]", color)

    def _aegis_run_imsi_scan(self):
        def do():
            self.after(0, lambda: self._aegis_log_event("[NET] Running IMSI/WiFi scan...", 'INFO'))
            self.aegis_physical._detect_imsi_catcher()
            self.after(0, lambda: (
                self._aegis_log_event(
                    f"IMSI scan complete  -  {self.aegis_physical._imsi_alerts} alert(s)", 'INFO'),
                self._refresh_aegis_stats()
            ))
        self._executor.submit(do)

    def _aegis_run_memory_scan(self):
        self._set_status("AEGIS: Running polymorphic memory scan...")
        def do():
            self.after(0, lambda: self._aegis_log_event("[SKULL] Fileless memory scan starting...", 'INFO'))
            self.aegis_ingest._polymorphic_memory_scan()
            hits = self.aegis_ingest.get_stats()['mem_scan_hits']
            self.after(0, lambda: (
                self._aegis_log_event(f"Memory scan complete  -  {hits} shellcode hit(s)", 'INFO'),
                self._set_status(f"AEGIS Memory scan: {hits} hits"),
                self._refresh_aegis_stats()
            ))
        self._executor.submit(do)

    def _aegis_dns_check(self):
        def do():
            self.after(0, lambda: self._aegis_log_event("[SHIELD] DNS Shield: flushing + checking...", 'INFO'))
            try:
                subprocess.run(['ipconfig', '/flushdns'], capture_output=True,
                               creationflags=subprocess.CREATE_NO_WINDOW,
                             timeout=15)
            except Exception:
                pass
            self.aegis_tcp._check_dns_shield()
            blocked = self.aegis_tcp.get_stats()['dns_blocked']
            self.after(0, lambda: (
                self._aegis_log_event(f"DNS Shield: {blocked} C2 domain(s) blocked", 'INFO'),
                self._add_alert(f"[SHIELD] DNS Shield: {blocked} C2 domains sunk", Colors.GAUGE_TEAL)
            ))
        self._executor.submit(do)

    def _aegis_show_all_events(self):
        """Show a scrollable window with all Aegis events"""
        win = tk.Toplevel(self)
        win.title("[SWORDS] downpour  -  Aegis Events")
        win.geometry("900x600")
        win.configure(bg=Colors.BG_STORM)
        win.attributes('-topmost', True)
        txt = tk.Text(win, bg=Colors.GLASS_DARK, fg=Colors.TEXT_LIGHT,
                      font=('Consolas', 8), wrap='word', state='disabled')
        sb = ttk.Scrollbar(win, orient='vertical', command=txt.yview, style='Vertical.TScrollbar')
        txt['yscrollcommand'] = sb.set
        sb.pack(side='right', fill='y')
        txt.pack(fill='both', expand=True, padx=4, pady=4)
        txt.tag_configure('CRITICAL', foreground=Colors.GAUGE_RED)
        txt.tag_configure('HIGH',     foreground=Colors.GAUGE_ORANGE)
        txt.tag_configure('INFO',     foreground=Colors.GAUGE_TEAL)
        def load():
            try:
                rows = self.db.execute(
                    "SELECT ts, layer, severity, event FROM aegis_events ORDER BY id DESC LIMIT 1000")
                txt.config(state='normal')
                for ts, layer, severity, event in rows:
                    txt.insert('end', f"[{ts[:19]}][{layer:8}][{severity:8}] {event}\n",
                               severity or 'INFO')
                txt.config(state='disabled')
            except Exception as e:
                txt.config(state='normal')
                txt.insert('end', f"Error loading events: {e}")
                txt.config(state='disabled')
        self._executor.submit(load)

    def _aegis_ephemeral_wipe(self):
        if messagebox.askyesno("[!] Ephemeral Wipe",
                                "Perform multi-pass session wipe?\n"
                                "All tracked secrets will be zeroed.\n\nContinue?"):
            self.aegis_memory._ephemeral_wipe()
            self._aegis_log_event("[INTEL] Ephemeral wipe complete  -  session secrets zeroed (4-pass)", 'INFO')
            self._queue_alert("[INTEL] AEGIS: Session wipe complete (DoD 5220.22-M)", Colors.GAUGE_PURPLE)

    def _aegis_full_sweep(self):
        """Run all Aegis detection sweeps simultaneously"""
        self._set_status("AEGIS: Full sweep running...")
        self._aegis_log_event("[SWORDS] Full AEGIS sweep initiated...", 'INFO')
        def do():
            self.aegis_physical._check_sensor_access()
            self.aegis_physical._detect_imsi_catcher()
            self.aegis_tcp._check_port_bindings()
            self.aegis_tcp._check_port_forwarding()
            self.aegis_tcp._check_remote_tool_hijacking()
            self.aegis_tcp._check_dns_shield()
            self.aegis_ingest._polymorphic_memory_scan()
            self.aegis_memory._detect_debugger()
            self.aegis_memory._detect_memory_dumper()
            stats = {
                'imsi':  self.aegis_physical._imsi_alerts,
                'ports': self.aegis_tcp._port_violations,
                'ueba':  self.aegis_tcp._ueba_anomalies,
                'mem':   self.aegis_ingest._mem_scan_hits,
                'tamper':self.aegis_memory._tamper_detected,
            }
            summary = (f"[OK] AEGIS Full Sweep Complete | "
                       f"IMSI:{stats['imsi']} Ports:{stats['ports']} "
                       f"UEBA:{stats['ueba']} MemHits:{stats['mem']} "
                       f"Tamper:{stats['tamper']}")
            self.after(0, lambda: (
                self._aegis_log_event(summary, 'INFO'),
                self._add_alert(summary, Colors.GAUGE_TEAL),
                self._set_status(summary),
                self._refresh_aegis_stats()
            ))
        self._executor.submit(do)

    def _aegis_fetch_extra(self):
        """Fetch all extra Aegis intelligence feeds"""
        self._aegis_log_event("[WEB] Fetching extra Aegis feeds...", 'INFO')
        def do():
            total = 0
            for feed_name in list(self.aegis_ingest.EXTRA_FEEDS.keys()):
                count = self.aegis_ingest.fetch_extra_feed(feed_name)
                total += count
                if count:
                    self.after(0, lambda f=feed_name, c=count:
                               self._aegis_log_event(f"  + {f}: {c} IOCs", 'INFO'))
            self.after(0, lambda: (
                self._aegis_log_event(f"[WEB] Extra feeds done  -  {total:,} IOCs added", 'INFO'),
                self._add_alert(f"[SWORDS] AEGIS: Extra feeds fetched  -  {total:,} IOCs", Colors.GAUGE_TEAL),
                self._stat_labels['iocs'].config(text=f"{self.db.count_intel():,}")
            ))
        self._executor.submit(do)

