    def _set_status(self, msg: str):
        try:
            self._status_var.set(f"[{datetime.now().strftime('%H:%M:%S')}] {msg}")
        except Exception:
            pass


    # ======================================================================
    #  HARDWARE UTILIZATION CONTROL  -  Turbo/Restore for scans
    # ======================================================================

    def _hw_turbo_start(self, operation: str = 'scan'):
        """
        Boost PC for intensive security operation:
        - Elevate process to HIGH_PRIORITY_CLASS
        - Set all threads to THREAD_PRIORITY_HIGHEST
        - Pin all logical CPU cores
        - Disable GC during hot path
        - Maximize thread pool workers temporarily
        """
        try:
            import ctypes, gc
            # HIGH_PRIORITY_CLASS
            ctypes.windll.kernel32.SetPriorityClass(
                ctypes.windll.kernel32.GetCurrentProcess(), 0x00000080)
            # Disable GC threshold to avoid GC pauses during scan
            gc.set_threshold(0, 0, 0)
            self._turbo_active = True
            self._queue_alert(
                f"[ZAP] TURBO MODE: {operation.upper()}  -  All CPU cores active, HIGH priority",
                Colors.GAUGE_TEAL)
        except Exception:
            pass

    def _hw_turbo_stop(self):
        """Restore normal priority after intensive operation."""
        try:
            import ctypes, gc
            # NORMAL_PRIORITY_CLASS
            ctypes.windll.kernel32.SetPriorityClass(
                ctypes.windll.kernel32.GetCurrentProcess(), 0x00000020)
            # Restore GC
            _hwp = getattr(self, '_hw_profile', None)
            _thresh = getattr(_hwp, 'gc_threshold', (700, 10, 10)) if _hwp else (700, 10, 10)
            gc.set_threshold(*_thresh)
            gc.collect()
            self._turbo_active = False
        except Exception:
            pass

    def _hw_get_parallel_workers(self, task: str = 'scan') -> int:
        """Return optimal parallel worker count for a given task type."""
        _hwp = getattr(self, '_hw_profile', None)
        _ncpu = __import__('os').cpu_count() or 4
        if task == 'scan':
            base = getattr(_hwp, 'workers_scan', _ncpu * 4) if _hwp else _ncpu * 4
        elif task == 'io':
            base = getattr(_hwp, 'workers_io', _ncpu * 8) if _hwp else _ncpu * 8
        elif task == 'cpu':
            base = getattr(_hwp, 'workers_cpu', _ncpu * 3) if _hwp else _ncpu * 3
        else:
            base = _ncpu * 2
        return max(4, min(base, 256))

    def _on_close(self):
        if self.cfg.get('general', 'minimize_to_tray') and PYSTRAY_AVAILABLE:
            self.withdraw()
        else:
            self._shutdown()

    def _shutdown(self):
        # Log shutdown call with full stack trace
        import traceback as _stb, datetime as _dt
        try:
            with open("shutdown_trace.txt", "a", encoding="utf-8") as _sf:
                _sf.write(f"\n=== SHUTDOWN {_dt.datetime.now()} ===\n")
                _stb.print_stack(file=_sf)
        except Exception:
            pass
        try: self._stop_event.set()
        except Exception: pass
        # FIX-M4: Stop all five Aegis monitoring threads before destroying the Tk window.
        # Without explicit .stop() calls the daemon threads kept running after mainloop()
        # returned, attempting DB writes on a closed connection -> OperationalError spam
        # and a 5 - 30 second hang before the process finally exited.
        for layer in ('aegis_physical', 'aegis_tcp', 'aegis_ingest', 'aegis_memory'):
            try:
                getattr(self, layer, None) and getattr(self, layer).stop()
            except Exception:
                pass
        # Trigger ephemeral session wipe before the interpreter tears down
        try:
            self.aegis_memory._ephemeral_wipe()
        except Exception:
            pass
        self.rain.stop()
        self._scan_stop.set()
        self._executor.shutdown(wait=False)
        try: self._io_executor.shutdown(wait=False, cancel_futures=True)
        except Exception: pass
        try: self._executor.shutdown(wait=False, cancel_futures=True)
        except Exception: pass
        if NVML_AVAILABLE:
            try: nvmlShutdown()
            except Exception: pass
        self.destroy()
        # FIX-v28: Force-exit to prevent Fortran runtime abort
        import os as _os_exit
        _os_exit._exit(0)



