    def _dns_build_poison(self, p):
        """DNS cache poisoning detection."""
        p.grid_rowconfigure(3, weight=1)
        p.grid_columnconfigure(0, weight=1)

        tk.Label(p, text='☠️ DNS POISONING & HIJACKING DETECTION',
                 font=('Consolas', 11, 'bold'), fg=Colors.GAUGE_RED,
                 bg=Colors.BG_VOID).grid(row=0, column=0, sticky='w', padx=10, pady=8)

        info = tk.Frame(p, bg=Colors.GLASS_PANEL)
        info.grid(row=1, column=0, sticky='ew', padx=8, pady=4)
        tk.Label(info,
                 text=('DNS poisoning occurs when malicious IPs are substituted for legitimate domains.\n'
                       'This tool cross-validates your DNS results against multiple trusted resolvers.'),
                 font=('Consolas', 8), fg=Colors.TEXT_DIM,
                 bg=Colors.GLASS_PANEL, justify='left').pack(anchor='w', padx=8, pady=6)

        # Domain list to check
        check_f = tk.Frame(p, bg=Colors.GLASS_CARD)
        check_f.grid(row=2, column=0, sticky='ew', padx=8, pady=4)
        tk.Label(check_f, text='Domains to verify (one per line or comma-separated):',
                 font=('Consolas', 9), fg=Colors.TEXT_DIM,
                 bg=Colors.GLASS_CARD).pack(anchor='w', padx=8, pady=(6,2))

        entry_f = tk.Frame(check_f, bg=Colors.GLASS_CARD)
        entry_f.pack(fill='x', padx=8, pady=4)
        self._dns_poison_domains_text = tk.Text(entry_f, height=4,
                                                 font=('Consolas', 9),
                                                 bg=Colors.GLASS_DARK, fg=Colors.TEXT_LIGHT,
                                                 relief='flat')
        self._dns_poison_domains_text.pack(fill='x')
        # Default critical domains to check
        _defaults = ('google.com, microsoft.com, cloudflare.com, github.com,\n'
                     'amazon.com, paypal.com, bankofamerica.com, chase.com,\n'
                     'wellsfargo.com, apple.com, facebook.com, twitter.com')
        self._dns_poison_domains_text.insert('1.0', _defaults)

        btn_f = tk.Frame(check_f, bg=Colors.GLASS_CARD)
        btn_f.pack(fill='x', padx=8, pady=6)
        tk.Button(btn_f, text='☠️ RUN POISON CHECK',
                  command=self._dns_run_poison_check,
                  font=('Consolas', 10, 'bold'),
                  bg=Colors.GAUGE_RED, fg='white',
                  relief='flat', padx=16, pady=6, cursor='hand2'
                  ).pack(side='left', padx=4)
        tk.Button(btn_f, text='🔄 Check Critical System Domains',
                  command=self._dns_check_system_domains,
                  font=('Consolas', 9),
                  bg=Colors.GAUGE_ORANGE, fg='white',
                  relief='flat', padx=10, cursor='hand2'
                  ).pack(side='left', padx=4)
        tk.Button(btn_f, text='Test Router DNS',
                  command=self._dns_test_router,
                  font=('Consolas', 9),
                  bg=Colors.GAUGE_BLUE, fg='white',
                  relief='flat', padx=10, cursor='hand2'
                  ).pack(side='left', padx=4)

        # Results
        self._dns_poison_results = tk.Text(p, font=('Consolas', 9),
                                            bg=Colors.GLASS_DARK, fg=Colors.TEXT_LIGHT,
                                            state='disabled', relief='flat')
        self._dns_poison_results.grid(row=3, column=0, sticky='nsew', padx=8, pady=4)
        _sb = ttk.Scrollbar(p, orient='vertical', command=self._dns_poison_results.yview, style='Vertical.TScrollbar')
        _sb.grid(row=3, column=1, sticky='ns')
        self._dns_poison_results.configure(yscrollcommand=_sb.set)
        p.grid_columnconfigure(1, weight=0)

