    # ======================================================================
    #  DNS HELPER METHODS
    # ======================================================================

    def _dns_srv_log(self, msg: str, color: str = None):
        if color is None: color = Colors.TEXT_DIM
        def _do():
            try:
                self._dns_srv_log_widget.configure(state='normal')
                ts = datetime.now().strftime('%H:%M:%S')
                start = self._dns_srv_log_widget.index('end')
                self._dns_srv_log_widget.insert('end', f'[{ts}] {msg}\\n')
                tag = f'c{abs(hash(msg)) % 9999}'
                end = self._dns_srv_log_widget.index('end-1l')
                self._dns_srv_log_widget.tag_configure(tag, foreground=color)
                self._dns_srv_log_widget.tag_add(tag, f'end-{len(msg)+12}c', 'end-1c')
                self._dns_srv_log_widget.see('end')
                if int(self._dns_srv_log_widget.index('end').split('.')[0]) > 300:
                    self._dns_srv_log_widget.delete('1.0', '80.0')
            except Exception:
                pass
            finally:
                try: self._dns_srv_log_widget.configure(state='disabled')
                except Exception: pass
        self.after(0, _do)

    def _dns_out(self, widget, msg: str, color: str = None, clear: bool = False):
        """Write to any DNS output text widget."""
        if color is None: color = Colors.TEXT_LIGHT
        def _do():
            try:
                widget.configure(state='normal')
                if clear:
                    widget.delete('1.0', 'end')
                ts = datetime.now().strftime('%H:%M:%S')
                widget.insert('end', f'[{ts}] {msg}\\n')
                tag = f'dns_{abs(hash(msg)) % 9999}'
                line_start = widget.index(f'end-{len(msg)+14}c')
                widget.tag_configure(tag, foreground=color)
                widget.tag_add(tag, line_start, 'end-1c')
                widget.see('end')
            except Exception:
                pass
            finally:
                try: widget.configure(state='disabled')
                except Exception: pass
        self.after(0, _do)

    def _dns_add_alert(self, msg: str):
        def _do():
            try:
                ts = datetime.now().strftime('%H:%M:%S')
                self._dns_alert_list.insert(0, f'[{ts}] {msg}')
                if self._dns_alert_list.size() > 100:
                    self._dns_alert_list.delete(100, 'end')
            except Exception:
                pass
        self.after(0, _do)

    # -- DNS command allowlist + shell injection guard -------------------------
    _DNS_SAFE_CMD_RE = re.compile(
        r'^(nslookup|ipconfig|netsh|powershell|Get-DnsClient)',
        re.IGNORECASE)
    _DNS_SHELL_META  = re.compile(r'[;&|`\r\n$(){}\[\]<>!]')

    def _dns_run_cmd(self, cmd: str, timeout: int = 15) -> str:
        """Run a DNS-related command safely.

        FIX-05: original used shell=True with unsanitised input.
        Now: metacharacters stripped, command validated against allowlist,
        non-PowerShell commands run as list (no shell).
        """
        if not cmd or not cmd.strip():
            return ''
        # Strip any shell metacharacters defensively
        if self._DNS_SHELL_META.search(cmd):
            cmd = self._DNS_SHELL_META.sub(' ', cmd).strip()
        if not self._DNS_SAFE_CMD_RE.match(cmd.strip()):
            return '[BLOCKED: command not in DNS allowlist]'
        try:
            parts = cmd.split()
            use_shell = parts[0].lower() in ('powershell',)
            r = subprocess.run(
                cmd if use_shell else parts,
                shell=use_shell,
                capture_output=True, text=True, timeout=timeout,
                creationflags=0x08000000)
            return r.stdout.strip() or r.stderr.strip()
        except subprocess.TimeoutExpired:
            return '[TIMEOUT]'
        except Exception as e:
            return f'[ERROR] {e}'

    # -- Domain/IP sanitizer for DNS lookups -----------------------------------
    _DNS_DOMAIN_RE = re.compile(r'^[a-zA-Z0-9._-]{1,253}$')
    _DNS_IP_RE     = re.compile(r'^[0-9]{1,3}(?:\.[0-9]{1,3}){3}$')

    def _dns_resolve(self, domain: str, dns_server: str = None) -> str:
        """Resolve domain using optional specific DNS server.

        Sanitises both `domain` and `dns_server` before passing to
        _dns_run_cmd to prevent shell injection via crafted DNS data.
        """
        # Sanitise domain
        domain = str(domain).strip().rstrip('.')
        if not self._DNS_DOMAIN_RE.match(domain):
            return 'INVALID'
        # Sanitise dns_server
        if dns_server:
            dns_server = str(dns_server).strip()
            if not (self._DNS_IP_RE.match(dns_server) or
                    self._DNS_DOMAIN_RE.match(dns_server)):
                dns_server = None
        try:
            if dns_server:
                result = self._dns_run_cmd(f'nslookup {domain} {dns_server}', 5)
            else:
                result = socket.gethostbyname(domain)
                return result
            # Parse nslookup output
            for line in result.splitlines():
                if 'Address' in line and '#' not in line and '53' not in line:
                    parts = line.split(':')
                    if len(parts) > 1:
                        addr = parts[1].strip()
                        if addr and not addr.startswith('::'):
                            return addr
            return result.split()[-1] if result.split() else 'N/A'
        except Exception as e:
            return f'ERROR: {e}'

    def _dns_refresh_overview(self):
        """Populate the DNS overview tab."""
        def _fetch():
            lines = []
            threat_score = 0
            issues = []

            # Current DNS servers
            try:
                lines.append('=== CURRENT DNS SERVERS ===')
                result = self._dns_run_cmd(
                    'powershell -Command "Get-DnsClientServerAddress | '
                    'Where-Object {$_.AddressFamily -eq 2} | '
                    'Select-Object InterfaceAlias, ServerAddresses | Format-Table -AutoSize"', 10)
                lines.append(result or '(could not read)')
            except Exception as e:
                lines.append(f'Error: {e}')

            # Check for ISP/local DNS (potential surveillance)
            try:
                gw = self._dns_run_cmd(
                    'powershell -Command "(Get-NetRoute -DestinationPrefix 0.0.0.0/0 | '
                    'Sort-Object RouteMetric | Select-Object -First 1).NextHop"', 5)
                lines.append(f'\\n=== DEFAULT GATEWAY ===\\n{gw}')
                if gw:
                    try:
                        ip_obj = ipaddress.ip_address(gw.strip())
                        if ip_obj.is_private:
                            lines.append('[INFO] Router/local gateway detected  -  verify router DNS settings')
                    except Exception:
                        pass
            except Exception as e:
                pass

            # DNSSEC test
            try:
                lines.append('\\n=== DNSSEC STATUS ===')
                dnssec_test = self._dns_run_cmd('nslookup -type=dnskey dnssec-failed.org 1.1.1.1', 5)
                if 'SERVFAIL' in dnssec_test or 'failed' in dnssec_test.lower():
                    lines.append('[OK] DNSSEC validation ACTIVE (bogus domain correctly blocked)')
                else:
                    lines.append('[!]  DNSSEC may NOT be enforced by your resolver')
                    threat_score += 15
                    issues.append('DNSSEC not enforced')
            except Exception:
                lines.append('(DNSSEC test skipped)')

            # Check for DNS-over-HTTPS
            try:
                lines.append('\\n=== DNS ENCRYPTION (DoH) ===')
                doh_check = self._dns_run_cmd(
                    'powershell -Command "reg query HKLM\\\\SYSTEM\\\\CurrentControlSet\\\\Services\\\\Dnscache\\\\Parameters /v EnableAutoDoh 2>$null"', 5)
                if 'EnableAutoDoh' in doh_check and '0x2' in doh_check:
                    lines.append('[OK] DNS-over-HTTPS: ENABLED (automatic)')
                elif 'EnableAutoDoh' in doh_check and '0x1' in doh_check:
                    lines.append('[OK] DNS-over-HTTPS: ENABLED (secure preferred)')
                else:
                    lines.append('[!]  DNS-over-HTTPS: NOT configured')
                    lines.append('   -> Run "Enable DoH" to encrypt DNS queries')
                    threat_score += 20
                    issues.append('DoH not enabled')
            except Exception:
                pass

            # Public DNS check (is your DNS leaking?)
            try:
                lines.append('\\n=== DNS LEAK QUICK TEST ===')
                test_ip1 = self._dns_resolve('one.one.one.one', '1.1.1.1')
                test_ip2 = self._dns_resolve('one.one.one.one')
                if '1.1.1.1' in test_ip1 or '1.0.0.1' in test_ip1:
                    lines.append('[OK] Cloudflare resolver accessible')
                else:
                    lines.append(f'[INFO] Cloudflare test: {test_ip1}')
                    threat_score += 5
            except Exception:
                lines.append('(leak test skipped)')

            # Check hosts file integrity
            try:
                hosts_path = r'C:\\Windows\\System32\\drivers\\etc\\hosts'
                with open(hosts_path, 'r', errors='ignore') as hf:
                    hosts_content = hf.read()
                suspicious_entries = []
                for line in hosts_content.splitlines():
                    line = line.strip()
                    if line and not line.startswith('#'):
                        if any(domain in line.lower() for domain in
                               ['google', 'microsoft', 'windows', 'apple', 'amazon']):
                            # Check if it redirects to non-localhost
                            parts = line.split()
                            if len(parts) >= 2 and parts[0] not in ('127.0.0.1', '::1', '0.0.0.0'):
                                suspicious_entries.append(line)
                if suspicious_entries:
                    lines.append('\\n[!]  SUSPICIOUS HOSTS FILE ENTRIES:')
                    for e in suspicious_entries[:5]:
                        lines.append(f'  [!]  {e}')
                    threat_score += 30
                    issues.append(f'{len(suspicious_entries)} suspicious hosts entries')
                    self._dns_add_alert(f'[!] Hosts file hijack detected: {len(suspicious_entries)} suspicious entries!')
                else:
                    lines.append('\\n[OK] Hosts file: Clean (no suspicious entries)')
            except Exception as e:
                lines.append(f'\\nHosts file check: {e}')

            final_score = max(0, 100 - threat_score)
            issue_text = ', '.join(issues) if issues else 'No issues detected'
            score_color = Colors.GAUGE_GREEN if final_score >= 80 else (
                          Colors.GAUGE_ORANGE if final_score >= 50 else Colors.GAUGE_RED)

            # FIX-v28: Guard against lazy DNS tab not yet built
            def _update_dns_ui():
                if not hasattr(self, '_dns_info_text'):
                    return  # DNS tab not yet loaded
                self._dns_info_text.configure(state='normal')
                self._dns_info_text.delete('1.0', 'end')
                self._dns_info_text.insert('1.0', '\n'.join(lines))
                self._dns_info_text.configure(state='disabled')
                if hasattr(self, '_dns_threat_score_var'):
                    self._dns_threat_score_var.set(f'{final_score} / 100')
                if hasattr(self, '_dns_threat_detail_var'):
                    self._dns_threat_detail_var.set(issue_text)
                if hasattr(self, '_dns_status_lbl'):
                    self._dns_status_lbl.configure(fg=score_color)
            self.after(0, _update_dns_ui)
        threading.Thread(target=_fetch, daemon=True, name='DNS-Overview').start()

    def _dns_flush_cache(self):
        def _do():
            self._dns_srv_log('Flushing DNS cache...', Colors.GAUGE_TEAL)
            result = self._dns_run_cmd('ipconfig /flushdns')
            self._dns_srv_log(result, Colors.GAUGE_GREEN)
            self._dns_add_alert('[OK] DNS cache flushed')
        threading.Thread(target=_do, daemon=True).start()

    def _dns_flush_all(self):
        """Flush DNS, NetBIOS, ARP cache."""
        def _do():
            cmds = [
                ('Flushing DNS cache...', 'ipconfig /flushdns'),
                ('Flushing NetBIOS cache...', 'nbtstat -RR'),
                ('Flushing ARP cache...', 'arp -d *'),
                ('Registering DNS...', 'ipconfig /registerdns'),
            ]
            for msg, cmd in cmds:
                self._dns_out(self._dns_adv_output, msg, Colors.GAUGE_TEAL)
                result = self._dns_run_cmd(cmd)
                self._dns_out(self._dns_adv_output, result, Colors.TEXT_LIGHT)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_reset_winsock(self):
        def _do():
            self._dns_out(self._dns_adv_output, 'Resetting Winsock...', Colors.GAUGE_ORANGE, True)
            result = self._dns_run_cmd('netsh winsock reset')
            self._dns_out(self._dns_adv_output, result)
            result2 = self._dns_run_cmd('netsh int ip reset')
            self._dns_out(self._dns_adv_output, result2)
            self._dns_out(self._dns_adv_output, '[OK] Winsock reset. RESTART may be required.', Colors.GAUGE_GREEN)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_reset_tcpip(self):
        def _do():
            self._dns_out(self._dns_adv_output, 'Resetting TCP/IP stack...', Colors.GAUGE_ORANGE, True)
            cmds = ['netsh int ip reset resetlog.txt',
                    'netsh int ipv6 reset resetlog.txt',
                    'netsh winsock reset catalog']
            for cmd in cmds:
                r = self._dns_run_cmd(cmd)
                self._dns_out(self._dns_adv_output, r)
            self._dns_out(self._dns_adv_output, '[OK] TCP/IP reset complete. RESTART recommended.', Colors.GAUGE_GREEN)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_apply_servers(self):
        """Apply custom DNS servers to all adapters."""
        primary = self._dns_primary_var.get().strip()
        secondary = self._dns_secondary_var.get().strip()
        if not primary:
            messagebox.showwarning('DNS', 'Enter a primary DNS server IP.')
            return
        def _do():
            self._dns_srv_log(f'Applying DNS: {primary} / {secondary}', Colors.GAUGE_TEAL)
            script = (
                f'$adapters = Get-NetAdapter | Where-Object {{$_.Status -eq "Up"}}; '
                f'foreach ($a in $adapters) {{ '
                f'  Set-DnsClientServerAddress -InterfaceAlias $a.Name '
                f'  -ServerAddresses ("{primary}", "{secondary}"); '
                f'  Write-Output "Applied to: $($a.Name)" }}'
            )
            result = self._dns_run_cmd(f'powershell -Command "{script}"', 20)
            self._dns_srv_log(result or 'Done', Colors.GAUGE_GREEN)
            self._dns_add_alert(f'[OK] DNS servers applied: {primary} / {secondary}')
        threading.Thread(target=_do, daemon=True).start()

    def _dns_apply_quad9(self):
        pinfo = self._DNS_PROVIDERS.get('[LOCK] Quad9 (Malware Blocking)')
        if pinfo:
            self._dns_primary_var.set(pinfo[0])
            self._dns_secondary_var.set(pinfo[1])
        self._dns_apply_servers()

    def _dns_reset_dhcp(self):
        def _do():
            self._dns_srv_log('Resetting DNS to DHCP (automatic)...', Colors.TEXT_DIM)
            script = (
                '$adapters = Get-NetAdapter | Where-Object {$_.Status -eq "Up"}; '
                'foreach ($a in $adapters) { '
                '  Set-DnsClientServerAddress -InterfaceAlias $a.Name -ResetServerAddresses; '
                '  Write-Output "Reset: $($a.Name)" }'
            )
            result = self._dns_run_cmd(f'powershell -Command "{script}"', 20)
            self._dns_srv_log(result or 'Done', Colors.GAUGE_GREEN)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_show_current(self):
        def _do():
            result = self._dns_run_cmd(
                'powershell -Command "Get-DnsClientServerAddress | Format-List"', 10)
            self._dns_srv_log('=== CURRENT DNS ===', Colors.GAUGE_TEAL)
            for line in result.splitlines():
                self._dns_srv_log(line, Colors.TEXT_LIGHT)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_test_latency(self):
        def _do():
            self._dns_srv_log('Testing DNS server latency...', Colors.GAUGE_TEAL)
            servers = {
                'Cloudflare': '1.1.1.1', 'Google': '8.8.8.8',
                'Quad9': '9.9.9.9', 'OpenDNS': '208.67.222.222',
                'AdGuard': '94.140.14.14',
            }
            test_domain = 'google.com'
            results = []
            for name, ip in servers.items():
                start = time.time()
                try:
                    self._dns_run_cmd(f'nslookup {test_domain} {ip}', 5)
                    ms = int((time.time() - start) * 1000)
                    results.append((ms, name, ip))
                    color = Colors.GAUGE_GREEN if ms < 50 else (
                            Colors.GAUGE_YELLOW if ms < 150 else Colors.GAUGE_RED)
                    self._dns_srv_log(f'{name:20} {ip:18} {ms:4}ms', color)
                except Exception as e:
                    self._dns_srv_log(f'{name:20} {ip:18} FAILED ({e})', Colors.GAUGE_RED)
            if results:
                results.sort()
                best = results[0]
                self._dns_srv_log(f'[OK] Fastest: {best[1]} ({best[2]})  -  {best[0]}ms', Colors.GAUGE_GREEN)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_test_leak(self):
        def _do():
            self._dns_srv_log('Testing for DNS leaks...', Colors.GAUGE_ORANGE)
            # Method 1: Multiple resolver test
            test_servers = [
                ('1.1.1.1', 'Cloudflare'),
                ('8.8.8.8', 'Google'),
                ('9.9.9.9', 'Quad9'),
                ('208.67.222.222', 'OpenDNS'),
            ]
            current_dns = self._dns_run_cmd(
                'powershell -Command "(Get-DnsClientServerAddress -AddressFamily IPv4).ServerAddresses[0]"', 5)
            self._dns_srv_log(f'Current DNS: {current_dns}', Colors.TEXT_LIGHT)

            leaks = []
            for ip, name in test_servers:
                result = self._dns_resolve('whoami.akamai.net', ip)
                if result and 'ERROR' not in result:
                    self._dns_srv_log(f'  Via {name} ({ip}): resolver seen as {result}', Colors.TEXT_DIM)
                    # Check if it matches expected
                    if not any(exp in result for exp in [ip.rsplit('.', 1)[0], 'akamai']):
                        leaks.append(f'{name}: {result}')

            if leaks:
                self._dns_srv_log(f'[!]  Possible DNS leak detected via: {", ".join(leaks)}', Colors.GAUGE_RED)
                self._dns_add_alert(f'[!] DNS leak possible via {len(leaks)} paths!')
            else:
                self._dns_srv_log('[OK] No obvious DNS leaks detected', Colors.GAUGE_GREEN)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_kill_leak(self):
        def _do():
            self._dns_srv_log('Emergency: Locking DNS to prevent leaks...', Colors.GAUGE_RED)
            # Force all adapters to Cloudflare
            cmds = [
                'powershell -Command "$a = Get-NetAdapter | Where-Object {$_.Status -eq \\"Up\\"}; foreach ($i in $a) { Set-DnsClientServerAddress -InterfaceAlias $i.Name -ServerAddresses (\\"1.1.1.1\\", \\"1.0.0.1\\") }"',
                'ipconfig /flushdns',
                'ipconfig /registerdns',
            ]
            for cmd in cmds:
                r = self._dns_run_cmd(cmd, 20)
                self._dns_srv_log(r, Colors.TEXT_DIM)
            self._dns_srv_log('[OK] DNS locked to Cloudflare (1.1.1.1). Leak suppressed.', Colors.GAUGE_GREEN)
            self._dns_add_alert('[ALERT] DNS leak kill-switch activated  -  locked to Cloudflare')
        threading.Thread(target=_do, daemon=True).start()

    def _dns_run_poison_check(self):
        """Cross-validate DNS responses against multiple trusted resolvers."""
        domain_raw = self._dns_poison_domains_text.get('1.0', 'end').strip()
        domains = [d.strip() for d in domain_raw.replace('\\n', ',').split(',') if d.strip()]
        if not domains:
            return
        def _do():
            self._dns_out(self._dns_poison_results, '=== DNS POISONING DETECTION SCAN ===',
                          Colors.GAUGE_RED, True)
            self._dns_out(self._dns_poison_results,
                          f'Testing {len(domains)} domains against 4 resolvers...\\n', Colors.TEXT_DIM)
            poison_found = 0
            resolvers = {
                'Cloudflare': '1.1.1.1',
                'Google':     '8.8.8.8',
                'Quad9':      '9.9.9.9',
                'OpenDNS':    '208.67.222.222',
            }
            for domain in domains:
                results = {}
                for name, ip in resolvers.items():
                    resolved = self._dns_resolve(domain, ip)
                    results[name] = resolved
                # Compare: if all 4 give same IP family but one differs significantly
                ips = [v for v in results.values() if 'ERROR' not in str(v) and v]
                unique_ips = set(ips)
                if len(unique_ips) <= 1:
                    self._dns_out(self._dns_poison_results,
                                  f'[OK] {domain:40} -> {next(iter(unique_ips), "?")}',
                                  Colors.GAUGE_GREEN)
                elif len(unique_ips) == 2:
                    self._dns_out(self._dns_poison_results,
                                  f'[!]  {domain:40} -> INCONSISTENT: {dict(zip(resolvers.keys(), ips))}',
                                  Colors.GAUGE_ORANGE)
                    poison_found += 1
                else:
                    self._dns_out(self._dns_poison_results,
                                  f'[R] {domain:40} -> POSSIBLE POISON! {results}',
                                  Colors.GAUGE_RED)
                    poison_found += 1
                    self._dns_add_alert(f'[SKULL] DNS poison detected for {domain}!')
                time.sleep(0.1)

            summary_color = Colors.GAUGE_GREEN if poison_found == 0 else Colors.GAUGE_RED
            self._dns_out(self._dns_poison_results,
                          f'\\n=== RESULT: {poison_found} suspicious domains found ===',
                          summary_color)
        threading.Thread(target=_do, daemon=True, name='DNS-Poison').start()

    def _dns_check_system_domains(self):
        critical = ('windows.com,microsoft.com,windowsupdate.com,download.windowsupdate.com,'
                    'login.microsoftonline.com,office365.com,azure.com,'
                    'google.com,gmail.com,cloudflare.com,github.com')
        self._dns_poison_domains_text.delete('1.0', 'end')
        self._dns_poison_domains_text.insert('1.0', critical)
        self._dns_run_poison_check()

    def _dns_test_router(self):
        def _do():
            self._dns_out(self._dns_poison_results, '=== ROUTER DNS TEST ===', Colors.GAUGE_BLUE, True)
            gw = self._dns_run_cmd(
                'powershell -Command "(Get-NetRoute -DestinationPrefix 0.0.0.0/0 | '
                'Sort-Object RouteMetric | Select-Object -First 1).NextHop"', 5).strip()
            if not gw:
                self._dns_out(self._dns_poison_results, 'Could not determine gateway', Colors.GAUGE_RED)
                return
            self._dns_out(self._dns_poison_results, f'Gateway: {gw}', Colors.TEXT_LIGHT)
            # Test if router is acting as DNS forwarder
            test_result = self._dns_resolve('google.com', gw)
            self._dns_out(self._dns_poison_results, f'Router DNS resolution of google.com: {test_result}', Colors.TEXT_LIGHT)
            # Check if router DNS points somewhere suspicious
            if '192.168.' in str(test_result) or '10.' in str(test_result):
                self._dns_out(self._dns_poison_results,
                              '[!]  Router returned private IP for google.com  -  potential DNS hijack!',
                              Colors.GAUGE_RED)
                self._dns_add_alert('[!] Router DNS hijack suspected!')
            else:
                self._dns_out(self._dns_poison_results, '[OK] Router DNS appears normal', Colors.GAUGE_GREEN)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_toggle_monitor(self):
        if self._dns_monitor_active:
            self._dns_monitor_active = False
            self._dns_mon_btn.configure(text='> START LIVE MONITOR', bg=Colors.GAUGE_GREEN, fg=Colors.BG_VOID)
            self._dns_status_var.set('* MONITOR OFF')
            self._dns_status_lbl.configure(fg=Colors.GAUGE_RED)
        else:
            self._dns_monitor_active = True
            self._dns_mon_btn.configure(text='⏹️ STOP MONITOR', bg=Colors.GAUGE_RED, fg='white')
            self._dns_status_var.set('* MONITOR ACTIVE')
            self._dns_status_lbl.configure(fg=Colors.GAUGE_GREEN)
            if not self._dns_monitor_thread or not self._dns_monitor_thread.is_alive():
                self._dns_monitor_thread = threading.Thread(target=self._dns_monitor_loop, daemon=True, name='DNS-Monitor')
                self._dns_monitor_thread.start()

    def _dns_monitor_loop(self):
        """Monitor DNS queries using netsh + polling."""
        q_count = 0
        t_count = 0
        import re
        while self._dns_monitor_active:
            try:
                # Use DNS Client cache as a proxy for recent queries
                result = self._dns_run_cmd(
                    'powershell -Command "Get-DnsClientCache | Select-Object Name, Data, Type, Status | Format-CSV"', 8)
                if result:
                    for line in result.splitlines()[1:]:  # skip header
                        parts = line.split(',')
                        if len(parts) >= 4:
                            domain = parts[0].strip('"')
                            data   = parts[1].strip('"')
                            rtype  = parts[2].strip('"')
                            status = parts[3].strip('"')
                            # Threat check
                            flag = ''
                            threat = False
                            for bad_domain in self._dns_threat_domains:
                                if bad_domain in domain.lower():
                                    flag = '[R] BLOCKLIST HIT'
                                    threat = True
                            import re as _re
                            for pattern in self._MALICIOUS_DNS_PATTERNS:
                                try:
                                    if _re.search(pattern, domain.lower()):
                                        flag = '[!] DGA/Suspicious'
                                        threat = True
                                except Exception:
                                    pass
                            if not flag:
                                flag = '[OK] Clean'
                            tag = 'threat' if threat else 'ok'
                            ts = datetime.now().strftime('%H:%M:%S')
                            q_count += 1
                            if threat:
                                t_count += 1
                                self._dns_add_alert(f'DNS threat: {domain} -> {flag}')
                            flt = self._dns_mon_filter.get().lower()
                            if flt and flt not in domain.lower():
                                pass
                            elif self._dns_mon_threat_only.get() and not threat:
                                pass
                            else:
                                def _add(d=domain, dt=data, rt=rtype, f=flag, tg=tag, t=ts):
                                    try:
                                        self._dns_mon_tree.insert('', 0, values=(t, d, rt, dt, f), tags=(tg,))
                                        kids = self._dns_mon_tree.get_children()
                                        if len(kids) > 200:
                                            self._dns_mon_tree.delete(kids[-1])
                                    except Exception:
                                        pass
                                self.after(0, _add)
                def _upd(q=q_count, t=t_count):
                    try:
                        self._dns_mon_count_var.set(f'Cache entries: {q}  |  Threats: {t}')
                    except Exception:
                        pass
                self.after(0, _upd)
            except Exception:
                pass
            time.sleep(3)

    def _dns_clear_monitor(self):
        try:
            self._dns_mon_tree.delete(*self._dns_mon_tree.get_children())
            self._dns_mon_count_var.set('Queries: 0  |  Threats: 0')
        except Exception:
            pass

    def _dns_export_monitor_log(self):
        path = filedialog.asksaveasfilename(
            defaultextension='.csv',
            filetypes=[('CSV', '*.csv'), ('All', '*.*')],
            title='Export DNS Monitor Log')
        if not path:
            return
        try:
            rows = [self._dns_mon_tree.item(iid, 'values')
                    for iid in self._dns_mon_tree.get_children()]
            with open(path, 'w', encoding='utf-8') as f:
                f.write('Time,Domain,Type,Result,Flag\\n')
                for row in rows:
                    f.write(','.join(f'"{c}"' for c in row) + '\\n')
            messagebox.showinfo('DNS', f'Log exported: {path}')
        except Exception as e:
            messagebox.showerror('DNS', f'Export failed: {e}')

    def _dns_mon_investigate(self, event=None):
        sel = self._dns_mon_tree.selection()
        if not sel:
            return
        vals = self._dns_mon_tree.item(sel[0], 'values')
        if vals:
            domain = vals[1]
            self._dns_adv_domain_var.set(domain)
            self._dns_adv_nslookup()

    def _dns_validate_dnssec(self):
        domain = self._dns_dnssec_var.get().strip() or 'dnssec-failed.org'
        def _do():
            self._dns_out(self._dns_dnssec_results, f'=== DNSSEC VALIDATION: {domain} ===',
                          Colors.GAUGE_GREEN, True)
            # Test DNSSEC-failed domain (should return SERVFAIL if DNSSEC enforced)
            if domain == 'dnssec-failed.org':
                result = self._dns_run_cmd(f'nslookup -type=A {domain} 1.1.1.1', 5)
                if 'SERVFAIL' in result or 'can\'t find' in result.lower():
                    self._dns_out(self._dns_dnssec_results,
                                  '[OK] DNSSEC is ENFORCED by your resolver\\n'
                                  '   (bogus domain correctly failed)', Colors.GAUGE_GREEN)
                else:
                    self._dns_out(self._dns_dnssec_results,
                                  '[!]  DNSSEC NOT enforced  -  your resolver returned a result\\n'
                                  '   for a known-bad DNSSEC domain. You are vulnerable to spoofing.',
                                  Colors.GAUGE_RED)
            else:
                # Get DNSKEY records
                self._dns_out(self._dns_dnssec_results, 'Fetching DNSKEY records...', Colors.TEXT_DIM)
                dnskey = self._dns_run_cmd(f'nslookup -type=DNSKEY {domain}', 5)
                ds = self._dns_run_cmd(f'nslookup -type=DS {domain}', 5)
                rrsig = self._dns_run_cmd(f'nslookup -type=RRSIG {domain}', 5)
                if any('DNSKEY' in r or 'Algorithm' in r for r in [dnskey]):
                    self._dns_out(self._dns_dnssec_results, f'[OK] DNSKEY found:\\n{dnskey}', Colors.GAUGE_GREEN)
                else:
                    self._dns_out(self._dns_dnssec_results, f'[!]  No DNSKEY found for {domain}', Colors.GAUGE_ORANGE)
                self._dns_out(self._dns_dnssec_results, f'DS record:\\n{ds}', Colors.TEXT_LIGHT)
                self._dns_out(self._dns_dnssec_results, f'RRSIG:\\n{rrsig}', Colors.TEXT_LIGHT)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_full_dnssec_audit(self):
        domains = ['google.com', 'cloudflare.com', 'gov.uk', 'dnssec-failed.org']
        def _do():
            self._dns_out(self._dns_dnssec_results, '=== FULL DNSSEC AUDIT ===', Colors.GAUGE_PURPLE, True)
            for d in domains:
                self._dns_dnssec_var.set(d)
                self._dns_validate_dnssec()
                time.sleep(0.5)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_hosts_load(self):
        hosts_path = r'C:\\Windows\\System32\\drivers\\etc\\hosts'
        try:
            with open(hosts_path, 'r', errors='ignore') as f:
                content = f.read()
            self._dns_hosts_text.delete('1.0', 'end')
            self._dns_hosts_text.insert('1.0', content)
            lines = len(content.splitlines())
            self._dns_hosts_status_var.set(f'Loaded: {hosts_path} ({lines} lines)')
        except PermissionError:
            self._dns_hosts_status_var.set('ERROR: Need admin rights to read hosts file')
            messagebox.showwarning('Hosts File', 'Run Downpour as Administrator to edit the hosts file.')
        except Exception as e:
            self._dns_hosts_status_var.set(f'Error: {e}')

    def _dns_hosts_save(self):
        content = self._dns_hosts_text.get('1.0', 'end')
        ok = self._write_hosts_elevated(content)
        if ok:
            self._dns_hosts_status_var.set('Hosts file saved successfully')
        else:
            self._dns_hosts_status_var.set('ERROR: Save failed - check logs')
            messagebox.showerror('Hosts File',
                'Could not save hosts file.\n\n'
                'Windows Defender Controlled Folder Access is blocking the write.\n\n'
                'To fix permanently:\n'
                '  Windows Security > Virus & threat protection >\n'
                '  Manage ransomware protection > Allow an app through CFA\n'
                '  Add: python.exe and pythonw.exe\n\n'
                'The launcher BAT should have done this automatically  -  '
                'try re-running launch_downpour.bat as Administrator.')

    def _dns_hosts_backup(self):
        hosts_path = r'C:\\Windows\\System32\\drivers\\etc\\hosts'
        backup_path = str(LOGS_DIR / f'hosts.bak.{datetime.now().strftime("%Y%m%d_%H%M%S")}')
        try:
            import shutil
            shutil.copy2(hosts_path, backup_path)
            self._dns_hosts_status_var.set(f'[OK] Backup saved: {backup_path}')
        except Exception as e:
            messagebox.showerror('Backup', f'Failed: {e}')

    def _dns_hosts_restore(self):
        path = filedialog.askopenfilename(
            initialdir=str(LOGS_DIR),
            title='Select hosts backup',
            filetypes=[('All', '*')])
        if not path:
            return
        try:
            with open(path, 'r', errors='ignore') as f:
                content = f.read()
            self._dns_hosts_text.delete('1.0', 'end')
            self._dns_hosts_text.insert('1.0', content)
            self._dns_hosts_status_var.set(f'Backup loaded from {path}  -  click Save to apply')
        except Exception as e:
            messagebox.showerror('Restore', f'Failed: {e}')

    def _dns_hosts_scan_hijacks(self):
        content = self._dns_hosts_text.get('1.0', 'end')
        if not content.strip():
            self._dns_hosts_load()
            return
        issues = []
        suspicious_targets = ['microsoft', 'windows', 'apple', 'google', 'amazon',
                               'paypal', 'bank', 'chase', 'wellsfargo', 'adobe']
        for lineno, line in enumerate(content.splitlines(), 1):
            line = line.strip()
            if line and not line.startswith('#'):
                parts = line.split()
                if len(parts) >= 2:
                    ip = parts[0]
                    domain = parts[1].lower()
                    if any(t in domain for t in suspicious_targets):
                        if ip not in ('127.0.0.1', '::1', '0.0.0.0'):
                            issues.append(f'Line {lineno}: {line} [HIJACK SUSPECTED]')
        if issues:
            self._dns_hosts_status_var.set(f'[!] {len(issues)} suspicious entries found!')
            self._dns_add_alert(f'[!] Hosts hijack: {len(issues)} entries')
            messagebox.showwarning('Hosts Hijack', '\\n'.join(issues[:10]))
        else:
            self._dns_hosts_status_var.set('[OK] No hijack patterns found in hosts file')

