    def _dns_hosts_import_stevenblack(self):
        def _do():
            self._dns_hosts_status_var.set('Downloading StevenBlack hosts list...')
            url = 'https://raw.githubusercontent.com/StevenBlack/hosts/master/hosts'
            try:
                req = urllib.request.Request(url, headers={'User-Agent': 'Downpour/22'})
                with urllib.request.urlopen(req, timeout=15) as r:
                    content = r.read().decode('utf-8', errors='ignore')
                self.after(0, lambda: [
                    self._dns_hosts_text.delete('1.0', 'end'),
                    self._dns_hosts_text.insert('1.0', content),
                    self._dns_hosts_status_var.set(f'[OK] Loaded StevenBlack list  -  {len(content.splitlines())} lines  -  click Save to apply'),
                ])
            except Exception as e:
                self.after(0, lambda _e=e: self._dns_hosts_status_var.set(f'Download failed: {_e}'))
        threading.Thread(target=_do, daemon=True).start()

    def _dns_enable_doh(self):
        def _do():
            self._dns_out(self._dns_encrypt_results, '=== ENABLING DNS-over-HTTPS ===', Colors.GAUGE_PURPLE, True)
            # Set DoH mode in registry (Windows 11+ native DoH)
            reg_cmds = [
                'reg add "HKLM\\\\SYSTEM\\\\CurrentControlSet\\\\Services\\\\Dnscache\\\\Parameters" /v EnableAutoDoh /t REG_DWORD /d 2 /f',
                'net stop dnscache',
                'net start dnscache',
            ]
            for cmd in reg_cmds:
                r = self._dns_run_cmd(cmd, 15)
                self._dns_out(self._dns_encrypt_results, r or 'OK', Colors.TEXT_DIM)
            self._dns_out(self._dns_encrypt_results,
                          '[OK] DoH enabled (requires compatible resolver like Cloudflare/Google/Quad9).',
                          Colors.GAUGE_GREEN)
            self._dns_add_alert('[OK] DNS-over-HTTPS enabled')
        threading.Thread(target=_do, daemon=True).start()

