    def _dns_test_doh(self):
        def _do():
            self._dns_out(self._dns_encrypt_results, 'Testing DoH connection...', Colors.GAUGE_PURPLE)
            url = self._dns_doh_template_var.get().strip() or 'https://cloudflare-dns.com/dns-query'
            # Make a simple DoH query for google.com
            try:
                import base64, struct
                # Build a simple DNS query packet for google.com (type A)
                qname = b'\\x06google\\x03com\\x00'
                query = b'\\xab\\xcd\\x01\\x00\\x00\\x01\\x00\\x00\\x00\\x00\\x00\\x00' + qname + b'\\x00\\x01\\x00\\x01'
                encoded = base64.urlsafe_b64encode(query).rstrip(b'=').decode()
                req_url = f'{url}?dns={encoded}'
                req = urllib.request.Request(req_url, headers={
                    'Accept': 'application/dns-message',
                    'User-Agent': 'Downpour/22'
                })
                with urllib.request.urlopen(req, timeout=5) as r:
                    resp = r.read()
                self._dns_out(self._dns_encrypt_results,
                              f'[OK] DoH working! Response: {len(resp)} bytes from {url}',
                              Colors.GAUGE_GREEN)
            except Exception as e:
                self._dns_out(self._dns_encrypt_results,
                              f'[!]  DoH test failed: {e}', Colors.GAUGE_ORANGE)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_view_cache(self):
        def _do():
            self._dns_out(self._dns_cache_text, '=== DNS CLIENT CACHE ===', Colors.GAUGE_TEAL, True)
            result = self._dns_run_cmd(
                'powershell -Command "Get-DnsClientCache | Sort-Object Name | '
                'Select-Object Name, Data, Type, Status, TimeToLive | Format-Table -AutoSize"', 10)
            self._dns_out(self._dns_cache_text, result or '(no cache entries)', Colors.TEXT_LIGHT)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_scan_cache_threats(self):
        def _do():
            self._dns_out(self._dns_cache_text, '=== CACHE THREAT SCAN ===', Colors.GAUGE_ORANGE)
            result = self._dns_run_cmd(
                'powershell -Command "Get-DnsClientCache | Select-Object Name, Data | ConvertTo-Csv"', 10)
            threats = 0
            import re as _re
            for line in result.splitlines()[1:]:
                parts = line.split(',')
                if len(parts) >= 1:
                    domain = parts[0].strip('"').lower()
                    for ioc in self._MALICIOUS_DNS_IOC:
                        if ioc in domain:
                            self._dns_out(self._dns_cache_text,
                                          f'[R] THREAT IN CACHE: {domain}  -  IOC: {ioc}',
                                          Colors.GAUGE_RED)
                            self._dns_add_alert(f'[R] Malware IOC in DNS cache: {domain}')
                            threats += 1
                    for pattern in self._MALICIOUS_DNS_PATTERNS:
                        try:
                            if _re.search(pattern, domain):
                                self._dns_out(self._dns_cache_text,
                                              f'[!]  DGA-like domain in cache: {domain}',
                                              Colors.GAUGE_ORANGE)
                                threats += 1
                        except Exception:
                            pass
            summary_color = Colors.GAUGE_GREEN if threats == 0 else Colors.GAUGE_RED
            self._dns_out(self._dns_cache_text,
                          f'\\n=== Scan complete: {threats} threats found ===', summary_color)
            if threats > 0:
                if messagebox.askyesno('DNS Threats', f'{threats} malicious cache entries found!\\nFlush DNS cache now?'):
                    self._dns_flush_cache()
        threading.Thread(target=_do, daemon=True).start()

    def _dns_export_cache(self):
        path = filedialog.asksaveasfilename(
            defaultextension='.txt',
            filetypes=[('Text', '*.txt'), ('All', '*.*')],
            title='Export DNS Cache')
        if not path:
            return
        try:
            content = self._dns_cache_text.get('1.0', 'end')
            with open(path, 'w', encoding='utf-8') as f:
                f.write(content)
            messagebox.showinfo('DNS', f'Cache exported: {path}')
        except Exception as e:
            messagebox.showerror('DNS', f'Export failed: {e}')

    def _dns_export_report(self):
        path = filedialog.asksaveasfilename(
            defaultextension='.txt',
            filetypes=[('Text', '*.txt'), ('All', '*.*')],
            title='Save DNS Security Report')
        if not path:
            return
        def _do():
            report = []
            report.append('DOWNPOUR DNS SECURITY REPORT')
            report.append(f'Generated: {datetime.now().isoformat()}')
            report.append('=' * 60)
            result = self._dns_run_cmd(
                'powershell -Command "Get-DnsClientServerAddress | Format-List"', 10)
            report.append('\\nDNS SERVERS:')
            report.append(result)
            doh = self._dns_run_cmd(
                'reg query "HKLM\\\\SYSTEM\\\\CurrentControlSet\\\\Services\\\\Dnscache\\\\Parameters" /v EnableAutoDoh 2>nul', 5)
            report.append('\\nDoH STATUS:')
            report.append(doh)
            report.append('\\nALERTS:')
            try:
                alerts = [self._dns_alert_list.get(i) for i in range(min(50, self._dns_alert_list.size()))]
                report.extend(alerts)
            except Exception:
                pass
            try:
                with open(path, 'w', encoding='utf-8') as f:
                    f.write('\\n'.join(report))
                self.after(0, lambda: messagebox.showinfo('DNS', f'Report saved: {path}'))
            except Exception as e:
                self.after(0, lambda _e=e: messagebox.showerror('DNS', f'Failed: {_e}'))
        threading.Thread(target=_do, daemon=True).start()

    def _dns_blocklist_add(self):
        domain = self._dns_block_entry_var.get().strip().lower()
        if not domain:
            return
        self._dns_threat_domains.add(domain)
        ts = datetime.now().strftime('%Y-%m-%d')
        self._dns_block_tree.insert('', 'end', values=(domain, 'Manual block', ts, 0))
        self._dns_block_entry_var.set('')
        self._dns_block_count_var.set(f'{len(self._dns_threat_domains)} domains blocked')
        # Apply to hosts file
        self._dns_add_alert(f'[BLOCK] Blocked: {domain}')

    def _dns_blocklist_remove(self):
        sel = self._dns_block_tree.selection()
        if sel:
            vals = self._dns_block_tree.item(sel[0], 'values')
            if vals:
                self._dns_threat_domains.discard(vals[0])
            self._dns_block_tree.delete(sel[0])
            self._dns_block_count_var.set(f'{len(self._dns_threat_domains)} domains blocked')

    def _dns_blocklist_import(self):
        path = filedialog.askopenfilename(
            title='Import blocklist',
            filetypes=[('Text', '*.txt'), ('Hosts', '*.hosts'), ('All', '*.*')])
        if not path:
            return
        try:
            count = 0
            with open(path, 'r', errors='ignore') as f:
                for line in f:
                    line = line.strip()
                    if line and not line.startswith('#'):
                        parts = line.split()
                        domain = parts[-1].lower() if parts else ''
                        if domain and '.' in domain:
                            self._dns_threat_domains.add(domain)
                            ts = datetime.now().strftime('%Y-%m-%d')
                            self._dns_block_tree.insert('', 'end',
                                values=(domain, f'Imported from {os.path.basename(path)}', ts, 0))
                            count += 1
            self._dns_block_count_var.set(f'{len(self._dns_threat_domains)} domains blocked')
            messagebox.showinfo('Blocklist', f'Imported {count} domains')
        except Exception as e:
            messagebox.showerror('Import', f'Failed: {e}')

    def _dns_blocklist_export(self):
        path = filedialog.asksaveasfilename(
            defaultextension='.txt',
            filetypes=[('Text', '*.txt'), ('All', '*.*')],
            title='Export Blocklist')
        if not path:
            return
        try:
            with open(path, 'w', encoding='utf-8') as f:
                for domain in sorted(self._dns_threat_domains):
                    f.write(f'0.0.0.0 {domain}\\n')
            messagebox.showinfo('Blocklist', f'Exported {len(self._dns_threat_domains)} domains to {path}')
        except Exception as e:
            messagebox.showerror('Export', f'Failed: {e}')

