    def _dns_spoofing_test(self):
        def _do():
            self._dns_out(self._dns_adv_output, '=== DNS SPOOFING TEST ===', Colors.GAUGE_RED, True)
            # Compare local resolution against authoritative
            test_domains = ['google.com', 'cloudflare.com', 'microsoft.com']
            for domain in test_domains:
                local = self._dns_resolve(domain)
                auth  = self._dns_resolve(domain, '1.1.1.1')
                self._dns_out(self._dns_adv_output, f'{domain}:', Colors.GAUGE_TEAL)
                self._dns_out(self._dns_adv_output, f'  Local:         {local}')
                self._dns_out(self._dns_adv_output, f'  Authoritative: {auth}')
                if local != auth and 'ERROR' not in str(local) and 'ERROR' not in str(auth):
                    self._dns_out(self._dns_adv_output, '  [!]  MISMATCH DETECTED!', Colors.GAUGE_RED)
                    self._dns_add_alert(f'[!] DNS spoofing possible for {domain}')
                else:
                    self._dns_out(self._dns_adv_output, '  [OK] Match', Colors.GAUGE_GREEN)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_rebinding_test(self):
        def _do():
            self._dns_out(self._dns_adv_output, '=== DNS REBINDING TEST ===', Colors.GAUGE_ORANGE, True)
            self._dns_out(self._dns_adv_output,
                          'DNS rebinding allows attackers to access your local network\\nby manipulating DNS to return private IPs.',
                          Colors.TEXT_DIM)
            # Test: can we resolve a domain to a private IP?
            test_ips = []
            try:
                # Check all current DNS cache entries for private IPs mapped to public domains
                result = self._dns_run_cmd(
                    'powershell -Command "Get-DnsClientCache | Select-Object Name, Data | Format-CSV"', 8)
                for line in result.splitlines()[1:]:
                    parts = line.split(',')
                    if len(parts) >= 2:
                        domain = parts[0].strip('"')
                        data   = parts[1].strip('"')
                        try:
                            ip = ipaddress.ip_address(data)
                            if ip.is_private and not any(
                                    local in domain.lower() for local in
                                    ['local', 'localhost', 'router', 'gateway', 'home']):
                                test_ips.append((domain, data))
                                self._dns_out(self._dns_adv_output,
                                              f'[!]  {domain} -> {data} (PRIVATE IP  -  possible rebinding!)',
                                              Colors.GAUGE_RED)
                        except Exception:
                            pass
                if not test_ips:
                    self._dns_out(self._dns_adv_output,
                                  '[OK] No DNS rebinding indicators found in current cache.', Colors.GAUGE_GREEN)
            except Exception as e:
                self._dns_out(self._dns_adv_output, f'Test error: {e}', Colors.GAUGE_ORANGE)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_check_hijack(self):
        def _do():
            self._dns_out(self._dns_adv_output, '=== DNS HIJACK DETECTION ===', Colors.GAUGE_RED, True)
            checks = [
                ('google.com', '142.250.', '172.217.', '64.233.'),
                ('cloudflare.com', '104.16.', '104.17.'),
                ('microsoft.com', '20.', '40.', '13.'),
            ]
            hijacked = 0
            for domain, *expected_prefixes in checks:
                resolved = self._dns_resolve(domain)
                matched = any(resolved.startswith(p) for p in expected_prefixes)
                if not matched and 'ERROR' not in str(resolved):
                    self._dns_out(self._dns_adv_output,
                                  f'[!]  {domain} -> {resolved} (unexpected!)', Colors.GAUGE_RED)
                    hijacked += 1
                else:
                    self._dns_out(self._dns_adv_output,
                                  f'[OK] {domain} -> {resolved}', Colors.GAUGE_GREEN)
            if hijacked:
                self._dns_add_alert(f'[ALERT] DNS hijack suspected: {hijacked} domains resolve incorrectly!')
            else:
                self._dns_out(self._dns_adv_output, '\\n[OK] No DNS hijacking detected.', Colors.GAUGE_GREEN)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_test_all_servers(self):
        def _do():
            self._dns_out(self._dns_adv_output, '=== TEST ALL DNS PROVIDERS ===', Colors.GAUGE_TEAL, True)
            for name, (primary, secondary, doh) in self._DNS_PROVIDERS.items():
                start = time.time()
                result = self._dns_resolve('google.com', primary)
                ms = int((time.time() - start) * 1000)
                ok = 'ERROR' not in str(result)
                color = Colors.GAUGE_GREEN if ok else Colors.GAUGE_RED
                self._dns_out(self._dns_adv_output,
                              f'{name[:35]:35} {primary:18} {ms:4}ms  {"[OK]" if ok else "[X]"}',
                              color)
                time.sleep(0.1)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_check_router_dns(self):
        def _do():
            self._dns_out(self._dns_adv_output, '=== ROUTER DNS CHECK ===', Colors.GAUGE_BLUE, True)
            gw = self._dns_run_cmd(
                'powershell -Command "(Get-NetRoute -DestinationPrefix 0.0.0.0/0 | '
                'Sort-Object RouteMetric | Select-Object -First 1).NextHop"', 5).strip()
            self._dns_out(self._dns_adv_output, f'Gateway: {gw}')
            # TCP latency probe to router (port 80 or 443) — no ICMP to avoid IDS flags
            import socket as _sock, time as _time
            _gw_ms = 9999
            for _p in (80, 443, 53):
                try:
                    _t0 = _time.perf_counter()
                    _s  = _sock.socket(_sock.AF_INET, _sock.SOCK_STREAM)
                    _s.settimeout(2.0)
                    _e  = _s.connect_ex((gw, _p))
                    _gw_ms = int((_time.perf_counter() - _t0) * 1000)
                    _s.close()
                    if _e == 0 or _e in (10061, 111):
                        break
                except OSError:
                    pass
            _reach = f'{_gw_ms}ms' if _gw_ms < 9999 else 'unreachable'
            self._dns_out(self._dns_adv_output, f'Gateway reachability (TCP): {_reach}', Colors.TEXT_DIM)
            # Check if gateway is acting as DNS
            current_dns = self._dns_run_cmd(
                'powershell -Command "(Get-DnsClientServerAddress -AddressFamily IPv4).ServerAddresses | Select-Object -First 1"', 5).strip()
            if current_dns == gw:
                self._dns_out(self._dns_adv_output,
                              f'[!]  Your router ({gw}) is your DNS server.\\n'
                              '   Router DNS can be compromised. Consider using encrypted DoH servers.',
                              Colors.GAUGE_ORANGE)
            else:
                self._dns_out(self._dns_adv_output,
                              f'[OK] DNS not routing through router. Current DNS: {current_dns}',
                              Colors.GAUGE_GREEN)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_test_bgp(self):
        def _do():
            self._dns_out(self._dns_adv_output, '=== BGP ROUTE LEAK / HIJACK CHECK ===', Colors.GAUGE_PURPLE, True)
            self._dns_out(self._dns_adv_output,
                          'Checking your public IP geolocation and AS info...', Colors.TEXT_DIM)
            try:
                req = urllib.request.Request('https://ipapi.co/json/',
                                             headers={'User-Agent': 'Downpour/22'})
                with urllib.request.urlopen(req, timeout=8) as r:
                    data = json.loads(r.read())
                ip   = data.get('ip', 'N/A')
                asn  = data.get('org', 'N/A')
                city = data.get('city', 'N/A')
                country = data.get('country_name', 'N/A')
                self._dns_out(self._dns_adv_output, f'Public IP: {ip}', Colors.GAUGE_TEAL)
                self._dns_out(self._dns_adv_output, f'AS/ISP:    {asn}', Colors.TEXT_LIGHT)
                self._dns_out(self._dns_adv_output, f'Location:  {city}, {country}', Colors.TEXT_LIGHT)
                # Flag if Tor/VPN/Proxy detected
                if data.get('threat', {}).get('is_tor') or data.get('proxy', False):
                    self._dns_out(self._dns_adv_output,
                                  '[!]  TOR/VPN/Proxy detected in your path  -  DNS may be redirected.',
                                  Colors.GAUGE_ORANGE)
            except Exception as e:
                self._dns_out(self._dns_adv_output, f'BGP check failed: {e}', Colors.GAUGE_ORANGE)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_lock_dns(self):
        if not messagebox.askyesno('Lock DNS',
                                    'This will lock DNS settings to prevent malware from changing them.\\n'
                                    'Uses registry restrictions.\\nContinue?'):
            return
        def _do():
            self._dns_out(self._dns_adv_output, 'Locking DNS configuration...', Colors.GAUGE_RED)
            # Disable automatic DNS via DHCP overrides
            cmds = [
                'reg add "HKLM\\\\SYSTEM\\\\CurrentControlSet\\\\Services\\\\Tcpip\\\\Parameters" /v NameServer /t REG_SZ /d "1.1.1.1" /f',
                'reg add "HKLM\\\\SYSTEM\\\\CurrentControlSet\\\\Services\\\\Tcpip\\\\Parameters" /v SearchList /t REG_SZ /d "" /f',
                # Enable DNS hardening
                'reg add "HKLM\\\\SYSTEM\\\\CurrentControlSet\\\\Services\\\\Dnscache\\\\Parameters" /v MaxNegativeCacheTtl /t REG_DWORD /d 5 /f',
                'reg add "HKLM\\\\SYSTEM\\\\CurrentControlSet\\\\Services\\\\Dnscache\\\\Parameters" /v MaxCacheEntryTtlLimit /t REG_DWORD /d 86400 /f',
            ]
            for cmd in cmds:
                r = self._dns_run_cmd(cmd, 10)
                self._dns_out(self._dns_adv_output, r or 'OK', Colors.TEXT_DIM)
            self._dns_out(self._dns_adv_output,
                          '[OK] DNS locked. Malware cannot easily change your DNS settings.',
                          Colors.GAUGE_GREEN)
        threading.Thread(target=_do, daemon=True).start()

    def _dns_emergency_fix(self):
        if not messagebox.askyesno('Emergency DNS Fix',
                                    'This will:\\n'
                                    '- Flush DNS cache\\n'
                                    '- Reset Winsock\\n'
                                    '- Set DNS to Cloudflare (1.1.1.1)\\n'
                                    '- Enable DoH\\n'
                                    '- Flush hosts file poison entries\\n\\n'
                                    'Apply emergency DNS fix now?'):
            return
        def _do():
            self._dns_out(self._dns_adv_output, '[ALERT] EMERGENCY DNS FIX IN PROGRESS...', Colors.GAUGE_RED, True)
            steps = [
                ('Flushing DNS cache...', 'ipconfig /flushdns'),
                ('Resetting Winsock...', 'netsh winsock reset'),
                ('Resetting TCP/IP...', 'netsh int ip reset'),
                ('Registering DNS...', 'ipconfig /registerdns'),
            ]
            for msg, cmd in steps:
                self._dns_out(self._dns_adv_output, msg, Colors.GAUGE_ORANGE)
                r = self._dns_run_cmd(cmd, 15)
                self._dns_out(self._dns_adv_output, r or 'Done', Colors.TEXT_DIM)
            # Set Cloudflare DNS
            self.after(0, lambda: [
                self._dns_primary_var.set('1.1.1.1'),
                self._dns_secondary_var.set('1.0.0.1'),
            ])
            time.sleep(0.2)
            self._dns_apply_servers()
            time.sleep(0.5)
            self._dns_enable_doh()
            self._dns_out(self._dns_adv_output,
                          '\\n[OK] Emergency DNS fix complete. Restart browser and test connectivity.',
                          Colors.GAUGE_GREEN)
            self._dns_add_alert('[ALERT] Emergency DNS fix applied')
        threading.Thread(target=_do, daemon=True).start()

    def _dns_backup_settings(self):
        path = str(LOGS_DIR / f'dns_backup_{datetime.now().strftime("%Y%m%d_%H%M%S")}.txt')
        def _do():
            result = self._dns_run_cmd(
                'powershell -Command "Get-DnsClientServerAddress | Format-List"', 10)
            try:
                with open(path, 'w') as f:
                    f.write(f'DNS Backup  -  {datetime.now().isoformat()}\\n')
                    f.write(result)
                self.after(0, lambda: self._dns_out(self._dns_adv_output,
                                                    f'[OK] DNS settings backed up to: {path}',
                                                    Colors.GAUGE_GREEN))
            except Exception as e:
                self.after(0, lambda _e=e: self._dns_out(self._dns_adv_output, f'Backup failed: {_e}', Colors.GAUGE_RED))
        threading.Thread(target=_do, daemon=True).start()

    def _dns_restore_settings(self):
        path = filedialog.askopenfilename(
            initialdir=str(LOGS_DIR),
            title='Select DNS backup',
            filetypes=[('Text', '*.txt'), ('All', '*.*')])
        if path:
            messagebox.showinfo('DNS Restore',
                                f'Loaded: {path}\\nManually review and use the Servers tab to reapply settings.')


    # ===========================================================================
