    def _build_remote_access_tab(self):
        """Remote Access Control panel  -  disable/enable every remote access vector."""
        p = self._tab_remote

        tk.Label(p, text="\U0001f6aa REMOTE ACCESS CONTROL",
                 font=('Consolas', 12, 'bold'), fg=Colors.GAUGE_RED,
                 bg=Colors.BG_VOID).pack(anchor='w', padx=10, pady=8)

        tk.Label(p,
            text=("Scan and control every remote access vector on this system.\n"
                  "Disable attack surface exposed via RDP, SSH, WinRM, VNC, telnet and more."),
            font=('Consolas', 9), fg=Colors.TEXT_DIM, bg=Colors.BG_VOID,
            justify='left').pack(anchor='w', padx=12, pady=2)

        # -- Status bar
        self._remote_status_lbl = tk.Label(p, text="Not scanned",
            font=('Consolas', 9, 'bold'), fg=Colors.GAUGE_YELLOW, bg=Colors.BG_VOID)
        self._remote_status_lbl.pack(anchor='w', padx=12, pady=2)

        # -- Button row
        btn_row = tk.Frame(p, bg=Colors.BG_VOID)
        btn_row.pack(fill='x', padx=10, pady=4)

        def _scan():
            if not _REMOTE_ACCESS_MODULE_AVAILABLE:
                messagebox.showerror('Module Missing',
                    'downpour_remote_access.py not found. Place it in the same folder as downpour_v29_titanium.py')
                return
            self._remote_status_lbl.config(text='\U0001f504 Scanning...', fg=Colors.GAUGE_YELLOW)
            # FIX: removed p.update_idletasks() — calling update_idletasks() from a
            # callback that fires during tab building crashes Tkinter fatally.
            def _run():
                # FIX-v28p19: Fully guarded remote access scan
                # Build per-vector dict from scan results + REMOTE_ACCESS_VECTORS
                results = {}
                try:
                    ctrl = RemoteAccessController()
                    scan_result = ctrl.scan_now()
                    # Collect open ports from scan
                    open_ports = set()
                    for p in getattr(scan_result, 'open_remote_ports', []):
                        port = p.get('port', 0) if isinstance(p, dict) else 0
                        if port:
                            open_ports.add(port)
                    # Build dict keyed by vector name
                    for key, vec in REMOTE_ACCESS_VECTORS.items():
                        enabled = any(p in open_ports for p in vec.get('ports', []))
                        details = []
                        for ev in getattr(scan_result, 'events', []):
                            if getattr(ev, 'event_type', '') == key:
                                details.append(f"{getattr(ev, 'risk_level', '')}: "
                                               f"{getattr(ev, 'process_name', '')} "
                                               f"({getattr(ev, 'remote_ip', '')})")
                        results[key] = {
                            'name': vec.get('desc', key),
                            'risk': vec.get('risk', 'LOW').upper(),
                            'enabled': enabled,
                            'details': details,
                        }
                except Exception as _e:
                    logger.error(f'RemoteAccessController: {_e}')
                    # Fallback: show vectors as unchecked
                    for key, vec in REMOTE_ACCESS_VECTORS.items():
                        results[key] = {
                            'name': vec.get('desc', key),
                            'risk': vec.get('risk', 'LOW').upper(),
                            'enabled': False,
                            'details': ['Scan error'],
                        }
                self._remote_last_results = results
                self.after(0, lambda: _populate(results))
            import threading
            threading.Thread(target=_run, daemon=True).start()

        def _disable_selected():
            sel = self._remote_tree.selection()
            if not sel:
                messagebox.showwarning('Select', 'Select a vector first.')
                return
            iid = sel[0]
            key = self._remote_tree.item(iid, 'values')[0]
            if key not in REMOTE_ACCESS_VECTORS:
                return
            vector = REMOTE_ACCESS_VECTORS[key]
            desc = vector.get('desc', key) if isinstance(vector, dict) else getattr(vector, 'name', key)
            if hasattr(RemoteAccessController, 'disable_vector'):
                ok, msg = RemoteAccessController.disable_vector(vector)
                _log(f'[{"OK" if ok else "FAIL"}] {msg}')
                _scan()
            else:
                messagebox.showinfo('Not Implemented',
                    f'Disabling {desc} is not yet automated.\nUse Windows Settings or netsh.')

        def _disable_all():
            if not messagebox.askyesno('Confirm',
                'Disable ALL remote access vectors?\n\nThis will stop RDP, SSH, WinRM, VNC, Telnet, NetBIOS and more.\n\nContinue?'):
                return
            if not _REMOTE_ACCESS_MODULE_AVAILABLE:
                return
            if hasattr(RemoteAccessController, 'disable_all_remote_access'):
                def _run():
                    msgs = RemoteAccessController.disable_all_remote_access(
                        progress_cb=lambda m: self.after(0, lambda: _log(m)))
                    self.after(0, _scan)
                import threading
                threading.Thread(target=_run, daemon=True).start()
            else:
                messagebox.showinfo('Not Implemented',
                    'Bulk disable is not yet automated.\nUse Windows Settings or netsh to disable individual vectors.')

        def _enable_selected():
            sel = self._remote_tree.selection()
            if not sel:
                messagebox.showwarning('Select', 'Select a vector first.')
                return
            iid = sel[0]
            key = self._remote_tree.item(iid, 'values')[0]
            if key not in REMOTE_ACCESS_VECTORS:
                return
            vector = REMOTE_ACCESS_VECTORS[key]
            desc = vector.get('desc', key) if isinstance(vector, dict) else getattr(vector, 'name', key)
            if hasattr(RemoteAccessController, 'enable_vector'):
                ok, msg = RemoteAccessController.enable_vector(vector)
                _log(f'[{"OK" if ok else "FAIL"}] {msg}')
                _scan()
            else:
                messagebox.showinfo('Not Implemented',
                    f'Re-enabling {desc} is not yet automated.\nUse Windows Settings.')

        def _populate(results):
            self._remote_tree.delete(*self._remote_tree.get_children())
            enabled_count = 0
            for key, r in results.items():
                risk   = r['risk']
                status = '\u26a0\ufe0f  ENABLED' if r['enabled'] else '\u2705 Disabled'
                detail = ' | '.join(r['details'][:1]) if r['details'] else ''
                color_tag = {'CRITICAL': 'crit', 'HIGH': 'high',
                             'MEDIUM': 'med', 'LOW': 'low'}.get(risk, '')
                self._remote_tree.insert('', 'end', iid=key,
                    values=(key, r['name'], risk, status, detail),
                    tags=(color_tag,) if r['enabled'] else ('clean',))
                if r['enabled']:
                    enabled_count += 1

            # Compute attack surface score inline
            _risk_weights = {'CRITICAL': 25, 'HIGH': 15, 'MEDIUM': 8, 'LOW': 3}
            score = sum(_risk_weights.get(r.get('risk', ''), 0)
                        for r in results.values() if r.get('enabled'))
            score = min(score, 100)
            label = ('MINIMAL' if score < 10 else 'LOW' if score < 25
                     else 'MODERATE' if score < 50 else 'HIGH' if score < 75
                     else 'CRITICAL')
            score_color = Colors.GAUGE_GREEN if score < 20 else Colors.GAUGE_YELLOW if score < 50 else Colors.GAUGE_RED
            self._remote_status_lbl.config(
                text=f'Attack Surface: {score}/100   -   {enabled_count} vector(s) enabled  |  {label}',
                fg=score_color)

        def _log(msg):
            self._remote_log.config(state='normal')
            self._remote_log.insert('end', msg + '\n')
            self._remote_log.see('end')
            self._remote_log.config(state='disabled')

        for text, cmd, color in [
            ('\U0001f50d Scan All',           _scan,            Colors.GAUGE_BLUE),
            ('\u274c Disable Selected',        _disable_selected, Colors.GAUGE_ORANGE),
            ('\U0001f6ab Disable ALL Vectors', _disable_all,     Colors.GAUGE_RED),
            ('\u2705 Re-enable Selected',      _enable_selected,  Colors.GAUGE_GREEN),
        ]:
            tk.Button(btn_row, text=text, font=('Consolas', 9, 'bold'), fg=color,
                bg=Colors.GLASS_CARD, relief='flat', padx=8,
                command=cmd).pack(side='left', padx=4)

        # -- Tree
        cols = ('key', 'Name', 'Risk', 'Status', 'Detail')
        self._remote_tree = ttk.Treeview(p, style='Titan.Treeview',
            columns=cols, show='headings', selectmode='browse', height=14)
        widths = {'key': 120, 'Name': 220, 'Risk': 80, 'Status': 110, 'Detail': 260}
        for col in cols:
            self._remote_tree.heading(col, text=col)
            self._remote_tree.column(col, width=widths.get(col, 100),
                                      stretch=(col == 'Detail'))
        for tag, color in [('crit', '#ff4444'), ('high', Colors.GAUGE_ORANGE),
                           ('med', Colors.GAUGE_YELLOW), ('low', Colors.TEXT_DIM),
                           ('clean', Colors.GAUGE_GREEN)]:
            self._remote_tree.tag_configure(tag, foreground=color)

        sb = tk.Scrollbar(p, orient='vertical', command=self._remote_tree.yview)
        self._remote_tree.configure(yscrollcommand=sb.set)
        self._style_sb(sb)
        tree_frame = tk.Frame(p, bg=Colors.BG_VOID)
        tree_frame.pack(fill='both', expand=True, padx=8, pady=4)
        self._remote_tree.pack(side='left', fill='both', expand=True, in_=tree_frame)
        sb.pack(side='right', fill='y', in_=tree_frame)

        # -- Log panel
        log_frame = tk.Frame(p, bg=Colors.GLASS_CARD)
        log_frame.pack(fill='x', padx=8, pady=(0, 6))
        tk.Label(log_frame, text='ACTION LOG', font=('Consolas', 8, 'bold'),
                 fg=Colors.GAUGE_GREEN, bg=Colors.GLASS_CARD).pack(anchor='w', padx=4, pady=2)
        self._remote_log = tk.Text(log_frame, bg=Colors.GLASS_DARK, fg=Colors.TEXT_LIGHT,
            font=('Consolas', 8), height=5, wrap='word', state='disabled', relief='flat')
        self._remote_log.pack(fill='x', padx=4, pady=(0, 4))

        self._remote_last_results = {}

        # FIX: <Visibility> fires immediately when the tab panel is first mapped
        # during _build_ui, triggering _scan which called p.update_idletasks()
        # and crashed Tkinter. Now guarded by _ui_ready flag — only scans after
        # the full UI is built and the window is shown.
        def _on_tab_visible(e):
            if getattr(self, '_ui_ready', False) and not self._remote_last_results:
                self.after(200, _scan)
        p.bind('<Visibility>', _on_tab_visible)

    # ===========================================================================
