    def _build_services_tab(self):
        """Smart Services Scanner  -  threat-score every running service."""
        p = self._tab_services

        tk.Label(p, text="\u2699 SMART SERVICES THREAT SCANNER",
                 font=('Consolas', 12, 'bold'), fg=Colors.GAUGE_ORANGE,
                 bg=Colors.BG_VOID).pack(anchor='w', padx=10, pady=8)

        tk.Label(p,
            text=("Threat-scores every installed Windows service. Detects unsigned binaries, "
                  "suspicious paths,\nmalware name patterns, svchost DLL hijacking, and known-bad services. "
                  "MITRE ATT&CK tagged."),
            font=('Consolas', 9), fg=Colors.TEXT_DIM, bg=Colors.BG_VOID,
            justify='left').pack(anchor='w', padx=12, pady=2)

        self._svc_status_lbl = tk.Label(p, text='Not scanned',
            font=('Consolas', 9, 'bold'), fg=Colors.GAUGE_YELLOW, bg=Colors.BG_VOID)
        self._svc_status_lbl.pack(anchor='w', padx=12, pady=2)

        # -- Filter row
        filter_row = tk.Frame(p, bg=Colors.BG_VOID)
        filter_row.pack(fill='x', padx=10, pady=2)
        tk.Label(filter_row, text='Filter:', font=('Consolas', 9),
                 fg=Colors.TEXT_DIM, bg=Colors.BG_VOID).pack(side='left')
        self._svc_filter_var = tk.StringVar()
        self._svc_filter_var.trace_add('write', lambda *_: self._svc_apply_filter())
        tk.Entry(filter_row, textvariable=self._svc_filter_var,
                 font=('Consolas', 9), bg=Colors.GLASS_DARK, fg=Colors.TEXT_LIGHT,
                 insertbackground=Colors.TEXT_LIGHT, relief='flat', width=28
                 ).pack(side='left', padx=6)
        self._svc_show_all = tk.BooleanVar(value=False)
        tk.Checkbutton(filter_row, text='Show CLEAN services', variable=self._svc_show_all,
                       font=('Consolas', 9), fg=Colors.TEXT_DIM, bg=Colors.BG_VOID,
                       selectcolor=Colors.GLASS_PANEL, activebackground=Colors.BG_VOID,
                       relief='flat',
                       command=self._svc_apply_filter).pack(side='left', padx=8)

        # -- Button row
        btn_row = tk.Frame(p, bg=Colors.BG_VOID)
        btn_row.pack(fill='x', padx=10, pady=4)

        def _scan():
            if not _REMOTE_ACCESS_MODULE_AVAILABLE:
                messagebox.showerror('Module Missing',
                    'downpour_remote_access.py not found in Downpour folder.')
                return
            self._svc_status_lbl.config(text='\U0001f504 Scanning services...', fg=Colors.GAUGE_YELLOW)
            # FIX: removed p.update_idletasks() — crash risk inside tab builder
            def _run():
                # FIX-v28p19: Fully guarded scanner with fallbacks
                results = []
                try:
                    if hasattr(SmartServicesScanner, '__init__'):
                        scanner = SmartServicesScanner()
                        if hasattr(scanner, 'scan_all'):
                            results = scanner.scan_all() or []
                except Exception as _e:
                    logger.error(f'SmartServicesScanner: {_e}')
                self._svc_all_results = results
                # Build summary with counts by risk level
                counts = {}
                running_count = 0
                for r in results:
                    rl = getattr(r, 'risk_level', 'safe').upper()
                    if rl == 'SAFE':
                        rl = 'CLEAN'
                    counts[rl] = counts.get(rl, 0) + 1
                    if getattr(r, 'status', '').lower() == 'running':
                        running_count += 1
                summary = {
                    'total_services': len(results),
                    'counts': counts,
                    'running_count': running_count,
                }
                self.after(0, lambda: _populate(results, summary))
            import threading
            threading.Thread(target=_run, daemon=True).start()

        def _populate(results, summary):
            self._svc_full_results = results
            self._svc_apply_filter()
            c = summary['counts']
            status = (f"Total: {summary['total_services']}  |  "
                      f"\U0001f534 CRITICAL: {c.get('CRITICAL',0)}  "
                      f"\U0001f7e0 HIGH: {c.get('HIGH',0)}  "
                      f"\U0001f7e1 MEDIUM: {c.get('MEDIUM',0)}  "
                      f"\u2705 CLEAN: {c.get('CLEAN',0)}  "
                      f"\U0001f7e2 Running: {summary['running_count']}")
            color = Colors.GAUGE_RED if c.get('CRITICAL',0) > 0 else (
                    Colors.GAUGE_ORANGE if c.get('HIGH',0) > 0 else Colors.GAUGE_GREEN)
            self._svc_status_lbl.config(text=status, fg=color)

        def _disable_selected():
            sel = self._svc_tree.selection()
            if not sel:
                messagebox.showwarning('Select', 'Select a service first.')
                return
            iid = sel[0]
            vals = self._svc_tree.item(iid, 'values')
            svc_name = vals[0] if vals else ''
            if not svc_name:
                return
            if messagebox.askyesno('Disable Service',
                f'Stop and disable service: {svc_name}?\n\nThis may affect system functionality.'):
                if hasattr(SmartServicesScanner, 'disable_service'):
                    ok, msg = SmartServicesScanner.disable_service(svc_name)
                    messagebox.showinfo('Result', msg)
                else:
                    import subprocess
                    try:
                        subprocess.run(['sc', 'stop', svc_name],
                                       capture_output=True, timeout=15)
                        subprocess.run(['sc', 'config', svc_name, 'start=disabled'],
                                       capture_output=True, timeout=15)
                        messagebox.showinfo('Result', f'Service {svc_name} stopped and disabled.')
                    except Exception as e:
                        messagebox.showerror('Error', f'Failed to disable {svc_name}: {e}')
                _scan()

        def _show_details():
            sel = self._svc_tree.selection()
            if not sel:
                return
            iid = sel[0]
            # Find matching result
            if not hasattr(self, '_svc_full_results'):
                return
            _risk_scores = {'critical': 100, 'high': 75, 'medium': 50, 'low': 25, 'safe': 0}
            for r in self._svc_full_results:
                svc_name = getattr(r, 'service_name', getattr(r, 'name', ''))
                if svc_name == iid:
                    rl = getattr(r, 'risk_level', 'safe').lower()
                    indicators = getattr(r, 'indicators', getattr(r, 'findings', []))
                    detail = (
                        f'Service: {getattr(r, "display_name", "")} ({svc_name})\n'
                        f'Status: {getattr(r, "status", "")}  |  '
                        f'Startup: {getattr(r, "start_type", getattr(r, "startup_type", ""))}\n'
                        f'Binary: {getattr(r, "executable", getattr(r, "binary_path", ""))}\n'
                        f'Risk: {rl.upper()} (score {_risk_scores.get(rl, 0)}/100)\n'
                        f'Action: {getattr(r, "recommended_action", getattr(r, "action", "monitor"))}\n\n'
                        f'Findings:\n' + '\n'.join(f'  {f}' for f in indicators or ['None'])
                    )
                    messagebox.showinfo(f'Service Details: {svc_name}', detail)
                    return

        def _revert_changes():
            """Revert all changes made by Downpour v29 Titanium."""
            if messagebox.askyesno('Revert Changes', 
                'This will revert ALL changes made by Downpour v29 Titanium to system settings.\n\n'
                'This includes:\n'
                '- Windows Defender exclusions\n'
                '- Registry modifications\n'
                '- Service configuration changes\n'
                '- Firewall rule additions\n'
                '- Security policy modifications\n\n'
                '[!] This action cannot be undone!\n\n'
                'Are you sure you want to continue?'):
                try:
                    import winreg, subprocess, os
                    reverted_items = []
                    
                    # Revert Windows Defender exclusions
                    try:
                        cmd = 'Remove-MpPreference -ControlledFolderAccessDisabled -Force'
                        subprocess.run(['powershell', '-Command', cmd], capture_output=True, check=False, creationflags=_NO_WIN)
                        reverted_items.append('- Windows Defender exclusions removed')
                    except Exception as e:
                        reverted_items.append(f'- Windows Defender: {str(e)}')
                    
                    # Revert registry changes
                    registry_keys = [
                        r'SOFTWARE\Downpour\v26\Settings',
                        r'SOFTWARE\Downpour\v26\Security',
                        r'SOFTWARE\Downpour\v26\Performance',
                        r'SYSTEM\CurrentControlSet\Control\Downpour',
                    ]
                    
                    for key_path in registry_keys:
                        try:
                            winreg.DeleteKey(winreg.HKEY_LOCAL_MACHINE, key_path)
                            reverted_items.append(f'- Registry key: {key_path}')
                        except FileNotFoundError:
                            pass  # Key doesn't exist
                        except Exception as e:
                            reverted_items.append(f'- Registry {key_path}: {str(e)}')
                    
                    # Revert service changes (restart disabled services)
                    if hasattr(self, '_svc_full_results') and self._svc_full_results:
                        for service in self._svc_full_results:
                            if hasattr(service, 'original_state') and service.original_state != service.status:
                                try:
                                    if service.original_state == 'RUNNING':
                                        subprocess.run(['sc', 'start', service.name], capture_output=True, check=False, creationflags=_NO_WIN)
                                        reverted_items.append(f'- Service {service.name} restarted')
                                except Exception as e:
                                    reverted_items.append(f'- Service {service.name}: {str(e)}')
                    
                    # Clean up Downpour files
                    cleanup_paths = [
                        os.path.expandvars(r'%APPDATA%\Downpour\v26'),
                        os.path.expandvars(r'%LOCALAPPDATA%\Downpour\v26'),
                        r'C:\ProgramData\Downpour\v26',
                    ]
                    
                    for path in cleanup_paths:
                        try:
                            if os.path.exists(path):
                                import shutil
                                shutil.rmtree(path)
                                reverted_items.append(f'- Directory removed: {path}')
                        except Exception as e:
                            reverted_items.append(f'- Cleanup {path}: {str(e)}')
                    
                    # Show results
                    result_msg = "Revert Operation Complete\n\n"
                    result_msg += f"Successfully reverted {len([i for i in reverted_items if not '-' in i or ':' not in i])} items\n\n"
                    result_msg += "Details:\n" + "\n".join(reverted_items[:10])  # Show first 10 items
                    if len(reverted_items) > 10:
                        result_msg += f"\n... and {len(reverted_items) - 10} more items"
                    
                    messagebox.showinfo('Revert Complete', result_msg)
                    
                    # Recommend restart
                    messagebox.showinfo('Restart Required', 
                        'System restart recommended to complete revert process.\n\n'
                        'Some changes may not take effect until after restart.')
                    
                except Exception as e:
                    messagebox.showerror('Revert Failed', f'Failed to revert changes:\n{str(e)}')

        for text, cmd, color in [
            ('\U0001f504 Scan Services',    _scan,             Colors.GAUGE_BLUE),
            ('\u274c Disable Selected',     _disable_selected, Colors.GAUGE_RED),
            ('\U0001f50e Details',           _show_details,     Colors.GAUGE_TEAL),
            ('\U0001f519 Revert Changes',    _revert_changes,  Colors.GAUGE_ORANGE),
        ]:
            tk.Button(btn_row, text=text, font=('Consolas', 9, 'bold'), fg=color,
                bg=Colors.GLASS_CARD, relief='flat', padx=8,
                command=cmd).pack(side='left', padx=4)

        # -- Tree
        cols = ('Name', 'Display Name', 'Status', 'Risk', 'Score', 'Action', 'Findings')
        tree_frame = tk.Frame(p, bg=Colors.BG_VOID)
        tree_frame.pack(fill='both', expand=True, padx=8, pady=4)
        tree_frame.grid_rowconfigure(0, weight=1)
        tree_frame.grid_columnconfigure(0, weight=1)
        
        self._svc_tree = ttk.Treeview(tree_frame, style='Titan.Treeview',
            columns=cols, show='headings', selectmode='browse', height=18)
        widths = {'Name': 150, 'Display Name': 200, 'Status': 70,
                  'Risk': 80, 'Score': 55, 'Action': 90, 'Findings': 320}
        for col in cols:
            self._svc_tree.heading(col, text=col,
                command=lambda c=col: self._svc_sort_by(c))
            self._svc_tree.column(col, width=widths.get(col, 100),
                                   stretch=(col == 'Findings'))
        for tag, color in [
            ('CRITICAL', '#ff4444'), ('HIGH', Colors.GAUGE_ORANGE),
            ('MEDIUM', Colors.GAUGE_YELLOW), ('LOW', Colors.TEXT_DIM),
            ('CLEAN', Colors.GAUGE_GREEN),
        ]:
            self._svc_tree.tag_configure(tag, foreground=color)

        vsb = tk.Scrollbar(tree_frame, orient='vertical', command=self._svc_tree.yview)
        hsb = tk.Scrollbar(tree_frame, orient='horizontal', command=self._svc_tree.xview)
        self._svc_tree.configure(yscrollcommand=vsb.set, xscrollcommand=hsb.set)
        self._style_sb(vsb)
        self._style_sb(hsb)

        self._svc_tree.grid(row=0, column=0, sticky='nsew')
        vsb.grid(row=0, column=1, sticky='ns')
        hsb.grid(row=1, column=0, sticky='ew')

        self._svc_all_results = []
        self._svc_full_results = []
        self._svc_sort_col = 'Score'
        self._svc_sort_rev = True

        # FIX: guard with _ui_ready so this doesn't fire during _build_ui
        def _on_svc_tab_visible(e):
            if getattr(self, '_ui_ready', False) and not self._svc_all_results:
                self.after(300, _scan)
        p.bind('<Visibility>', _on_svc_tab_visible)
        
        # Also trigger scan on first tab selection
        def on_tab_changed(event=None):
            if not getattr(self, '_ui_ready', False):
                return
            if hasattr(self, '_notebook') and self._notebook.index(self._notebook.select()) == self._notebook.index(self._tab_services):
                if not self._svc_all_results:
                    self.after(100, _scan)
        
        if hasattr(self, '_notebook'):
            self._notebook.bind('<<NotebookTabChanged>>', on_tab_changed)

    def _svc_apply_filter(self):
        """Re-populate services tree using current filter text and show-all toggle."""
        if not hasattr(self, '_svc_full_results') or not self._svc_full_results:
            return
        ftext = self._svc_filter_var.get().lower()
        show_clean = self._svc_show_all.get()
        self._svc_tree.delete(*self._svc_tree.get_children())
        _risk_scores = {'critical': 100, 'high': 75, 'medium': 50, 'low': 25, 'safe': 0}
        for r in self._svc_full_results:
            rl = getattr(r, 'risk_level', 'safe').lower()
            if not show_clean and rl == 'safe':
                continue
            svc_name = getattr(r, 'service_name', getattr(r, 'name', ''))
            disp_name = getattr(r, 'display_name', '')
            if ftext and ftext not in svc_name.lower() and ftext not in disp_name.lower():
                continue
            indicators = getattr(r, 'indicators', getattr(r, 'findings', []))
            findings_str = ' | '.join(indicators[:2]) if indicators else ''
            score = _risk_scores.get(rl, 0)
            action = getattr(r, 'recommended_action', getattr(r, 'action', 'monitor'))
            self._svc_tree.insert('', 'end', iid=svc_name,
                values=(svc_name, disp_name, getattr(r, 'status', ''),
                        rl.upper(), str(score),
                        action, findings_str),
                tags=(rl.upper(),))

    def _svc_sort_by(self, col):
        """Sort services tree by column header click."""
        if not hasattr(self, '_svc_full_results'):
            return
        _risk_scores = {'critical': 100, 'high': 75, 'medium': 50, 'low': 25, 'safe': 0}

        def _key(r):
            if col == 'Name':
                return (getattr(r, 'service_name', None) or getattr(r, 'name', '') or '').lower()
            if col == 'Display Name':
                return (getattr(r, 'display_name', '') or '').lower()
            if col == 'Status':
                return (getattr(r, 'status', '') or '').lower()
            if col == 'Risk':
                return (getattr(r, 'risk_level', '') or '').lower()
            if col == 'Score':
                return _risk_scores.get(getattr(r, 'risk_level', 'safe').lower(), 0)
            if col == 'Action':
                return (getattr(r, 'recommended_action', None) or getattr(r, 'action', '') or '').lower()
            return ''

        rev = getattr(self, '_svc_sort_rev', True)
        if getattr(self, '_svc_sort_col', None) == col:
            self._svc_sort_rev = not rev
        else:
            self._svc_sort_col = col
            self._svc_sort_rev = True
        self._svc_full_results.sort(key=_key, reverse=self._svc_sort_rev)
        self._svc_apply_filter()


    # ═══════════════════════════════════════════════════════════════════════════
    #  TOOLTIP HELPER
    # ═══════════════════════════════════════════════════════════════════════════

    def _tooltip(self, widget, text: str) -> None:
        """Attach a simple hover tooltip to any widget."""
        import tkinter as tk

        tip_win: list = [None]

        def _enter(e):
            x = widget.winfo_rootx() + widget.winfo_width() // 2
            y = widget.winfo_rooty() + widget.winfo_height() + 4
            tw = tk.Toplevel(widget)
            tw.overrideredirect(True)
            tw.attributes('-topmost', True)
            tw.configure(bg=Colors.GLASS_DARK,
                         highlightbackground=Colors.GLASS_BORDER,
                         highlightthickness=1)
            tk.Label(tw, text=text, font=('Consolas', 8),
                     fg=Colors.TEXT_LIGHT, bg=Colors.GLASS_DARK,
                     padx=8, pady=4, wraplength=320,
                     justify='left').pack()
            tw.geometry(f'+{x}+{y}')
            tip_win[0] = tw

        def _leave(e):
            if tip_win[0]:
                try:
                    tip_win[0].destroy()
                except Exception:
                    pass
                tip_win[0] = None

        widget.bind('<Enter>', _enter)
        widget.bind('<Leave>', _leave)
        widget.bind('<ButtonPress>', _leave)

    # ═══════════════════════════════════════════════════════════════════════════
    #  TOAST NOTIFICATION SYSTEM
    # ═══════════════════════════════════════════════════════════════════════════

    _toast_queue: list = []
    _toast_active: int = 0
    _TOAST_MAX     = 4        # max simultaneous toasts
    _TOAST_MARGIN  = 8        # px from edge
    _TOAST_H       = 60       # height per toast
    _TOAST_W       = 360      # width

    # ═══════════════════════════════════════════════════════════════════════════
    #  TOAST NOTIFICATION SYSTEM
    # ═══════════════════════════════════════════════════════════════════════════

    def show_notification(self, title: str, message: str = '',
                          level: str = 'info', duration_ms: int = 4000):
        """
        Show a stacking toast notification in the bottom-right corner.
        level: 'info' | 'success' | 'warning' | 'error'
        """
        try:
            import tkinter as _tk
            colors = {
                'info':    ('#00e5ff', '#0d1a22'),
                'success': ('#00e676', '#0a1a0f'),
                'warning': ('#ff9800', '#1a1200'),
                'error':   ('#ff1744', '#1a0000'),
            }
            fg, bg = colors.get(level, colors['info'])
            icon_map = {'info': '[INFO]', 'success': '[OK]', 'warning': '[WARN]', 'error': '✖'}
            icon = icon_map.get(level, '[INFO]')

            toast = _tk.Toplevel(self)
            toast.overrideredirect(True)
            toast.attributes('-topmost', True)
            toast.attributes('-alpha', 0.0)
            toast.configure(bg=bg, highlightbackground=fg, highlightthickness=1)

            sw = self.winfo_screenwidth()
            sh = self.winfo_screenheight()
            x  = sw - self._TOAST_W - self._TOAST_MARGIN - 16
            y  = sh - 60 - (self._toast_active * (self._TOAST_H + 6)) - self._TOAST_MARGIN
            toast.geometry(f'{self._TOAST_W}x{self._TOAST_H}+{x}+{y}')

            inner = _tk.Frame(toast, bg=bg, padx=10, pady=8)
            inner.pack(fill='both', expand=True)
            hdr = _tk.Frame(inner, bg=bg)
            hdr.pack(fill='x')
            _tk.Label(hdr, text=f'{icon} {title}', font=('Consolas', 10, 'bold'),
                      fg=fg, bg=bg).pack(side='left')

            def _close(t=toast):
                try:
                    self._toast_active = max(0, self._toast_active - 1)
                    t.destroy()
                except Exception:
                    pass

            _tk.Button(hdr, text='✕', font=('Consolas', 8), fg=fg, bg=bg,
                       relief='flat', bd=0, cursor='hand2',
                       command=_close).pack(side='right')
            if message:
                msg = message[:80] + ('…' if len(message) > 80 else '')
                _tk.Label(inner, text=msg, font=('Consolas', 8),
                          fg='#cccccc', bg=bg, wraplength=self._TOAST_W - 30,
                          justify='left').pack(anchor='w')

            self._toast_active = min(self._toast_active + 1, self._TOAST_MAX)
            toast.after(duration_ms, _close)

            def _fade(alpha=0.0):
                if not toast.winfo_exists():
                    return
                alpha = min(0.95, alpha + 0.15)
                toast.attributes('-alpha', alpha)
                if alpha < 0.95:
                    toast.after(16, lambda: _fade(alpha))
            toast.after(10, _fade)

        except Exception:
            pass

    # ═══════════════════════════════════════════════════════════════════════════
    #  CLEANUP CENTER TAB  (5 sub-tabs)
    # ═══════════════════════════════════════════════════════════════════════════

    def _build_cleanup_tab(self):
        """🧹 Cleanup Center — 5 engines, all preview-first."""
        import tkinter as tk
        from tkinter import ttk

        p = self._tab_cleanup
        p.grid_rowconfigure(1, weight=1)
        p.grid_columnconfigure(0, weight=1)

        # ── Header bar ────────────────────────────────────────────────────────
        hdr = tk.Frame(p, bg=Colors.BG_VOID)
        hdr.grid(row=0, column=0, sticky='ew', padx=8, pady=(6, 2))
        tk.Label(hdr, text='CLEANUP CENTER',
                 font=('Consolas', 12, 'bold'), fg=Colors.GAUGE_TEAL,
                 bg=Colors.BG_VOID).pack(side='left')
        tk.Label(hdr,
                 text='All operations show a full preview before any deletion.  '
                      'Irreversible actions require explicit confirmation.',
                 font=('Consolas', 8), fg=Colors.TEXT_DIM,
                 bg=Colors.BG_VOID).pack(side='left', padx=12)

        # ── Sub-notebook ──────────────────────────────────────────────────────
        style = ttk.Style()
        style.configure('Cleanup.TNotebook', background=Colors.BG_VOID, borderwidth=0)
        style.configure('Cleanup.TNotebook.Tab',
                        font=('Consolas', 9, 'bold'),
                        background=Colors.GLASS_CARD, foreground=Colors.TEXT_DIM,
                        padding=[12, 5])
        style.map('Cleanup.TNotebook.Tab',
                  background=[('selected', Colors.GLASS_LIGHT)],
                  foreground=[('selected', Colors.GAUGE_TEAL)])

        sub_nb = ttk.Notebook(p, style='Cleanup.TNotebook')
        sub_nb.grid(row=1, column=0, sticky='nsew', padx=6, pady=4)

        # Create sub-tab frames
        def _frame():
            return tk.Frame(sub_nb, bg=Colors.BG_VOID)

        cache_f   = _frame(); sub_nb.add(cache_f,   text='Cache & Temp')
        dupe_f    = _frame(); sub_nb.add(dupe_f,    text='🔍  Duplicates')
        large_f   = _frame(); sub_nb.add(large_f,   text='📏  Large Files')
        empty_f   = _frame(); sub_nb.add(empty_f,   text='📁  Empty Folders')
        startup_f = _frame(); sub_nb.add(startup_f, text='🚀  Startup Items')
        disk_f    = _frame(); sub_nb.add(disk_f,    text='💾  Disk Usage')
        sec_f     = _frame(); sub_nb.add(sec_f,     text='[SHIELD]  Security Cleanup')

        # FIX-v28p13: Build only first tab, defer rest to reduce 15s block
        self._cleanup_build_cache_tab(cache_f)
        self.after(500, lambda: self._cleanup_build_dupe_tab(dupe_f))
        self.after(1000, lambda: self._cleanup_build_large_tab(large_f))
        self.after(1500, lambda: self._cleanup_build_empty_tab(empty_f))
        self.after(2000, lambda: self._cleanup_build_startup_tab(startup_f))
        self.after(2500, lambda: self._cleanup_build_disk_tab(disk_f))
        self.after(3000, lambda: self._cleanup_build_security_tab(sec_f))

    # ─────────────────────────────────────────────────────────────────────────
    #  SUB-TAB 1 — CACHE & TEMP CLEANER
    # ─────────────────────────────────────────────────────────────────────────

    def _cleanup_build_cache_tab(self, parent):
        import tkinter as tk
        from tkinter import ttk, messagebox

        C = Colors  # alias

        parent.grid_rowconfigure(3, weight=1)
        parent.grid_columnconfigure(0, weight=1)

        # ── Stats bar ─────────────────────────────────────────────────────────
        stats = tk.Frame(parent, bg=C.GLASS_CARD, pady=5)
        stats.grid(row=0, column=0, sticky='ew', padx=8, pady=(4, 0))

        self._cu_total_size_var  = tk.StringVar(value='—')
        self._cu_total_files_var = tk.StringVar(value='—')
        self._cu_freed_var       = tk.StringVar(value='—')
        self._cu_status_var      = tk.StringVar(value='Ready — click Scan to begin')

        for lbl, var, color in [
            ('Found:',  self._cu_total_size_var,  C.GAUGE_TEAL),
            ('📄 Files:',  self._cu_total_files_var, C.GAUGE_YELLOW),
            ('[OK] Freed:',  self._cu_freed_var,       C.GAUGE_GREEN),
        ]:
            cell = tk.Frame(stats, bg=C.GLASS_CARD, padx=14)
            cell.pack(side='left')
            tk.Label(cell, text=lbl,  font=('Consolas', 8),
                     fg=C.TEXT_DIM,  bg=C.GLASS_CARD).pack(side='left')
            tk.Label(cell, textvariable=var, font=('Consolas', 10, 'bold'),
                     fg=color, bg=C.GLASS_CARD).pack(side='left', padx=3)

        tk.Label(stats, textvariable=self._cu_status_var, font=('Consolas', 8),
                 fg=C.TEXT_DIM, bg=C.GLASS_CARD).pack(side='right', padx=12)

        # ── Button row ────────────────────────────────────────────────────────
        btn_row = tk.Frame(parent, bg=C.BG_VOID)
        btn_row.grid(row=1, column=0, sticky='ew', padx=8, pady=4)

        def _btn(txt, cmd, col, tip=None):
            b = tk.Button(btn_row, text=txt, font=('Consolas', 9, 'bold'),
                          fg=col, bg=C.GLASS_CARD, relief='flat', padx=10, pady=4,
                          cursor='hand2', activebackground=C.GLASS_LIGHT,
                          activeforeground=col, command=cmd)
            b.pack(side='left', padx=3)
            if tip:
                self._tooltip(b, tip)
            return b

        self._cu_scan_btn  = _btn('🔍 Scan ALL Categories', self._cleanup_do_scan,
                                  C.GAUGE_TEAL,
                                  'Scan ALL categories across all drives — checkboxes control what gets cleaned, not what gets scanned')
        self._cu_clean_btn = _btn('🧹 Clean Selected', self._cleanup_do_clean,
                                  C.GAUGE_GREEN,
                                  'Delete items in CHECKED categories only')
        self._cu_clean_btn.config(state='disabled')
        self._cu_clean_all_btn = _btn('🗑 CLEAN ALL FOUND', self._cleanup_clean_all_found,
                                  C.GAUGE_RED,
                                  'Clean EVERYTHING found in the last scan — ignores checkboxes')
        self._cu_clean_all_btn.config(state='disabled')
        _btn('☑ All', lambda: self._cleanup_check_all(True),
             C.GAUGE_YELLOW, 'Select all categories')
        _btn('☐ None', lambda: self._cleanup_check_all(False),
             C.TEXT_DIM, 'Deselect all categories')
        _btn('📋 Export Report', self._cleanup_export_report,
             C.GAUGE_ORANGE, 'Save scan results as a text report')

        # Progress bar
        self._cu_progress = ttk.Progressbar(parent, mode='determinate',
                                             style='TProgressbar')
        self._cu_progress.grid(row=2, column=0, sticky='ew', padx=8, pady=(0, 0))
        self._cu_progress.grid_remove()   # hidden until scan runs

        # ── Main pane: left = categories, right = result tree ─────────────────
        pane = tk.PanedWindow(parent, orient='horizontal',
                              bg=C.BG_VOID, sashwidth=5, sashrelief='flat')
        pane.grid(row=3, column=0, sticky='nsew', padx=8, pady=4)

        # LEFT PANEL: scrollable category list
        cat_outer = tk.Frame(pane, bg=C.GLASS_PANEL, width=250)
        cat_outer.pack_propagate(False)
        pane.add(cat_outer, minsize=210)

        tk.Label(cat_outer, text='CATEGORIES TO CLEAN',
                 font=('Consolas', 8, 'bold'),
                 fg=C.GAUGE_TEAL, bg=C.GLASS_PANEL, pady=2).pack(anchor='w', padx=8)
        tk.Label(cat_outer,
                 text='[OK] = include when cleaning\n(scan always finds everything)',
                 font=('Consolas', 7), fg=C.TEXT_DIM,
                 bg=C.GLASS_PANEL, justify='left').pack(anchor='w', padx=8, pady=(0, 4))

        cat_canvas = tk.Canvas(cat_outer, bg=C.GLASS_PANEL, bd=0,
                               highlightthickness=0)
        cat_vsb = ttk.Scrollbar(cat_outer, orient='vertical',
                                command=cat_canvas.yview,
                                style='Vertical.TScrollbar')
        cat_canvas.configure(yscrollcommand=cat_vsb.set)
        cat_vsb.pack(side='right', fill='y')
        cat_canvas.pack(side='left', fill='both', expand=True)
        cat_inner = tk.Frame(cat_canvas, bg=C.GLASS_PANEL)
        cat_win_id = cat_canvas.create_window((0, 0), window=cat_inner, anchor='nw')

        def _on_cat_configure(e):
            cat_canvas.configure(scrollregion=cat_canvas.bbox('all'))
            cat_canvas.itemconfig(cat_win_id, width=cat_canvas.winfo_width())
        cat_inner.bind('<Configure>', _on_cat_configure)
        cat_canvas.bind('<Configure>',
                        lambda e: cat_canvas.itemconfig(cat_win_id,
                                                        width=e.width))
        cat_canvas.bind('<MouseWheel>',
                        lambda e: cat_canvas.yview_scroll(
                            -1 if e.delta > 0 else 1, 'units'))

        # Populate categories
        self._cleanup_check_vars   = {}
        self._cleanup_targets_ui   = {}   # key → (size_label, count_label)
        self._cleanup_selected_key = None

        if not _CLEANUP_MODULE_AVAILABLE or not hasattr(self, 'cleanup_engine'):
            tk.Label(cat_inner,
                     text='[WARN] downpour_cleanup_module.py\nnot found.',
                     font=('Consolas', 8), fg=Colors.GAUGE_RED,
                     bg=C.GLASS_PANEL, wraplength=220).pack(padx=8, pady=8)
        else:
            for target in self.cleanup_engine.targets:
                row = tk.Frame(cat_inner, bg=C.GLASS_PANEL, pady=2)
                row.pack(fill='x', padx=4)

                var = tk.BooleanVar(value=target.enabled)
                self._cleanup_check_vars[target.key] = var

                # Determine risk color
                risk_col = C.TEXT_LIGHT
                if hasattr(target, 'risk_level'):
                    from downpour_cleanup_module import RiskLevel
                    if target.risk_level == RiskLevel.CRITICAL:
                        risk_col = C.GAUGE_RED
                    elif target.risk_level == RiskLevel.HIGH:
                        risk_col = C.GAUGE_ORANGE
                    elif target.risk_level == RiskLevel.MODERATE:
                        risk_col = C.GAUGE_YELLOW
                elif not getattr(target, 'safe', True):
                    risk_col = C.GAUGE_YELLOW

                chk = tk.Checkbutton(
                    row, text=f'{target.icon} {target.label}',
                    variable=var, font=('Consolas', 8, 'bold'),
                    fg=risk_col, bg=C.GLASS_PANEL,
                    selectcolor=C.GLASS_DARK,
                    activebackground=C.GLASS_LIGHT,
                    activeforeground=risk_col,
                    relief='flat', anchor='w',
                    command=lambda k=target.key: self._cleanup_on_cat_click(k))
                chk.pack(side='left', fill='x', expand=True)

                # Risk badge
                if hasattr(target, 'risk_level'):
                    from downpour_cleanup_module import RiskLevel
                    if target.risk_level in (RiskLevel.HIGH, RiskLevel.CRITICAL):
                        badge_txt = '[WARN]' if target.risk_level == RiskLevel.HIGH else '[CRITICAL]'
                        tk.Label(row, text=badge_txt, font=('Consolas', 9),
                                 fg=risk_col, bg=C.GLASS_PANEL).pack(side='right', padx=2)

                size_lbl = tk.Label(row, text='', font=('Consolas', 7),
                                    fg=C.GAUGE_TEAL, bg=C.GLASS_PANEL, width=8, anchor='e')
                size_lbl.pack(side='right', padx=2)
                cnt_lbl  = tk.Label(row, text='', font=('Consolas', 7),
                                    fg=C.TEXT_DIM, bg=C.GLASS_PANEL, width=8, anchor='e')
                cnt_lbl.pack(side='right', padx=2)
                self._cleanup_targets_ui[target.key] = (size_lbl, cnt_lbl)

        # DESCRIPTION PANEL at bottom of left panel
        desc_frame = tk.Frame(cat_outer, bg=C.GLASS_DARK, height=80)
        desc_frame.pack(fill='x', padx=4, pady=4)
        desc_frame.pack_propagate(False)
        tk.Label(desc_frame, text='DESCRIPTION', font=('Consolas', 7, 'bold'),
                 fg=C.TEXT_DIM, bg=C.GLASS_DARK).pack(anchor='w', padx=6, pady=(3, 0))
        self._cu_desc_lbl = tk.Label(desc_frame, text='Hover or click a category to see details.',
                                     font=('Consolas', 7), fg=C.TEXT_LIGHT,
                                     bg=C.GLASS_DARK, wraplength=220,
                                     justify='left', anchor='nw')
        self._cu_desc_lbl.pack(fill='both', expand=True, padx=6, pady=2)

        # RIGHT PANEL: results tree
        right = tk.Frame(pane, bg=C.BG_VOID)
        pane.add(right, minsize=360)
        right.grid_rowconfigure(0, weight=1)
        right.grid_columnconfigure(0, weight=1)

        cols = ('Category', 'Size', 'Files', 'Status')
        self._cu_tree = ttk.Treeview(right, style='Titan.Treeview',
                                     columns=cols, show='headings',
                                     selectmode='browse')
        widths = {'Category': 200, 'Size': 90, 'Files': 80, 'Status': 100}
        for col in cols:
            self._cu_tree.heading(col, text=col,
                                  command=lambda c=col: self._cleanup_sort(c))
            self._cu_tree.column(col, width=widths[col],
                                 minwidth=50, stretch=(col == 'Category'))

        self._cu_tree.tag_configure('zero',     foreground=C.TEXT_DIM)
        self._cu_tree.tag_configure('safe',     foreground=C.GAUGE_GREEN)
        self._cu_tree.tag_configure('moderate', foreground=C.GAUGE_YELLOW)
        self._cu_tree.tag_configure('high',     foreground=C.GAUGE_ORANGE)
        self._cu_tree.tag_configure('critical', foreground=C.GAUGE_RED)

        vsb = ttk.Scrollbar(right, orient='vertical', command=self._cu_tree.yview,
                            style='Vertical.TScrollbar')
        self._cu_tree.configure(yscrollcommand=vsb.set)
        self._cu_tree.grid(row=0, column=0, sticky='nsew')
        vsb.grid(row=0, column=1, sticky='ns')
        self._cu_tree.bind('<<TreeviewSelect>>', self._cleanup_on_select)

    def _cleanup_on_cat_click(self, key: str):
        """Update description panel when a category checkbox is clicked."""
        if not _CLEANUP_MODULE_AVAILABLE or not hasattr(self, 'cleanup_engine'):
            return
        target = self.cleanup_engine.get_target(key)
        if target and hasattr(self, '_cu_desc_lbl'):
            self._cu_desc_lbl.config(text=target.description)

    def _cleanup_do_scan(self):
        import threading
        if not _CLEANUP_MODULE_AVAILABLE or not hasattr(self, 'cleanup_engine'):
            import tkinter.messagebox as mb
            mb.showerror('Module Missing',
                         'downpour_cleanup_module.py not found in the Downpour folder.\n'
                         'Place it next to downpour_v28_titanium.py and restart.')
            return
        
        # Safety check - ensure cleanup vars are initialized
        if not hasattr(self, '_cleanup_check_vars') or not self._cleanup_check_vars:
            import tkinter.messagebox as mb
            mb.showerror('Cleanup Error', 'Cleanup module not properly initialized. Please restart the application.')
            return
        
        # Log enhanced metrics if available
        if ENHANCED_LOGGING_AVAILABLE:
            try:
                from enhanced_logging import EnhancedLogger
                enhanced_logger.log_ui_response('cleanup_scan_start', 100)
            except Exception:
                pass
        
        # Always scan ALL categories — checkboxes only control what gets cleaned
        all_keys = [t.key for t in self.cleanup_engine.targets]

        self._cu_scan_btn.config(state='disabled', text='⏳ Scanning…')
        self._cu_clean_btn.config(state='disabled')
        self._cu_clean_all_btn.config(state='disabled')
        self._cu_status_var.set('Scanning all categories across all drives…')
        self._cu_progress.grid()
        self._cu_progress.configure(value=0)

        def _prog(msg, pct):
            self.after(0, lambda m=msg: self._cu_status_var.set(m))
            self.after(0, lambda p=pct: self._cu_progress.configure(value=p))

        def _run():
            results = self.cleanup_engine.scan(
                keys=all_keys, progress_cb=_prog, all_drives=True)
            self.after(0, lambda: self._cleanup_scan_done(results))

        threading.Thread(target=_run, daemon=True).start()

    def _cleanup_render_results(self, results: dict):
        from downpour_cleanup_module import size_fmt, RiskLevel

        for row in self._cu_tree.get_children():
            self._cu_tree.delete(row)

        total_sz = total_fc = 0
        for key, target in results.items():
            sz_str = size_fmt(target.scanned_size)
            cnt_str = str(target.item_count)

            if target.item_count == 0:
                tag = 'zero'
            elif hasattr(target, 'risk_level'):
                if target.risk_level == RiskLevel.CRITICAL:
                    tag = 'critical'
                elif target.risk_level == RiskLevel.HIGH:
                    tag = 'high'
                elif target.risk_level == RiskLevel.MODERATE:
                    tag = 'moderate'
                else:
                    tag = 'safe'
            else:
                tag = 'safe' if getattr(target, 'safe', True) else 'moderate'

            self._cu_tree.insert('', 'end', iid=key,
                values=(f'{target.icon} {target.label}',
                        sz_str, cnt_str,
                        '— empty' if target.item_count == 0
                        else f'🗑 {cnt_str} items'),
                tags=(tag,))

            if key in self._cleanup_targets_ui:
                sl, cl = self._cleanup_targets_ui[key]
                sl.config(text=sz_str if target.item_count else '')
                cl.config(text=f'{target.item_count:,}' if target.item_count else '')

            total_sz += target.scanned_size
            total_fc += target.item_count

        self._cu_total_size_var.set(size_fmt(total_sz))
        self._cu_total_files_var.set(f'{total_fc:,}')
        self._cu_scan_btn.config(state='normal', text='🔍 Scan ALL Categories')
        self._cu_progress.grid_remove()

        checked_items = 0
        if hasattr(self, '_cleanup_check_vars') and hasattr(self, 'cleanup_engine'):
            checked_items = sum(
                t.item_count for t in self.cleanup_engine.targets
                if self._cleanup_check_vars.get(t.key) and self._cleanup_check_vars[t.key].get()
            )
        self._cu_clean_btn.config(
            state='normal' if checked_items > 0 else 'disabled',
            text='🧹 Clean Selected')
        self._cu_clean_all_btn.config(
            state='normal' if total_fc > 0 else 'disabled',
            text='🗑 CLEAN ALL FOUND')
        return total_sz, total_fc

    def _cleanup_scan_done(self, results: dict):
        from downpour_cleanup_module import size_fmt

        total_sz, total_fc = self._cleanup_render_results(results)
        self._cu_status_var.set(
            f'Scan complete — {size_fmt(total_sz)} found in {total_fc:,} files')

        self.show_notification(
            'Scan Complete',
            f'Found {size_fmt(total_sz)} in {total_fc:,} files',
            'success' if total_sz > 0 else 'info')

    def _cleanup_do_clean(self):
        """Clean selected categories — with tiered risk confirmation."""
        import tkinter.messagebox as mb
        import threading
        from downpour_cleanup_module import size_fmt, RiskLevel

        if not _CLEANUP_MODULE_AVAILABLE or not hasattr(self, 'cleanup_engine'):
            mb.showerror('Module Missing', 'Cleanup module not available.')
            return

        # Safety check - ensure cleanup vars are initialized
        if not hasattr(self, '_cleanup_check_vars') or not self._cleanup_check_vars:
            mb.showerror('Cleanup Error', 'Cleanup module not properly initialized. Please restart the application.')
            return

        checked = [k for k, v in self._cleanup_check_vars.items() if v.get()]
        targets  = [t for t in self.cleanup_engine.targets
                    if t.key in checked and t.item_count > 0]
        if not targets:
            mb.showwarning('Nothing to Clean',
                           'No cleanable items found.\n'
                           'Run a scan first, or check more categories.')
            return

        total_sz = sum(t.scanned_size for t in targets)
        total_fc = sum(t.item_count   for t in targets)

        # ── Determine highest risk level across all selected targets ──────────
        from downpour_cleanup_module import RiskLevel
        max_risk = RiskLevel.SAFE
        risk_order = [RiskLevel.SAFE, RiskLevel.MODERATE,
                      RiskLevel.HIGH, RiskLevel.CRITICAL]
        for t in targets:
            r = getattr(t, 'risk_level', RiskLevel.SAFE)
            if risk_order.index(r) > risk_order.index(max_risk):
                max_risk = r

        # Gather risk notes from included targets
        risk_notes = [t.risk_note for t in targets if getattr(t, 'risk_note', '')]
        confirm_msgs = [t.confirm_msg for t in targets
                        if getattr(t, 'confirm_msg', '')]

        cat_list = '\n'.join(f'  • {t.icon} {t.label} ({size_fmt(t.scanned_size)}, '
                             f'{t.item_count:,} files)'
                             for t in targets[:20])
        if len(targets) > 20:
            cat_list += f'\n  …and {len(targets)-20} more categories'

        # ── SAFE / MODERATE: standard messagebox ─────────────────────────────
        if max_risk in (RiskLevel.SAFE, RiskLevel.MODERATE):
            extra = ('\n\n[WARN]  IMPORTANT:\n' +
                     '\n'.join(f'  • {n}' for n in risk_notes)
                     ) if risk_notes else ''
            confirm_extra = ('\n\n' + '\n'.join(confirm_msgs)) if confirm_msgs else ''
            msg = (f'You are about to permanently delete:\n\n'
                   f'{cat_list}\n\n'
                   f'Total: {size_fmt(total_sz)}  ({total_fc:,} files)\n'
                   f'{extra}{confirm_extra}\n\n'
                   f'This cannot be undone. Continue?')
            if not mb.askyesno('Confirm Cleanup', msg,
                               icon='warning' if max_risk == RiskLevel.MODERATE
                               else 'question'):
                return

        # ── HIGH: orange warning — show every target + extra confirmation ─────
        elif max_risk == RiskLevel.HIGH:
            warn_list = '\n'.join(f'  [WARN]  {t.risk_note}' for t in targets
                                  if getattr(t, 'risk_note', ''))
            msg = (f'[WARN]  WARNING — HIGH-RISK OPERATION\n\n'
                   f'The following will be permanently deleted:\n\n'
                   f'{cat_list}\n\n'
                   f'Total: {size_fmt(total_sz)}  ({total_fc:,} files)\n\n'
                   f'RISKS:\n{warn_list}\n\n'
                   f'These files CANNOT be recovered once deleted.\n'
                   f'Are you absolutely sure you want to continue?')
            if not mb.askyesno('HIGH-RISK Cleanup', msg, icon='warning'):
                return
            # Second confirmation for HIGH
            if not mb.askyesno('Confirm Again',
                               f'Second confirmation required.\n\n'
                               f'Delete {size_fmt(total_sz)} permanently?',
                               icon='warning'):
                return

        # ── CRITICAL: red two-step ────────────────────────────────────────────
        elif max_risk == RiskLevel.CRITICAL:
            crit_targets = [t for t in targets
                            if getattr(t, 'risk_level', None) == RiskLevel.CRITICAL]
            crit_notes = '\n'.join(f'  [CRITICAL]  {t.risk_note}' for t in crit_targets
                                   if getattr(t, 'risk_note', ''))
            crit_confirms = '\n'.join(getattr(t, 'confirm_msg', '') for t in crit_targets
                                      if getattr(t, 'confirm_msg', ''))
            msg = (f'CRITICAL WARNING\n\n'
                   f'You are about to perform an IRREVERSIBLE operation:\n\n'
                   f'{cat_list}\n\n'
                   f'CRITICAL RISKS:\n{crit_notes}\n\n'
                   f'{crit_confirms}\n\n'
                   f'Total: {size_fmt(total_sz)}  ({total_fc:,} files)\n\n'
                   f'THIS CANNOT BE UNDONE UNDER ANY CIRCUMSTANCES.\n'
                   f'Do you understand and wish to continue?')
            if not mb.askyesno('CRITICAL WARNING', msg, icon='warning'):
                return
            # Type-to-confirm for CRITICAL operations
            import tkinter as tk
            import tkinter.simpledialog as sd
            answer = sd.askstring(
                'Final Confirmation',
                'Type  DELETE  (all caps) to confirm this irreversible operation:',
                parent=self)
            if answer != 'DELETE':
                mb.showinfo('Cancelled',
                            'Operation cancelled — confirmation text did not match.')
                return

        # ── Execute in background ─────────────────────────────────────────────
        keys = [t.key for t in targets]
        self._cu_clean_btn.config(state='disabled', text='⏳ Cleaning…')
        self._cu_clean_all_btn.config(state='disabled')
        self._cu_scan_btn.config(state='disabled')
        self._cu_progress.grid()
        self._cu_progress.configure(value=0)

        def _prog(msg, pct):
            self.after(0, lambda m=msg: self._cu_status_var.set(m))
            self.after(0, lambda p=pct: self._cu_progress.configure(value=p))

        def _run():
            report = self.cleanup_engine.execute_cleanup(
                keys=keys, progress_cb=_prog, flush_dns=True)
            self.after(0, lambda: self._cleanup_clean_done(report))

        threading.Thread(target=_run, daemon=True).start()

    def _cleanup_clean_done(self, report):
        from downpour_cleanup_module import size_fmt
        self._cu_freed_var.set(size_fmt(report.bytes_freed))

        msg = (f'Freed: {size_fmt(report.bytes_freed)}\n'
               f'Files deleted: {report.files_deleted:,}\n'
               f'Dirs deleted: {report.dirs_deleted:,}\n'
               f'Locked/skipped: {report.skipped:,}\n'
               f'Duration: {report.duration_s:.1f}s')
        if report.errors:
            msg += f'\n\n{len(report.errors)} error(s) — run Export Report for details.'

        remaining_results = {t.key: t for t in self.cleanup_engine.targets}
        remaining_sz, remaining_fc = self._cleanup_render_results(remaining_results)
        if remaining_fc > 0:
            self._cu_status_var.set(
                f'Done — freed {size_fmt(report.bytes_freed)} in {report.duration_s:.1f}s; '
                f'{size_fmt(remaining_sz)} remains in {remaining_fc:,} files')
        else:
            self._cu_status_var.set(
                f'Done — freed {size_fmt(report.bytes_freed)} in {report.duration_s:.1f}s')
        self.show_notification('Cleanup Complete',
                               f'Freed {size_fmt(report.bytes_freed)}',
                               'success')

        import tkinter.messagebox as mb
        mb.showinfo('Cleanup Complete', msg)

    def _cleanup_clean_all_found(self):
        """Clean EVERYTHING found in the last scan, regardless of checkbox state."""
        import tkinter.messagebox as mb
        from downpour_cleanup_module import size_fmt
        if not _CLEANUP_MODULE_AVAILABLE or not hasattr(self, 'cleanup_engine'):
            mb.showerror('Module Missing', 'Cleanup module not available.')
            return
        # All targets that actually have items from the scan
        targets = [t for t in self.cleanup_engine.targets if t.item_count > 0]
        if not targets:
            mb.showwarning('Nothing to Clean',
                           'No items found. Run "Scan All Drives" first.')
            return
        total_sz = sum(t.scanned_size for t in targets)
        total_fc = sum(t.item_count   for t in targets)
        cat_list = '\n'.join(
            f'  • {t.icon} {t.label} — {size_fmt(t.scanned_size)} ({t.item_count:,} files)'
            for t in targets[:25])
        if len(targets) > 25:
            cat_list += f'\n  …and {len(targets)-25} more'
        if not mb.askyesno(
                '🗑 Clean ALL Found Items',
                f'You are about to permanently delete ALL scanned items:\n\n'
                f'{cat_list}\n\n'
                f'Total: {size_fmt(total_sz)}  ({total_fc:,} files)\n\n'
                f'This CANNOT be undone. Continue?',
                icon='warning'):
            return

        # Directly run the engine — no second dialog
        import threading
        keys = [t.key for t in targets]
        self._cu_clean_btn.config(state='disabled')
        self._cu_clean_all_btn.config(state='disabled', text='⏳ Cleaning…')
        self._cu_scan_btn.config(state='disabled')
        self._cu_progress.grid()
        self._cu_progress.configure(value=0)

        def _prog(msg, pct):
            self.after(0, lambda m=msg: self._cu_status_var.set(m))
            self.after(0, lambda p=pct: self._cu_progress.configure(value=p))

        def _run():
            report = self.cleanup_engine.execute_cleanup(
                keys=keys, progress_cb=_prog, flush_dns=True)
            self.after(0, lambda: self._cleanup_clean_done(report))

        threading.Thread(target=_run, daemon=True).start()

    def _cleanup_check_all(self, state: bool):
        # Safety check - ensure cleanup vars are initialized
        if not hasattr(self, '_cleanup_check_vars') or not self._cleanup_check_vars:
            return
        for var in self._cleanup_check_vars.values():
            var.set(state)

    def _cleanup_on_select(self, event):
        """Update description panel when tree row is selected."""
        sel = self._cu_tree.selection()
        if not sel or not _CLEANUP_MODULE_AVAILABLE:
            return
        key = sel[0]
        if not hasattr(self, 'cleanup_engine'):
            return
        target = self.cleanup_engine.get_target(key)
        if target and hasattr(self, '_cu_desc_lbl'):
            self._cu_desc_lbl.config(text=target.description)

    @staticmethod
    def _parse_size_bytes(s: str) -> float:
        """Convert formatted size string ('1.4 MB', '450 KB', etc.) to bytes for sorting."""
        try:
            parts = s.strip().split()
            if not parts:
                return 0.0
            val = float(parts[0].replace(',', ''))
            unit = parts[1].upper() if len(parts) > 1 else 'B'
            mult = {'B': 1, 'KB': 1024, 'MB': 1_048_576,
                    'GB': 1_073_741_824, 'TB': 1_099_511_627_776}
            return val * mult.get(unit, 1)
        except Exception:
            return 0.0

    def _cleanup_sort(self, col: str):
        if not hasattr(self, '_cu_sort_dirs'):
            self._cu_sort_dirs: dict = {}
        rev = self._cu_sort_dirs.get(col, False)
        items = [(self._cu_tree.set(k, col), k)
                 for k in self._cu_tree.get_children('')]
        if col == 'Size':
            items.sort(key=lambda x: self._parse_size_bytes(x[0]), reverse=rev)
        elif col == 'Files':
            items.sort(key=lambda x: int(x[0].replace(',', '') or '0'), reverse=rev)
        else:
            items.sort(key=lambda x: x[0].lower(), reverse=rev)
        for idx, (_, k) in enumerate(items):
            self._cu_tree.move(k, '', idx)
        self._cu_sort_dirs[col] = not rev

    def _cleanup_export_report(self):
        from tkinter import filedialog
        from downpour_cleanup_module import size_fmt
        import datetime

        if not _CLEANUP_MODULE_AVAILABLE or not hasattr(self, 'cleanup_engine'):
            return

        path = filedialog.asksaveasfilename(
            defaultextension='.txt',
            filetypes=[('Text files', '*.txt'), ('All files', '*.*')],
            initialfile=f'downpour_cleanup_{datetime.date.today()}.txt',
            title='Save Cleanup Report')
        if not path:
            return

        lines = [
            '=' * 72,
            'DOWNPOUR CLEANUP REPORT',
            f'Generated: {datetime.datetime.now():%Y-%m-%d %H:%M:%S}',
            '=' * 72, '',
        ]
        total_sz = total_fc = 0
        for target in self.cleanup_engine.targets:
            if target.item_count == 0:
                continue
            lines.append(f'{target.icon}  {target.label}')
            lines.append(f'   Size   : {size_fmt(target.scanned_size)}')
            lines.append(f'   Files  : {target.item_count:,}')
            if getattr(target, 'risk_note', ''):
                lines.append(f'   [WARN] Risk : {target.risk_note}')
            for item in target.items[:10]:
                lines.append(f'   {item.path}  ({size_fmt(item.size_bytes)})')
            if len(target.items) > 10:
                lines.append(f'   …and {len(target.items)-10} more files')
            lines.append('')
            total_sz += target.scanned_size
            total_fc += target.item_count

        lines += [
            '-' * 72,
            f'TOTAL FOUND: {size_fmt(total_sz)}  ({total_fc:,} files)',
            '=' * 72,
        ]

        try:
            with open(path, 'w', encoding='utf-8') as f:
                f.write('\n'.join(lines))
            self.show_notification('Report Saved',
                                   f'Saved to {path}', 'success')
        except OSError as e:
            import tkinter.messagebox as mb
            mb.showerror('Save Failed', str(e))

