    def _da_do_analyze(self):
        import threading
        if not _CLEANUP_MODULE_AVAILABLE:
            import tkinter.messagebox as mb
            mb.showerror('Module Missing', 'Cleanup module not available.')
            return

        root = self._da_path_var.get().strip()
        if not os.path.isdir(root):
            import tkinter.messagebox as mb
            mb.showerror('Invalid Path', f'Not a valid directory:\n{root}')
            return

        from downpour_cleanup_module import DiskAnalyzer, _get_all_drives
        self._da_analyze_btn.config(state='disabled', text='⏳ Analyzing…')
        self._da_status_var.set('Analyzing…')
        for row in self._da_tree.get_children():
            self._da_tree.delete(row)

        analyzer = DiskAnalyzer()

        def _prog(msg):
            self.after(0, lambda m=msg: self._da_status_var.set(m))

        def _run():
            entries = analyzer.analyze(root, max_depth=1,
                                       top_n=40, progress_cb=_prog)
            # Drive info
            drive = os.path.splitdrive(root)[0] + '\\'
            info  = DiskAnalyzer.get_drive_info(drive)
            self.after(0, lambda: self._da_analyze_done(entries, info, drive))

        threading.Thread(target=_run, daemon=True).start()

    def _da_analyze_done(self, entries: list, drive_info: dict, drive: str):
        from downpour_cleanup_module import size_fmt
        self._da_analyze_btn.config(state='normal', text='📊 Analyze')

        total = sum(e.size_bytes for e in entries)
        self._da_status_var.set(
            f'{len(entries):,} entries  •  {size_fmt(total)} total')

        # Drive usage bar
        if drive_info.get('total'):
            used_pct = drive_info['used'] / drive_info['total'] * 100
            self._da_drive_frame.grid()
            for widget in self._da_drive_frame.winfo_children():
                widget.destroy()

            import tkinter as tk
            tk.Label(self._da_drive_frame,
                     text=f'Drive {drive}:',
                     font=('Consolas', 8, 'bold'), fg=Colors.TEXT_DIM,
                     bg=Colors.GLASS_CARD).pack(side='left', padx=8)
            col = (Colors.GAUGE_RED if used_pct > 90
                   else Colors.GAUGE_ORANGE if used_pct > 75
                   else Colors.GAUGE_GREEN)
            tk.Label(self._da_drive_frame,
                     text=(f'Total: {size_fmt(drive_info["total"])}  '
                           f'Used: {size_fmt(drive_info["used"])} '
                           f'({used_pct:.1f}%)  '
                           f'Free: {size_fmt(drive_info["free"])}'),
                     font=('Consolas', 9, 'bold'), fg=col,
                     bg=Colors.GLASS_CARD).pack(side='left', padx=4)

        # Fill tree
        GB = 1_073_741_824
        for e in entries:
            tag = ('huge'   if e.pct_of_total >= 30
                   else 'large'  if e.pct_of_total >= 15
                   else 'medium' if e.pct_of_total >= 5
                   else 'small')
            bar  = '█' * int(e.pct_of_total / 2.5)
            self._da_tree.insert('', 'end',
                values=(os.path.basename(e.path) or e.path,
                        size_fmt(e.size_bytes),
                        f'{bar}  {e.pct_of_total:.1f}%',
                        f'{e.file_count:,}'),
                tags=(tag,))

    def _da_sort(self, col: str):
        if not hasattr(self, '_da_sort_dirs'):
            self._da_sort_dirs: dict = {}
        rev = self._da_sort_dirs.get(col, False)
        items = [(self._da_tree.set(k, col), k)
                 for k in self._da_tree.get_children('')]
        if col == 'Size':
            items.sort(key=lambda x: self._parse_size_bytes(x[0]), reverse=rev)
        elif col == '% of Total':
            # value looks like "███  12.3%" — extract the number
            def _pct(s):
                try:
                    return float(s.split()[-1].rstrip('%'))
                except Exception:
                    return 0.0
            items.sort(key=lambda x: _pct(x[0]), reverse=rev)
        elif col == 'Files':
            items.sort(key=lambda x: int(x[0].replace(',', '') or '0'), reverse=rev)
        else:
            items.sort(key=lambda x: x[0].lower(), reverse=rev)
        for idx, (_, k) in enumerate(items):
            self._da_tree.move(k, '', idx)
        self._da_sort_dirs[col] = not rev


