    def _cleanup_build_security_tab(self, parent):
        """Security Cleanup — restore quarantined files, purge false positives,
        remove stale firewall rules, reset network state."""
        import tkinter as tk
        from tkinter import ttk, messagebox
        C = Colors

        parent.grid_rowconfigure(2, weight=1)
        parent.grid_columnconfigure(0, weight=1)

        # ── Header ──────────────────────────────────────────────────────────
        hdr = tk.Frame(parent, bg=C.GLASS_CARD, pady=6)
        hdr.grid(row=0, column=0, sticky='ew', padx=8, pady=(4, 0))
        tk.Label(hdr, text='SECURITY CLEANUP',
                 font=('Consolas', 11, 'bold'), fg=C.GAUGE_TEAL,
                 bg=C.GLASS_CARD).pack(side='left', padx=8)
        self._sec_status_var = tk.StringVar(value='Ready')
        tk.Label(hdr, textvariable=self._sec_status_var,
                 font=('Consolas', 9), fg=C.TEXT_DIM,
                 bg=C.GLASS_CARD).pack(side='right', padx=12)

        # ── Action buttons ──────────────────────────────────────────────────
        btn_frame = tk.Frame(parent, bg=C.BG_VOID)
        btn_frame.grid(row=1, column=0, sticky='ew', padx=8, pady=4)

        for txt, cmd, col in [
            ("Scan for Issues",        self._sec_scan,               C.GAUGE_TEAL),
            ("Restore Quarantined",    self._sec_restore_quarantine, C.GAUGE_GREEN),
            ("Purge False Positives",  self._sec_purge_fp,           C.GAUGE_ORANGE),
            ("Clean Firewall Rules",   self._sec_clean_firewall,     C.GAUGE_YELLOW),
            ("Reset Network",          self._sec_reset_network,      C.GAUGE_BLUE),
            ("NUKE PORT PROXIES",      self._sec_nuke_portproxy,     '#ff2222'),
            ("FULL CLEANUP",           self._sec_full_cleanup,       C.GAUGE_RED),
        ]:
            tk.Button(btn_frame, text=txt, font=('Consolas', 9, 'bold'),
                      fg=col, bg=C.GLASS_CARD, relief='flat', padx=8, pady=3,
                      command=cmd).pack(side='left', padx=3)

        # ── Results log ─────────────────────────────────────────────────────
        log_frame = tk.Frame(parent, bg=C.BG_VOID)
        log_frame.grid(row=2, column=0, sticky='nsew', padx=8, pady=4)
        log_frame.grid_rowconfigure(0, weight=1)
        log_frame.grid_columnconfigure(0, weight=1)

        self._sec_log = tk.Text(log_frame, bg=C.GLASS_DARK, fg=C.TEXT_LIGHT,
                                font=('Consolas', 9), wrap='word',
                                relief='flat', state='disabled')
        sb = ttk.Scrollbar(log_frame, command=self._sec_log.yview,
                           style='Vertical.TScrollbar')
        self._sec_log.configure(yscrollcommand=sb.set)
        self._sec_log.grid(row=0, column=0, sticky='nsew')
        sb.grid(row=0, column=1, sticky='ns')

        # Configure text tags
        self._sec_log.tag_configure('ok',   foreground=C.GAUGE_GREEN)
        self._sec_log.tag_configure('warn', foreground=C.GAUGE_ORANGE)
        self._sec_log.tag_configure('err',  foreground=C.GAUGE_RED)
        self._sec_log.tag_configure('info', foreground=C.GAUGE_TEAL)
        self._sec_log.tag_configure('hdr',  foreground=C.GAUGE_TEAL,
                                    font=('Consolas', 10, 'bold'))

    def _sec_log_msg(self, msg: str, tag: str = 'info'):
        """Append a message to the security cleanup log."""
        try:
            self._sec_log.configure(state='normal')
            self._sec_log.insert('end', msg + '\n', tag)
            self._sec_log.see('end')
            self._sec_log.configure(state='disabled')
        except Exception:
            pass

    def _sec_scan(self):
        """Scan for security issues: FP entries, quarantine state, stale rules."""
        import threading
        def _scan():
            self._sec_status_var.set('Scanning...')
            self._sec_log.configure(state='normal')
            self._sec_log.delete('1.0', 'end')
            self._sec_log.configure(state='disabled')

            self._sec_log_msg('SECURITY ISSUE SCAN', 'hdr')
            self._sec_log_msg('=' * 50, 'info')
            issues = 0

            # Check quarantine for false positives
            try:
                rows = self.db.execute(
                    "SELECT original_path FROM quarantine WHERE restored = 0"
                ).fetchall() if hasattr(self, 'db') else []
                defender_q = [r[0] for r in rows
                              if 'windows defender' in r[0].lower()]
                if defender_q:
                    issues += len(defender_q)
                    self._sec_log_msg(
                        f'\n[!] {len(defender_q)} Windows Defender files in quarantine:',
                        'err')
                    for f in defender_q:
                        self._sec_log_msg(f'    {os.path.basename(f)}', 'warn')
                else:
                    self._sec_log_msg('\n[OK] No critical files quarantined', 'ok')
            except Exception as e:
                self._sec_log_msg(f'\n[ERR] Quarantine check: {e}', 'err')

            # Check threat_events for ServiceCreation FPs
            try:
                count = self.db.execute(
                    "SELECT COUNT(*) FROM threat_events "
                    "WHERE type = 'ServiceCreation'"
                ).fetchone()
                svc_count = count[0] if count else 0
                if svc_count > 100:
                    issues += 1
                    self._sec_log_msg(
                        f'\n[!] {svc_count} ServiceCreation events '
                        f'(mostly false positives from safe Windows services)',
                        'warn')
                else:
                    self._sec_log_msg(
                        f'\n[OK] ServiceCreation events: {svc_count}', 'ok')
            except Exception as e:
                self._sec_log_msg(f'\n[ERR] DB check: {e}', 'err')

            # Check worm_events
            try:
                count = self.db.execute(
                    "SELECT COUNT(*) FROM worm_events"
                ).fetchone()
                worm_count = count[0] if count else 0
                if worm_count > 50:
                    issues += 1
                    self._sec_log_msg(
                        f'\n[!] {worm_count} worm events '
                        f'(includes false positives from system processes)',
                        'warn')
                else:
                    self._sec_log_msg(
                        f'\n[OK] Worm events: {worm_count}', 'ok')
            except Exception:
                pass

            # Check Downpour firewall rules
            try:
                r = subprocess.run(
                    ['netsh', 'advfirewall', 'firewall', 'show', 'rule',
                     'name=all', 'dir=out'],
                    capture_output=True, text=True, timeout=15,
                    creationflags=subprocess.CREATE_NO_WINDOW)
                dp_rules = sum(1 for line in r.stdout.splitlines()
                               if 'DOWNPOUR_' in line)
                if dp_rules > 0:
                    issues += 1
                    self._sec_log_msg(
                        f'\n[!] {dp_rules} Downpour firewall rules active',
                        'warn')
                else:
                    self._sec_log_msg(
                        '\n[OK] No stale Downpour firewall rules', 'ok')
            except Exception:
                pass

            # Check inflated threat families
            try:
                rows = self.db.execute(
                    "SELECT name, count FROM threat_families "
                    "WHERE count > 100 ORDER BY count DESC"
                ).fetchall()
                if rows:
                    issues += len(rows)
                    self._sec_log_msg(
                        f'\n[!] {len(rows)} inflated threat families:', 'warn')
                    for name, count in rows[:5]:
                        self._sec_log_msg(
                            f'    {name}: {count} entries', 'warn')
                else:
                    self._sec_log_msg(
                        '\n[OK] Threat family counts are normal', 'ok')
            except Exception:
                pass

            self._sec_log_msg(f'\n{"="*50}', 'info')
            if issues:
                self._sec_log_msg(
                    f'Found {issues} issue(s). '
                    f'Use buttons above to fix, or click FULL CLEANUP.',
                    'warn')
            else:
                self._sec_log_msg('No issues found. System is clean.', 'ok')
            self._sec_status_var.set(
                f'Scan complete — {issues} issue(s)' if issues
                else 'Scan complete — clean')

        threading.Thread(target=_scan, daemon=True).start()

    def _sec_restore_quarantine(self):
        """Restore falsely quarantined files (e.g., Windows Defender)."""
        import threading
        from tkinter import messagebox
        _DEFENDER_FILES = {
            'mpoav.dll', 'mpcmdrun.exe', 'mpclient.dll', 'mpdetours.dll',
            'mpdetourscopyaccelerator.dll', 'endpointdlp.dll', 'mdediag.dll',
            'msmpeng.exe', 'nissrv.exe', 'mpengine.dll', 'mpsigstub.exe',
        }

        def _restore():
            self._sec_status_var.set('Restoring...')
            self._sec_log_msg('\nRESTORING QUARANTINED FILES', 'hdr')
            restored = 0
            try:
                rows = self.db.execute(
                    "SELECT id, original_path, quarantine_path "
                    "FROM quarantine WHERE restored = 0"
                ).fetchall()
                for row_id, orig, qpath in rows:
                    fname = os.path.basename(orig).lower()
                    if fname in _DEFENDER_FILES or \
                       'windows defender' in orig.lower():
                        self._sec_log_msg(f'  Restoring: {fname}', 'info')
                        if os.path.exists(qpath):
                            try:
                                os.makedirs(os.path.dirname(orig),
                                            exist_ok=True)
                                shutil.move(qpath, orig)
                                self.db.execute(
                                    "UPDATE quarantine SET restored=1 "
                                    "WHERE id=?", (row_id,))
                                restored += 1
                                self._sec_log_msg(
                                    f'    [OK] Restored to {orig}', 'ok')
                            except Exception as e:
                                self._sec_log_msg(
                                    f'    [FAIL] {e} (run as Admin)', 'err')
                        else:
                            self._sec_log_msg(
                                f'    [WARN] File not in quarantine vault',
                                'warn')
                            self.db.execute(
                                "UPDATE quarantine SET restored=1 "
                                "WHERE id=?", (row_id,))
                self.db.commit()
            except Exception as e:
                self._sec_log_msg(f'  [ERR] {e}', 'err')

            self._sec_log_msg(
                f'\n  Restored {restored} files. '
                f'Restart PC to re-enable Defender services.', 'ok')
            self._sec_status_var.set(f'Restored {restored} files')

        threading.Thread(target=_restore, daemon=True).start()

    def _sec_purge_fp(self):
        """Purge false positive entries from threat database tables."""
        import threading

        def _purge():
            self._sec_status_var.set('Purging false positives...')
            self._sec_log_msg('\nPURGING FALSE POSITIVE DB ENTRIES', 'hdr')
            total = 0

            # ServiceCreation events from safe paths
            try:
                safe_locs = ('\\systemroot\\', '\\windows\\', '\\system32\\',
                             '\\driverstore\\', 'svchost.exe',
                             '\\program files\\', '\\program files (x86)\\')
                rows = self.db.execute(
                    "SELECT id, detail FROM threat_events "
                    "WHERE type='ServiceCreation'"
                ).fetchall()
                safe_ids = [r[0] for r in rows
                            if any(sp in (r[1] or '').lower()
                                   for sp in safe_locs) or not (r[1] or '').strip()]
                for i in range(0, len(safe_ids), 500):
                    batch = safe_ids[i:i+500]
                    ph = ','.join('?' * len(batch))
                    self.db.execute(
                        f"DELETE FROM threat_events WHERE id IN ({ph})", batch)
                self.db.commit()
                total += len(safe_ids)
                self._sec_log_msg(
                    f'  [OK] Removed {len(safe_ids)} safe ServiceCreation entries',
                    'ok')
            except Exception as e:
                self._sec_log_msg(f'  [ERR] ServiceCreation: {e}', 'err')

            # Worm events from system processes
            try:
                before = self.db.execute(
                    "SELECT COUNT(*) FROM worm_events").fetchone()[0]
                for pat in ['%conhost.exe%', '%csrss.exe%', '%svchost.exe%',
                            '%lsass.exe%', '%services.exe%', '%explorer.exe%']:
                    self.db.execute(
                        "DELETE FROM worm_events WHERE file_path LIKE ?",
                        (pat,))
                self.db.execute(
                    "DELETE FROM worm_events WHERE event_type='network_scanning'"
                    " AND confidence <= 0.6")
                self.db.commit()
                after = self.db.execute(
                    "SELECT COUNT(*) FROM worm_events").fetchone()[0]
                removed = before - after
                total += removed
                self._sec_log_msg(
                    f'  [OK] Removed {removed} false worm events', 'ok')
            except Exception as e:
                self._sec_log_msg(f'  [ERR] Worm events: {e}', 'err')

            # Memory injection FPs (Google Play Games installer)
            try:
                self.db.execute(
                    "DELETE FROM memory_injection_events "
                    "WHERE evidence LIKE '%Install-GooglePlayGames%'")
                self.db.execute(
                    "DELETE FROM memory_injection_events "
                    "WHERE evidence LIKE '%microsoftedgedownloads%'")
                self.db.commit()
                self._sec_log_msg(
                    '  [OK] Removed installer false positives', 'ok')
            except Exception:
                pass

            # Inflated threat families
            try:
                rows = self.db.execute(
                    "SELECT id, name, count FROM threat_families "
                    "WHERE name IN ('Shellcode Detected','Packed/Encrypted') "
                    "AND count > 100"
                ).fetchall()
                for fid, fname, fcount in rows:
                    self.db.execute(
                        "DELETE FROM threat_families WHERE id=?", (fid,))
                    self._sec_log_msg(
                        f'  [OK] Removed inflated family: {fname} '
                        f'(count={fcount})', 'ok')
                    total += 1
                self.db.commit()
            except Exception:
                pass

            self._sec_log_msg(
                f'\n  Total: {total} false positive entries removed', 'ok')
            self._sec_status_var.set(f'Purged {total} FP entries')

        threading.Thread(target=_purge, daemon=True).start()

    def _sec_clean_firewall(self):
        """Remove stale Downpour firewall rules."""
        import threading

        def _clean():
            self._sec_status_var.set('Cleaning firewall rules...')
            self._sec_log_msg('\nCLEANING DOWNPOUR FIREWALL RULES', 'hdr')
            try:
                r = subprocess.run(
                    ['netsh', 'advfirewall', 'firewall', 'show', 'rule',
                     'name=all', 'dir=out'],
                    capture_output=True, text=True, timeout=15,
                    creationflags=subprocess.CREATE_NO_WINDOW)
                rules = []
                for line in r.stdout.splitlines():
                    if line.strip().startswith('Rule Name:'):
                        name = line.split(':', 1)[1].strip()
                        if name.startswith(('DOWNPOUR_ISOLATE_',
                                           'DOWNPOUR_BLOCK_')):
                            rules.append(name)

                removed = 0
                for rule in rules:
                    try:
                        subprocess.run(
                            ['netsh', 'advfirewall', 'firewall', 'delete',
                             'rule', f'name={rule}'],
                            capture_output=True, timeout=10,
                            creationflags=subprocess.CREATE_NO_WINDOW)
                        removed += 1
                        self._sec_log_msg(f'  Removed: {rule}', 'ok')
                    except Exception:
                        pass

                if not rules:
                    self._sec_log_msg(
                        '  No Downpour firewall rules found', 'ok')
                else:
                    self._sec_log_msg(
                        f'\n  Removed {removed}/{len(rules)} rules', 'ok')
                self._sec_status_var.set(
                    f'Cleaned {removed} rules' if removed
                    else 'No rules to clean')
            except Exception as e:
                self._sec_log_msg(f'  [ERR] {e}', 'err')
                self._sec_status_var.set('Error')

        threading.Thread(target=_clean, daemon=True).start()

    def _sec_nuke_portproxy(self):
        """Emergency: delete ALL netsh portproxy rules (the 2100-rule MITM backdoor)."""
        import threading
        from tkinter import messagebox

        # Show current count first
        try:
            r = subprocess.run(
                ['netsh', 'interface', 'portproxy', 'show', 'all'],
                capture_output=True, text=True, timeout=10,
                creationflags=subprocess.CREATE_NO_WINDOW)
            rule_lines = [l for l in r.stdout.splitlines()
                          if l.strip() and not l.startswith('Listen') and
                          not l.startswith('---') and not l.startswith('Address')]
            count = len(rule_lines)
        except Exception:
            count = -1

        msg = (f"This will delete ALL {count} netsh portproxy rules.\n\n"
               f"{'='*40}\n"
               f"PORT PROXY RULES ARE AN ACTIVE MITM BACKDOOR.\n"
               f"{'='*40}\n\n"
               f"The malware created {count} forwarding rules to intercept\n"
               f"your network traffic. This MUST be purged.\n\n"
               f"Run 'netsh interface portproxy reset' now?")
        if not messagebox.askyesno("NUKE PORT PROXIES", msg):
            return

        def _nuke():
            self._sec_status_var.set('Nuking port proxies...')
            self._sec_log_msg('\nNUKING ALL PORT PROXY RULES', 'hdr')
            self._sec_log_msg(
                f'  Malware installed {count} MITM forwarding rules. Purging...', 'err')

            try:
                r = subprocess.run(
                    ['netsh', 'interface', 'portproxy', 'reset'],
                    capture_output=True, text=True, timeout=30,
                    creationflags=subprocess.CREATE_NO_WINDOW)
                if r.returncode == 0:
                    self._sec_log_msg(
                        f'  [OK] All {count} portproxy rules deleted', 'ok')
                    self._sec_log_msg(
                        '  Run "netsh interface portproxy show all" to confirm', 'info')
                else:
                    self._sec_log_msg(
                        f'  [WARN] Exit code {r.returncode}: {r.stderr.strip()}', 'warn')
                    self._sec_log_msg('  Try running as Administrator', 'warn')
            except Exception as e:
                self._sec_log_msg(f'  [ERR] {e}', 'err')

            # Verify
            try:
                r2 = subprocess.run(
                    ['netsh', 'interface', 'portproxy', 'show', 'all'],
                    capture_output=True, text=True, timeout=10,
                    creationflags=subprocess.CREATE_NO_WINDOW)
                remaining = [l for l in r2.stdout.splitlines()
                             if l.strip() and not l.startswith('Listen') and
                             not l.startswith('---') and not l.startswith('Address')]
                if remaining:
                    self._sec_log_msg(
                        f'  [WARN] {len(remaining)} rules remain — '
                        f'may require reboot or Admin', 'warn')
                else:
                    self._sec_log_msg(
                        '  [OK] VERIFIED: zero portproxy rules remain', 'ok')
            except Exception:
                pass

            self._sec_log_msg(
                '\n  Also restart your PC to ensure the malware\'s '
                'portproxy service cannot restore these rules.', 'warn')
            self._sec_status_var.set('Port proxies nuked')

        threading.Thread(target=_nuke, daemon=True).start()

    def _sec_reset_network(self):
        """Flush DNS, clear ARP cache, reset network state."""
        import threading

        def _reset():
            self._sec_status_var.set('Resetting network...')
            self._sec_log_msg('\nRESETTING NETWORK STATE', 'hdr')

            cmds = [
                (['ipconfig', '/flushdns'], 'Flush DNS cache'),
                (['netsh', 'interface', 'ip', 'delete', 'arpcache'],
                 'Clear ARP cache'),
            ]
            for cmd, desc in cmds:
                try:
                    r = subprocess.run(
                        cmd, capture_output=True, text=True, timeout=10,
                        creationflags=subprocess.CREATE_NO_WINDOW)
                    tag = 'ok' if r.returncode == 0 else 'warn'
                    self._sec_log_msg(f'  [{tag.upper()}] {desc}', tag)
                except Exception as e:
                    self._sec_log_msg(f'  [ERR] {desc}: {e}', 'err')

            # Clean hosts file (Downpour entries)
            try:
                hosts = (Path(os.environ.get('SystemRoot', 'C:\\Windows'))
                         / 'System32' / 'drivers' / 'etc' / 'hosts')
                with open(hosts, 'r') as f:
                    lines = f.readlines()
                clean = [l for l in lines
                         if '# DOWNPOUR' not in l and '# downpour' not in l]
                removed = len(lines) - len(clean)
                if removed:
                    with open(hosts, 'w') as f:
                        f.writelines(clean)
                    self._sec_log_msg(
                        f'  [OK] Removed {removed} hosts entries', 'ok')
                else:
                    self._sec_log_msg(
                        '  [OK] No Downpour hosts entries', 'ok')
            except PermissionError:
                self._sec_log_msg(
                    '  [WARN] Hosts file: run as Administrator', 'warn')
            except Exception as e:
                self._sec_log_msg(f'  [ERR] Hosts: {e}', 'err')

            self._sec_status_var.set('Network reset complete')

        threading.Thread(target=_reset, daemon=True).start()

    def _sec_full_cleanup(self):
        """Run all security cleanup operations in sequence."""
        import threading
        from tkinter import messagebox

        if not messagebox.askyesno(
                "Full Security Cleanup",
                "This will:\n"
                "- Restore falsely quarantined files (Windows Defender)\n"
                "- Purge all false positive database entries\n"
                "- Remove stale Downpour firewall rules\n"
                "- Reset DNS and ARP cache\n\n"
                "Continue?"):
            return

        def _full():
            self._sec_status_var.set('Running full cleanup...')
            self._sec_log.configure(state='normal')
            self._sec_log.delete('1.0', 'end')
            self._sec_log.configure(state='disabled')
            self._sec_log_msg('FULL SECURITY CLEANUP', 'hdr')
            self._sec_log_msg('=' * 50, 'info')

            # Each step runs synchronously in this thread
            self._sec_restore_quarantine_sync()
            self._sec_purge_fp_sync()
            self._sec_clean_firewall_sync()
            self._sec_reset_network_sync()

            self._sec_log_msg('\n' + '=' * 50, 'info')
            self._sec_log_msg(
                'FULL CLEANUP COMPLETE. Restart your PC to '
                'ensure all services start correctly.', 'ok')
            self._sec_status_var.set('Full cleanup complete')

        threading.Thread(target=_full, daemon=True).start()

    def _sec_restore_quarantine_sync(self):
        """Synchronous restore for use in full cleanup chain."""
        _DEFENDER_FILES = {
            'mpoav.dll', 'mpcmdrun.exe', 'mpclient.dll', 'mpdetours.dll',
            'mpdetourscopyaccelerator.dll', 'endpointdlp.dll', 'mdediag.dll',
            'msmpeng.exe', 'nissrv.exe', 'mpengine.dll',
        }
        self._sec_log_msg('\n[1/4] RESTORING QUARANTINED FILES', 'hdr')
        restored = 0
        try:
            rows = self.db.execute(
                "SELECT id, original_path, quarantine_path "
                "FROM quarantine WHERE restored = 0"
            ).fetchall()
            for row_id, orig, qpath in rows:
                fname = os.path.basename(orig).lower()
                if fname in _DEFENDER_FILES or \
                   'windows defender' in orig.lower():
                    if os.path.exists(qpath):
                        try:
                            os.makedirs(os.path.dirname(orig), exist_ok=True)
                            shutil.move(qpath, orig)
                            self.db.execute(
                                "UPDATE quarantine SET restored=1 WHERE id=?",
                                (row_id,))
                            restored += 1
                            self._sec_log_msg(
                                f'  Restored: {fname}', 'ok')
                        except Exception as e:
                            self._sec_log_msg(
                                f'  Failed: {fname} ({e})', 'err')
                    else:
                        self.db.execute(
                            "UPDATE quarantine SET restored=1 WHERE id=?",
                            (row_id,))
            self.db.commit()
        except Exception as e:
            self._sec_log_msg(f'  Error: {e}', 'err')
        self._sec_log_msg(f'  Result: {restored} files restored', 'ok')

    def _sec_purge_fp_sync(self):
        """Synchronous FP purge for use in full cleanup chain."""
        self._sec_log_msg('\n[2/4] PURGING FALSE POSITIVES', 'hdr')
        total = 0
        try:
            safe_locs = ('\\systemroot\\', '\\windows\\', '\\system32\\',
                         '\\driverstore\\', 'svchost.exe',
                         '\\program files\\', '\\program files (x86)\\')
            rows = self.db.execute(
                "SELECT id, detail FROM threat_events "
                "WHERE type='ServiceCreation'").fetchall()
            safe_ids = [r[0] for r in rows
                        if any(sp in (r[1] or '').lower()
                               for sp in safe_locs) or not (r[1] or '').strip()]
            for i in range(0, len(safe_ids), 500):
                batch = safe_ids[i:i+500]
                ph = ','.join('?' * len(batch))
                self.db.execute(
                    f"DELETE FROM threat_events WHERE id IN ({ph})", batch)
            total += len(safe_ids)
            self._sec_log_msg(
                f'  Removed {len(safe_ids)} ServiceCreation FPs', 'ok')

            for pat in ['%conhost.exe%', '%csrss.exe%', '%svchost.exe%',
                        '%lsass.exe%', '%services.exe%']:
                self.db.execute(
                    "DELETE FROM worm_events WHERE file_path LIKE ?", (pat,))
            self.db.execute(
                "DELETE FROM worm_events "
                "WHERE event_type='network_scanning' AND confidence<=0.6")

            self.db.execute(
                "DELETE FROM memory_injection_events "
                "WHERE evidence LIKE '%Install-GooglePlayGames%'")

            rows = self.db.execute(
                "SELECT id, name, count FROM threat_families "
                "WHERE name IN ('Shellcode Detected','Packed/Encrypted') "
                "AND count > 100").fetchall()
            for fid, fname, _ in rows:
                self.db.execute(
                    "DELETE FROM threat_families WHERE id=?", (fid,))
            self.db.commit()
        except Exception as e:
            self._sec_log_msg(f'  Error: {e}', 'err')
        self._sec_log_msg(f'  Result: {total}+ entries purged', 'ok')

    def _sec_clean_firewall_sync(self):
        """Synchronous firewall cleanup for use in full cleanup chain."""
        self._sec_log_msg('\n[3/4] CLEANING FIREWALL RULES', 'hdr')
        try:
            r = subprocess.run(
                ['netsh', 'advfirewall', 'firewall', 'show', 'rule',
                 'name=all', 'dir=out'],
                capture_output=True, text=True, timeout=15,
                creationflags=subprocess.CREATE_NO_WINDOW)
            removed = 0
            for line in r.stdout.splitlines():
                if line.strip().startswith('Rule Name:'):
                    name = line.split(':', 1)[1].strip()
                    if name.startswith(('DOWNPOUR_ISOLATE_', 'DOWNPOUR_BLOCK_')):
                        try:
                            subprocess.run(
                                ['netsh', 'advfirewall', 'firewall', 'delete',
                                 'rule', f'name={name}'],
                                capture_output=True, timeout=10,
                                creationflags=subprocess.CREATE_NO_WINDOW)
                            removed += 1
                        except Exception:
                            pass
            self._sec_log_msg(f'  Removed {removed} rules', 'ok')
        except Exception as e:
            self._sec_log_msg(f'  Error: {e}', 'err')

    def _sec_reset_network_sync(self):
        """Synchronous network reset for use in full cleanup chain."""
        self._sec_log_msg('\n[4/4] RESETTING NETWORK', 'hdr')
        for cmd, desc in [
            (['ipconfig', '/flushdns'], 'Flush DNS'),
            (['netsh', 'interface', 'ip', 'delete', 'arpcache'], 'Clear ARP'),
        ]:
            try:
                r = subprocess.run(
                    cmd, capture_output=True, text=True, timeout=10,
                    creationflags=subprocess.CREATE_NO_WINDOW)
                self._sec_log_msg(
                    f'  {"[OK]" if r.returncode == 0 else "[WARN]"} {desc}',
                    'ok' if r.returncode == 0 else 'warn')
            except Exception as e:
                self._sec_log_msg(f'  [ERR] {desc}: {e}', 'err')


