    def _wifi_run(self, cmd, timeout=15):
        import subprocess
        try:
            r = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout,
                               encoding='utf-8', errors='replace',
                               creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0x08000000))
            return r.stdout
        except Exception as e:
            return str(e)

    def _thread_safe_ui_update(self, callback, *args, **kwargs):
        """Thread-safe UI update helper method"""
        try:
            import threading
            if threading.current_thread() == threading.main_thread():
                # Already in main thread, execute directly
                callback(*args, **kwargs)
            else:
                # In background thread, use self.after (thread-safe via override)
                self.after(0, lambda: callback(*args, **kwargs))
        except Exception:
            # Silent fail to prevent crashes
            pass

    def _wifi_refresh_current(self):
        import threading
        out = self._wifi_run(['netsh', 'wlan', 'show', 'interfaces'])
        ssid = auth = signal = ip = ''
        import re
        for line in out.splitlines():
            l = line.strip()
            if l.startswith('SSID') and 'BSSID' not in l:
                ssid = l.split(':', 1)[-1].strip()
            elif l.startswith('Authentication'):
                auth = l.split(':', 1)[-1].strip()
            elif l.startswith('Signal'):
                m = re.search(r'(\d+)%', l)
                signal = m.group(1) if m else ''
            elif l.startswith('IPv4'):
                if 'DHCP' in l:
                    parts = l.split(':')
                    if len(parts) > 1:
                        ip = parts[1].strip().split()[0]
        # Thread-safe UI update
        self._thread_safe_ui_update(self._wifi_status_lbl.config, 
                                   text=f"📡 {ssid or 'Not connected'} ({auth or 'Unknown'})",
                                   fg=Colors.GAUGE_GREEN if ssid else Colors.GAUGE_RED)
        self._thread_safe_ui_update(self._wifi_signal_lbl.config,
                                   text=f"Signal: {signal}%" if signal else "Signal: N/A")
        self._thread_safe_ui_update(self._wifi_ip_lbl.config,
                                   text=f"IP: {ip}" if ip else "IP: N/A")
        score = self._wifi_auth_score(auth)
        if ssid:
            color = Colors.GAUGE_GREEN if score >= 70 else (Colors.GAUGE_ORANGE if score >= 40 else Colors.GAUGE_RED)
            txt = f"SSID: {ssid}  |  Auth: {auth}  |  Signal: {signal}  |  IP: {ip}  |  Score: {score}/100"
        else:
            txt = "No WiFi connection detected"
            color = Colors.TEXT_DIM
        
        # Thread-safe UI update
        self._thread_safe_ui_update(self._wifi_cur_lbl.config, text=txt, fg=color)

    def _wifi_auth_score(self, auth: str) -> int:
        auth = (auth or '').upper()
        if 'WPA3' in auth: return 100
        if 'WPA2' in auth: return 75
        if 'WPA' in auth:  return 45
        if 'WEP' in auth:  return 10
        if 'OPEN' in auth or not auth: return 0
        return 60

    def _wifi_scan(self):
        import threading
        self._wifi_status_lbl.config(text="⏳ Scanning WiFi networks...", fg=Colors.GAUGE_YELLOW)
        def _run():
            out = self._wifi_run(['netsh', 'wlan', 'show', 'networks', 'mode=bssid'], timeout=20)
            nets = self._wifi_parse_networks(out)
            self._thread_safe_ui_update(self._wifi_populate, nets)
        threading.Thread(target=_run, daemon=True).start()

    def _wifi_parse_networks(self, raw: str) -> list:
        nets = []
        current = {}
        bssid_count = 0
        for line in raw.splitlines():
            line = line.strip()
            if line.startswith('SSID') and 'BSSID' not in line and ':' in line:
                if current:
                    nets.append(current)
                current = {'SSID': line.split(':', 1)[1].strip(),
                            'BSSID': '', 'Signal': '', 'Auth': '', 'Cipher': '', 'Band': ''}
                bssid_count = 0
            elif 'BSSID' in line and ':' in line and current:
                if bssid_count == 0:
                    current['BSSID'] = line.split(':', 1)[1].strip()
                bssid_count += 1
            elif line.startswith('Signal') and current:
                current['Signal'] = line.split(':', 1)[1].strip()
            elif line.startswith('Authentication') and current:
                current['Auth'] = line.split(':', 1)[1].strip()
            elif line.startswith('Cipher') and current:
                current['Cipher'] = line.split(':', 1)[1].strip()
            elif line.startswith('Radio type') and current:
                current['Band'] = line.split(':', 1)[1].strip()
        if current:
            nets.append(current)
        # Detect evil twins
        from collections import defaultdict
        ssid_map = defaultdict(list)
        for n in nets:
            ssid_map[n['SSID']].append(n)
        for n in nets:
            n['EvilTwin'] = '[WARN] YES' if len(ssid_map[n['SSID']]) > 1 else 'No'
            n['Score'] = self._wifi_auth_score(n.get('Auth',''))
        return nets

    def _wifi_populate(self, nets: list):
        self._wifi_all_nets = nets
        self._wifi_tree.delete(*self._wifi_tree.get_children())
        for n in nets:
            s = n.get('Score', 0)
            tag = 'safe' if s >= 70 else ('warn' if s >= 40 else 'danger')
            if n.get('EvilTwin','') == '[WARN] YES':
                tag = 'eviltwin'
            self._wifi_tree.insert('', 'end', values=(
                n.get('SSID',''), n.get('BSSID',''), n.get('Signal',''),
                n.get('Auth',''), n.get('Cipher',''), n.get('Band',''),
                f"{n.get('Score',0)}/100", n.get('EvilTwin','No')), tags=(tag,))
        danger_count = sum(1 for n in nets if n.get('Score',0) < 40)
        evil_count   = sum(1 for n in nets if n.get('EvilTwin','') == '[WARN] YES')
        self._wifi_status_lbl.config(
            text=f"[OK] {len(nets)} networks found  |  [WARN] Low security: {danger_count}  |  [EVIL] Evil twins: {evil_count}",
            fg=Colors.GAUGE_RED if evil_count else (Colors.GAUGE_ORANGE if danger_count else Colors.GAUGE_GREEN))

    def _wifi_on_select(self, _=None):
        sel = self._wifi_tree.selection()
        if not sel: return
        vals = self._wifi_tree.item(sel[0], 'values')
        ssid, bssid, signal, auth, cipher, band, score, evil = vals
        score_int = int(score.split('/')[0]) if '/' in score else 0
        auth_u = auth.upper()
        findings = []
        if score_int < 40:
            findings.append(f"⛔ WEAK SECURITY: {auth} authentication is outdated/insecure")
        if 'WEP' in auth_u:
            findings.append("⛔ WEP is broken — can be cracked in minutes")
        if 'OPEN' in auth_u or not auth.strip():
            findings.append("⛔ OPEN NETWORK — no encryption, all traffic visible")
        if 'WPA2' in auth_u and 'WPA3' not in auth_u:
            findings.append("[WARN] WPA2 — upgrade to WPA3 if router supports it")
        if 'WPA3' in auth_u:
            findings.append("[OK] WPA3 — current best practice")
        if 'TKIP' in cipher.upper():
            findings.append("[WARN] TKIP cipher is deprecated — prefer AES/CCMP")
        if evil == '[WARN] YES':
            findings.append("⛔ EVIL TWIN DETECTED — another network has same SSID!")
            findings.append("   This may be a rogue AP for MITM attacks")
        if not findings:
            findings.append("[OK] No obvious security issues detected")

        txt = f"Network: {ssid}\nBSSID: {bssid}\nSignal: {signal}  Band: {band}\n"
        txt += f"Auth: {auth}  Cipher: {cipher}\nSecurity Score: {score}\n\n"
        txt += "FINDINGS:\n" + "\n".join(findings)

        self._wifi_analysis.config(state='normal')
        self._wifi_analysis.delete('1.0', 'end')
        self._wifi_analysis.insert('end', txt)
        self._wifi_analysis.config(state='disabled')

    def _wifi_show_passwords(self):
        import threading
        def _run():
            import subprocess
            out_all = ''
            # Get profile names
            r = subprocess.run(['netsh', 'wlan', 'show', 'profiles'],
                               capture_output=True, text=True,
                               creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0x08000000))
            import re
            profiles = re.findall(r'All User Profile\s*:\s*(.+)', r.stdout)
            results = []
            for prof in profiles:
                prof = prof.strip()
                r2 = subprocess.run(['netsh', 'wlan', 'show', 'profile',
                                     f'name={prof}', 'key=clear'],
                                    capture_output=True, text=True,
                                    creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0x08000000))
                pw = re.search(r'Key Content\s*:\s*(.+)', r2.stdout)
                pw = pw.group(1).strip() if pw else '(no password / WPA-Enterprise)'
                results.append(f"{'─'*50}\nSSID: {prof}\nPassword: {pw}")
            final = '\n'.join(results) if results else "No saved WiFi profiles found."
            self.after(0, lambda: messagebox.showinfo("Saved WiFi Passwords", final[:3000]))
        threading.Thread(target=_run, daemon=True).start()

    def _wifi_dns_leak_test(self):
        import threading, socket
        def _run():
            results = []
            test_domains = ['myip.opendns.com', 'whoami.akamai.net', 'checkip.amazonaws.com']
            resolvers = []
            for d in test_domains:
                try:
                    ip = socket.gethostbyname(d)
                    results.append(f"[OK] {d} → {ip}")
                except Exception as e:
                    results.append(f"[FAIL] {d} → {e}")
            # Check configured DNS
            import subprocess
            r = subprocess.run(['nslookup', 'whoami.akamai.net'],
                               capture_output=True, text=True,
                               creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0x08000000))
            results.append(f"\nDNS Resolution Test:\n{r.stdout[:500]}")
            self.after(0, lambda: messagebox.showinfo("DNS Leak Test", '\n'.join(results[:20])))
        threading.Thread(target=_run, daemon=True).start()

    def _wifi_export(self):
        from tkinter import filedialog
        path = filedialog.asksaveasfilename(defaultextension='.csv',
            filetypes=[('CSV','*.csv')], title="Export WiFi Scan")
        if not path: return
        try:
            import csv
            with open(path, 'w', newline='', encoding='utf-8') as f:
                w = csv.writer(f)
                w.writerow(['SSID','BSSID','Signal','Auth','Cipher','Band','Score','Evil Twin?'])
                for n in self._wifi_all_nets:
                    w.writerow([n.get(k,'') for k in
                                ('SSID','BSSID','Signal','Auth','Cipher','Band','Score','EvilTwin')])
            messagebox.showinfo("Exported", f"Saved to:\n{path}")
        except Exception as e:
            messagebox.showerror("Export Error", str(e))

