    def _usb_run_ps(self, cmd: str, timeout: int = 20) -> str:
        import subprocess
        try:
            r = subprocess.run(
                ['powershell', '-NoProfile', '-Command', cmd],
                capture_output=True, text=True, timeout=timeout, encoding='utf-8', errors='replace',
                creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0x08000000))
            return r.stdout
        except Exception as e:
            return str(e)

    def _usb_scan(self):
        import threading
        self._usb_status_lbl.config(text="⏳ Enumerating USB devices...", fg=Colors.GAUGE_YELLOW)
        def _run():
            # Use WMI via PowerShell to get USB devices
            ps = (
                "Get-PnpDevice -Class USB,HIDClass,DiskDrive -ErrorAction SilentlyContinue | "
                "Where-Object {$_.InstanceId -like 'USB*' -or $_.InstanceId -like 'USBSTOR*'} | "
                "Select-Object FriendlyName,InstanceId,Manufacturer,Class,Status | "
                "ForEach-Object { "
                "$_.FriendlyName + '|||' + $_.InstanceId + '|||' + $_.Manufacturer + '|||' + "
                "$_.Class + '|||' + $_.Status }"
            )
            out = self._usb_run_ps(ps, timeout=30)
            devices = []
            for line in out.splitlines():
                parts = line.split('|||')
                if len(parts) >= 4:
                    devices.append({
                        'name':  parts[0].strip() or 'Unknown Device',
                        'id':    parts[1].strip(),
                        'mfr':   parts[2].strip() or 'Unknown',
                        'class': parts[3].strip(),
                        'status':parts[4].strip() if len(parts) > 4 else '',
                        'seen':  'Current session',
                    })
            # Also get all USB storage from registry history
            self.after(0, lambda: self._usb_populate(devices))
        threading.Thread(target=_run, daemon=True).start()

    def _usb_load_history(self):
        import threading
        self._usb_status_lbl.config(text="⏳ Reading USB history from registry...", fg=Colors.GAUGE_YELLOW)
        def _run():
            ps = (
                "$path = 'HKLM:\\SYSTEM\\CurrentControlSet\\Enum\\USBSTOR';"
                "if (Test-Path $path) {"
                "  Get-ChildItem $path | ForEach-Object {"
                "    $devClass = $_.PSChildName;"
                "    Get-ChildItem $_.PSPath | ForEach-Object {"
                "      $serial = $_.PSChildName;"
                "      $friendly = (Get-ItemProperty $_.PSPath -ErrorAction SilentlyContinue).FriendlyName;"
                "      $mfr = (Get-ItemProperty $_.PSPath -ErrorAction SilentlyContinue).Mfg;"
                "      $inst = $_.PSPath -replace '.*Enum\\\\','';"
                "      Write-Output ($friendly + '|||' + $inst + '|||' + $mfr + '|||' + $devClass + '|||' + $serial)"
                "    }"
                "  }"
                "}"
            )
            out = self._usb_run_ps(ps, timeout=30)
            devices = []
            for line in out.splitlines():
                parts = line.split('|||')
                if len(parts) >= 4:
                    devices.append({
                        'name':   parts[0].strip() or 'Unknown Device',
                        'id':     parts[1].strip(),
                        'mfr':    parts[2].strip() or '',
                        'class':  parts[3].strip(),
                        'status': 'Historical',
                        'seen':   parts[4].strip() if len(parts) > 4 else '',
                    })
            self.after(0, lambda: self._usb_populate(devices))
        threading.Thread(target=_run, daemon=True).start()

    def _usb_populate(self, devices: list):
        self._usb_all_devices = devices
        self._usb_tree.delete(*self._usb_tree.get_children())
        unknown_count = 0
        for d in devices:
            did = d.get('id', '')
            tag = 'whitelisted' if did in self._usb_whitelist else 'unknown'
            if tag == 'unknown': unknown_count += 1
            self._usb_tree.insert('', 'end', iid=did or d['name'],
                values=(d['name'], did, d.get('mfr',''), d.get('class',''),
                        d.get('status',''), d.get('seen','')), tags=(tag,))
        self._usb_status_lbl.config(
            text=f"[OK] {len(devices)} USB devices  |  [OK] Whitelisted: {len(devices)-unknown_count}"
                 f"  |  [WARN] Unknown: {unknown_count}",
            fg=Colors.GAUGE_ORANGE if unknown_count else Colors.GAUGE_GREEN)

    def _usb_add_whitelist(self):
        sel = self._usb_tree.selection()
        if not sel:
            messagebox.showwarning("USB Guard", "Select a device first."); return
        did = self._usb_tree.item(sel[0], 'values')[1]
        name = self._usb_tree.item(sel[0], 'values')[0]
        self._usb_whitelist.add(did)
        self._usb_wl_box.insert('end', f"{name}\n  {did}\n\n")
        self._usb_save_whitelist()
        # Refresh row color
        self._usb_tree.item(sel[0], tags=('whitelisted',))
        messagebox.showinfo("Whitelist", f"Added to whitelist:\n{name}")

    def _usb_remove_whitelist(self):
        try:
            idx = self._usb_wl_box.index('sel.first')
            self._usb_wl_box.delete('sel.first', 'sel.last')
        except Exception:
            messagebox.showwarning("USB Guard", "Select text in the whitelist to remove.")

    def _usb_block_device(self):
        sel = self._usb_tree.selection()
        if not sel:
            messagebox.showwarning("USB Guard", "Select a device first."); return
        name = self._usb_tree.item(sel[0], 'values')[0]
        did  = self._usb_tree.item(sel[0], 'values')[1]
        if not messagebox.askyesno("Block Device",
                f"Disable device:\n{name}\n\nThis will prevent it from working until re-enabled."): return
        import threading
        def _run():
            # Extract the short PnP ID for Disable-PnpDevice
            pnp_id = did.split('\\')[-2] + '\\' + did.split('\\')[-1] if '\\' in did else did
            ps = f"Disable-PnpDevice -InstanceId '{did}' -Confirm:$false -ErrorAction SilentlyContinue"
            out = self._usb_run_ps(ps, timeout=20)
            self.after(0, lambda: messagebox.showinfo("Device Blocked",
                f"Device '{name}' has been disabled.\n\nTo re-enable: Device Manager → Show hidden devices"))
            self._usb_alert_log_msg(f"🚫 BLOCKED: {name}")
            self._usb_tree.item(sel[0], tags=('blocked',))
        threading.Thread(target=_run, daemon=True).start()

    def _usb_toggle_monitor(self):
        self._usb_monitor_active = not self._usb_monitor_active
        if self._usb_monitor_active:
            self._usb_mon_indicator.config(text="● MONITOR ON", fg=Colors.GAUGE_GREEN)
            self._usb_alert_log_msg("USB monitor started")
            import threading
            threading.Thread(target=self._usb_monitor_loop, daemon=True).start()
        else:
            self._usb_mon_indicator.config(text="● MONITOR OFF", fg=Colors.TEXT_DIM)
            self._usb_alert_log_msg("USB monitor stopped")

    def _usb_monitor_loop(self):
        import time
        # Snapshot current devices
        ps = (
            "Get-PnpDevice -Class USB -ErrorAction SilentlyContinue | "
            "Where-Object {$_.InstanceId -like 'USB*'} | "
            "Select-Object -ExpandProperty InstanceId"
        )
        snapshot = set(self._usb_run_ps(ps).splitlines())
        self._usb_known_devices = snapshot
        while getattr(self, '_usb_monitor_active', False):
            time.sleep(3)
            try:
                # Check if app window still exists before continuing
                if not self.winfo_exists():
                    break
                current = set(self._usb_run_ps(ps).splitlines())
                new_devs = current - self._usb_known_devices
                removed  = self._usb_known_devices - current
                for dev in new_devs:
                    dev = dev.strip()
                    if not dev: continue
                    wl = dev in getattr(self, '_usb_whitelist', set())
                    msg = f"{'[OK] KNOWN' if wl else '[WARN] UNKNOWN'} USB inserted: {dev[:60]}"
                    self.after(0, lambda m=msg: self._usb_alert_log_msg(m))
                    if not wl:
                        self.after(0, lambda d=dev: messagebox.showwarning(
                            "USB Guard — Unknown Device",
                            f"Unknown USB device connected:\n{d}\n\nAdd to whitelist if trusted."))
                for dev in removed:
                    dev = dev.strip()
                    if not dev: continue
                    self.after(0, lambda d=dev:
                        self._usb_alert_log_msg(f"🔌 USB removed: {d[:60]}"))
                self._usb_known_devices = current
            except Exception:
                # Window closed or other error - exit gracefully
                break
                pass

    def _usb_alert_log_msg(self, msg: str):
        if not hasattr(self, '_usb_alert_log'):
            return  # USB tab not built yet
        import datetime
        ts = datetime.datetime.now().strftime('%H:%M:%S')
        try:
            self._usb_alert_log.config(state='normal')
            self._usb_alert_log.insert('end', f"[{ts}] {msg}\n")
            self._usb_alert_log.see('end')
            self._usb_alert_log.config(state='disabled')
        except Exception:
            pass

    def _usb_copy_id(self):
        sel = self._usb_tree.selection()
        if sel:
            did = self._usb_tree.item(sel[0], 'values')[1]
            self.clipboard_clear(); self.clipboard_append(did)

    def _usb_sort(self, col: str):
        items = [(self._usb_tree.set(k, col), k) for k in self._usb_tree.get_children('')]
        rev = (col == self._usb_sort_col) and not self._usb_sort_rev
        self._usb_sort_col = col; self._usb_sort_rev = rev
        items.sort(key=lambda x: x[0].lower(), reverse=rev)
        for idx, (_, k) in enumerate(items):
            self._usb_tree.move(k, '', idx)

    def _usb_whitelist_path(self):
        import os
        return os.path.join(os.path.dirname(os.path.abspath(__file__)), 'usb_whitelist.txt')

    def _usb_load_whitelist(self):
        try:
            with open(self._usb_whitelist_path(), 'r', encoding='utf-8') as f:
                for line in f:
                    line = line.strip()
                    if line:
                        self._usb_whitelist.add(line)
                        self._usb_wl_box.insert('end', line + '\n')
        except FileNotFoundError:
            pass
        except Exception:
            pass

    def _usb_save_whitelist(self):
        try:
            with open(self._usb_whitelist_path(), 'w', encoding='utf-8') as f:
                for entry in self._usb_whitelist:
                    f.write(entry + '\n')
        except Exception as e:
            logging.getLogger('Downpour').warning(f"USB whitelist save failed: {e}")

    def _usb_export(self):
        from tkinter import filedialog
        path = filedialog.asksaveasfilename(defaultextension='.csv',
            filetypes=[('CSV','*.csv')], title="Export USB Device List")
        if not path: return
        try:
            import csv
            with open(path, 'w', newline='', encoding='utf-8') as f:
                w = csv.writer(f)
                w.writerow(['Device','Device ID','Manufacturer','Class','Status','First Seen','Whitelisted'])
                for d in self._usb_all_devices:
                    w.writerow([d.get('name',''), d.get('id',''), d.get('mfr',''),
                                d.get('class',''), d.get('status',''), d.get('seen',''),
                                'Yes' if d.get('id','') in self._usb_whitelist else 'No'])
            messagebox.showinfo("Exported", f"Saved to:\n{path}")
        except Exception as e:
            messagebox.showerror("Export Error", str(e))

    # ==========================================================================
    #  🌐 NETWORK TAB — Bandwidth Monitor Enhancement
    # (called from _build_network_tab, adds bandwidth stats bar)
    # ==========================================================================

    def _net_start_bandwidth_monitor(self):
        """Start background bandwidth monitoring thread."""
        import threading
        if getattr(self, '_net_bw_running', False):
            return
        self._net_bw_running = True
        threading.Thread(target=self._net_bw_loop, daemon=True).start()

    def _net_bw_loop(self):
        import time, psutil
        prev = psutil.net_io_counters()
        while getattr(self, '_net_bw_running', False):
            time.sleep(2)
            try:
                curr = psutil.net_io_counters()
                sent  = (curr.bytes_sent  - prev.bytes_sent)  / 2
                recv  = (curr.bytes_recv  - prev.bytes_recv)  / 2
                pkts_s = (curr.packets_sent - prev.packets_sent) / 2
                pkts_r = (curr.packets_recv - prev.packets_recv) / 2
                prev = curr

                def _fmt(b):
                    if b >= 1_048_576: return f"{b/1_048_576:.1f} MB/s"
                    if b >= 1024:      return f"{b/1024:.1f} KB/s"
                    return f"{b:.0f} B/s"

                txt = (f"⬆ {_fmt(sent)}  ⬇ {_fmt(recv)}"
                       f"  |  📦 {pkts_s:.0f} pkt/s out  {pkts_r:.0f} pkt/s in")
                if hasattr(self, '_net_bw_lbl'):
                    self.after(0, lambda t=txt: self._net_bw_lbl.config(text=t,
                        fg=Colors.GAUGE_GREEN))
            except Exception:
                pass

