    def _cleanup_registry_junk(self):
        """Clean up junk registry entries"""
        def _run():
            self._log_registry_event("🧹 Cleaning up registry junk...")
            
            try:
                import winreg
                cleanup_count = 0
                
                # Common junk locations to clean
                junk_paths = [
                    (winreg.HKEY_CURRENT_USER, r'SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\RecentDocs'),
                    (winreg.HKEY_CURRENT_USER, r'SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\RunMRU'),
                    (winreg.HKEY_LOCAL_MACHINE, r'SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall'),
                ]
                
                for root, subkey in junk_paths:
                    try:
                        key = winreg.OpenKey(root, subkey, 0, winreg.KEY_READ | winreg.KEY_SET_VALUE)
                        
                        # Count and clean old entries
                        i = 0
                        while True:
                            try:
                                name, value, type = winreg.EnumValue(key, i)
                                # Clean old/unwanted entries
                                if any(keyword in name.lower() for keyword in ['temp', 'cache', 'old', 'backup']):
                                    winreg.DeleteValue(key, name)
                                    cleanup_count += 1
                                else:
                                    i += 1
                            except WindowsError:
                                break
                        
                        winreg.CloseKey(key)
                    except Exception:
                        pass
                
                self._log_registry_event(f"🧹 Registry cleanup complete: {cleanup_count} entries removed")
                    
            except Exception as e:
                self._log_registry_event(f"❌ Registry cleanup failed: {e}")
        
        import threading
        threading.Thread(target=_run, daemon=True).start()

