    def _emergency_collect_forensics(self):
        """Collect forensic artifacts: process list, network connections, recent events."""
        from tkinter import filedialog
        import threading, datetime, os
        ts = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
        path = filedialog.asksaveasfilename(
            defaultextension='.txt',
            initialfile=f'downpour_forensics_{ts}.txt',
            filetypes=[('Text','*.txt'),('All','*.*')],
            title="Save Forensic Collection")
        if not path: return

        def _log(msg):
            self._emergency_log.config(state='normal')
            self._emergency_log.insert('end', msg + '\n')
            self._emergency_log.see('end')
            self._emergency_log.config(state='disabled')

        def _run():
            self.after(0, lambda: _log("🔬 Starting forensic collection..."))
            import subprocess, psutil
            lines = [f"DOWNPOUR FORENSIC COLLECTION — {ts}", "="*60, ""]

            # Process list
            lines.append("=== RUNNING PROCESSES ===")
            try:
                for proc in sorted(psutil.process_iter(['pid','name','exe','username',
                                                         'cpu_percent','memory_percent',
                                                         'create_time','cmdline']),
                                   key=lambda p: p.info['pid']):
                    try:
                        info = proc.info
                        lines.append(f"PID {info['pid']:5}  {info['name'][:40]:40}  "
                                     f"CPU:{info['cpu_percent']:5.1f}%  "
                                     f"MEM:{info['memory_percent']:5.1f}%  "
                                     f"User:{info['username'] or '?'}  "
                                     f"Exe:{info['exe'] or 'N/A'}")
                    except Exception:
                        pass
            except Exception as e:
                lines.append(f"Error: {e}")

            lines += ["", "=== NETWORK CONNECTIONS ==="]
            try:
                for conn in psutil.net_connections(kind='inet'):
                    try:
                        la = f"{conn.laddr.ip}:{conn.laddr.port}" if conn.laddr else '?'
                        ra = f"{conn.raddr.ip}:{conn.raddr.port}" if conn.raddr else '*'
                        lines.append(f"PID {conn.pid or 0:5}  {conn.status:12}  "
                                     f"{la:25} -> {ra}")
                    except Exception:
                        pass
            except Exception as e:
                lines.append(f"Error: {e}")

            lines += ["", "=== AUTORUN ENTRIES (HKLM\\Run) ==="]
            try:
                import winreg
                for hive, path_r in [
                    (winreg.HKEY_LOCAL_MACHINE, r'SOFTWARE\Microsoft\Windows\CurrentVersion\Run'),
                    (winreg.HKEY_CURRENT_USER,  r'SOFTWARE\Microsoft\Windows\CurrentVersion\Run'),
                ]:
                    try:
                        with winreg.OpenKey(hive, path_r) as k:
                            i = 0
                            while True:
                                try:
                                    name, val, _ = winreg.EnumValue(k, i)
                                    lines.append(f"  {name}: {val}")
                                    i += 1
                                except OSError:
                                    break
                    except Exception:
                        pass
            except Exception as e:
                lines.append(f"Error: {e}")

            lines += ["", "=== RECENT SECURITY EVENTS (last 50) ==="]
            try:
                ps_cmd = (
                    'Get-WinEvent -FilterHashtable @{LogName="Security";Level=2,3} '
                    '-MaxEvents 50 -ErrorAction SilentlyContinue | '
                    'ForEach-Object { $_.TimeCreated.ToString("yyyy-MM-dd HH:mm:ss") + " ID:" + '
                    '$_.Id + " " + ($_.Message -replace "\\n"," ").Substring(0,[Math]::Min(120,($_.Message).Length)) }'
                )
                r = subprocess.run(['powershell', '-NoProfile', '-Command', ps_cmd],
                                   capture_output=True, text=True, timeout=30,
                                   creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0x08000000))
                lines += r.stdout.splitlines()[:60]
            except Exception as e:
                lines.append(f"Error: {e}")

            lines += ["", "=== SYSTEM INFO ==="]
            try:
                r2 = subprocess.run(['systeminfo'], capture_output=True, text=True, timeout=30,
                                    creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0x08000000))
                lines += r2.stdout.splitlines()[:40]
            except Exception as e:
                lines.append(f"Error: {e}")

            with open(path, 'w', encoding='utf-8', errors='replace') as f:
                f.write('\n'.join(lines))

            count = len(lines)
            self.after(0, lambda: _log(f"[OK] Forensic collection complete — {count} lines → {path}"))
            self.after(0, lambda: messagebox.showinfo("Forensics",
                f"Collection saved to:\n{path}\n\n{count} lines of data captured."))
        threading.Thread(target=_run, daemon=True).start()

