    def _emergency_quarantine_all(self):
        """Quarantine EXEs of every suspicious process."""
        import threading, tkinter.messagebox as mb
        procs = [p for p in getattr(self, '_proc_cache', []) if p.is_suspicious]
        if not procs:
            mb.showinfo('Quarantine All', 'No suspicious processes detected.')
            return
        if not mb.askyesno('Quarantine ALL',
                           f'Quarantine {len(procs)} suspicious process EXE(s)?\n'
                           f'This will terminate and quarantine:\n' +
                           '\n'.join(f'  {p.name}' for p in procs[:8]) +
                           ('\n  ...' if len(procs) > 8 else ''),
                           icon='warning'):
            return
        def _run():
            moved = []
            for proc in procs:
                try:
                    self._mitigate_single(proc.pid, 'quarantine')
                    moved.append(proc.name)
                except Exception:
                    pass
            self.after(0, lambda: (
                self._scan_processes_now(),
                mb.showinfo('Done', f'Quarantined {len(moved)} process EXE(s).')
            ))
        threading.Thread(target=_run, daemon=True).start()

    def _emergency_wipe_temp(self):
        """Wipe common temp/cache directories that malware stages from."""
        import subprocess, tkinter.messagebox as mb, os
        _NO_WIN = 0x08000000
        dirs = [
            os.environ.get('TEMP', r'C:\Windows\Temp'),
            os.environ.get('TMP',  r'C:\Windows\Temp'),
            os.path.join(os.environ.get('LOCALAPPDATA',''), 'Temp'),
            r'C:\Windows\Prefetch',
        ]
        try:
            for d in dirs:
                if d and os.path.isdir(d):
                    subprocess.run(
                        ['cmd', '/c', f'del /q /s /f "{d}\\*" 2>nul'],
                        capture_output=True, timeout=30, creationflags=_NO_WIN)
            mb.showinfo('Wipe Complete',
                        f'Temp/cache wiped:\n' + '\n'.join(d for d in dirs if d))
            self._queue_alert('[WIPE] Temp/cache directories cleared', Colors.GAUGE_TEAL)
        except Exception as e:
            mb.showerror('Wipe Error', str(e))

    def _emergency_ir_report(self):
        """Generate a full Incident Response HTML report."""
        self._threats_generate_report()

    # ── v29 Network power-button implementations ──────────────────────────────

    def _net_block_all_c2(self):
        """Block every C2/malicious IP seen in current connections via firewall."""
        import subprocess, tkinter.messagebox as mb
        _NO_WIN = 0x08000000
        c2_ips = [e['remote_ip'] for e in getattr(self, '_conn_cache', [])
                  if e.get('threat') and e.get('remote_ip')
                  and e['remote_ip'] not in ('', '*', '0.0.0.0', '127.0.0.1')]
        if not c2_ips:
            mb.showinfo('Block C2', 'No C2/threat IPs found in current connections.')
            return
        if not mb.askyesno('Block ALL C2 IPs',
                           f'Add firewall BLOCK rules for {len(c2_ips)} C2 IP(s)?\n' +
                           '\n'.join(c2_ips[:10]) + ('\n...' if len(c2_ips) > 10 else '')):
            return
        blocked = []
        for ip in set(c2_ips):
            try:
                subprocess.run([
                    'netsh', 'advfirewall', 'firewall', 'add', 'rule',
                    f'name=Downpour_C2_Block_{ip}', 'dir=out',
                    'action=block', f'remoteip={ip}', 'enable=yes'],
                    capture_output=True, timeout=15, creationflags=_NO_WIN)
                blocked.append(ip)
            except Exception:
                pass
        self._queue_alert(f'[NET] Blocked {len(blocked)} C2 IP(s) in firewall', Colors.GAUGE_RED)
        mb.showinfo('Blocked', f'Added firewall block rules for {len(blocked)} IPs.')

    def _net_kill_c2_procs(self):
        """Kill all processes that have active C2 connections."""
        import subprocess, tkinter.messagebox as mb, psutil
        _NO_WIN = 0x08000000
        c2_pids = {e['pid'] for e in getattr(self, '_conn_cache', [])
                   if e.get('threat') and e.get('pid')}
        if not c2_pids:
            mb.showinfo('Kill C2 Procs', 'No C2-connected processes found.')
            return
        names = []
        for pid in c2_pids:
            try:
                p = psutil.Process(pid)
                names.append(f'PID {pid}: {p.name()}')
            except Exception:
                names.append(f'PID {pid}')
        if not mb.askyesno('Kill C2 Processes',
                           f'Kill {len(c2_pids)} process(es) with C2 connections?\n' +
                           '\n'.join(names[:10]), icon='warning'):
            return
        killed = 0
        for pid in c2_pids:
            try:
                subprocess.run(['taskkill', '/F', '/PID', str(pid)],
                               capture_output=True, timeout=10, creationflags=_NO_WIN)
                killed += 1
            except Exception:
                pass
        self._queue_alert(f'[NET] Killed {killed} C2-connected process(es)', Colors.GAUGE_RED)
        mb.showinfo('Done', f'Killed {killed} process(es).')
        self._refresh_network()

    def _net_whitelist_selected(self):
        """Add selected IP to session whitelist (suppresses future threat flags)."""
        import tkinter.messagebox as mb
        sel = self._net_tree.selection()
        if not sel:
            mb.showwarning('Whitelist', 'Select a connection first.')
            return
        values = self._net_tree.item(sel[0], 'values')
        ip = values[3] if len(values) > 3 else ''
        if not ip or ip in ('*', ''):
            mb.showwarning('Whitelist', 'No valid remote IP for selected connection.')
            return
        if not hasattr(self, '_ip_whitelist'):
            self._ip_whitelist = set()
        self._ip_whitelist.add(ip)
        self._queue_alert(f'[NET] Whitelisted {ip} — future alerts suppressed', Colors.GAUGE_GREEN)
        mb.showinfo('Whitelisted', f'{ip} added to session whitelist.')

    def _net_export_csv(self):
        """Export all network connections to CSV."""
        from tkinter import filedialog
        import tkinter.messagebox as mb
        path = filedialog.asksaveasfilename(
            defaultextension='.csv',
            filetypes=[('CSV', '*.csv'), ('All', '*.*')],
            title='Export Network Connections')
        if not path:
            return
        try:
            conns = getattr(self, '_conn_cache', [])
            with open(path, 'w', encoding='utf-8') as f:
                f.write('PID,Process,Local,Remote IP,Port,Status,Threat,Country\n')
                for c in conns:
                    f.write(f"{c.get('pid','')},{c.get('process','')},{c.get('local','')}"
                            f",{c.get('remote_ip','')},{c.get('port','')},{c.get('status','')}"
                            f",\"{c.get('threat','')}\",{c.get('country','')}\n")
            mb.showinfo('Exported', f'Connections saved to:\n{path}')
        except Exception as e:
            mb.showerror('Export Error', str(e))

