    def _procs_kill_all_suspicious(self):
        """Kill every process with risk score ≥ 50."""
        import subprocess, tkinter.messagebox as mb
        _NO_WIN = 0x08000000
        suspects = [p for p in getattr(self, '_proc_cache', [])
                    if getattr(p, 'is_suspicious', False)]
        if not suspects:
            mb.showinfo('Kill All', 'No suspicious processes found.')
            return
        if not mb.askyesno('Kill ALL Suspicious',
                           f'Kill {len(suspects)} suspicious process(es)?\n' +
                           '\n'.join(f'  PID {p.pid}: {p.name}' for p in suspects[:10]) +
                           ('\n  ...' if len(suspects) > 10 else ''),
                           icon='warning'):
            return
        killed = 0
        for proc in suspects:
            try:
                subprocess.run(['taskkill', '/F', '/PID', str(proc.pid)],
                               capture_output=True, timeout=10, creationflags=_NO_WIN)
                killed += 1
            except Exception:
                pass
        self._queue_alert(f'[PROC] Killed {killed} suspicious process(es)', Colors.GAUGE_RED)
        mb.showinfo('Done', f'Killed {killed} suspicious process(es).')
        self._scan_processes_now()

