    def _procs_scan_selected_exe(self):
        """Hash + YARA scan the EXE of the selected process."""
        import tkinter.messagebox as mb
        sel = getattr(self, '_proc_tree', None) and self._proc_tree.selection()
        if not sel:
            mb.showwarning('Scan EXE', 'Select a process first.')
            return
        vals = self._proc_tree.item(sel[0], 'values')
        pid_str = vals[0] if vals else ''
        try:
            pid = int(pid_str)
            import psutil
            exe = psutil.Process(pid).exe()
            if exe:
                self._queue_alert(f'[SCAN] Queuing EXE scan: {exe}', Colors.GAUGE_TEAL)
                self._executor.submit(self._scan_single_file, exe)
            else:
                mb.showinfo('Scan EXE', 'No EXE path available for this process.')
        except Exception as e:
            mb.showerror('Scan Error', str(e))



