    # ── IoT tab helpers ───────────────────────────────────────────────────────

    def _iot_set_status(self, txt: str, col=None):
        try:
            import tkinter as tk
            if col is None:
                col = Colors.GAUGE_YELLOW
            self._iot_status_lbl.config(text=txt, fg=col)
        except Exception:
            pass

    def _iot_log_prog(self, txt: str):
        try:
            self._iot_prog_lbl.config(text=txt)
        except Exception:
            pass

    def _iot_populate_row(self, dev):
        """Insert or update a device row in the treeview."""
        try:
            import tkinter as tk
            ports_str = ', '.join(str(p) for p in sorted(dev.open_ports)[:8])
            blocked_str = '🚫' if dev.is_blocked else ''
            vals = (dev.ip, dev.mac or '—', dev.vendor or '—',
                    dev.device_type or '—', ports_str or '—',
                    dev.risk_level or '?', blocked_str)
            tag = dev.risk_level if dev.risk_level in ('CRITICAL', 'HIGH', 'MEDIUM', 'LOW') else ''
            if dev.is_blocked:
                tag = 'BLOCKED'
            # Update existing row or insert
            existing = [i for i in self._iot_tree.get_children()
                        if self._iot_tree.item(i, 'values')[0] == dev.ip]
            if existing:
                self._iot_tree.item(existing[0], values=vals, tags=(tag,))
            else:
                self._iot_tree.insert('', 'end', values=vals, tags=(tag,))
        except Exception:
            pass

    def _iot_scan_network(self):
        """Run full subnet scan in background thread."""
        if not self._iot_scanner:
            return
        import threading
        self._iot_set_status('● SCANNING...', Colors.GAUGE_YELLOW)

        def _run():
            try:
                subnet = self._iot_scanner.get_local_subnet()
                self.after(0, lambda: self._iot_log_prog(f"Scanning subnet {subnet} ..."))

                def _progress(msg):
                    self.after(0, lambda m=msg: self._iot_log_prog(m))

                devices = self._iot_scanner.scan_subnet(subnet, progress_cb=_progress)
                self._iot_devices = {d.ip: d for d in devices}

                def _populate():
                    # Clear old rows
                    for row in self._iot_tree.get_children():
                        self._iot_tree.delete(row)
                    for dev in sorted(devices, key=lambda d: d.ip):
                        self._iot_populate_row(dev)
                    self._iot_set_status(f'● DONE — {len(devices)} device(s) found', Colors.GAUGE_GREEN)
                    self._iot_log_prog(f"Scan complete. {len(devices)} devices found on {subnet}")

                self.after(0, _populate)
            except Exception as e:
                self.after(0, lambda _e=str(e): self._iot_set_status(f'● ERROR: {_e}', Colors.GAUGE_RED))

        threading.Thread(target=_run, daemon=True).start()

    def _iot_selected_ip(self):
        sel = self._iot_tree.selection()
        if not sel:
            return None
        vals = self._iot_tree.item(sel[0], 'values')
        return vals[0] if vals else None

    def _iot_on_select(self, _event=None):
        """Show device details when a row is selected."""
        ip = self._iot_selected_ip()
        if not ip or ip not in self._iot_devices:
            return
        dev = self._iot_devices[ip]
        try:
            lines = [
                f"IP Address : {dev.ip}",
                f"MAC Address: {dev.mac or '—'}",
                f"Hostname   : {dev.hostname or '—'}",
                f"Vendor     : {dev.vendor or '—'}",
                f"Device Type: {dev.device_type or '—'}",
                f"Risk Level : {dev.risk_level or '—'}",
                f"Blocked    : {'Yes' if dev.is_blocked else 'No'}",
                f"Last Seen  : {dev.last_seen or '—'}",
                "",
                f"Open Ports ({len(dev.open_ports)}):",
            ]
            for port in sorted(dev.open_ports):
                lines.append(f"  • {port}")
            if dev.http_banner:
                lines += ["", "HTTP Banner:", f"  {dev.http_banner}"]
            if dev.telnet_banner:
                lines += ["", "Telnet Banner:", f"  {dev.telnet_banner[:200]}"]
            if dev.notes:
                lines += ["", "Notes:", f"  {dev.notes}"]

            txt = '\n'.join(lines)
            self._iot_detail.config(state='normal')
            self._iot_detail.delete('1.0', 'end')
            self._iot_detail.insert('end', txt)
            self._iot_detail.config(state='disabled')

            # Botnet indicators
            if dev.botnet_indicators:
                self._iot_botnet_lbl.config(
                    text='\n'.join(f"[WARN] {b}" for b in dev.botnet_indicators),
                    fg=Colors.GAUGE_RED)
            else:
                self._iot_botnet_lbl.config(text="None detected", fg=Colors.GAUGE_GREEN)
        except Exception:
            pass

    def _iot_fingerprint_sel(self):
        """Re-fingerprint selected device."""
        ip = self._iot_selected_ip()
        if not ip or not self._iot_scanner:
            from tkinter import messagebox
            messagebox.showwarning("IoT Scanner", "Select a device first.")
            return
        import threading

        self._iot_set_status(f'● Fingerprinting {ip}...', Colors.GAUGE_YELLOW)

        def _run():
            try:
                mac = (self._iot_devices.get(ip) or type('_', (), {'mac': None})()).mac
                dev = self._iot_scanner.fingerprint_device(ip, mac or '')
                self._iot_devices[ip] = dev
                self.after(0, lambda: self._iot_populate_row(dev))
                self.after(0, lambda: self._iot_on_select())
                self.after(0, lambda: self._iot_set_status(
                    f'● Fingerprint done — Risk: {dev.risk_level}', Colors.GAUGE_GREEN))
            except Exception as e:
                self.after(0, lambda _e=str(e): self._iot_set_status(f'● Fingerprint error: {_e}', Colors.GAUGE_RED))

        threading.Thread(target=_run, daemon=True).start()

    def _iot_mozi_scan_sel(self):
        """Deep Mozi botnet scan on selected device."""
        ip = self._iot_selected_ip()
        if not ip or not self._iot_scanner:
            from tkinter import messagebox
            messagebox.showwarning("IoT Scanner", "Select a device first.")
            return
        import threading

        self._iot_set_status(f'● Mozi scan {ip}...', Colors.GAUGE_YELLOW)

        def _run():
            try:
                results = self._iot_scanner.scan_mozi(ip)
                summary = '; '.join(results) if results else 'No Mozi indicators found'
                dev = self._iot_devices.get(ip)
                if dev and results:
                    dev.botnet_indicators = list(set(dev.botnet_indicators + results))
                    dev.risk_level = 'CRITICAL'
                    self._iot_devices[ip] = dev
                    self.after(0, lambda: self._iot_populate_row(dev))
                    self.after(0, lambda: self._iot_on_select())
                self.after(0, lambda s=summary: self._iot_set_status(
                    f'● Mozi: {s[:80]}', Colors.GAUGE_RED if results else Colors.GAUGE_GREEN))
            except Exception as e:
                self.after(0, lambda _e=str(e): self._iot_set_status(f'● Mozi scan error: {_e}', Colors.GAUGE_RED))

        threading.Thread(target=_run, daemon=True).start()

    def _iot_block_sel(self):
        """Block selected device via Windows Firewall."""
        ip = self._iot_selected_ip()
        if not ip or not self._iot_scanner:
            from tkinter import messagebox
            messagebox.showwarning("IoT Scanner", "Select a device first.")
            return
        from tkinter import messagebox
        if not messagebox.askyesno("Block Device",
                                    f"Add Windows Firewall rules to BLOCK all traffic\nto/from {ip}?\n\nThis takes effect immediately."):
            return
        import threading

        def _run():
            try:
                self._iot_scanner.block_device(ip)
                dev = self._iot_devices.get(ip)
                if dev:
                    dev.is_blocked = True
                    self._iot_devices[ip] = dev
                    self.after(0, lambda: self._iot_populate_row(dev))
                self.after(0, lambda: self._iot_set_status(f'● {ip} BLOCKED', Colors.GAUGE_RED))
            except Exception as e:
                self.after(0, lambda _e=str(e): self._iot_set_status(f'● Block error: {_e}', Colors.GAUGE_RED))

        threading.Thread(target=_run, daemon=True).start()

    def _iot_unblock_sel(self):
        """Remove firewall block for selected device."""
        ip = self._iot_selected_ip()
        if not ip or not self._iot_scanner:
            from tkinter import messagebox
            messagebox.showwarning("IoT Scanner", "Select a device first.")
            return
        import threading

        def _run():
            try:
                self._iot_scanner.unblock_device(ip)
                dev = self._iot_devices.get(ip)
                if dev:
                    dev.is_blocked = False
                    self._iot_devices[ip] = dev
                    self.after(0, lambda: self._iot_populate_row(dev))
                self.after(0, lambda: self._iot_set_status(f'● {ip} unblocked', Colors.GAUGE_GREEN))
            except Exception as e:
                self.after(0, lambda _e=str(e): self._iot_set_status(f'● Unblock error: {_e}', Colors.GAUGE_RED))

        threading.Thread(target=_run, daemon=True).start()

    def _iot_router_cmds_sel(self):
        """Show router/firewall block commands for selected device."""
        ip = self._iot_selected_ip()
        if not ip or not self._iot_scanner:
            from tkinter import messagebox
            messagebox.showwarning("IoT Scanner", "Select a device first.")
            return
        try:
            import tkinter as tk
            from tkinter import scrolledtext as _st
            cmds = self._iot_scanner.get_router_commands(ip)
            win = tk.Toplevel(self)
            win.title(f"Block Commands — {ip}")
            win.configure(bg=Colors.BG_VOID)
            win.geometry("620x440")
            tk.Label(win, text=f"Commands to block {ip} on various platforms:",
                     font=('Consolas', 9, 'bold'), fg=Colors.GAUGE_YELLOW,
                     bg=Colors.BG_VOID).pack(anchor='w', padx=8, pady=(8, 0))
            txt = _st.ScrolledText(win, font=('Consolas', 8), bg=Colors.GLASS_CARD,
                                    fg=Colors.TEXT_BRIGHT, relief='flat', wrap='word')
            txt.pack(fill='both', expand=True, padx=8, pady=4)
            txt.insert('end', cmds)
            txt.config(state='disabled')
            tk.Button(win, text="Close", font=('Consolas', 9),
                      bg=Colors.GLASS_CARD, fg=Colors.TEXT_DIM, relief='flat',
                      command=win.destroy).pack(pady=(0, 6))
        except Exception as e:
            from tkinter import messagebox
            messagebox.showerror("Router Commands", str(e))

    def _iot_copy_sel(self):
        """Copy selected device info to clipboard."""
        ip = self._iot_selected_ip()
        if not ip or ip not in self._iot_devices:
            return
        dev = self._iot_devices[ip]
        try:
            import tkinter as tk
            info = (f"IP: {dev.ip}\nMAC: {dev.mac}\nVendor: {dev.vendor}\n"
                    f"Device: {dev.device_type}\nRisk: {dev.risk_level}\n"
                    f"Ports: {', '.join(str(p) for p in sorted(dev.open_ports))}\n"
                    f"Indicators: {'; '.join(dev.botnet_indicators)}")
            self.clipboard_clear()
            self.clipboard_append(info)
            self._iot_set_status('● Copied to clipboard', Colors.GAUGE_GREEN)
        except Exception:
            pass

