    def _threats_lookup_intel(self):
        """Open threat intel search in browser for selected alert."""
        import re, webbrowser, tkinter.messagebox as mb
        entries = self._threats_selected_entries()
        if not entries:
            mb.showwarning('Intel Lookup', 'Select a threat first.')
            return
        e = entries[0]
        msg = e['description']
        # Try to extract IP, hash, or domain for lookup
        ip_m   = re.search(r'\b(\d{1,3}(?:\.\d{1,3}){3})\b', msg)
        hash_m = re.search(r'\b([a-fA-F0-9]{64}|[a-fA-F0-9]{40}|[a-fA-F0-9]{32})\b', msg)
        dom_m  = re.search(r'\b([a-z0-9\-]{3,}\.[a-z]{2,6})\b', msg, re.IGNORECASE)

        if hash_m:
            query = hash_m.group(1)
            url = f'https://www.virustotal.com/gui/search/{query}'
        elif ip_m:
            query = ip_m.group(1)
            url = f'https://www.abuseipdb.com/check/{query}'
        elif dom_m:
            query = dom_m.group(1)
            url = f'https://www.virustotal.com/gui/domain/{query}'
        else:
            # Fall back to general search
            query = e['category']
            url = f'https://www.google.com/search?q=site:attack.mitre.org+{query}'

        webbrowser.open(url)
        self._queue_alert(f'[INTEL] Looking up: {query}', Colors.GAUGE_TEAL)



